--
-- Name: allocate_workers(uuid, uuid, integer, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.allocate_workers(p_run_id uuid, p_environment_id uuid, p_worker_count integer, p_worker_pool_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_env RECORD;
  v_pool RECORD;
  v_available INTEGER;
  v_allocation_id UUID;
BEGIN
  SELECT * INTO v_env
  FROM test_environments
  WHERE id = p_environment_id AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Environment not found');
  END IF;

  IF v_env.status != 'available' THEN
    RETURN jsonb_build_object('error', 'Environment is not available');
  END IF;

  v_available := v_env.capacity - v_env.allocated;
  IF p_worker_count > v_available THEN
    RETURN jsonb_build_object('error', 'Insufficient capacity', 'available', v_available);
  END IF;

  IF p_worker_pool_id IS NOT NULL THEN
    SELECT * INTO v_pool
    FROM worker_pools
    WHERE id = p_worker_pool_id
    FOR UPDATE;

    IF NOT FOUND THEN
      RETURN jsonb_build_object('error', 'Worker pool not found');
    END IF;

    IF v_pool.available_workers < p_worker_count THEN
      RETURN jsonb_build_object('error', 'Insufficient workers in pool', 'available', v_pool.available_workers);
    END IF;

    UPDATE worker_pools SET
      available_workers = available_workers - p_worker_count,
      assigned_workers = assigned_workers + p_worker_count,
      updated_at = NOW()
    WHERE id = p_worker_pool_id;
  END IF;

  UPDATE test_environments SET
    allocated = allocated + p_worker_count,
    updated_at = NOW()
  WHERE id = p_environment_id;

  INSERT INTO resource_allocations (run_id, environment_id, worker_pool_id, workers_allocated)
  VALUES (p_run_id, p_environment_id, p_worker_pool_id, p_worker_count)
  ON CONFLICT (run_id) DO UPDATE SET
    workers_allocated = resource_allocations.workers_allocated + p_worker_count,
    allocated_at = NOW()
  RETURNING id INTO v_allocation_id;

  RETURN jsonb_build_object(
    'success', true,
    'allocation_id', v_allocation_id,
    'workers_allocated', p_worker_count,
    'environment_allocated', v_env.allocated + p_worker_count,
    'environment_capacity', v_env.capacity
  );
END;
$$;


--
-- Name: aqd_checkout_week(uuid, uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aqd_checkout_week(p_week_id uuid, p_carryover_item_ids uuid[] DEFAULT ARRAY[]::uuid[]) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_list_id UUID;
  v_next_week_id UUID;
  v_next_week_start DATE;
  v_next_week_end DATE;
  v_next_week_number INT;
  v_next_year INT;
  v_item RECORD;
  v_new_item_id UUID;
  v_max_rank INT;
BEGIN
  -- Get list_id and validate week
  SELECT list_id INTO v_list_id
  FROM public.aqd_weeks
  WHERE id = p_week_id AND status = 'active';
  
  IF v_list_id IS NULL THEN
    RAISE EXCEPTION 'Week not found or already closed';
  END IF;
  
  -- Close current week
  UPDATE public.aqd_weeks
  SET status = 'closed',
      checkout_completed_at = now(),
      checkout_completed_by = auth.uid()
  WHERE id = p_week_id;
  
  -- Calculate next week boundaries
  SELECT end_date + INTERVAL '1 day' INTO v_next_week_start
  FROM public.aqd_weeks WHERE id = p_week_id;
  
  v_next_week_end := v_next_week_start + INTERVAL '6 days';
  v_next_week_number := EXTRACT(WEEK FROM v_next_week_start)::INT;
  v_next_year := EXTRACT(YEAR FROM v_next_week_start)::INT;
  
  -- Create next week
  INSERT INTO public.aqd_weeks (list_id, week_number, year, start_date, end_date, status)
  VALUES (v_list_id, v_next_week_number, v_next_year, v_next_week_start, v_next_week_end, 'active')
  RETURNING id INTO v_next_week_id;
  
  -- Get max rank for new items
  SELECT COALESCE(MAX(rank), 0) INTO v_max_rank
  FROM public.aqd_items WHERE week_id = v_next_week_id;
  
  -- Carryover selected items
  FOR v_item IN 
    SELECT * FROM public.aqd_items 
    WHERE id = ANY(p_carryover_item_ids) AND status != 'done'
  LOOP
    v_max_rank := v_max_rank + 1;
    
    INSERT INTO public.aqd_items (
      list_id, week_id, title, description, status, due_date, assignee_id,
      rank, is_carryover, carryover_from_week_id, taskhub_key
    )
    VALUES (
      v_list_id, v_next_week_id, v_item.title, v_item.description, 
      'pending', v_item.due_date, v_item.assignee_id,
      v_max_rank, true, p_week_id, v_item.taskhub_key
    )
    RETURNING id INTO v_new_item_id;
    
    -- Mark original as carried over
    UPDATE public.aqd_items
    SET checkout_decision = 'carried_over'
    WHERE id = v_item.id;
  END LOOP;
  
  -- Mark dropped items
  UPDATE public.aqd_items
  SET checkout_decision = 'dropped'
  WHERE week_id = p_week_id 
    AND status != 'done'
    AND checkout_decision IS NULL;
  
  RETURN v_next_week_id;
END;
$$;


--
-- Name: aqd_confirm_carryover(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aqd_confirm_carryover(p_item_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  UPDATE public.aqd_items 
  SET carryover_confirmed = true, is_carryover = false
  WHERE id = p_item_id AND is_carryover = true;
END;
$$;


--
-- Name: aqd_create_list_with_week(text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aqd_create_list_with_week(p_name text, p_created_by uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  new_list_id uuid;
  new_week_id uuid;
  week_info record;
BEGIN
  -- Create the list
  INSERT INTO public.aqd_lists (name, created_by)
  VALUES (p_name, p_created_by)
  RETURNING id INTO new_list_id;
  
  -- Get current week dates (Sun-Thu model)
  SELECT * INTO week_info FROM public.aqd_get_week_dates(CURRENT_DATE);
  
  -- Create initial week
  INSERT INTO public.aqd_weeks (list_id, week_number, year, start_date, end_date, status)
  VALUES (new_list_id, week_info.week_num, week_info.week_year, week_info.week_start, week_info.week_end, 'active')
  RETURNING id INTO new_week_id;
  
  RETURN json_build_object(
    'list_id', new_list_id,
    'week_id', new_week_id,
    'week_number', week_info.week_num,
    'year', week_info.week_year
  );
END;
$$;


--
-- Name: aqd_cycle_item_status(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aqd_cycle_item_status(p_item_id uuid, p_user_id uuid DEFAULT NULL::uuid) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE v_current_status TEXT; v_new_status TEXT;
BEGIN
  SELECT status INTO v_current_status FROM aqd_items WHERE id = p_item_id;
  IF v_current_status IS NULL THEN RAISE EXCEPTION 'Item not found: %', p_item_id; END IF;
  v_new_status := CASE v_current_status WHEN 'not_started' THEN 'in_progress' WHEN 'in_progress' THEN 'completed' WHEN 'completed' THEN 'not_started' END;
  UPDATE aqd_items SET status = v_new_status, updated_at = now() WHERE id = p_item_id;
  INSERT INTO aqd_item_history (item_id, field_name, old_value, new_value, changed_by) VALUES (p_item_id, 'status', v_current_status, v_new_status, p_user_id);
  RETURN v_new_status;
END; $$;


--
-- Name: aqd_ensure_current_week(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aqd_ensure_current_week(p_list_id uuid) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_week_id UUID;
  v_week_start DATE;
  v_week_end DATE;
  v_week_number INT;
  v_year INT;
BEGIN
  -- Calculate current week boundaries (Monday to Sunday)
  v_week_start := date_trunc('week', CURRENT_DATE)::DATE;
  v_week_end := v_week_start + INTERVAL '6 days';
  v_week_number := EXTRACT(WEEK FROM CURRENT_DATE)::INT;
  v_year := EXTRACT(YEAR FROM CURRENT_DATE)::INT;
  
  -- Check if week already exists
  SELECT id INTO v_week_id
  FROM public.aqd_weeks
  WHERE list_id = p_list_id
    AND start_date = v_week_start
    AND end_date = v_week_end;
  
  -- Create if not exists
  IF v_week_id IS NULL THEN
    INSERT INTO public.aqd_weeks (list_id, week_number, year, start_date, end_date, status)
    VALUES (p_list_id, v_week_number, v_year, v_week_start, v_week_end, 'active')
    RETURNING id INTO v_week_id;
  END IF;
  
  RETURN v_week_id;
END;
$$;


--
-- Name: aqd_get_kpis(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aqd_get_kpis(p_list_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_result JSON;
BEGIN
  SELECT json_build_object(
    'total_items', COALESCE(COUNT(*), 0),
    'done_items', COALESCE(COUNT(*) FILTER (WHERE status = 'done'), 0),
    'pending_items', COALESCE(COUNT(*) FILTER (WHERE status = 'pending'), 0),
    'in_progress_items', COALESCE(COUNT(*) FILTER (WHERE status = 'in_progress'), 0),
    'overdue_items', COALESCE(COUNT(*) FILTER (WHERE status != 'done' AND due_date < CURRENT_DATE), 0),
    'due_today', COALESCE(COUNT(*) FILTER (WHERE status != 'done' AND due_date = CURRENT_DATE), 0),
    'completion_rate', CASE 
      WHEN COUNT(*) = 0 THEN 0
      ELSE ROUND((COUNT(*) FILTER (WHERE status = 'done')::numeric / COUNT(*)) * 100, 1)
    END,
    'weeks_active', (
      SELECT COUNT(DISTINCT week_id) FROM public.aqd_items WHERE list_id = p_list_id
    )
  ) INTO v_result
  FROM public.aqd_items
  WHERE list_id = p_list_id;
  
  RETURN v_result;
END;
$$;


--
-- Name: aqd_get_or_create_current_week(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aqd_get_or_create_current_week(p_list_id uuid) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE v_week_id UUID; v_week_number INT; v_year INT; v_start_date DATE; v_end_date DATE;
BEGIN
  v_year := EXTRACT(YEAR FROM CURRENT_DATE)::INT;
  v_week_number := EXTRACT(WEEK FROM CURRENT_DATE)::INT;
  v_start_date := DATE_TRUNC('week', CURRENT_DATE)::DATE;
  v_end_date := (DATE_TRUNC('week', CURRENT_DATE) + INTERVAL '4 days')::DATE;
  SELECT id INTO v_week_id FROM aqd_weeks WHERE list_id = p_list_id AND week_number = v_week_number AND year = v_year AND status = 'active';
  IF v_week_id IS NULL THEN
    INSERT INTO aqd_weeks (list_id, week_number, year, start_date, end_date, status)
    VALUES (p_list_id, v_week_number, v_year, v_start_date, v_end_date, 'active') RETURNING id INTO v_week_id;
  END IF;
  RETURN v_week_id;
END; $$;


--
-- Name: aqd_get_week_dates(date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aqd_get_week_dates(target_date date) RETURNS TABLE(week_start date, week_end date, week_num integer, week_year integer)
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
  sunday_start date;
  thursday_end date;
BEGIN
  -- Get the Sunday of the week containing target_date
  sunday_start := target_date - EXTRACT(DOW FROM target_date)::integer;
  thursday_end := sunday_start + 4;
  week_num := EXTRACT(WEEK FROM target_date)::integer;
  week_year := EXTRACT(ISOYEAR FROM target_date)::integer;
  
  RETURN QUERY SELECT sunday_start, thursday_end, week_num, week_year;
END;
$$;


--
-- Name: aqd_log_item_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aqd_log_item_change() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Log status changes
  IF OLD.status IS DISTINCT FROM NEW.status THEN
    INSERT INTO public.aqd_item_history (item_id, field_name, old_value, new_value, changed_by)
    VALUES (NEW.id, 'status', OLD.status, NEW.status, auth.uid());
  END IF;
  
  -- Log title changes
  IF OLD.title IS DISTINCT FROM NEW.title THEN
    INSERT INTO public.aqd_item_history (item_id, field_name, old_value, new_value, changed_by)
    VALUES (NEW.id, 'title', OLD.title, NEW.title, auth.uid());
  END IF;
  
  -- Log assignee changes
  IF OLD.assignee_id IS DISTINCT FROM NEW.assignee_id THEN
    INSERT INTO public.aqd_item_history (item_id, field_name, old_value, new_value, changed_by)
    VALUES (NEW.id, 'assignee_id', OLD.assignee_id::text, NEW.assignee_id::text, auth.uid());
  END IF;
  
  -- Log due_date changes
  IF OLD.due_date IS DISTINCT FROM NEW.due_date THEN
    INSERT INTO public.aqd_item_history (item_id, field_name, old_value, new_value, changed_by)
    VALUES (NEW.id, 'due_date', OLD.due_date::text, NEW.due_date::text, auth.uid());
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- Name: aqd_record_history(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aqd_record_history() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF OLD.status IS DISTINCT FROM NEW.status THEN INSERT INTO aqd_item_history (item_id, field_name, old_value, new_value, changed_by) VALUES (NEW.id, 'status', OLD.status, NEW.status, NEW.assignee_id); END IF;
  IF OLD.title IS DISTINCT FROM NEW.title THEN INSERT INTO aqd_item_history (item_id, field_name, old_value, new_value, changed_by) VALUES (NEW.id, 'title', OLD.title, NEW.title, NEW.assignee_id); END IF;
  IF OLD.rank IS DISTINCT FROM NEW.rank AND OLD.rank != 0 AND NEW.rank != 0 THEN INSERT INTO aqd_item_history (item_id, field_name, old_value, new_value, changed_by) VALUES (NEW.id, 'rank', OLD.rank::text, NEW.rank::text, NEW.assignee_id); END IF;
  RETURN NEW;
END; $$;


--
-- Name: aqd_record_history(uuid, text, text, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aqd_record_history(p_item_id uuid, p_field_name text, p_old_value text, p_new_value text, p_user_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  INSERT INTO public.aqd_item_history (item_id, field_name, old_value, new_value, changed_by)
  VALUES (p_item_id, p_field_name, p_old_value, p_new_value, p_user_id);
END;
$$;


--
-- Name: aqd_reorder_item(uuid, integer, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aqd_reorder_item(p_item_id uuid, p_new_rank integer, p_week_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_old_rank INTEGER;
  v_current_user_id UUID;
  v_temp_rank INTEGER;
  r INTEGER;
BEGIN
  -- Prevent race conditions within a week
  PERFORM pg_advisory_xact_lock(hashtext(p_week_id::text));

  -- Fetch current rank
  SELECT rank INTO v_old_rank
  FROM public.aqd_items
  WHERE id = p_item_id;

  IF v_old_rank IS NULL THEN
    RAISE EXCEPTION 'Item not found for reorder: %', p_item_id;
  END IF;

  -- No-op
  IF v_old_rank = p_new_rank THEN
    RETURN;
  END IF;

  -- Ensure we have a free temporary rank within allowed check range [0..20]
  SELECT gs INTO v_temp_rank
  FROM generate_series(0, 20) AS gs
  WHERE NOT EXISTS (
    SELECT 1
    FROM public.aqd_items i
    WHERE i.week_id = p_week_id
      AND i.rank = gs
      AND i.id <> p_item_id
  )
  LIMIT 1;

  IF v_temp_rank IS NULL THEN
    RAISE EXCEPTION 'No temporary rank slot available (0..20) for week %', p_week_id;
  END IF;

  -- Get current user for activity
  v_current_user_id := auth.uid();

  -- PHASE 1: move the item out of the way into the free temp rank
  UPDATE public.aqd_items
  SET rank = v_temp_rank,
      updated_at = NOW()
  WHERE id = p_item_id;

  -- PHASE 2: shift other items one-by-one to avoid unique collisions
  IF p_new_rank < v_old_rank THEN
    -- Moving up (toward smaller number): other items shift down (+1)
    FOR r IN REVERSE (v_old_rank - 1)..p_new_rank LOOP
      UPDATE public.aqd_items
      SET rank = r + 1,
          updated_at = NOW()
      WHERE week_id = p_week_id
        AND rank = r
        AND id <> p_item_id;
    END LOOP;
  ELSE
    -- Moving down (toward larger number): other items shift up (-1)
    FOR r IN (v_old_rank + 1)..p_new_rank LOOP
      UPDATE public.aqd_items
      SET rank = r - 1,
          updated_at = NOW()
      WHERE week_id = p_week_id
        AND rank = r
        AND id <> p_item_id;
    END LOOP;
  END IF;

  -- PHASE 3: place item at final rank + update rank-change tracking
  UPDATE public.aqd_items
  SET rank = p_new_rank,
      previous_rank = v_old_rank,
      rank_changed_at = NOW(),
      updated_at = NOW()
  WHERE id = p_item_id;

  INSERT INTO public.aqd_activity (item_id, action, field_name, old_value, new_value, created_by)
  VALUES (p_item_id, 'rank_changed', 'rank', v_old_rank::text, p_new_rank::text, v_current_user_id);
END;
$$;


--
-- Name: aqd_reorder_items(jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aqd_reorder_items(p_items jsonb) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  item record;
BEGIN
  FOR item IN SELECT * FROM jsonb_to_recordset(p_items) AS x(id uuid, rank integer)
  LOOP
    UPDATE public.aqd_items SET rank = item.rank WHERE id = item.id;
  END LOOP;
END;
$$;


--
-- Name: aqd_reorder_items(uuid[], integer[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aqd_reorder_items(p_item_ids uuid[], p_new_ranks integer[]) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  i INT;
BEGIN
  IF array_length(p_item_ids, 1) != array_length(p_new_ranks, 1) THEN
    RAISE EXCEPTION 'Arrays must have same length';
  END IF;
  
  FOR i IN 1..array_length(p_item_ids, 1) LOOP
    UPDATE public.aqd_items
    SET rank = p_new_ranks[i], updated_at = now()
    WHERE id = p_item_ids[i];
  END LOOP;
END;
$$;


--
-- Name: aqd_reorder_items(uuid, uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aqd_reorder_items(p_week_id uuid, p_item_id uuid, p_new_rank integer) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE v_old_rank INT;
BEGIN
  SELECT rank INTO v_old_rank FROM aqd_items WHERE id = p_item_id;
  IF v_old_rank IS NULL THEN RAISE EXCEPTION 'Item not found'; END IF;
  IF v_old_rank = p_new_rank THEN RETURN; END IF;
  UPDATE aqd_items SET rank = 0 WHERE id = p_item_id;
  IF p_new_rank < v_old_rank THEN
    UPDATE aqd_items SET rank = rank + 1, updated_at = now() WHERE week_id = p_week_id AND rank >= p_new_rank AND rank < v_old_rank AND id != p_item_id;
  ELSE
    UPDATE aqd_items SET rank = rank - 1, updated_at = now() WHERE week_id = p_week_id AND rank > v_old_rank AND rank <= p_new_rank AND id != p_item_id;
  END IF;
  UPDATE aqd_items SET rank = p_new_rank, updated_at = now() WHERE id = p_item_id;
END; $$;


