--
-- Name: auto_archive_active_snapshot(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.auto_archive_active_snapshot() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NEW.status = 'ACTIVE' AND (OLD IS NULL OR OLD.status IS NULL OR OLD.status != 'ACTIVE') THEN
    UPDATE public.strategy_snapshots
    SET status = 'ARCHIVED', 
        archived_at = now(),
        updated_at = now()
    WHERE status = 'ACTIVE' 
      AND id != NEW.id;
    NEW.active_since := now();
  END IF;
  
  IF NEW.status = 'ARCHIVED' AND (OLD IS NULL OR OLD.status IS NULL OR OLD.status != 'ARCHIVED') THEN
    NEW.archived_at := now();
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- Name: auto_generate_defect_id(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.auto_generate_defect_id() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NEW.defect_id IS NULL THEN
    NEW.defect_id := generate_next_defect_id();
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: auto_generate_epic_key(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.auto_generate_epic_key() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
BEGIN
  -- Only generate if epic_key is null and program_id exists
  IF NEW.epic_key IS NULL AND NEW.primary_program_id IS NOT NULL THEN
    NEW.epic_key := generate_next_epic_key(NEW.primary_program_id);
  END IF;
  
  -- Validate epic_key format if provided
  IF NEW.epic_key IS NOT NULL AND NEW.epic_key !~ '^[A-Z]{3}-\d{3}$' THEN
    RAISE EXCEPTION 'Invalid epic key format: %. Must be AAA-### (3 uppercase letters, hyphen, 3 digits)', NEW.epic_key;
  END IF;
  
  RETURN NEW;
END;
$_$;


--
-- Name: auto_generate_task_key(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.auto_generate_task_key() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NEW.key IS NULL AND NEW.team_id IS NOT NULL THEN
    NEW.key := generate_work_manager_task_key(NEW.team_id);
  ELSIF NEW.key IS NULL THEN
    NEW.key := 'TSK-' || LPAD(FLOOR(RANDOM() * 10000)::TEXT, 4, '0');
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: auto_update_risk_status(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.auto_update_risk_status() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- When resolution_method changes to 'Resolved', set status to 'Closed'
  IF NEW.resolution_method = 'Resolved' AND (OLD.resolution_method IS NULL OR OLD.resolution_method != 'Resolved') THEN
    NEW.status = 'Closed';
  END IF;
  
  -- When resolution_method changes from 'Resolved' to anything else, set status to 'Open'
  IF OLD.resolution_method = 'Resolved' AND NEW.resolution_method != 'Resolved' THEN
    NEW.status = 'Open';
  END IF;
  
  RETURN NEW;
END;
$$;


