    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$ SELECT EXISTS (SELECT 1 FROM boards WHERE id = _board_id AND deleted_at IS NULL); $$;


--
-- Name: bulk_assign_roles(uuid[], public.app_role, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.bulk_assign_roles(_user_ids uuid[], _role public.app_role, _notes text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  _user_id uuid;
BEGIN
  -- Only admins can bulk assign roles
  IF NOT has_role(auth.uid(), 'admin') THEN
    RAISE EXCEPTION 'Only admins can bulk assign roles';
  END IF;

  -- Assign role to each user
  FOREACH _user_id IN ARRAY _user_ids
  LOOP
    -- Insert role if not exists
    INSERT INTO public.user_roles (user_id, role)
    VALUES (_user_id, _role)
    ON CONFLICT (user_id, role) DO NOTHING;
    
    -- Log the change with notes
    INSERT INTO public.user_role_history (user_id, role, action, changed_by, notes)
    VALUES (_user_id, _role, 'assigned', auth.uid(), _notes);
  END LOOP;
END;
$$;


--
-- Name: bulk_change_priority(uuid, uuid[], text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.bulk_change_priority(p_run_id uuid, p_item_ids uuid[], p_new_priority text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_priority_value INTEGER;
  v_updated_count INTEGER;
BEGIN
  -- Validate priority
  v_priority_value := CASE p_new_priority
    WHEN 'critical' THEN 100
    WHEN 'high' THEN 75
    WHEN 'medium' THEN 50
    WHEN 'low' THEN 25
    ELSE NULL
  END;

  IF v_priority_value IS NULL THEN
    RETURN jsonb_build_object('error', 'Invalid priority value');
  END IF;

  -- Update priorities
  WITH updated AS (
    UPDATE execution_queue SET
      priority = v_priority_value
    WHERE run_id = p_run_id
      AND id = ANY(p_item_ids)
    RETURNING id
  )
  SELECT COUNT(*) INTO v_updated_count FROM updated;

  RETURN jsonb_build_object('success', true, 'updated_count', v_updated_count);
END;
$$;


--
-- Name: bulk_map_tests(uuid, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.bulk_map_tests(p_connector_id uuid, p_mappings jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_mapping JSONB;
  v_count INTEGER := 0;
BEGIN
  FOR v_mapping IN SELECT * FROM jsonb_array_elements(p_mappings)
  LOOP
    INSERT INTO automation_test_mappings (connector_id, external_test_id, test_case_id)
    VALUES (p_connector_id, v_mapping->>'external_test_id', (v_mapping->>'test_case_id')::UUID)
    ON CONFLICT (connector_id, external_test_id) DO UPDATE
    SET test_case_id = EXCLUDED.test_case_id;

    -- Update existing results
    UPDATE automation_results
    SET test_case_id = (v_mapping->>'test_case_id')::UUID
    WHERE connector_id = p_connector_id AND external_test_id = v_mapping->>'external_test_id';

    v_count := v_count + 1;
  END LOOP;

  RETURN jsonb_build_object('success', true, 'mapped_count', v_count);
END;
$$;


--
-- Name: bulk_remove_roles(uuid[], public.app_role, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.bulk_remove_roles(_user_ids uuid[], _role public.app_role, _notes text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  _user_id uuid;
BEGIN
  -- Only admins can bulk remove roles
  IF NOT has_role(auth.uid(), 'admin') THEN
    RAISE EXCEPTION 'Only admins can bulk remove roles';
  END IF;

  -- Remove role from each user
  FOREACH _user_id IN ARRAY _user_ids
  LOOP
    -- Delete role
    DELETE FROM public.user_roles
    WHERE user_id = _user_id AND role = _role;
    
    -- Log the change with notes
    INSERT INTO public.user_role_history (user_id, role, action, changed_by, notes)
    VALUES (_user_id, _role, 'removed', auth.uid(), _notes);
  END LOOP;
END;
$$;


--
-- Name: bulk_update_permissions(text[], text[], text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.bulk_update_permissions(p_module_keys text[], p_role_codes text[], p_access_level text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_count INT := 0;
  v_module TEXT;
  v_role TEXT;
BEGIN
  FOREACH v_module IN ARRAY p_module_keys LOOP
    FOREACH v_role IN ARRAY p_role_codes LOOP
      IF v_role != 'super_admin' THEN
        PERFORM update_module_permission(v_role, v_module, p_access_level);
        v_count := v_count + 1;
      END IF;
    END LOOP;
  END LOOP;
  RETURN jsonb_build_object('success', true, 'updated', v_count);
END;
$$;


--
-- Name: calculate_defect_sla(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_defect_sla() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  NEW.sla_target_hours := CASE NEW.severity
    WHEN 'critical' THEN 4
    WHEN 'major' THEN 24
    WHEN 'minor' THEN 72
    WHEN 'trivial' THEN NULL
  END;
  RETURN NEW;
END;
$$;


--
-- Name: calculate_epic_process_time(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_epic_process_time() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Calculate cycle time when exiting a step
  IF NEW.exited_at IS NOT NULL AND OLD.exited_at IS NULL THEN
    NEW.cycle_time_hours := EXTRACT(EPOCH FROM (NEW.exited_at - NEW.entered_at)) / 3600;
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- Name: calculate_epic_wsjf(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_epic_wsjf() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Calculate WSJF score: (BV + TC + RR/OE) / JS
  IF NEW.business_value IS NOT NULL 
     AND NEW.time_value IS NOT NULL 
     AND NEW.rroe_value IS NOT NULL 
     AND NEW.job_size IS NOT NULL 
     AND NEW.job_size > 0 THEN
    NEW.wsjf_score := ROUND(
      (NEW.business_value + NEW.time_value + NEW.rroe_value)::NUMERIC / NEW.job_size::NUMERIC, 
      2
    );
  ELSE
    NEW.wsjf_score := NULL;
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- Name: calculate_feature_wsjf(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_feature_wsjf() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Calculate WSJF score: (BV + TC + RR) / JS
  -- Only calculate if all components are present and job_size > 0
  IF NEW.business_value IS NOT NULL 
     AND NEW.time_criticality IS NOT NULL 
     AND NEW.risk_reduction IS NOT NULL 
     AND NEW.job_size IS NOT NULL 
     AND NEW.job_size > 0 THEN
    NEW.wsjf_score := ROUND(
      (NEW.business_value + NEW.time_criticality + NEW.risk_reduction)::NUMERIC / NEW.job_size::NUMERIC, 
      2
    );
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- Name: calculate_impact_score(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_impact_score() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  NEW.calculated_score := ROUND(
    (COALESCE(NEW.imperative, 0) * 0.25) +
    (COALESCE(NEW.ministry_efficiency, 0) * 0.15) +
    (COALESCE(NEW.pain_severity, 0) * 0.20) +
    (COALESCE(NEW.alignment, 0) * 0.20) +
    (COALESCE(NEW.complexity, 0) * 0.10) +
    (COALESCE(NEW.timeframe, 0) * 0.10)
  , 2);
  RETURN NEW;
END;
$$;


--
-- Name: calculate_impact_total(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_impact_total() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF (NEW.imperative + NEW.ministry_efficiency + NEW.pain_severity + NEW.alignment + NEW.complexity_score + NEW.timeframe_score) > 0 THEN
    NEW.impact_total := ROUND(
      (NEW.imperative * 0.25) + (NEW.ministry_efficiency * 0.20) + (NEW.pain_severity * 0.20) +
      (NEW.alignment * 0.15) + (NEW.complexity_score * 0.10) + (NEW.timeframe_score * 0.10), 2);
  ELSE NEW.impact_total := 0;
  END IF;
  RETURN NEW;
END; $$;


--
-- Name: calculate_objective_score(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_objective_score(objective_uuid uuid) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
  total_score DECIMAL;
  kr_count INTEGER;
  has_scored BOOLEAN;
  override_score DECIMAL;
BEGIN
  SELECT score_override INTO override_score FROM objectives WHERE id = objective_uuid;
  IF override_score IS NOT NULL THEN RETURN override_score; END IF;
  
  SELECT 
    SUM(CASE 
      WHEN goal_value != COALESCE(baseline_value, 0) AND current_value IS NOT NULL THEN
        GREATEST(0, LEAST(1, 
          (current_value - COALESCE(baseline_value, 0)) / 
          NULLIF(goal_value - COALESCE(baseline_value, 0), 0)
        ))
      ELSE 0
    END),
    COUNT(*),
    BOOL_OR(current_value IS NOT NULL)
  INTO total_score, kr_count, has_scored
  FROM key_results WHERE objective_id = objective_uuid;
  
  IF kr_count = 0 OR NOT has_scored THEN RETURN NULL; END IF;
  RETURN ROUND(total_score / kr_count, 2);
END;
$$;


--
-- Name: calculate_release_health(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_release_health(p_release_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_metrics JSONB;
  v_pass_rate NUMERIC;
  v_coverage NUMERIC;
  v_defect_score NUMERIC;
  v_automation_score NUMERIC;
  v_health_score NUMERIC;
  v_health_level TEXT;
BEGIN
  -- Get metrics first
  v_metrics := get_release_quality_metrics(p_release_id);
  
  -- Extract values
  v_pass_rate := COALESCE((v_metrics->'test_execution'->>'pass_rate')::NUMERIC, 0);
  v_coverage := COALESCE((v_metrics->'test_execution'->>'coverage_percent')::NUMERIC, 0);
  v_automation_score := COALESCE((v_metrics->'automation'->>'rate')::NUMERIC, 0);
  
  -- Calculate defect score (100 - penalty for open defects)
  v_defect_score := GREATEST(0, 100 - 
    (COALESCE((v_metrics->'defects'->>'blocker')::INTEGER, 0) * 25) -
    (COALESCE((v_metrics->'defects'->>'critical')::INTEGER, 0) * 15) -
    (COALESCE((v_metrics->'defects'->>'open')::INTEGER, 0) * 5)
  );

  -- Calculate weighted health score
  -- Pass Rate: 40%, Coverage: 25%, Defects: 25%, Automation: 10%
  v_health_score := ROUND(
    (v_pass_rate * 0.40) +
    (v_coverage * 0.25) +
    (v_defect_score * 0.25) +
    (v_automation_score * 0.10)
  , 1);

  -- Determine health level
  v_health_level := CASE
    WHEN v_health_score >= 85 THEN 'healthy'
    WHEN v_health_score >= 70 THEN 'attention'
    WHEN v_health_score >= 50 THEN 'at_risk'
    ELSE 'critical'
  END;

  RETURN jsonb_build_object(
    'success', true,
    'release_id', p_release_id,
    'score', v_health_score,
    'level', v_health_level,
    'breakdown', jsonb_build_object(
      'pass_rate', jsonb_build_object('value', v_pass_rate, 'weight', 40),
      'coverage', jsonb_build_object('value', v_coverage, 'weight', 25),
      'defects', jsonb_build_object('value', v_defect_score, 'weight', 25),
      'automation', jsonb_build_object('value', v_automation_score, 'weight', 10)
    ),
    'metrics', v_metrics,
    'calculated_at', now()
  );
END;
$$;


--
-- Name: can_access_all_workstreams(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_access_all_workstreams(_user_id uuid) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT EXISTS (
    -- Check for admin role in user_roles
    SELECT 1 FROM public.user_roles
    WHERE user_id = _user_id AND role = 'admin'
  )
  OR EXISTS (
    -- Check for super_admin in user_product_roles
    SELECT 1 FROM public.user_product_roles upr
    JOIN public.product_roles pr ON pr.id = upr.role_id
    WHERE upr.user_id = _user_id AND pr.code = 'super_admin'
  )
$$;


--
-- Name: can_manage_lead_notes(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_manage_lead_notes(task_uuid uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  user_id UUID := auth.uid();
  user_role TEXT;
  workstream_uuid UUID;
  is_workstream_lead BOOLEAN := FALSE;
  has_management_role BOOLEAN := FALSE;
BEGIN
  IF user_id IS NULL THEN
    RETURN FALSE;
  END IF;
  
  -- Get user's system role
  SELECT role INTO user_role
  FROM user_roles
  WHERE user_roles.user_id = can_manage_lead_notes.user_id
  ORDER BY created_at DESC
  LIMIT 1;
  
  -- Admin or program_manager can always manage
  IF user_role IN ('admin', 'program_manager') THEN
    RETURN TRUE;
  END IF;
  
  -- Check for super_admin or management product role
  SELECT EXISTS(
    SELECT 1 
    FROM user_product_roles upr
    JOIN product_roles pr ON pr.id = upr.role_id
    WHERE upr.user_id = can_manage_lead_notes.user_id
    AND pr.code IN ('super_admin', 'management')
  ) INTO has_management_role;
  
  IF has_management_role THEN
    RETURN TRUE;
  END IF;
  
  -- Get workstream from task
  SELECT workstream_id INTO workstream_uuid
  FROM planner_tasks
  WHERE id = task_uuid;
  
  IF workstream_uuid IS NULL THEN
    RETURN FALSE;
  END IF;
  
  -- Check if user is lead of the workstream
  SELECT EXISTS(
    SELECT 1
    FROM workstream_members wm
    WHERE wm.workstream_id = workstream_uuid
    AND wm.user_id = can_manage_lead_notes.user_id
    AND LOWER(wm.role) = 'lead'
  ) INTO is_workstream_lead;
  
  RETURN is_workstream_lead;
END;
$$;


--
-- Name: can_transition(character varying, uuid, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_transition(p_entity_type character varying, p_entity_id uuid, p_from_status character varying, p_to_status character varying) RETURNS TABLE(allowed boolean, reason character varying, pending_count integer, approved_count integer, total_count integer, veto_approved boolean)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_pending INTEGER;
  v_approved INTEGER;
  v_total INTEGER;
  v_veto_approved BOOLEAN;
  v_has_config BOOLEAN;
BEGIN
  -- Check if this transition requires approval
  SELECT EXISTS(
    SELECT 1 FROM transition_approval_configs
    WHERE entity_type = p_entity_type
      AND from_status = p_from_status
      AND to_status = p_to_status
      AND is_active = true
  ) INTO v_has_config;
  
  IF NOT v_has_config THEN
    RETURN QUERY SELECT true, 'No approval required'::VARCHAR, 0, 0, 0, false;
    RETURN;
  END IF;
  
  -- Count approvals for this specific transition
  SELECT
    COUNT(*) FILTER (WHERE status IN ('pending', 'waiting')),
    COUNT(*) FILTER (WHERE status = 'approved'),
    COUNT(*),
    COALESCE(bool_or(is_veto AND status = 'approved'), false)
  INTO v_pending, v_approved, v_total, v_veto_approved
  FROM transition_approvers
  WHERE entity_type = p_entity_type
    AND entity_id = p_entity_id
    AND from_status = p_from_status
    AND to_status = p_to_status;
  
  -- No approvers configured for this entity
  IF v_total = 0 THEN
    RETURN QUERY SELECT true, 'No approvers configured'::VARCHAR, 0, 0, 0, false;
    RETURN;
  END IF;
  
  -- Veto approved = allow immediately
  IF v_veto_approved THEN
    RETURN QUERY SELECT true, 'Veto approved'::VARCHAR, v_pending, v_approved, v_total, true;
    RETURN;
  END IF;
  
  -- Still have pending approvals
  IF v_pending > 0 THEN
    RETURN QUERY SELECT false, 'Pending approvals'::VARCHAR, v_pending, v_approved, v_total, false;
    RETURN;
  END IF;
  
  -- All approved
  RETURN QUERY SELECT true, 'All approved'::VARCHAR, 0, v_approved, v_total, false;
END;
$$;


--
-- Name: can_view_board(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_view_board(_board_id uuid, _user_id uuid) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1 FROM boards b WHERE b.id = _board_id AND b.deleted_at IS NULL
      AND (
        b.visibility = 'global'
        OR (b.visibility = 'private' AND b.created_by = _user_id)
        OR (b.project_id IS NOT NULL AND b.visibility <> 'private' AND EXISTS (
          SELECT 1 FROM project_members pm WHERE pm.project_id = b.project_id AND pm.user_id = _user_id
        ))
        OR (b.project_id IS NOT NULL AND b.visibility <> 'private' AND EXISTS (
          SELECT 1 FROM ph_project_members ppm
          JOIN ph_projects pp ON pp.id = ppm.project_id
          JOIN projects p ON lower(p.name) = lower(pp.name)
          WHERE p.id = b.project_id AND ppm.user_id = _user_id
        ))
        OR EXISTS (SELECT 1 FROM board_members bm WHERE bm.board_id = b.id AND bm.user_id = _user_id)
        OR (b.is_personal = true AND b.created_by = _user_id)
      )
  );
$$;


--
-- Name: catalyst_comment_notify_trigger(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.catalyst_comment_notify_trigger() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_actor         UUID;
  v_entity_id     UUID;
  v_entity_type   TEXT;
  v_entity_key    TEXT;
  v_entity_title  TEXT;
  v_hub_source    TEXT;
  v_icon_type     TEXT;
  v_comment_preview TEXT;
  v_assignee_id   UUID;
  v_status        TEXT;
BEGIN
  -- Only fire on INSERT
  IF TG_OP <> 'INSERT' THEN
    RETURN NEW;
  END IF;

  CASE TG_TABLE_NAME

    -- ── Generic comments (stories, epics, OKRs) ──
    WHEN 'comments' THEN
      v_actor := COALESCE(NEW.user_id, auth.uid());
      v_entity_id := NEW.entity_id;
      v_comment_preview := LEFT(NEW.content, 120);

      CASE NEW.entity_type
        WHEN 'story' THEN
          SELECT COALESCE(s.story_key, s.id::TEXT), COALESCE(s.title, s.name, 'Story'),
                 COALESCE(s.assignee_id, s.owner_id), COALESCE(s.status, 'unknown')
            INTO v_entity_key, v_entity_title, v_assignee_id, v_status
            FROM stories s WHERE s.id = NEW.entity_id;
          v_entity_type := 'story'; v_hub_source := 'ProjectHub'; v_icon_type := 'story';

        WHEN 'epic' THEN
          SELECT COALESCE(e.epic_key, e.id::TEXT), COALESCE(e.name, 'Epic'),
                 COALESCE(e.assignee_id, e.owner_id), COALESCE(e.status, 'unknown')
            INTO v_entity_key, v_entity_title, v_assignee_id, v_status
            FROM epics e WHERE e.id = NEW.entity_id;
          v_entity_type := 'epic'; v_hub_source := 'ProjectHub'; v_icon_type := 'epic';

        WHEN 'objective' THEN
          SELECT COALESCE(o.objective_key, o.id::TEXT), COALESCE(o.title, 'Objective'),
                 o.owner_id, COALESCE(o.status, 'unknown')
            INTO v_entity_key, v_entity_title, v_assignee_id, v_status
            FROM objectives o WHERE o.id = NEW.entity_id;
          v_entity_type := 'objective'; v_hub_source := 'StrategyHub'; v_icon_type := 'objective';

        WHEN 'initiative' THEN
          SELECT COALESCE(i.initiative_key, i.id::TEXT), COALESCE(i.name, 'Initiative'),
                 i.owner_id, COALESCE(i.status, 'unknown')
            INTO v_entity_key, v_entity_title, v_assignee_id, v_status
            FROM initiatives i WHERE i.id = NEW.entity_id;
          v_entity_type := 'initiative'; v_hub_source := 'StrategyHub'; v_icon_type := 'initiative';

        ELSE
          -- Unknown entity type, skip
          RETURN NEW;
      END CASE;

    -- ── TestHub comments (test cases, defects, plans) ──
    WHEN 'tm_comments' THEN
      v_actor := COALESCE(NEW.author_id, auth.uid());
      v_entity_id := NEW.entity_id;
      v_comment_preview := LEFT(NEW.content, 120);

      CASE NEW.entity_type
        WHEN 'test_case' THEN
          SELECT COALESCE(tc.case_key, tc.id::TEXT), COALESCE(tc.title, 'Test Case'),
                 tc.assigned_to, COALESCE(tc.status, 'unknown')
            INTO v_entity_key, v_entity_title, v_assignee_id, v_status
            FROM tm_test_cases tc WHERE tc.id = NEW.entity_id;
          v_entity_type := 'test_case'; v_hub_source := 'TestHub'; v_icon_type := 'bug';

        WHEN 'defect' THEN
          SELECT COALESCE(d.defect_key, d.id::TEXT), COALESCE(d.title, 'Defect'),
                 d.assignee_id, COALESCE(d.status, 'unknown')
            INTO v_entity_key, v_entity_title, v_assignee_id, v_status
            FROM tm_defects d WHERE d.id = NEW.entity_id;
          v_entity_type := 'defect'; v_hub_source := 'TestHub'; v_icon_type := 'bug';

        WHEN 'test_plan' THEN
          SELECT COALESCE(tp.plan_key, tp.id::TEXT), COALESCE(tp.name, 'Test Plan'),
                 tp.owner_id, COALESCE(tp.status, 'unknown')
            INTO v_entity_key, v_entity_title, v_assignee_id, v_status
            FROM tm_test_plans tp WHERE tp.id = NEW.entity_id;
          v_entity_type := 'test_plan'; v_hub_source := 'TestHub'; v_icon_type := 'test_plan';

        ELSE
          RETURN NEW;
      END CASE;

    -- ── Incident comments ──
    WHEN 'incident_comments' THEN
      v_actor := COALESCE(NEW.author_id, auth.uid());
      v_entity_id := NEW.incident_id;
      v_comment_preview := LEFT(NEW.content, 120);

      SELECT COALESCE(inc.incident_key, inc.id::TEXT), COALESCE(inc.title, 'Incident'),
             inc.assignee_id, COALESCE(inc.status, 'unknown')
        INTO v_entity_key, v_entity_title, v_assignee_id, v_status
        FROM incidents inc WHERE inc.id = NEW.incident_id;
      v_entity_type := 'incident'; v_hub_source := 'IncidentHub'; v_icon_type := 'incident';

    -- ── Ideation comments ──
    WHEN 'ph_idea_comments' THEN
      v_actor := COALESCE(NEW.user_id, auth.uid());
      v_entity_id := NEW.idea_id;
      v_comment_preview := LEFT(NEW.content, 120);

      SELECT COALESCE(idea.idea_key, idea.id::TEXT), COALESCE(idea.title, 'Idea'),
             idea.author_id, COALESCE(idea.status, 'unknown')
        INTO v_entity_key, v_entity_title, v_assignee_id, v_status
        FROM ph_ideas idea WHERE idea.id = NEW.idea_id;
      v_entity_type := 'idea'; v_hub_source := 'ProductHub'; v_icon_type := 'improvement';

    ELSE
      RETURN NEW;
  END CASE;

  -- ── Notify the assignee/owner that someone commented ──
  IF v_assignee_id IS NOT NULL
     AND v_assignee_id IS DISTINCT FROM v_actor
  THEN
    INSERT INTO notifications (
      recipient_user_id, actor_user_id, notification_type,
      entity_id, entity_type, entity_key, entity_title,
      hub_source, icon_type, status, status_type,
      metadata, tab
    ) VALUES (
      v_assignee_id, v_actor, 'commented_on_work_item',
      v_entity_id, v_entity_type, v_entity_key, v_entity_title,
      v_hub_source, v_icon_type,
      v_status,
      CASE v_status
        WHEN 'done' THEN 'green'
        WHEN 'in_progress' THEN 'blue'
        WHEN 'in_review' THEN 'blue'
        ELSE 'gray'
      END,
      jsonb_build_object('comment_preview', v_comment_preview, 'comment_id', NEW.id::TEXT),
      'direct'
    );
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: catalyst_notify_trigger(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.catalyst_notify_trigger() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_recipient    UUID;
  v_actor        UUID;
  v_old_assignee UUID;
  v_new_assignee UUID;
  v_old_status   TEXT;
  v_new_status   TEXT;
  v_entity_key   TEXT;
  v_entity_title TEXT;
  v_entity_type  TEXT;
  v_hub_source   TEXT;
  v_icon_type    TEXT;
  v_tc_key       TEXT;
  v_tc_title     TEXT;
  v_notif_type   TEXT;
  v_status_color TEXT;
BEGIN
  CASE TG_TABLE_NAME
    WHEN 'tm_test_cases' THEN
      v_entity_type  := 'test_case';
      v_hub_source   := 'TestHub';
      v_icon_type    := 'bug';
      v_entity_key   := COALESCE(NEW.case_key, NEW.id::TEXT);
      v_entity_title := COALESCE(NEW.title, 'Test Case');
      v_new_assignee := NEW.assigned_to;
      v_old_assignee := CASE WHEN TG_OP='UPDATE' THEN OLD.assigned_to ELSE NULL END;
      v_new_status   := NEW.status;
      v_old_status   := CASE WHEN TG_OP='UPDATE' THEN OLD.status ELSE NULL END;
      v_actor        := COALESCE(NEW.created_by, auth.uid());

    WHEN 'tm_cycle_scope' THEN
      v_entity_type  := 'test_case';
      v_hub_source   := 'TestHub';
      v_icon_type    := 'bug';
      SELECT tc.case_key, tc.title
        INTO v_tc_key, v_tc_title
        FROM tm_test_cases tc
       WHERE tc.id = NEW.test_case_id;
      v_entity_key   := COALESCE(v_tc_key, NEW.test_case_id::TEXT);
      v_entity_title := COALESCE(v_tc_title, 'Test Case');
      v_new_assignee := NEW.assigned_to;
      v_old_assignee := CASE WHEN TG_OP='UPDATE' THEN OLD.assigned_to ELSE NULL END;
      v_new_status   := NEW.current_status::TEXT;
      v_old_status   := CASE WHEN TG_OP='UPDATE' THEN OLD.current_status::TEXT ELSE NULL END;
      v_actor        := auth.uid();

    WHEN 'catalyst_issues' THEN
      v_entity_type  := 'issue';
      v_hub_source   := 'ProjectHub';
      v_icon_type    := COALESCE(LOWER(NEW.issue_type), 'task');
      v_entity_key   := COALESCE(NEW.issue_key, NEW.id::TEXT);
      v_entity_title := COALESCE(NEW.title, 'Issue');
      v_new_assignee := NEW.assignee_id;
      v_old_assignee := CASE WHEN TG_OP='UPDATE' THEN OLD.assignee_id ELSE NULL END;
      v_new_status   := NEW.status;
      v_old_status   := CASE WHEN TG_OP='UPDATE' THEN OLD.status ELSE NULL END;
      v_actor        := COALESCE(NEW.reporter_id, auth.uid());

    WHEN 'stories' THEN
      v_entity_type  := 'story';
      v_hub_source   := 'ProjectHub';
      v_icon_type    := 'story';
      v_entity_key   := COALESCE(NEW.story_key, NEW.id::TEXT);
      v_entity_title := COALESCE(NEW.title, NEW.name, 'Story');
      v_new_assignee := COALESCE(NEW.assignee_id, NEW.owner_id);
      v_old_assignee := CASE WHEN TG_OP='UPDATE' THEN COALESCE(OLD.assignee_id, OLD.owner_id) ELSE NULL END;
      v_new_status   := NEW.status;
      v_old_status   := CASE WHEN TG_OP='UPDATE' THEN OLD.status ELSE NULL END;
      v_actor        := auth.uid();

    WHEN 'epics' THEN
      v_entity_type  := 'epic';
      v_hub_source   := 'ProjectHub';
      v_icon_type    := 'epic';
      v_entity_key   := COALESCE(NEW.epic_key, NEW.id::TEXT);
      v_entity_title := COALESCE(NEW.name, 'Epic');
      v_new_assignee := COALESCE(NEW.assignee_id, NEW.owner_id);
      v_old_assignee := CASE WHEN TG_OP='UPDATE' THEN COALESCE(OLD.assignee_id, OLD.owner_id) ELSE NULL END;
      v_new_status   := NEW.status;
      v_old_status   := CASE WHEN TG_OP='UPDATE' THEN OLD.status ELSE NULL END;
      v_actor        := COALESCE(NEW.reporter_id, auth.uid());

    WHEN 'defects' THEN
      v_entity_type  := 'defect';
      v_hub_source   := 'TestHub';
      v_icon_type    := 'bug';
      v_entity_key   := COALESCE(NEW.defect_key, NEW.id::TEXT);
      v_entity_title := COALESCE(NEW.title, 'Defect');
      v_new_assignee := NEW.assignee_id;
      v_old_assignee := CASE WHEN TG_OP='UPDATE' THEN OLD.assignee_id ELSE NULL END;
      v_new_status   := NEW.status;
      v_old_status   := CASE WHEN TG_OP='UPDATE' THEN OLD.status ELSE NULL END;
      v_actor        := COALESCE(NEW.reporter_id, auth.uid());

    WHEN 'incidents' THEN
      v_entity_type  := 'incident';
      v_hub_source   := 'IncidentHub';
      v_icon_type    := 'incident';
      v_entity_key   := COALESCE(NEW.incident_key, NEW.id::TEXT);
      v_entity_title := COALESCE(NEW.title, 'Incident');
      v_new_assignee := NEW.assignee_id;
      v_old_assignee := CASE WHEN TG_OP='UPDATE' THEN OLD.assignee_id ELSE NULL END;
      v_new_status   := NEW.status;
      v_old_status   := CASE WHEN TG_OP='UPDATE' THEN OLD.status ELSE NULL END;
      v_actor        := COALESCE(NEW.reporter_id, auth.uid());

    WHEN 'releases' THEN
      v_entity_type  := 'release';
      v_hub_source   := 'ReleaseHub';
      v_icon_type    := 'release';
      v_entity_key   := COALESCE(NEW.version, NEW.id::TEXT);
      v_entity_title := COALESCE(NEW.name, 'Release');
      v_new_assignee := NEW.release_manager_id;
      v_old_assignee := CASE WHEN TG_OP='UPDATE' THEN OLD.release_manager_id ELSE NULL END;
      v_new_status   := NEW.status;
      v_old_status   := CASE WHEN TG_OP='UPDATE' THEN OLD.status ELSE NULL END;
      v_actor        := auth.uid();

    WHEN 'planner_tasks' THEN
      v_entity_type  := 'planner_task';
      v_hub_source   := 'TaskHub';
      v_icon_type    := 'task';
      v_entity_key   := COALESCE(NEW.task_key, NEW.id::TEXT);
      v_entity_title := COALESCE(NEW.title, 'Task');
      v_new_assignee := NEW.assignee_id;
      v_old_assignee := CASE WHEN TG_OP='UPDATE' THEN OLD.assignee_id ELSE NULL END;
      SELECT s.name INTO v_new_status FROM planner_statuses s WHERE s.id = NEW.status_id;
      IF TG_OP = 'UPDATE' THEN
        SELECT s.name INTO v_old_status FROM planner_statuses s WHERE s.id = OLD.status_id;
      END IF;
      v_actor        := auth.uid();

    WHEN 'subtasks' THEN
      v_entity_type  := 'subtask';
      v_hub_source   := 'ProjectHub';
      v_icon_type    := 'subtask';
      v_entity_key   := COALESCE(NEW.subtask_key, NEW.id::TEXT);
      v_entity_title := COALESCE(NEW.title, 'Subtask');
      v_new_assignee := NEW.assignee_id;
      v_old_assignee := CASE WHEN TG_OP='UPDATE' THEN OLD.assignee_id ELSE NULL END;
      v_new_status   := NEW.status;
      v_old_status   := CASE WHEN TG_OP='UPDATE' THEN OLD.status ELSE NULL END;
      v_actor        := auth.uid();

    WHEN 't10_items' THEN
      v_entity_type  := 't10_item';
      v_hub_source   := 'TaskHub';
      v_icon_type    := 'task';
      v_entity_key   := COALESCE(NEW.item_key, NEW.id::TEXT);
      v_entity_title := COALESCE(NEW.title, 'T10 Item');
      v_new_assignee := NEW.assignee_id;
      v_old_assignee := CASE WHEN TG_OP='UPDATE' THEN OLD.assignee_id ELSE NULL END;
      v_new_status   := NEW.status;
      v_old_status   := CASE WHEN TG_OP='UPDATE' THEN OLD.status ELSE NULL END;
      v_actor        := auth.uid();

    WHEN 'features' THEN
      v_entity_type  := 'feature';
      v_hub_source   := 'ProductHub';
      v_icon_type    := 'feature';
      v_entity_key   := COALESCE(NEW.feature_key, NEW.id::TEXT);
      v_entity_title := COALESCE(NEW.name, 'Feature');
      v_new_assignee := NEW.owner_id;
      v_old_assignee := CASE WHEN TG_OP='UPDATE' THEN OLD.owner_id ELSE NULL END;
      v_new_status   := NEW.status;
      v_old_status   := CASE WHEN TG_OP='UPDATE' THEN OLD.status ELSE NULL END;
      v_actor        := auth.uid();

    WHEN 'products' THEN
      v_entity_type  := 'product';
      v_hub_source   := 'ProductHub';
      v_icon_type    := 'product';
      v_entity_key   := COALESCE(NEW.product_key, NEW.id::TEXT);
      v_entity_title := COALESCE(NEW.name, 'Product');
      v_new_assignee := NEW.owner_id;
      v_old_assignee := CASE WHEN TG_OP='UPDATE' THEN OLD.owner_id ELSE NULL END;
      v_new_status   := NEW.status;
      v_old_status   := CASE WHEN TG_OP='UPDATE' THEN OLD.status ELSE NULL END;
      v_actor        := auth.uid();

    WHEN 'objectives' THEN
      v_entity_type  := 'objective';
      v_hub_source   := 'StrategyHub';
      v_icon_type    := 'objective';
      v_entity_key   := COALESCE(NEW.objective_key, NEW.id::TEXT);
      v_entity_title := COALESCE(NEW.title, 'Objective');
      v_new_assignee := NEW.owner_id;
      v_old_assignee := CASE WHEN TG_OP='UPDATE' THEN OLD.owner_id ELSE NULL END;
      v_new_status   := NEW.status;
      v_old_status   := CASE WHEN TG_OP='UPDATE' THEN OLD.status ELSE NULL END;
      v_actor        := auth.uid();

    WHEN 'initiatives' THEN
      v_entity_type  := 'initiative';
      v_hub_source   := 'StrategyHub';
      v_icon_type    := 'initiative';
      v_entity_key   := COALESCE(NEW.initiative_key, NEW.id::TEXT);
      v_entity_title := COALESCE(NEW.title, 'Initiative');
      v_new_assignee := NEW.owner_id;
      v_old_assignee := CASE WHEN TG_OP='UPDATE' THEN OLD.owner_id ELSE NULL END;
      v_new_status   := NEW.status;
      v_old_status   := CASE WHEN TG_OP='UPDATE' THEN OLD.status ELSE NULL END;
      v_actor        := auth.uid();

    ELSE
      RETURN NEW;
  END CASE;

  v_actor := COALESCE(v_actor, auth.uid());

  IF TG_OP = 'INSERT' AND v_new_assignee IS NOT NULL AND v_new_assignee IS DISTINCT FROM v_actor THEN
    INSERT INTO catalyst_notifications (
      user_id, type, hub_source, icon_type, title, body,
      entity_type, entity_id, entity_key, actor_id
    ) VALUES (
      v_new_assignee, 'assignment', v_hub_source, v_icon_type,
      v_entity_key || ' assigned to you', v_entity_title,
      v_entity_type, NEW.id, v_entity_key, v_actor
    );
  END IF;

  IF TG_OP = 'UPDATE' AND v_new_assignee IS DISTINCT FROM v_old_assignee AND v_new_assignee IS NOT NULL AND v_new_assignee IS DISTINCT FROM v_actor THEN
    INSERT INTO catalyst_notifications (
      user_id, type, hub_source, icon_type, title, body,
      entity_type, entity_id, entity_key, actor_id
    ) VALUES (
      v_new_assignee, 'assignment', v_hub_source, v_icon_type,
      v_entity_key || ' assigned to you', v_entity_title,
      v_entity_type, NEW.id, v_entity_key, v_actor
    );
  END IF;

  IF TG_OP = 'UPDATE' AND v_new_status IS DISTINCT FROM v_old_status AND v_new_assignee IS NOT NULL AND v_new_assignee IS DISTINCT FROM v_actor THEN
    v_status_color := CASE
      WHEN LOWER(COALESCE(v_new_status,'')) IN ('done','completed','approved','resolved','closed') THEN 'green'
      WHEN LOWER(COALESCE(v_new_status,'')) IN ('in_progress','in progress','active','in review','review') THEN 'blue'
      ELSE 'grey'
    END;

    INSERT INTO catalyst_notifications (
      user_id, type, hub_source, icon_type, title, body,
      entity_type, entity_id, entity_key, actor_id, metadata
    ) VALUES (
      v_new_assignee, 'status_change', v_hub_source, v_icon_type,
      v_entity_key || ' → ' || COALESCE(v_new_status, 'unknown'), v_entity_title,
      v_entity_type, NEW.id, v_entity_key, v_actor,
      jsonb_build_object('old_status', v_old_status, 'new_status', v_new_status, 'status_color', v_status_color)
    );
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: check_circular_dependency(text, uuid, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_circular_dependency(p_dependent_type text, p_dependent_id uuid, p_blocker_type text, p_blocker_id uuid) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    has_circular BOOLEAN := FALSE;
BEGIN
    WITH RECURSIVE dep_chain AS (
        SELECT blocker_type, blocker_id, 1 as depth
        FROM work_item_dependencies
        WHERE dependent_type = p_blocker_type AND dependent_id = p_blocker_id
        
        UNION ALL
        
        SELECT d.blocker_type, d.blocker_id, dc.depth + 1
        FROM work_item_dependencies d
        JOIN dep_chain dc ON d.dependent_type = dc.blocker_type AND d.dependent_id = dc.blocker_id
        WHERE dc.depth < 100
    )
    SELECT EXISTS (
        SELECT 1 FROM dep_chain 
        WHERE blocker_type = p_dependent_type AND blocker_id = p_dependent_id
    ) INTO has_circular;
    
    RETURN has_circular;
END;
$$;


--
-- Name: check_milestone_limit(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_milestone_limit() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF (SELECT COUNT(*) FROM es_theme_milestones WHERE theme_id = NEW.theme_id) >= 20 THEN
    RAISE EXCEPTION 'Maximum 20 milestones per theme';
  END IF;
  RETURN NEW;
END; $$;


--
-- Name: check_permission(uuid, text, public.permission_action, public.permission_scope, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_permission(_user_id uuid, _entity_type text, _action public.permission_action, _scope_type public.permission_scope DEFAULT 'global'::public.permission_scope, _scope_id uuid DEFAULT NULL::uuid) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  -- Check if user has admin role (full access)
  SELECT CASE
    WHEN has_role(_user_id, 'admin') THEN true
    ELSE EXISTS (
      SELECT 1
      FROM public.user_roles ur
      JOIN public.permission_grants pg ON pg.role_id IN (
        SELECT id FROM public.permission_roles pr
        WHERE pr.name = (
          SELECT role::text FROM public.user_roles WHERE user_id = _user_id LIMIT 1
        )
      )
      WHERE ur.user_id = _user_id
        AND pg.entity_type = _entity_type
        AND pg.action = _action
        AND pg.scope_type = _scope_type
        AND (pg.scope_id IS NULL OR pg.scope_id = _scope_id)
        AND pg.allowed = true
    )
  END;
$$;


--
-- Name: check_sla_breaches(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_sla_breaches() RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE sla_records
  SET
    response_breached = TRUE
  WHERE
    response_breached = FALSE
    AND response_met_at IS NULL
    AND response_due_at < now();

  UPDATE sla_records
  SET
    resolution_breached = TRUE
  WHERE
    resolution_breached = FALSE
    AND resolution_met_at IS NULL
    AND resolution_due_at < now();
END;
$$;


--
-- Name: check_theme_is_active(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_theme_is_active(p_theme_id uuid) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_status text;
BEGIN
  IF p_theme_id IS NULL THEN
    RETURN true; -- Allow null theme_id (unlinking)
  END IF;
  
  SELECT status INTO v_status
  FROM public.strategic_themes
  WHERE id = p_theme_id;
  
  IF v_status IS NULL THEN
    RETURN true; -- Theme not found, let FK handle it
  END IF;
  
  -- Only allow 'active' themes
  RETURN v_status = 'active';
END;
$$;


--
-- Name: claim_next_test(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.claim_next_test(p_run_id uuid, p_worker_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_queue_item RECORD;
  v_test_case RECORD;
  v_config RECORD;
BEGIN
  -- Get config
  SELECT * INTO v_config
  FROM parallel_run_configs
  WHERE run_id = p_run_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Parallel run not configured');
  END IF;

  -- Claim next available test (atomic with row lock)
  SELECT eq.* INTO v_queue_item
  FROM execution_queue eq
  WHERE eq.run_id = p_run_id
    AND eq.status = 'queued'
  ORDER BY 
    CASE WHEN v_config.priority_mode = 'priority' THEN eq.priority END DESC,
    CASE WHEN v_config.priority_mode = 'fifo' THEN eq.position END ASC,
    CASE WHEN v_config.priority_mode = 'random' THEN RANDOM() END
  LIMIT 1
  FOR UPDATE SKIP LOCKED;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('empty', true, 'message', 'No tests available in queue');
  END IF;

  -- Update queue item
  UPDATE execution_queue SET
    status = 'claimed',
    claimed_by = p_worker_id,
    claimed_at = NOW()
  WHERE id = v_queue_item.id;

  -- Update worker
  UPDATE parallel_workers SET
    status = 'running',
    current_test_id = v_queue_item.test_case_id,
    current_execution_id = v_queue_item.execution_result_id,
    claimed_at = NOW(),
    last_heartbeat = NOW()
  WHERE id = p_worker_id;

  -- Get test case details
  SELECT tc.*, er.id as execution_id
  INTO v_test_case
  FROM test_cases tc
  JOIN test_execution_results er ON er.test_case_id = tc.id
  WHERE tc.id = v_queue_item.test_case_id
    AND er.id = v_queue_item.execution_result_id;

  RETURN jsonb_build_object(
    'success', true,
    'queue_item_id', v_queue_item.id,
    'test_case', jsonb_build_object(
      'id', v_test_case.id,
      'case_number', v_test_case.case_number,
      'title', v_test_case.title,
      'priority', v_test_case.priority
    ),
    'execution_id', v_test_case.execution_id
  );
END;
$$;


--
-- Name: clean_stale_presence(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.clean_stale_presence() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  DELETE FROM work_item_presence 
  WHERE last_seen_at < NOW() - INTERVAL '2 minutes';
END;
$$;


--
-- Name: cleanup_user_data(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.cleanup_user_data() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Reassign or nullify owner_id and assignee_id fields
  UPDATE public.strategic_themes SET owner_id = NULL WHERE owner_id = OLD.id;
  UPDATE public.initiatives SET owner_id = NULL WHERE owner_id = OLD.id;
  UPDATE public.epics SET owner_id = NULL WHERE owner_id = OLD.id;
  UPDATE public.features SET owner_id = NULL WHERE owner_id = OLD.id;
  UPDATE public.stories SET assignee_id = NULL WHERE assignee_id = OLD.id;
  UPDATE public.stories SET owner_id = NULL WHERE owner_id = OLD.id;
  UPDATE public.subtasks SET assignee_id = NULL WHERE assignee_id = OLD.id;
  UPDATE public.risks SET owner_id = NULL WHERE owner_id = OLD.id;
  UPDATE public.objectives SET owner_id = NULL WHERE owner_id = OLD.id;

  RETURN OLD;
END;
$$;


--
-- Name: close_previous_cost_record(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.close_previous_cost_record() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
    UPDATE public.resource_cost_history
    SET effective_to = NEW.effective_from - INTERVAL '1 day',
        updated_at = NOW()
    WHERE resource_id = NEW.resource_id
      AND effective_to IS NULL
      AND id != NEW.id
      AND effective_from < NEW.effective_from;
    
    RETURN NEW;
END;
$$;


--
-- Name: complete_export_job(uuid, text, integer, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.complete_export_job(p_job_id uuid, p_file_name text, p_file_size integer, p_file_url text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_job RECORD;
BEGIN
  -- Get and update job
  UPDATE export_jobs SET
    status = 'completed',
    file_name = p_file_name,
    file_size = p_file_size,
    file_url = p_file_url,
    exported_records = total_records,
    completed_at = NOW(),
    expires_at = NOW() + INTERVAL '7 days'
  WHERE id = p_job_id
  RETURNING * INTO v_job;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Export job not found');
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'file_name', p_file_name,
    'file_size', p_file_size,
    'file_url', p_file_url,
    'exported_records', v_job.total_records
  );
END;
$$;


--
-- Name: complete_parallel_test(uuid, text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.complete_parallel_test(p_worker_id uuid, p_result_status text, p_execution_time integer DEFAULT 0) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_worker RECORD;
  v_queue_item_id UUID;
BEGIN
  -- Get worker state
  SELECT * INTO v_worker
  FROM parallel_workers
  WHERE id = p_worker_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Worker not found');
  END IF;

  IF v_worker.current_execution_id IS NULL THEN
    RETURN jsonb_build_object('error', 'Worker has no active test');
  END IF;

  -- Update queue item
  UPDATE execution_queue SET
    status = CASE WHEN p_result_status IN ('passed', 'failed', 'blocked', 'skipped') THEN 'completed' ELSE p_result_status END,
    completed_at = NOW()
  WHERE execution_result_id = v_worker.current_execution_id
  RETURNING id INTO v_queue_item_id;

  -- Update execution result
  UPDATE test_execution_results SET
    result_status = p_result_status,
    completed_at = NOW()
  WHERE id = v_worker.current_execution_id;

  -- Update worker stats
  UPDATE parallel_workers SET
    status = 'idle',
    current_test_id = NULL,
    current_execution_id = NULL,
    claimed_at = NULL,
    last_heartbeat = NOW(),
    completed_count = completed_count + CASE WHEN p_result_status IN ('passed', 'blocked', 'skipped') THEN 1 ELSE 0 END,
    failed_count = failed_count + CASE WHEN p_result_status = 'failed' THEN 1 ELSE 0 END,
    total_execution_time = total_execution_time + p_execution_time
  WHERE id = p_worker_id;

  RETURN jsonb_build_object(
    'success', true,
    'queue_item_id', v_queue_item_id,
    'result_status', p_result_status
  );
END;
$$;


--
-- Name: complete_step_timer(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.complete_step_timer(p_execution_id uuid, p_step_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_result RECORD;
  v_duration INTEGER;
BEGIN
  SELECT * INTO v_result
  FROM test_execution_step_results
  WHERE execution_id = p_execution_id AND step_id = p_step_id;

  IF NOT FOUND OR v_result.timer_started_at IS NULL THEN
    RETURN jsonb_build_object('error', 'No timer found for this step');
  END IF;

  IF v_result.is_timer_running THEN
    v_duration := EXTRACT(EPOCH FROM (NOW() - v_result.timer_started_at))::INTEGER - COALESCE(v_result.timer_total_paused, 0);
  ELSE
    v_duration := EXTRACT(EPOCH FROM (v_result.timer_paused_at - v_result.timer_started_at))::INTEGER - COALESCE(v_result.timer_total_paused, 0);
  END IF;

  UPDATE test_execution_step_results SET
    started_at = timer_started_at,
    completed_at = NOW(),
    is_timer_running = false
  WHERE id = v_result.id;

  RETURN jsonb_build_object(
    'success', true,
    'duration_seconds', v_duration,
    'started_at', v_result.timer_started_at,
    'completed_at', NOW()
  );
END;
$$;


--
-- Name: complete_test_run_v2(uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.complete_test_run_v2(p_run_id uuid, p_overall_result text, p_notes text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_step_summary RECORD;
  v_started_at TIMESTAMPTZ;
  v_duration INTEGER;
BEGIN
  -- Validate overall result
  IF p_overall_result NOT IN ('passed', 'failed', 'blocked', 'skipped') THEN
    RETURN jsonb_build_object('error', 'Invalid overall result. Must be passed, failed, blocked, or skipped');
  END IF;

  -- Validate run exists
  IF NOT EXISTS (SELECT 1 FROM tm_test_runs WHERE id = p_run_id) THEN
    RETURN jsonb_build_object('error', 'Run not found');
  END IF;

  -- Get step summary
  SELECT
    COUNT(*) as total_steps,
    COUNT(*) FILTER (WHERE sr.status IS NOT NULL AND sr.status != 'not_run') as executed_steps,
    COUNT(*) FILTER (WHERE sr.status = 'failed') as failed_steps,
    COUNT(*) FILTER (WHERE sr.status = 'blocked') as blocked_steps,
    COUNT(*) FILTER (WHERE sr.status = 'passed') as passed_steps,
    COALESCE(SUM(sr.duration_seconds), 0) as total_duration
  INTO v_step_summary
  FROM tm_test_steps s
  JOIN tm_test_runs r ON s.test_case_id = r.test_case_id
  LEFT JOIN tm_step_results sr ON sr.test_step_id = s.id AND sr.test_run_id = r.id
  WHERE r.id = p_run_id;

  -- Get started time
  SELECT executed_at INTO v_started_at
  FROM tm_test_runs WHERE id = p_run_id;

  -- Calculate total duration
  v_duration := COALESCE(v_step_summary.total_duration, 0);
  IF v_started_at IS NOT NULL THEN
    v_duration := GREATEST(v_duration, EXTRACT(EPOCH FROM (NOW() - v_started_at))::INTEGER);
  END IF;

  -- Update run
  UPDATE tm_test_runs SET
    status = p_overall_result::tm_execution_status,
    comments = NULLIF(TRIM(COALESCE(p_notes, '')), ''),
    duration_seconds = v_duration,
    updated_at = NOW()
  WHERE id = p_run_id;

  RETURN jsonb_build_object(
    'success', true,
    'run_id', p_run_id,
    'overall_result', p_overall_result,
    'summary', jsonb_build_object(
      'total_steps', COALESCE(v_step_summary.total_steps, 0),
      'executed_steps', COALESCE(v_step_summary.executed_steps, 0),
      'passed_steps', COALESCE(v_step_summary.passed_steps, 0),
      'failed_steps', COALESCE(v_step_summary.failed_steps, 0),
      'blocked_steps', COALESCE(v_step_summary.blocked_steps, 0),
      'total_duration', v_duration
    )
  );
END;
$$;


--
-- Name: compute_freshness_scores(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.compute_freshness_scores() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  UPDATE wiki_pages SET
    freshness_score = GREATEST(0, LEAST(100, 100 - (EXTRACT(EPOCH FROM (now() - updated_at)) / 86400 / 90 * 100))),
    verification_status = CASE WHEN verification_status = 'verified' AND updated_at < now() - interval '90 days' THEN 'needs_review' ELSE verification_status END
  WHERE deleted_at IS NULL;
END; $$;


--
-- Name: compute_home_analytics_daily(date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.compute_home_analytics_daily(target_date date DEFAULT (CURRENT_DATE - 1)) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  mode_rec RECORD;
BEGIN
  -- For each mode, compute key metrics
  FOR mode_rec IN SELECT DISTINCT home_mode FROM public.home_analytics_events 
    WHERE created_at::date = target_date
  LOOP
    -- Total events
    INSERT INTO public.home_analytics_daily (date, home_mode, metric_name, metric_value)
    SELECT 
      target_date,
      mode_rec.home_mode,
      'total_events',
      COUNT(*)
    FROM public.home_analytics_events
    WHERE home_mode = mode_rec.home_mode
      AND created_at::date = target_date
    ON CONFLICT (date, home_mode, metric_name) 
    DO UPDATE SET metric_value = EXCLUDED.metric_value, computed_at = now();
    
    -- Unique users
    INSERT INTO public.home_analytics_daily (date, home_mode, metric_name, metric_value)
    SELECT 
      target_date,
      mode_rec.home_mode,
      'unique_users',
      COUNT(DISTINCT user_id)
    FROM public.home_analytics_events
    WHERE home_mode = mode_rec.home_mode
      AND created_at::date = target_date
    ON CONFLICT (date, home_mode, metric_name) 
    DO UPDATE SET metric_value = EXCLUDED.metric_value, computed_at = now();
    
    -- Home views
    INSERT INTO public.home_analytics_daily (date, home_mode, metric_name, metric_value)
    SELECT 
      target_date,
      mode_rec.home_mode,
      'home_views',
      COUNT(*)
    FROM public.home_analytics_events
    WHERE home_mode = mode_rec.home_mode
      AND event_name = 'home_viewed'
      AND created_at::date = target_date
    ON CONFLICT (date, home_mode, metric_name) 
    DO UPDATE SET metric_value = EXCLUDED.metric_value, computed_at = now();
    
    -- Items opened
    INSERT INTO public.home_analytics_daily (date, home_mode, metric_name, metric_value)
    SELECT 
      target_date,
      mode_rec.home_mode,
      'items_opened',
      COUNT(*)
    FROM public.home_analytics_events
    WHERE home_mode = mode_rec.home_mode
      AND event_name LIKE '%_item_opened'
      AND created_at::date = target_date
    ON CONFLICT (date, home_mode, metric_name) 
    DO UPDATE SET metric_value = EXCLUDED.metric_value, computed_at = now();
    
    -- Errors
    INSERT INTO public.home_analytics_daily (date, home_mode, metric_name, metric_value)
    SELECT 
      target_date,
      mode_rec.home_mode,
      'error_count',
      COUNT(*)
    FROM public.home_analytics_events
    WHERE home_mode = mode_rec.home_mode
      AND event_name LIKE 'home_%_error'
      AND created_at::date = target_date
    ON CONFLICT (date, home_mode, metric_name) 
    DO UPDATE SET metric_value = EXCLUDED.metric_value, computed_at = now();
  END LOOP;
END;
$$;


--
-- Name: compute_idea_impact_score(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.compute_idea_impact_score() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  NEW.impact_total := ROUND(
    (COALESCE(NEW.impact_investor_fit, 0) * 0.25) +
    (COALESCE(NEW.impact_market_size, 0) * 0.20) +
    (COALESCE(NEW.impact_problem_severity, 0) * 0.20) +
    (COALESCE(NEW.impact_user_benefit, 0) * 0.15) +
    (COALESCE(NEW.impact_complexity_inv, 0) * 0.10) +
    (COALESCE(NEW.impact_time_to_value, 0) * 0.10),
  2);
  RETURN NEW;
END;
$$;


--
-- Name: compute_idea_impact_total(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.compute_idea_impact_total() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  NEW.impact_total := ROUND(
    (COALESCE(NEW.impact_investor_fit, 0) * 0.25) +
    (COALESCE(NEW.impact_market_size, 0) * 0.20) +
    (COALESCE(NEW.impact_problem_severity, 0) * 0.20) +
    (COALESCE(NEW.impact_user_benefit, 0) * 0.15) +
    (COALESCE(NEW.impact_complexity_inv, 0) * 0.10) +
    (COALESCE(NEW.impact_time_to_value, 0) * 0.10),
    2
  );
  RETURN NEW;
END;
$$;


--
-- Name: compute_incident_priority(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.compute_incident_priority() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  sev_score    INT := 0;
  impact_score INT := 0;
  urgency_score INT := 0;
  total        INT := 0;
  computed_p   TEXT;
  computed_maj BOOLEAN := FALSE;
BEGIN
  -- Severity score
  sev_score := CASE NEW.severity
    WHEN 'SEV1' THEN 4
    WHEN 'SEV2' THEN 3
    WHEN 'SEV3' THEN 2
    WHEN 'SEV4' THEN 1
    ELSE 0
  END;

  -- Impact score
  impact_score := CASE NEW.impact
    WHEN 'high'   THEN 3
    WHEN 'medium' THEN 2
    WHEN 'low'    THEN 1
    ELSE 0
  END;

  -- Urgency score
  urgency_score := CASE NEW.urgency
    WHEN 'high'   THEN 3
    WHEN 'medium' THEN 2
    WHEN 'low'    THEN 1
    ELSE 0
  END;

  total := sev_score + impact_score + urgency_score;

  computed_p := CASE
    WHEN total >= 9 THEN 'P1'
    WHEN total >= 7 THEN 'P2'
    WHEN total >= 5 THEN 'P3'
    ELSE 'P4'
  END;

  -- Major incident auto-flag
  computed_maj := (
    NEW.severity = 'SEV1'
    AND NEW.impact = 'high'
    AND NEW.urgency = 'high'
  );

  -- Override whatever the UI tried to set
  NEW.priority := computed_p;
  NEW.is_major_incident := computed_maj;

  RETURN NEW;
END;
$$;


--
-- Name: convert_idea_to_initiative(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.convert_idea_to_initiative(p_idea_id uuid, p_user_id uuid DEFAULT auth.uid()) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_idea RECORD;
  v_initiative_id UUID;
BEGIN
  SELECT * INTO v_idea FROM ph_ideas WHERE id = p_idea_id AND is_deleted = FALSE;
  IF v_idea IS NULL THEN RAISE EXCEPTION 'Idea not found or deleted: %', p_idea_id; END IF;
  IF v_idea.status = 'Converted' THEN RAISE EXCEPTION 'Idea already converted: %', p_idea_id; END IF;
  IF v_idea.status != 'Approved' THEN RAISE EXCEPTION 'Only approved ideas can be converted. Current status: %', v_idea.status; END IF;

  INSERT INTO ph_initiatives (title, description, status, department, priority, created_at)
  VALUES (
    v_idea.title,
    COALESCE(v_idea.ai_summary, v_idea.description, ''),
    'New Demand',
    v_idea.department,
    CASE v_idea.priority WHEN 'P1' THEN 5.0 WHEN 'P2' THEN 4.0 WHEN 'P3' THEN 3.0 WHEN 'P4' THEN 2.0 ELSE 3.0 END,
    now()
  )
  RETURNING id INTO v_initiative_id;

  UPDATE ph_ideas
  SET status = 'Converted', linked_initiative_id = v_initiative_id, converted_at = now(), converted_by = p_user_id
  WHERE id = p_idea_id;

  INSERT INTO ph_idea_audit_log (idea_id, action, field_changed, old_value, new_value, changed_by)
  VALUES (p_idea_id, 'CONVERTED', 'linked_initiative_id', NULL, v_initiative_id::TEXT, p_user_id);

  RETURN v_initiative_id;
END;
$$;


--
-- Name: create_adhoc_cycle(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_adhoc_cycle() RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  adhoc_cycle_id UUID;
BEGIN
  -- Check if Adhoc cycle already exists
  SELECT id INTO adhoc_cycle_id
  FROM test_cycles
  WHERE is_adhoc = true
  LIMIT 1;

  -- If not, create it
  IF adhoc_cycle_id IS NULL THEN
    INSERT INTO test_cycles (
      name,
      description,
      status,
      is_adhoc,
      created_by,
      created_at
    ) VALUES (
      'Adhoc Cycle',
      'Default cycle for unplanned testing. Created automatically.',
      'active',
      true,
      auth.uid(),
      NOW()
    )
    RETURNING id INTO adhoc_cycle_id;
  END IF;

  RETURN adhoc_cycle_id;
END;
$$;


