-- Name: create_automation_connector(text, text, jsonb, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_automation_connector(p_name text, p_connector_type text, p_config jsonb DEFAULT '{}'::jsonb, p_webhook_url text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_connector_id UUID;
  v_webhook_secret TEXT;
BEGIN
  -- Generate webhook secret if URL provided
  IF p_webhook_url IS NOT NULL THEN
    v_webhook_secret := encode(gen_random_bytes(32), 'hex');
  END IF;

  INSERT INTO automation_connectors (name, connector_type, config, webhook_url, webhook_secret, created_by)
  VALUES (p_name, p_connector_type, p_config, p_webhook_url, v_webhook_secret, auth.uid())
  RETURNING id INTO v_connector_id;

  RETURN jsonb_build_object(
    'success', true,
    'connector_id', v_connector_id,
    'webhook_secret', v_webhook_secret
  );
END;
$$;


--
-- Name: create_batch_delete_job(uuid, jsonb, public.delete_type); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_batch_delete_job(p_project_id uuid, p_test_case_ids jsonb, p_delete_type public.delete_type DEFAULT 'soft'::public.delete_type) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_job_id UUID;
  v_total INTEGER;
  v_actor UUID := auth.uid();
BEGIN
  v_total := jsonb_array_length(p_test_case_ids);

  IF v_total = 0 THEN
    RETURN jsonb_build_object('error', 'No test cases selected');
  END IF;

  -- Create job
  INSERT INTO batch_delete_jobs (
    project_id, test_case_ids, delete_type, total_records, created_by
  ) VALUES (
    p_project_id, p_test_case_ids, p_delete_type, v_total, v_actor
  )
  RETURNING id INTO v_job_id;

  RETURN jsonb_build_object(
    'success', true,
    'job_id', v_job_id,
    'total_records', v_total
  );
END;
$$;


