-- Name: create_batch_update_job(uuid, jsonb, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_batch_update_job(p_project_id uuid, p_test_case_ids jsonb, p_field_updates jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_job_id UUID;
  v_total INTEGER;
  v_actor UUID := auth.uid();
BEGIN
  v_total := jsonb_array_length(COALESCE(p_test_case_ids, '[]'::jsonb));

  IF v_total = 0 THEN
    RETURN jsonb_build_object('error', 'No test cases selected');
  END IF;

  IF p_field_updates = '{}'::jsonb OR p_field_updates IS NULL THEN
    RETURN jsonb_build_object('error', 'No fields to update');
  END IF;

  -- Create job
  INSERT INTO batch_update_jobs (
    project_id, test_case_ids, field_updates, total_records, created_by
  ) VALUES (
    p_project_id, p_test_case_ids, p_field_updates, v_total, v_actor
  )
  RETURNING id INTO v_job_id;

  RETURN jsonb_build_object(
    'success', true,
    'job_id', v_job_id,
    'total_records', v_total
  );
END;
$$;


--
-- Name: create_board(text, uuid, boolean, text, text, text, jsonb, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_board(p_name text, p_project_id uuid DEFAULT NULL::uuid, p_is_personal boolean DEFAULT false, p_visibility text DEFAULT 'project'::text, p_swimlane_type text DEFAULT 'none'::text, p_color text DEFAULT '#2563EB'::text, p_columns jsonb DEFAULT NULL::jsonb, p_user_id uuid DEFAULT NULL::uuid) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
declare
  v_board_id uuid;
  v_col jsonb;
  v_pos int := 0;
  v_uid uuid := coalesce(p_user_id, auth.uid());
  v_default_cols jsonb := coalesce(p_columns, '[
    {"name":"To Do","is_backlog":true,"is_done":false},
    {"name":"In Progress","is_backlog":false,"is_done":false},
    {"name":"Done","is_backlog":false,"is_done":true}
  ]'::jsonb);
begin
  insert into public.boards(name, project_id, is_personal, visibility, swimlane_type,
    show_swimlanes, color, filter_project_ids, created_by, updated_by)
  values(p_name, p_project_id, p_is_personal, p_visibility, p_swimlane_type,
    true, p_color,
    case when p_project_id is not null then array[p_project_id] else '{}'::uuid[] end,
    v_uid, v_uid)
  returning id into v_board_id;

  for v_col in select * from jsonb_array_elements(v_default_cols) loop
    insert into public.board_columns(board_id, name, position, status_ids, is_backlog, is_done)
    values(v_board_id, v_col->>'name', v_pos, '{}',
      coalesce((v_col->>'is_backlog')::boolean, false),
      coalesce((v_col->>'is_done')::boolean, false));
    v_pos := v_pos + 1;
  end loop;

  insert into public.board_quick_filters(board_id, name, filter_type, is_system, sort_order) values
    (v_board_id, 'All Issues', 'all', true, 0),
    (v_board_id, 'My Issues', 'mine', true, 1),
    (v_board_id, 'Current Release', 'release', true, 2);

  insert into public.board_members(board_id, user_id, role)
  values(v_board_id, v_uid, 'admin')
  on conflict(board_id, user_id) do nothing;

  return v_board_id;
end;
$$;


