--

CREATE FUNCTION public.create_default_space_permissions(p_space_id uuid) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    INSERT INTO space_permissions (space_id, permission_key, administrator, member, viewer) VALUES
        (p_space_id, 'browse_space', true, true, true),
        (p_space_id, 'create_work_items', true, true, false),
        (p_space_id, 'edit_work_items', true, true, false),
        (p_space_id, 'delete_work_items', true, false, false),
        (p_space_id, 'transition_work_items', true, true, false),
        (p_space_id, 'assign_work_items', true, true, false),
        (p_space_id, 'schedule_work_items', true, true, false),
        (p_space_id, 'manage_versions', true, false, false),
        (p_space_id, 'manage_components', true, false, false),
        (p_space_id, 'administer_space', true, false, false)
    ON CONFLICT (space_id, permission_key) DO NOTHING;
END;
$$;


--
-- Name: create_execution_run(uuid, text, text, text, jsonb, timestamp with time zone, uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_execution_run(p_project_id uuid, p_name text, p_description text DEFAULT NULL::text, p_environment text DEFAULT 'staging'::text, p_configuration jsonb DEFAULT '{}'::jsonb, p_scheduled_start timestamp with time zone DEFAULT NULL::timestamp with time zone, p_assigned_testers uuid[] DEFAULT '{}'::uuid[]) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_run_id UUID;
  v_run_number INTEGER;
  v_created_by UUID := auth.uid();
BEGIN
  -- Validate project exists
  IF NOT EXISTS (SELECT 1 FROM projects WHERE id = p_project_id) THEN
    RETURN jsonb_build_object('error', 'Project not found');
  END IF;

  -- Validate name
  IF TRIM(COALESCE(p_name, '')) = '' THEN
    RETURN jsonb_build_object('error', 'Run name is required');
  END IF;

  -- Validate environment
  IF p_environment NOT IN ('development', 'staging', 'production', 'custom') THEN
    RETURN jsonb_build_object('error', 'Invalid environment');
  END IF;

  -- Generate run number (auto-increment per project)
  SELECT COALESCE(MAX(run_number), 0) + 1 INTO v_run_number
  FROM test_execution_runs
  WHERE project_id = p_project_id;

  -- Insert new run
  INSERT INTO test_execution_runs (
    project_id,
    run_number,
    name,
    description,
    environment,
    configuration,
    status,
    scheduled_start,
    created_by,
    assigned_testers,
    created_at,
    updated_at
  ) VALUES (
    p_project_id,
    v_run_number,
    TRIM(p_name),
    NULLIF(TRIM(COALESCE(p_description, '')), ''),
    p_environment,
    COALESCE(p_configuration, '{}'),
    'draft',
    p_scheduled_start,
    v_created_by,
    COALESCE(p_assigned_testers, '{}'),
    NOW(),
    NOW()
  )
  RETURNING id INTO v_run_id;

  -- Audit log
  INSERT INTO execution_run_audit_logs (entity_type, entity_id, action, actor_id, changes)
  VALUES ('test_execution_run', v_run_id, 'create', v_created_by, 
    jsonb_build_object(
      'name', p_name,
      'environment', p_environment,
      'run_number', v_run_number
    )
  );

  RETURN jsonb_build_object(
    'success', true,
    'run_id', v_run_id,
    'run_number', v_run_number
  );
END;
$$;


--
-- Name: create_export_job(uuid, public.export_format, jsonb, jsonb, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_export_job(p_project_id uuid, p_format public.export_format, p_fields jsonb, p_filters jsonb, p_test_case_ids jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_job_id UUID;
  v_total INTEGER;
  v_actor UUID := auth.uid();
BEGIN
  -- Count records to export
  IF jsonb_array_length(COALESCE(p_test_case_ids, '[]'::jsonb)) > 0 THEN
    v_total := jsonb_array_length(p_test_case_ids);
  ELSE
    SELECT COUNT(*) INTO v_total
    FROM test_cases
    WHERE project_id = p_project_id AND deleted_at IS NULL;
  END IF;

  -- Create job
  INSERT INTO export_jobs (
    project_id, format, fields, filters, test_case_ids, total_records, created_by
  ) VALUES (
    p_project_id, p_format, p_fields, COALESCE(p_filters, '{}'::jsonb), 
    COALESCE(p_test_case_ids, '[]'::jsonb), v_total, v_actor
  )
  RETURNING id INTO v_job_id;

  RETURN jsonb_build_object(
    'success', true,
    'job_id', v_job_id,
    'total_records', v_total
  );
END;
$$;


--
-- Name: create_incident_sla_record(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_incident_sla_record() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  config sla_configs%ROWTYPE;
BEGIN
  SELECT * INTO config FROM sla_configs WHERE severity = NEW.severity;
  
  IF config.id IS NOT NULL THEN
    INSERT INTO sla_records (
      incident_id,
      response_due_at,
      resolution_due_at
    ) VALUES (
      NEW.id,
      NEW.created_at + (config.response_minutes || ' minutes')::INTERVAL,
      NEW.created_at + (config.resolution_minutes || ' minutes')::INTERVAL
    );
  END IF;
  
  RETURN NEW;
END;
$$;


