--
-- Name: create_notification_with_dedup(uuid, character varying, character varying, text, character varying, character varying, uuid, uuid, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_notification_with_dedup(p_user_id uuid, p_type character varying, p_title character varying, p_message text, p_link character varying, p_entity_type character varying DEFAULT NULL::character varying, p_entity_id uuid DEFAULT NULL::uuid, p_actor_id uuid DEFAULT NULL::uuid, p_severity character varying DEFAULT 'info'::character varying, p_idempotency_key character varying DEFAULT NULL::character varying) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_notification_id UUID;
    v_existing_id UUID;
BEGIN
    IF p_idempotency_key IS NOT NULL THEN
        SELECT id INTO v_existing_id 
        FROM user_notifications 
        WHERE idempotency_key = p_idempotency_key;
        
        IF v_existing_id IS NOT NULL THEN
            RETURN v_existing_id;
        END IF;
    END IF;
    
    IF p_user_id = p_actor_id THEN
        RETURN NULL;
    END IF;
    
    IF EXISTS (
        SELECT 1 FROM user_notification_preferences
        WHERE user_id = p_user_id
        AND in_app_notifications_enabled = false
    ) THEN
        RETURN NULL;
    END IF;
    
    INSERT INTO user_notifications (
        id, user_id, type, title, message, link, 
        entity_type, entity_id, actor_id, severity, 
        idempotency_key, is_read, created_at
    )
    VALUES (
        gen_random_uuid(), p_user_id, p_type, p_title, p_message, p_link,
        p_entity_type, p_entity_id, p_actor_id, p_severity,
        p_idempotency_key, false, now()
    )
    RETURNING id INTO v_notification_id;
    
    RETURN v_notification_id;
END;
$$;


--
-- Name: create_parallel_run(uuid, integer, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_parallel_run(p_run_id uuid, p_max_workers integer DEFAULT 3, p_priority_mode text DEFAULT 'priority'::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_config_id UUID;
  v_queue_count INTEGER;
BEGIN
  -- Validate run exists
  IF NOT EXISTS (SELECT 1 FROM test_execution_runs WHERE id = p_run_id AND deleted_at IS NULL) THEN
    RETURN jsonb_build_object('error', 'Run not found');
  END IF;

  -- Create config
  INSERT INTO parallel_run_configs (run_id, max_workers, priority_mode)
  VALUES (p_run_id, p_max_workers, p_priority_mode)
  ON CONFLICT (run_id) DO UPDATE SET
    max_workers = p_max_workers,
    priority_mode = p_priority_mode
  RETURNING id INTO v_config_id;

  -- Create workers
  FOR i IN 1..p_max_workers LOOP
    INSERT INTO parallel_workers (run_id, worker_number, status)
    VALUES (p_run_id, i, 'idle')
    ON CONFLICT (run_id, worker_number) DO UPDATE SET
      status = 'idle',
      current_test_id = NULL,
      current_execution_id = NULL,
      last_heartbeat = NOW();
  END LOOP;

  -- Populate queue from run's test cases
  INSERT INTO execution_queue (run_id, test_case_id, execution_result_id, priority, position)
  SELECT 
    p_run_id,
    er.test_case_id,
    er.id,
    CASE tc.priority
      WHEN 'critical' THEN 100
      WHEN 'high' THEN 75
      WHEN 'medium' THEN 50
      WHEN 'low' THEN 25
      ELSE 50
    END,
    ROW_NUMBER() OVER (ORDER BY tc.priority DESC, tc.created_at ASC)
  FROM test_execution_results er
  JOIN test_cases tc ON er.test_case_id = tc.id
  WHERE er.run_id = p_run_id
    AND er.result_status IS NULL
  ON CONFLICT (run_id, test_case_id) DO NOTHING;

  SELECT COUNT(*) INTO v_queue_count
  FROM execution_queue
  WHERE run_id = p_run_id AND status = 'queued';

  RETURN jsonb_build_object(
    'success', true,
    'config_id', v_config_id,
    'workers', p_max_workers,
    'queue_count', v_queue_count
  );
END;
$$;


--
-- Name: create_plan_version(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_plan_version() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF OLD.status IS DISTINCT FROM NEW.status THEN
    INSERT INTO tm_plan_versions (plan_id, version, snapshot, created_by, change_summary)
    VALUES (NEW.id, NEW.version, to_jsonb(OLD), auth.uid(), 'Status changed from ' || OLD.status || ' to ' || NEW.status);
    NEW.version := OLD.version + 1;
  END IF;
  NEW.updated_at := NOW();
  RETURN NEW;
END;
$$;


