--
-- Name: create_sla_record(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_sla_record() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  response_hours  NUMERIC;
  resolution_hours NUMERIC;
BEGIN
  -- SLA targets by severity
  CASE NEW.severity
    WHEN 'SEV1' THEN
      response_hours := 0.25;   -- 15 minutes
      resolution_hours := 1;
    WHEN 'SEV2' THEN
      response_hours := 0.5;    -- 30 minutes
      resolution_hours := 4;
    WHEN 'SEV3' THEN
      response_hours := 1;      -- 1 hour
      resolution_hours := 8;
    WHEN 'SEV4' THEN
      response_hours := 2;
      resolution_hours := 24;
    ELSE
      response_hours := 4;
      resolution_hours := 48;
  END CASE;

  INSERT INTO sla_records (
    incident_id,
    response_due_at,
    resolution_due_at,
    response_breached,
    resolution_breached
  ) VALUES (
    NEW.id,
    NEW.created_at + (response_hours || ' hours')::INTERVAL,
    NEW.created_at + (resolution_hours || ' hours')::INTERVAL,
    FALSE,
    FALSE
  )
  ON CONFLICT (incident_id) DO NOTHING;

  RETURN NEW;
END;
$$;


