--
-- Name: dependency_auto_derive_fields(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.dependency_auto_derive_fields() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  req_container RECORD;
  dep_container RECORD;
BEGIN
  -- Derive dependency level from work item types
  IF NEW.requesting_work_item_type IS NOT NULL AND NEW.depends_on_work_item_type IS NOT NULL THEN
    NEW.dependency_level_v2 := derive_dependency_level(NEW.requesting_work_item_type, NEW.depends_on_work_item_type);
    NEW.is_cross_level_exception := (NEW.dependency_level_v2 = 'cross_level');
  END IF;

  -- Derive requesting container
  IF NEW.requesting_work_item_type IS NOT NULL AND NEW.requesting_work_item_id IS NOT NULL THEN
    SELECT * INTO req_container 
    FROM derive_dependency_container(NEW.requesting_work_item_type, NEW.requesting_work_item_id);
    IF FOUND THEN
      NEW.derived_requesting_container_type := req_container.container_type;
      NEW.derived_requesting_container_id := req_container.container_id;
    END IF;
  END IF;

  -- Derive respondent container
  IF NEW.depends_on_work_item_type IS NOT NULL AND NEW.depends_on_work_item_id IS NOT NULL THEN
    SELECT * INTO dep_container 
    FROM derive_dependency_container(NEW.depends_on_work_item_type, NEW.depends_on_work_item_id);
    IF FOUND THEN
      NEW.derived_respondent_container_type := dep_container.container_type;
      NEW.derived_respondent_container_id := dep_container.container_id;
    END IF;
  END IF;

  -- Derive quarter from needed_by_date if not explicitly set
  IF NEW.needed_by_date IS NOT NULL AND (NEW.quarter IS NULL OR NEW.quarter_derived_from_date = TRUE) THEN
    NEW.quarter := derive_quarter_from_date(NEW.needed_by_date::DATE);
    NEW.quarter_derived_from_date := TRUE;
  END IF;

  -- Track blocked state changes for audit
  IF TG_OP = 'UPDATE' THEN
    IF NEW.source_blocked = TRUE AND (OLD.source_blocked IS NULL OR OLD.source_blocked = FALSE) THEN
      NEW.source_blocked_at := NOW();
      NEW.source_blocked_by := auth.uid();
    ELSIF NEW.source_blocked = FALSE AND OLD.source_blocked = TRUE THEN
      NEW.source_blocked_at := NULL;
      NEW.source_blocked_by := NULL;
      NEW.source_blocked_reason := NULL;
    END IF;

    IF NEW.target_delayed = TRUE AND (OLD.target_delayed IS NULL OR OLD.target_delayed = FALSE) THEN
      NEW.target_delayed_at := NOW();
      NEW.target_delayed_by := auth.uid();
    ELSIF NEW.target_delayed = FALSE AND OLD.target_delayed = TRUE THEN
      NEW.target_delayed_at := NULL;
      NEW.target_delayed_by := NULL;
      NEW.target_delayed_reason := NULL;
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: derive_dependency_container(public.work_item_dependency_type, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.derive_dependency_container(p_work_item_type public.work_item_dependency_type, p_work_item_id uuid) RETURNS TABLE(container_type text, container_id uuid)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF p_work_item_type = 'epic' THEN
    -- Epic belongs to a Program
    RETURN QUERY
    SELECT 'program'::TEXT, e.program_id
    FROM public.epics e
    WHERE e.id = p_work_item_id;
  ELSIF p_work_item_type = 'feature' THEN
    -- Feature belongs to a Project
    RETURN QUERY
    SELECT 'project'::TEXT, f.project_id
    FROM public.features f
    WHERE f.id = p_work_item_id;
  END IF;
END;
$$;


--
-- Name: derive_dependency_level(public.work_item_dependency_type, public.work_item_dependency_type); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.derive_dependency_level(p_requesting_type public.work_item_dependency_type, p_depends_on_type public.work_item_dependency_type) RETURNS public.dependency_level_v2
    LANGUAGE plpgsql IMMUTABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF p_requesting_type = 'epic' AND p_depends_on_type = 'epic' THEN
    RETURN 'execution'::dependency_level_v2;
  ELSIF p_requesting_type = 'feature' AND p_depends_on_type = 'feature' THEN
    RETURN 'delivery'::dependency_level_v2;
  ELSE
    RETURN 'cross_level'::dependency_level_v2;
  END IF;
END;
$$;


--
-- Name: derive_incident_priority(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.derive_incident_priority() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  NEW.priority := CASE
    WHEN NEW.impact = 'high' AND NEW.urgency = 'high' THEN 'P1'
    WHEN NEW.impact = 'high' AND NEW.urgency = 'medium' THEN 'P2'
    WHEN NEW.impact = 'high' AND NEW.urgency = 'low' THEN 'P3'
    WHEN NEW.impact = 'medium' AND NEW.urgency = 'high' THEN 'P2'
    WHEN NEW.impact = 'medium' AND NEW.urgency = 'medium' THEN 'P3'
    WHEN NEW.impact = 'medium' AND NEW.urgency = 'low' THEN 'P4'
    WHEN NEW.impact = 'low' AND NEW.urgency = 'high' THEN 'P3'
    WHEN NEW.impact = 'low' AND NEW.urgency = 'medium' THEN 'P4'
    WHEN NEW.impact = 'low' AND NEW.urgency = 'low' THEN 'P4'
    ELSE 'P3'
  END::priority_level;
  RETURN NEW;
END;
$$;


--
-- Name: derive_quarter_from_date(date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.derive_quarter_from_date(p_date date) RETURNS text
    LANGUAGE plpgsql IMMUTABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  q INT;
  y INT;
BEGIN
  IF p_date IS NULL THEN
    RETURN NULL;
  END IF;
  q := EXTRACT(QUARTER FROM p_date);
  y := EXTRACT(YEAR FROM p_date);
  RETURN 'Q' || q || ' ' || y;
END;
$$;


--
-- Name: es_calculate_kr_progress(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.es_calculate_kr_progress() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE es_key_results SET
    current_value = NEW.value,
    progress_pct = LEAST(100, GREATEST(0,
      CASE WHEN target_value = start_value THEN 0
      ELSE ROUND(((NEW.value - start_value) / NULLIF(target_value - start_value, 0)) * 100, 2) END
    )),
    status = CASE
      WHEN ROUND(((NEW.value - start_value) / NULLIF(target_value - start_value, 0)) * 100, 2) >= 100 THEN 'achieved'
      WHEN ROUND(((NEW.value - start_value) / NULLIF(target_value - start_value, 0)) * 100, 2) >= 70 THEN 'on_track'
      WHEN ROUND(((NEW.value - start_value) / NULLIF(target_value - start_value, 0)) * 100, 2) >= 40 THEN 'in_progress'
      ELSE 'at_risk' END,
    updated_at = now()
  WHERE id = NEW.key_result_id;

  UPDATE es_goals SET
    progress_pct = (SELECT ROUND(AVG(progress_pct), 2) FROM es_key_results WHERE goal_id = (
      SELECT goal_id FROM es_key_results WHERE id = NEW.key_result_id
    ) AND status != 'cancelled'),
    updated_at = now()
  WHERE id = (SELECT goal_id FROM es_key_results WHERE id = NEW.key_result_id)
    AND progress_override = false;

  RETURN NEW;
END;
$$;


--
-- Name: es_update_updated_at(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.es_update_updated_at() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN NEW.updated_at = now(); RETURN NEW; END;
$$;


--
-- Name: es_validate_link_type(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.es_validate_link_type() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.link_type NOT IN ('predecessor','successor','related','blocks','depends_on') THEN
    RAISE EXCEPTION 'Invalid link_type';
  END IF;
  RETURN NEW;
END; $$;


--
-- Name: es_validate_milestone_fields(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.es_validate_milestone_fields() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.category IS NOT NULL AND NEW.category NOT IN ('discover','define','design','deliver') THEN
    RAISE EXCEPTION 'Invalid milestone category';
  END IF;
  IF NEW.state IS NOT NULL AND NEW.state NOT IN ('not_started','in_progress','completed','missed') THEN
    RAISE EXCEPTION 'Invalid milestone state';
  END IF;
  RETURN NEW;
END; $$;


--
-- Name: es_validate_theme_fields(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.es_validate_theme_fields() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.progress_pct IS NOT NULL AND (NEW.progress_pct < 0 OR NEW.progress_pct > 100) THEN
    RAISE EXCEPTION 'progress_pct must be between 0 and 100';
  END IF;
  IF NEW.ai_health_score IS NOT NULL AND (NEW.ai_health_score < 0 OR NEW.ai_health_score > 100) THEN
    RAISE EXCEPTION 'ai_health_score must be between 0 and 100';
  END IF;
  IF NEW.priority IS NOT NULL AND NEW.priority NOT IN ('critical','high','medium','low') THEN
    RAISE EXCEPTION 'Invalid priority value';
  END IF;
  RETURN NEW;
END; $$;


--
-- Name: execute_batch_update(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.execute_batch_update(p_job_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
  v_job RECORD;
  v_tc_id UUID;
  v_updated INTEGER := 0;
  v_failed INTEGER := 0;
  v_update_sql TEXT;
BEGIN
  -- Get job
  SELECT * INTO v_job
  FROM batch_update_jobs
  WHERE id = p_job_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Job not found');
  END IF;

  -- Update status
  UPDATE batch_update_jobs SET
    status = 'executing',
    started_at = NOW()
  WHERE id = p_job_id;

  -- Apply updates per test case
  FOR v_tc_id IN 
    SELECT DISTINCT test_case_id
    FROM batch_update_changes
    WHERE job_id = p_job_id AND NOT applied
  LOOP
    BEGIN
      -- Build dynamic update statement
      SELECT 'UPDATE test_cases SET ' || 
        string_agg(
          format('%I = %L', field_name, new_value),
          ', '
        ) || 
        ', updated_at = NOW() WHERE id = $1'
      INTO v_update_sql
      FROM batch_update_changes
      WHERE job_id = p_job_id
        AND test_case_id = v_tc_id
        AND NOT applied;

      IF v_update_sql IS NOT NULL THEN
        EXECUTE v_update_sql USING v_tc_id;
      END IF;

      -- Mark changes as applied
      UPDATE batch_update_changes SET
        applied = true
      WHERE job_id = p_job_id
        AND test_case_id = v_tc_id;

      v_updated := v_updated + 1;

    EXCEPTION WHEN OTHERS THEN
      v_failed := v_failed + 1;
    END;
  END LOOP;

  -- Update job status
  UPDATE batch_update_jobs SET
    status = 'completed',
    updated_records = v_updated,
    failed_records = v_failed,
    completed_at = NOW()
  WHERE id = p_job_id;

  RETURN jsonb_build_object(
    'success', true,
    'updated', v_updated,
    'failed', v_failed
  );
END;
$_$;


--
-- Name: execute_permanent_delete(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.execute_permanent_delete(p_job_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_job RECORD;
  v_tc_id UUID;
  v_deleted INTEGER := 0;
  v_failed INTEGER := 0;
  v_actor UUID := auth.uid();
  v_tc_data JSONB;
BEGIN
  -- Get job
  SELECT * INTO v_job
  FROM batch_delete_jobs
  WHERE id = p_job_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Job not found');
  END IF;

  -- Update status
  UPDATE batch_delete_jobs SET
    status = 'executing',
    started_at = NOW()
  WHERE id = p_job_id;

  -- Process each test case
  FOR v_tc_id IN 
    SELECT (jsonb_array_elements_text(v_job.test_case_ids))::UUID
  LOOP
    BEGIN
      -- Get test case data before deletion
      SELECT to_jsonb(tc.*) INTO v_tc_data
      FROM test_cases tc
      WHERE tc.id = v_tc_id;

      IF v_tc_data IS NOT NULL THEN
        -- Store deletion record (for audit)
        INSERT INTO deleted_items_log (
          job_id, test_case_id, test_case_data, delete_type, deleted_by
        ) VALUES (
          p_job_id, v_tc_id, v_tc_data, 'permanent', v_actor
        );

        -- Delete related data
        DELETE FROM test_steps WHERE test_case_id = v_tc_id;
        
        -- Delete test case
        DELETE FROM test_cases WHERE id = v_tc_id;

        v_deleted := v_deleted + 1;
      END IF;

    EXCEPTION WHEN OTHERS THEN
      v_failed := v_failed + 1;
    END;
  END LOOP;

  -- Update job status
  UPDATE batch_delete_jobs SET
    status = 'completed',
    deleted_records = v_deleted,
    failed_records = v_failed,
    completed_at = NOW()
  WHERE id = p_job_id;

  RETURN jsonb_build_object(
    'success', true,
    'deleted', v_deleted,
    'failed', v_failed,
    'can_restore', false
  );
END;
$$;


--
-- Name: execute_soft_delete(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.execute_soft_delete(p_job_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_job RECORD;
  v_tc_id UUID;
  v_deleted INTEGER := 0;
  v_failed INTEGER := 0;
  v_actor UUID := auth.uid();
  v_tc_data JSONB;
BEGIN
  -- Get job
  SELECT * INTO v_job
  FROM batch_delete_jobs
  WHERE id = p_job_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Job not found');
  END IF;

  -- Update status
  UPDATE batch_delete_jobs SET
    status = 'executing',
    started_at = NOW()
  WHERE id = p_job_id;

  -- Process each test case
  FOR v_tc_id IN 
    SELECT (jsonb_array_elements_text(v_job.test_case_ids))::UUID
  LOOP
    BEGIN
      -- Get test case data
      SELECT to_jsonb(tc.*) INTO v_tc_data
      FROM test_cases tc
      WHERE tc.id = v_tc_id AND tc.deleted_at IS NULL;

      IF v_tc_data IS NOT NULL THEN
        -- Store for potential restore
        INSERT INTO deleted_items_log (
          job_id, test_case_id, test_case_data, delete_type, deleted_by, expires_at
        ) VALUES (
          p_job_id, v_tc_id, v_tc_data, 'soft', v_actor, NOW() + INTERVAL '30 days'
        );

        -- Soft delete
        UPDATE test_cases SET
          deleted_at = NOW()
        WHERE id = v_tc_id;

        v_deleted := v_deleted + 1;
      END IF;

    EXCEPTION WHEN OTHERS THEN
      v_failed := v_failed + 1;
    END;
  END LOOP;

  -- Update job status
  UPDATE batch_delete_jobs SET
    status = 'completed',
    deleted_records = v_deleted,
    failed_records = v_failed,
    completed_at = NOW()
  WHERE id = p_job_id;

  RETURN jsonb_build_object(
    'success', true,
    'deleted', v_deleted,
    'failed', v_failed,
    'can_restore', true,
    'expires_in_days', 30
  );
END;
$$;


--
-- Name: execute_sql_query(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.execute_sql_query(query_text text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  result jsonb;
BEGIN
  EXECUTE 'SELECT jsonb_agg(row_to_json(t)) FROM (' || query_text || ') t' INTO result;
  RETURN COALESCE(result, '[]'::jsonb);
END;
$$;


--
-- Name: extract_kb_tiptap_text(jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.extract_kb_tiptap_text(content jsonb) RETURNS text
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
  result TEXT := '';
  node JSONB;
BEGIN
  FOR node IN SELECT jsonb_array_elements(content->'content')
  LOOP
    IF node->>'type' = 'text' THEN
      result := result || ' ' || (node->>'text');
    ELSIF node->'content' IS NOT NULL THEN
      result := result || ' ' || extract_kb_tiptap_text(node);
    END IF;
  END LOOP;
  RETURN trim(result);
END;
$$;


