--
-- Name: find_feature_by_short_id(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.find_feature_by_short_id(p_short text) RETURNS TABLE(id uuid, display_id text)
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  SELECT f.id, f.display_id
  FROM public.features f
  WHERE substring(f.id::text, 1, 6) = lower(p_short)
    AND f.deleted_at IS NULL
  LIMIT 1;
$$;


--
-- Name: find_similar_articles(text, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.find_similar_articles(p_title text, p_content text, p_exclude_id uuid DEFAULT NULL::uuid) RETURNS TABLE(page_id uuid, title text, similarity numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT wp.id, wp.title,
    ROUND(ts_rank(wp.fts_vector, plainto_tsquery('english', p_title || ' ' || LEFT(p_content, 200)))::numeric, 3) AS similarity
  FROM wiki_pages wp
  WHERE wp.deleted_at IS NULL AND (p_exclude_id IS NULL OR wp.id != p_exclude_id)
    AND wp.fts_vector @@ plainto_tsquery('english', p_title)
  ORDER BY similarity DESC LIMIT 5;
END; $$;


--
-- Name: find_story_by_short_id(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.find_story_by_short_id(p_short text) RETURNS TABLE(id uuid, story_key text)
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  SELECT s.id, s.story_key
  FROM public.stories s
  WHERE substring(s.id::text, 1, 6) = lower(p_short)
    AND s.deleted_at IS NULL
  LIMIT 1;
$$;


--
-- Name: fn_after_checkin(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_after_checkin() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE es_key_results SET
    current_value = NEW.value,
    check_in_count = COALESCE(check_in_count, 0) + 1,
    last_check_in_at = COALESCE(NEW.created_at, now()),
    confidence_level = COALESCE(NEW.confidence_level::text, confidence_level),
    updated_at = now()
  WHERE id = NEW.key_result_id;
  
  UPDATE es_goals SET
    check_in_count = COALESCE(check_in_count, 0) + 1,
    last_check_in_at = COALESCE(NEW.created_at, now()),
    updated_at = now()
  WHERE id = (SELECT goal_id FROM es_key_results WHERE id = NEW.key_result_id);
  
  RETURN NEW;
END;
$$;


