--
-- Name: fn_goal_auto_key(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_goal_auto_key() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
DECLARE
  next_num INTEGER;
BEGIN
  SELECT COALESCE(MAX(CAST(SUBSTRING(goal_key FROM 3) AS INTEGER)), 0) + 1
  INTO next_num
  FROM es_goals
  WHERE goal_key IS NOT NULL AND goal_key ~ '^G-[0-9]+$';
  
  NEW.goal_key := 'G-' || LPAD(next_num::TEXT, 3, '0');
  RETURN NEW;
END;
$_$;


--
-- Name: fn_guard_execution_on_active_cycle(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_guard_execution_on_active_cycle() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_cycle_status text;
BEGIN
  SELECT tc.status INTO v_cycle_status
  FROM public.tm_cycle_scope cs
  JOIN public.tm_test_cycles tc ON tc.id = cs.cycle_id
  WHERE cs.id = NEW.cycle_scope_id;

  IF v_cycle_status IS NULL THEN
    RAISE EXCEPTION 'Cycle scope not found for id %', NEW.cycle_scope_id;
  END IF;

  IF v_cycle_status NOT IN ('active') THEN
    RAISE EXCEPTION 'Cannot add execution: parent cycle is not active (status: %)', v_cycle_status;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: fn_kr_auto_key(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_kr_auto_key() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
DECLARE
  next_num INTEGER;
BEGIN
  SELECT COALESCE(MAX(CAST(SUBSTRING(kr_key FROM 4) AS INTEGER)), 0) + 1
  INTO next_num
  FROM es_key_results
  WHERE kr_key IS NOT NULL AND kr_key ~ '^KR-[0-9]+$';
  
  NEW.kr_key := 'KR-' || LPAD(next_num::TEXT, 3, '0');
  RETURN NEW;
END;
$_$;


--
-- Name: fn_kr_compute_progress(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_kr_compute_progress() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.target_value IS NOT NULL AND NEW.start_value IS NOT NULL AND NEW.target_value != NEW.start_value THEN
    NEW.progress_pct := LEAST(100, GREATEST(0, 
      ROUND(((COALESCE(NEW.current_value,0) - COALESCE(NEW.start_value,0)) / NULLIF(NEW.target_value - NEW.start_value, 0)) * 100, 1)
    ));
  ELSE
    NEW.progress_pct := 0;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: fn_lock_scope_version(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_lock_scope_version() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.locked_version IS NULL THEN
    SELECT version INTO NEW.locked_version
    FROM tm_test_cases
    WHERE id = NEW.test_case_id;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: fn_notify_watchers(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_notify_watchers() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_issue_key TEXT;
  v_issue_title TEXT;
BEGIN
  -- Resolve issue details for notification
  SELECT issue_key, title INTO v_issue_key, v_issue_title
  FROM public.catalyst_issues WHERE id = NEW.issue_id;

  INSERT INTO public.notifications(
    recipient_user_id, notification_type, entity_id, entity_key,
    entity_title, entity_type, entity_icon_type, hub_source,
    actor_user_id, status_type, tab, metadata
  )
  SELECT
    iw.user_id,
    CASE NEW.activity_type
      WHEN 'status_changed'   THEN 'status_changed'
      WHEN 'comment_added'    THEN 'commented_on_work_item'
      WHEN 'assignee_changed' THEN 'assigned_to_work_item'
      WHEN 'priority_changed' THEN 'status_changed'
      ELSE 'status_changed'
    END,
    NEW.issue_id::TEXT,
    COALESCE(v_issue_key, ''),
    COALESCE(v_issue_title, ''),
    'issue',
    'story',
    'ProjectHub',
    NEW.actor_id,
    'info',
    'direct',
    jsonb_build_object(
      'activity_type', NEW.activity_type,
      'old_value', NEW.old_value,
      'new_value', NEW.new_value,
      'source', 'watching'
    )
  FROM public.issue_watchers iw
  WHERE iw.issue_id = NEW.issue_id
    AND iw.user_id != COALESCE(NEW.actor_id, '00000000-0000-0000-0000-000000000000'::uuid);

  RETURN NEW;
END;
$$;


--
-- Name: fn_ph_budget_item_audit(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_ph_budget_item_audit() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO ph_initiative_audit_log (initiative_id, user_id, action, entity_type, entity_id, metadata)
    VALUES (NEW.initiative_id, NEW.created_by, 'budget_item_added', 'budget_item', NEW.id,
            jsonb_build_object('title', NEW.description, 'category', NEW.category, 'amount', NEW.planned_amount));
  ELSIF TG_OP = 'DELETE' THEN
    INSERT INTO ph_initiative_audit_log (initiative_id, user_id, action, entity_type, entity_id, metadata)
    VALUES (OLD.initiative_id, NULL, 'deleted', 'budget_item', OLD.id,
            jsonb_build_object('title', OLD.description));
  END IF;
  RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: fn_ph_bulk_update(uuid[], text, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_ph_bulk_update(p_item_ids uuid[], p_field text, p_value text, p_user_id uuid) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE v_count INTEGER;
BEGIN
  IF p_field = 'release_id' THEN
    UPDATE ph_work_items SET release_id = p_value::UUID WHERE id = ANY(p_item_ids);
  ELSIF p_field = 'theme_id' THEN
    UPDATE ph_work_items SET theme_id = p_value::UUID WHERE id = ANY(p_item_ids);
  ELSIF p_field = 'status' THEN
    UPDATE ph_work_items SET status = p_value WHERE id = ANY(p_item_ids);
  ELSIF p_field = 'assignee_user_id' THEN
    UPDATE ph_work_items SET assignee_user_id = p_value::UUID WHERE id = ANY(p_item_ids);
  ELSE
    RAISE EXCEPTION 'Invalid field: %', p_field;
  END IF;
  GET DIAGNOSTICS v_count = ROW_COUNT;
  INSERT INTO ph_bulk_ops_log (operation, affected_item_ids, field_changed, new_values, item_count, performed_by)
  VALUES ('bulk_' || p_field, p_item_ids, p_field, jsonb_build_object(p_field, p_value), v_count, p_user_id);
  RETURN v_count;
END;
$$;


--
-- Name: fn_ph_get_item_tree(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_ph_get_item_tree(p_parent_id uuid DEFAULT NULL::uuid) RETURNS TABLE(id uuid, item_key text, item_type text, summary text, status text, depth integer, parent_id uuid, release_id uuid, theme_id uuid, assignee_user_id uuid, due_date date, children_count bigint)
    LANGUAGE sql STABLE
    AS $$
  WITH RECURSIVE tree AS (
    SELECT wi.id, wi.item_key, wi.item_type, wi.summary, wi.status,
      0 AS depth, wi.parent_id, wi.release_id, wi.theme_id,
      wi.assignee_user_id, wi.due_date
    FROM ph_work_items wi
    WHERE (p_parent_id IS NULL AND wi.parent_id IS NULL)
       OR (p_parent_id IS NOT NULL AND wi.parent_id = p_parent_id)
    UNION ALL
    SELECT child.id, child.item_key, child.item_type, child.summary, child.status,
      tree.depth + 1, child.parent_id, child.release_id, child.theme_id,
      child.assignee_user_id, child.due_date
    FROM ph_work_items child
    JOIN tree ON child.parent_id = tree.id
  )
  SELECT t.*,
    (SELECT COUNT(*) FROM ph_work_items c WHERE c.parent_id = t.id) AS children_count
  FROM tree t
  ORDER BY t.depth, t.item_key;
$$;


--
-- Name: fn_ph_initiative_audit(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_ph_initiative_audit() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
  v_fields TEXT[] := ARRAY['title','description','status','progress','assignee_id','department_id','business_owner_id','target_quarter','budget_allocated','reporter_id','kickoff_date','target_complete','business_ask_date'];
  v_field TEXT;
  v_old TEXT;
  v_new TEXT;
  v_user_id UUID;
BEGIN
  v_user_id := auth.uid();

  IF TG_OP = 'INSERT' THEN
    INSERT INTO ph_initiative_audit_log (initiative_id, user_id, action, entity_type, entity_id, metadata)
    VALUES (NEW.id, v_user_id, 'created', 'initiative', NEW.id, jsonb_build_object('title', NEW.title));
    RETURN NEW;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    IF OLD.is_deleted IS DISTINCT FROM NEW.is_deleted AND NEW.is_deleted = true THEN
      INSERT INTO ph_initiative_audit_log (initiative_id, user_id, action, entity_type, entity_id)
      VALUES (NEW.id, v_user_id, 'deleted', 'initiative', NEW.id);
      RETURN NEW;
    END IF;

    FOREACH v_field IN ARRAY v_fields LOOP
      EXECUTE format('SELECT ($1).%I::text, ($2).%I::text', v_field, v_field)
        INTO v_old, v_new USING OLD, NEW;
      IF v_old IS DISTINCT FROM v_new THEN
        INSERT INTO ph_initiative_audit_log (initiative_id, user_id, action, entity_type, entity_id, field_name, old_value, new_value)
        VALUES (NEW.id, v_user_id, CASE WHEN v_field = 'status' THEN 'status_changed' ELSE 'updated' END,
                'initiative', NEW.id, v_field, v_old, v_new);
      END IF;
    END LOOP;
    RETURN NEW;
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$_$;


--
-- Name: fn_ph_release_summary(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_ph_release_summary() RETURNS TABLE(version_name text, release_date text, total_items bigint, done_items bigint, in_progress_items bigint, in_review_items bigint, blocked_items bigint, todo_items bigint, completion_percent integer, projects text[], assignees jsonb)
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  WITH exploded AS (
    SELECT
      v->>'name' AS version_name,
      v->>'releaseDate' AS release_date,
      i.project_key,
      lower(i.status) AS status_lower,
      lower(i.status_category) AS cat_lower,
      i.assignee_account_id,
      i.assignee_display_name
    FROM ph_issues i,
         jsonb_array_elements(i.fix_versions) AS v
    WHERE i.fix_versions IS NOT NULL
      AND jsonb_array_length(i.fix_versions) > 0
      AND v->>'name' IS NOT NULL
  ),
  agg AS (
    SELECT
      e.version_name,
      max(e.release_date) AS release_date,
      count(*) AS total_items,
      count(*) FILTER (WHERE e.cat_lower = 'done') AS done_items,
      count(*) FILTER (WHERE e.cat_lower != 'done' AND e.status_lower != 'blocked'
        AND e.status_lower NOT IN ('in review','technical validation','ready for qa','ready for uat')
        AND (e.cat_lower = 'in progress' OR e.status_lower IN ('in progress','in development','in beta'))
      ) AS in_progress_items,
      count(*) FILTER (WHERE e.cat_lower != 'done' AND e.status_lower != 'blocked'
        AND e.status_lower IN ('in review','technical validation','ready for qa','ready for uat')
      ) AS in_review_items,
      count(*) FILTER (WHERE e.cat_lower != 'done' AND e.status_lower = 'blocked') AS blocked_items,
      count(*) FILTER (WHERE e.cat_lower != 'done' AND e.status_lower != 'blocked'
        AND e.status_lower NOT IN ('in review','technical validation','ready for qa','ready for uat')
        AND e.cat_lower != 'in progress'
        AND e.status_lower NOT IN ('in progress','in development','in beta')
      ) AS todo_items,
      array_agg(DISTINCT e.project_key ORDER BY e.project_key) AS projects
    FROM exploded e
    GROUP BY e.version_name
  ),
  assignee_agg AS (
    SELECT
      e.version_name,
      jsonb_agg(DISTINCT jsonb_build_object(
        'accountId', e.assignee_account_id,
        'displayName', e.assignee_display_name,
        'avatarUrl', COALESCE(p.avatar_url, um.jira_avatar_url),
        'roleName', ri.role_name
      )) AS assignees
    FROM exploded e
    LEFT JOIN ph_user_mapping um ON um.jira_account_id = e.assignee_account_id
    LEFT JOIN profiles p ON p.id = um.catalyst_profile_id
    LEFT JOIN resource_inventory ri ON ri.profile_id = um.catalyst_profile_id
    WHERE e.assignee_account_id IS NOT NULL
    GROUP BY e.version_name
  )
  SELECT
    a.version_name,
    a.release_date,
    a.total_items,
    a.done_items,
    a.in_progress_items,
    a.in_review_items,
    a.blocked_items,
    a.todo_items,
    CASE WHEN a.total_items > 0 THEN (a.done_items * 100 / a.total_items)::integer ELSE 0 END AS completion_percent,
    a.projects,
    COALESCE(aa.assignees, '[]'::jsonb) AS assignees
  FROM agg a
  LEFT JOIN assignee_agg aa ON aa.version_name = a.version_name
  ORDER BY a.release_date DESC NULLS LAST, a.version_name;
$$;


--
-- Name: fn_ph_risk_audit(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_ph_risk_audit() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO ph_initiative_audit_log (initiative_id, user_id, action, entity_type, entity_id, metadata)
    VALUES (NEW.initiative_id, NEW.created_by, 'risk_added', 'risk', NEW.id,
            jsonb_build_object('title', NEW.title, 'risk_key', NEW.risk_key, 'severity',
              CASE WHEN NEW.risk_score >= 20 THEN 'Critical' WHEN NEW.risk_score >= 15 THEN 'High'
                   WHEN NEW.risk_score >= 8 THEN 'Medium' ELSE 'Low' END));
  ELSIF TG_OP = 'DELETE' THEN
    INSERT INTO ph_initiative_audit_log (initiative_id, user_id, action, entity_type, entity_id, metadata)
    VALUES (OLD.initiative_id, NULL, 'deleted', 'risk', OLD.id,
            jsonb_build_object('title', OLD.title, 'risk_key', OLD.risk_key));
  END IF;
  RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: fn_ph_score_audit(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_ph_score_audit() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'UPDATE' THEN
    IF OLD.computed_score IS DISTINCT FROM NEW.computed_score THEN
      INSERT INTO public.ph_initiative_audit_log (
        initiative_id,
        user_id,
        action,
        entity_type,
        entity_id,
        field_name,
        old_value,
        new_value
      )
      VALUES (
        NEW.initiative_id,
        NEW.scored_by,
        'score_updated',
        'score',
        NEW.id,
        'computed_score',
        OLD.computed_score::text,
        NEW.computed_score::text
      );
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: fn_ph_update_theme_progress(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_ph_update_theme_progress() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE ph_themes SET progress = (
    SELECT CASE WHEN COUNT(*) = 0 THEN 0
    ELSE ROUND((COUNT(*) FILTER (WHERE status = 'Done')::NUMERIC / COUNT(*)) * 100, 1)
    END
    FROM ph_work_items
    WHERE theme_id = COALESCE(NEW.theme_id, OLD.theme_id)
  )
  WHERE id = COALESCE(NEW.theme_id, OLD.theme_id);
  RETURN NEW;
END;
$$;


