--
-- Name: fn_ph_work_item_filters(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_ph_work_item_filters() RETURNS jsonb
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  SELECT jsonb_build_object(
    'issue_types', (SELECT coalesce(jsonb_agg(DISTINCT issue_type ORDER BY issue_type), '[]'::jsonb) FROM ph_issues),
    'statuses', (SELECT coalesce(jsonb_agg(DISTINCT status ORDER BY status), '[]'::jsonb) FROM ph_issues),
    'project_keys', (SELECT coalesce(jsonb_agg(DISTINCT project_key ORDER BY project_key), '[]'::jsonb) FROM ph_issues),
    'fix_versions', (
      SELECT coalesce(jsonb_agg(jsonb_build_object('name', v->>'name', 'releaseDate', v->>'releaseDate') ORDER BY v->>'releaseDate' DESC NULLS LAST, v->>'name'), '[]'::jsonb)
      FROM (
        SELECT DISTINCT ON (v->>'name') v
        FROM ph_issues i, jsonb_array_elements(i.fix_versions) AS v
        WHERE i.fix_versions IS NOT NULL AND jsonb_array_length(i.fix_versions) > 0 AND v->>'name' IS NOT NULL
        ORDER BY v->>'name', v->>'releaseDate' DESC NULLS LAST
      ) sub
    )
  );
$$;


--
-- Name: fn_recompute_goal_progress(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_recompute_goal_progress() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_goal_id UUID;
  v_progress NUMERIC;
  v_kr_count INTEGER;
BEGIN
  v_goal_id := COALESCE(NEW.goal_id, OLD.goal_id);
  
  SELECT
    CASE 
      WHEN SUM(COALESCE(weight,1)) > 0 THEN ROUND(SUM(COALESCE(progress_pct,0) * COALESCE(weight,1)) / SUM(COALESCE(weight,1)), 1)
      ELSE 0
    END,
    COUNT(*)
  INTO v_progress, v_kr_count
  FROM es_key_results
  WHERE goal_id = v_goal_id;
  
  UPDATE es_goals SET
    progress_pct = CASE WHEN score_override IS NOT NULL THEN score_override * 100 ELSE v_progress END,
    kr_count = v_kr_count,
    updated_at = now()
  WHERE id = v_goal_id;
  
  RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: fn_resource_360_siblings(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_resource_360_siblings(p_work_item_id text) RETURNS TABLE(id text, item_key text, title text, item_type text, status text, hub text, assigner_name text, age_days integer)
    LANGUAGE sql STABLE
    AS $$
  SELECT 
    phi.issue_key AS id,
    phi.issue_key AS item_key,
    phi.summary AS title,
    phi.issue_type AS item_type,
    phi.status AS status,
    'ProjectHub' AS hub,
    phi.reporter_display_name AS assigner_name,
    GREATEST(0, EXTRACT(DAY FROM now() - phi.jira_created_at)::int) AS age_days
  FROM ph_issues phi
  WHERE phi.parent_key = (
    SELECT parent_key FROM ph_issues WHERE issue_key = p_work_item_id LIMIT 1
  )
  AND phi.parent_key IS NOT NULL
  ORDER BY phi.jira_created_at DESC;
$$;


--
-- Name: fn_track_issue_changes(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_track_issue_changes() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF OLD.status IS DISTINCT FROM NEW.status THEN
    INSERT INTO public.watch_activity(issue_id, actor_id, activity_type, old_value, new_value)
    VALUES(NEW.id, auth.uid(), 'status_changed', OLD.status, NEW.status);
  END IF;

  IF OLD.assignee_id IS DISTINCT FROM NEW.assignee_id THEN
    INSERT INTO public.watch_activity(issue_id, actor_id, activity_type, old_value, new_value)
    VALUES(NEW.id, auth.uid(), 'assignee_changed', OLD.assignee_id::TEXT, NEW.assignee_id::TEXT);
  END IF;

  IF OLD.priority IS DISTINCT FROM NEW.priority THEN
    INSERT INTO public.watch_activity(issue_id, actor_id, activity_type, old_value, new_value)
    VALUES(NEW.id, auth.uid(), 'priority_changed', OLD.priority, NEW.priority);
  END IF;

  RETURN NEW;
END;
$$;


