--
-- Name: generate_brd_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_brd_number() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  current_year TEXT;
  next_seq INTEGER;
BEGIN
  IF NEW.type = 'brd' AND NEW.brd_number IS NULL THEN
    current_year := to_char(now(), 'YYYY');
    SELECT COALESCE(MAX(
      CAST(SUBSTRING(brd_number FROM 10) AS INTEGER)
    ), 0) + 1
    INTO next_seq
    FROM ra_documents
    WHERE brd_number LIKE 'BRD-' || current_year || '-%';

    NEW.brd_number := 'BRD-' || current_year || '-' || LPAD(next_seq::TEXT, 4, '0');
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: generate_business_request_key(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_business_request_key() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
DECLARE
  max_num INTEGER;
  new_num INTEGER;
BEGIN
  -- Find the highest existing MIM number
  SELECT COALESCE(MAX(
    CASE 
      WHEN request_key ~ '^MIM-[0-9]+$' 
      THEN CAST(SUBSTRING(request_key FROM 5) AS INTEGER)
      ELSE 0
    END
  ), 0) INTO max_num
  FROM business_requests;
  
  -- Increment by 1
  new_num := max_num + 1;
  
  -- Format as MIM-XXX (3 digits, zero-padded)
  NEW.request_key := 'MIM-' || LPAD(new_num::TEXT, 3, '0');
  
  RETURN NEW;
END;
$_$;


