--

CREATE FUNCTION public.generate_change_key() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.change_key IS NULL OR NEW.change_key = '' THEN
    NEW.change_key := 'CHG-' || LPAD(nextval('change_request_key_seq')::TEXT, 3, '0');
  END IF;
  RETURN NEW;
END;
