--
-- Name: generate_change_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_change_number() RETURNS character varying
    LANGUAGE plpgsql
    AS $$
DECLARE
  year_part VARCHAR(4);
  seq_num INTEGER;
  new_number VARCHAR(20);
BEGIN
  year_part := EXTRACT(YEAR FROM NOW())::VARCHAR;
  
  SELECT COALESCE(MAX(
    CAST(SUBSTRING(number FROM 'CHG-\d{4}-(\d+)') AS INTEGER)
  ), 0) + 1
  INTO seq_num
  FROM change_numbers
  WHERE number LIKE 'CHG-' || year_part || '-%';
  
  new_number := 'CHG-' || year_part || '-' || LPAD(seq_num::VARCHAR, 4, '0');
  
  RETURN new_number;
END;
$$;


