--
-- Name: generate_next_defect_id(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_next_defect_id() RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_year INTEGER;
  v_next_seq INTEGER;
BEGIN
  v_year := EXTRACT(YEAR FROM NOW())::INTEGER;
  
  -- Get or create sequence for current year
  INSERT INTO defect_id_sequences (year, last_sequence)
  VALUES (v_year, 0)
  ON CONFLICT (year) DO NOTHING;
  
  -- Increment and get the next sequence
  UPDATE defect_id_sequences
  SET last_sequence = last_sequence + 1, updated_at = NOW()
  WHERE year = v_year
  RETURNING last_sequence INTO v_next_seq;
  
  -- Return formatted ID: DEF-YYYY-NNNN
  RETURN 'DEF-' || v_year || '-' || LPAD(v_next_seq::TEXT, 4, '0');
END;
$$;


--
-- Name: generate_next_epic_key(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_next_epic_key(p_program_id uuid) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
  v_program_key TEXT;
  v_next_seq INTEGER;
BEGIN
  -- Get the program's 3-letter key
  SELECT key INTO v_program_key
  FROM programs
  WHERE id = p_program_id;
  
  IF v_program_key IS NULL THEN
    RAISE EXCEPTION 'Program not found: %', p_program_id;
  END IF;
  
  -- Validate program key is exactly 3 uppercase letters
  IF v_program_key !~ '^[A-Z]{3}$' THEN
    -- Extract first 3 letters as fallback
    v_program_key := UPPER(LEFT(REGEXP_REPLACE(v_program_key, '[^A-Za-z]', '', 'g'), 3));
    IF LENGTH(v_program_key) < 3 THEN
      v_program_key := 'PRG';
    END IF;
  END IF;
  
  -- Get or create sequence
  INSERT INTO epic_key_sequences (program_id, last_sequence)
  VALUES (p_program_id, 0)
  ON CONFLICT (program_id) DO NOTHING;
  
  -- Increment and get the next sequence
  UPDATE epic_key_sequences
  SET last_sequence = last_sequence + 1, updated_at = NOW()
  WHERE program_id = p_program_id
  RETURNING last_sequence INTO v_next_seq;
  
  -- Return formatted key: AAA-###
  RETURN v_program_key || '-' || LPAD(v_next_seq::TEXT, 3, '0');
END;
$_$;


