--
-- Name: generate_work_item_display_id(uuid, public.work_item_type); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_work_item_display_id(p_generation_id uuid, p_item_type public.work_item_type) RETURNS character varying
    LANGUAGE plpgsql
    AS $$
DECLARE
  prefix VARCHAR(10);
  next_num INTEGER;
BEGIN
  prefix := CASE p_item_type
    WHEN 'epic' THEN 'EPIC'
    WHEN 'feature' THEN 'FEAT'
    WHEN 'story' THEN 'US'
    WHEN 'task' THEN 'TASK'
    WHEN 'test_case' THEN 'TC'
    WHEN 'prd' THEN 'PRD'
    ELSE 'ITEM'
  END;
  
  SELECT COALESCE(MAX(CAST(NULLIF(SUBSTRING(display_id FROM LENGTH(prefix) + 2), '') AS INTEGER)), 0) + 1
  INTO next_num
  FROM work_items
  WHERE generation_id = p_generation_id AND item_type = p_item_type;
  
  RETURN prefix || '-' || LPAD(next_num::text, 3, '0');
END;
$$;


--
-- Name: generate_work_item_key(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_work_item_key() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  project_key TEXT;
  next_seq INTEGER;
BEGIN
  -- Get project key
  SELECT key INTO project_key FROM projects WHERE id = NEW.project_id;
  
  -- Get next sequence number for this project
  SELECT COALESCE(MAX(sequence_number), 0) + 1 INTO next_seq
  FROM work_items
  WHERE project_id = NEW.project_id;
  
  -- Set the sequence number and key
  NEW.sequence_number := next_seq;
  NEW.key := COALESCE(project_key, 'WI') || '-' || next_seq;
  
  RETURN NEW;
END;
$$;


--
-- Name: generate_work_manager_task_key(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_work_manager_task_key(p_team_id uuid) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_team_name TEXT;
  v_prefix TEXT;
  v_next_seq INTEGER;
BEGIN
  -- Get team name and create prefix
  SELECT name INTO v_team_name FROM teams WHERE id = p_team_id;
  IF v_team_name IS NULL THEN
    v_prefix := 'TSK';
  ELSE
    v_prefix := UPPER(LEFT(REGEXP_REPLACE(v_team_name, '[^A-Za-z]', '', 'g'), 3));
    IF LENGTH(v_prefix) < 3 THEN
      v_prefix := RPAD(v_prefix, 3, 'X');
    END IF;
  END IF;
  
  -- Get or create sequence
  INSERT INTO work_manager_task_sequences (team_id, last_sequence)
  VALUES (p_team_id, 0)
  ON CONFLICT (team_id) DO NOTHING;
  
  -- Increment and get next sequence
  UPDATE work_manager_task_sequences
  SET last_sequence = last_sequence + 1, updated_at = NOW()
  WHERE team_id = p_team_id
  RETURNING last_sequence INTO v_next_seq;
  
  RETURN 'TSK-' || LPAD(v_next_seq::TEXT, 4, '0');
END;
$$;


--
-- Name: generate_workstream_task_key(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_workstream_task_key(p_workstream_id uuid) RETURNS character varying
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
  v_max_existing INTEGER;
  v_task_key VARCHAR(50);
BEGIN
  -- Find the current max TSK number across ALL tasks
  SELECT COALESCE(MAX(
    CASE 
      WHEN task_key ~ '^TSK-[0-9]+$' 
      THEN CAST(SUBSTRING(task_key FROM 5) AS INTEGER)
      ELSE 0
    END
  ), 0) + 1 INTO v_max_existing
  FROM planner_tasks;

  v_task_key := 'TSK-' || v_max_existing;
  RETURN v_task_key;
END;
$_$;


--
-- Name: get_accessible_workstreams(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_accessible_workstreams(_user_id uuid) RETURNS SETOF uuid
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  -- If user can access all, return all workstream IDs
  SELECT id FROM public.planner_workstreams
  WHERE public.can_access_all_workstreams(_user_id)
  UNION
  -- Otherwise return only workstreams they are members of
  SELECT workstream_id FROM public.workstream_members
  WHERE user_id = _user_id
$$;


--
-- Name: get_active_allocations(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_active_allocations(p_project_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_allocations JSONB;
BEGIN
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', ra.id,
        'run', jsonb_build_object(
          'id', r.id,
          'run_number', r.run_number,
          'name', r.name,
          'status', r.status,
          'progress', (
            SELECT ROUND(
              (COUNT(*) FILTER (WHERE result_status IS NOT NULL)::DECIMAL / 
               NULLIF(COUNT(*), 0)) * 100, 1
            )
            FROM test_execution_results
            WHERE run_id = r.id
          )
        ),
        'environment', jsonb_build_object(
          'id', e.id,
          'name', e.name,
          'status', e.status
        ),
        'workers_allocated', ra.workers_allocated,
        'allocated_at', ra.allocated_at,
        'pool', CASE WHEN wp.id IS NOT NULL THEN jsonb_build_object(
          'id', wp.id,
          'name', wp.name
        ) ELSE NULL END
      ) ORDER BY ra.allocated_at DESC
    ),
    '[]'::jsonb
  ) INTO v_allocations
  FROM resource_allocations ra
  JOIN test_execution_runs r ON ra.run_id = r.id
  JOIN test_environments e ON ra.environment_id = e.id
  LEFT JOIN worker_pools wp ON ra.worker_pool_id = wp.id
  WHERE r.project_id = p_project_id
    AND r.status IN ('running', 'paused')
    AND ra.released_at IS NULL;

  RETURN v_allocations;
END;
$$;


--
-- Name: get_all_blockers(text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_all_blockers(p_item_type text, p_item_id uuid) RETURNS TABLE(blocker_type text, blocker_id uuid, depth integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH RECURSIVE blocker_chain AS (
        SELECT d.blocker_type, d.blocker_id, 1 as depth
        FROM work_item_dependencies d
        WHERE d.dependent_type = p_item_type 
          AND d.dependent_id = p_item_id
          AND d.is_resolved = FALSE
        
        UNION ALL
        
        SELECT d.blocker_type, d.blocker_id, bc.depth + 1
        FROM work_item_dependencies d
        JOIN blocker_chain bc ON d.dependent_type = bc.blocker_type 
                              AND d.dependent_id = bc.blocker_id
        WHERE d.is_resolved = FALSE AND bc.depth < 50
    )
    SELECT DISTINCT bc.blocker_type, bc.blocker_id, MIN(bc.depth)
    FROM blocker_chain bc
    GROUP BY bc.blocker_type, bc.blocker_id;
END;
$$;


--
-- Name: get_audit_stats(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_audit_stats(p_days integer DEFAULT 30) RETURNS TABLE(total_events bigint, creates bigint, updates bigint, deletes bigint, active_users bigint, most_active_entity text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COUNT(*)::BIGINT,
    COUNT(*) FILTER (WHERE a.action = 'create')::BIGINT,
    COUNT(*) FILTER (WHERE a.action = 'update')::BIGINT,
    COUNT(*) FILTER (WHERE a.action = 'delete')::BIGINT,
    COUNT(DISTINCT a.user_id)::BIGINT,
    (SELECT al.entity_type FROM th_audit_log al
     WHERE al.created_at >= NOW() - (p_days || ' days')::INTERVAL
     GROUP BY al.entity_type ORDER BY COUNT(*) DESC LIMIT 1)::TEXT
  FROM th_audit_log a
  WHERE a.created_at >= NOW() - (p_days || ' days')::INTERVAL;
END;
$$;


--
-- Name: get_automation_sync_status(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_automation_sync_status(p_project_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_total INTEGER;
  v_automated INTEGER;
  v_manual INTEGER;
  v_candidate INTEGER;
  v_mapped INTEGER;
  v_with_results INTEGER;
BEGIN
  -- Get counts from test_cases
  SELECT 
    COUNT(*),
    COUNT(*) FILTER (WHERE automation_status = 'automated'),
    COUNT(*) FILTER (WHERE automation_status = 'manual' OR automation_status IS NULL),
    COUNT(*) FILTER (WHERE automation_status IN ('candidate', 'in_progress', 'planned'))
  INTO v_total, v_automated, v_manual, v_candidate
  FROM test_cases
  WHERE (p_project_id IS NULL OR project_id = p_project_id);

  -- Get mapped count
  SELECT COUNT(DISTINCT test_case_id) INTO v_mapped
  FROM automation_test_mappings
  WHERE test_case_id IN (
    SELECT id FROM test_cases WHERE (p_project_id IS NULL OR project_id = p_project_id)
  );

  -- Get count with recent results
  SELECT COUNT(DISTINCT ar.test_case_id) INTO v_with_results
  FROM automation_results ar
  WHERE ar.test_case_id IS NOT NULL
    AND ar.imported_at > now() - INTERVAL '30 days'
    AND (p_project_id IS NULL OR ar.test_case_id IN (
      SELECT id FROM test_cases WHERE project_id = p_project_id
    ));

  RETURN jsonb_build_object(
    'success', true,
    'total', v_total,
    'automated', v_automated,
    'manual', v_manual,
    'candidate', v_candidate,
    'mapped', v_mapped,
    'with_recent_results', v_with_results,
    'automation_rate', CASE WHEN v_total > 0 THEN ROUND((v_automated::NUMERIC / v_total) * 100, 1) ELSE 0 END
  );
END;
$$;


--
-- Name: get_batch_delete_status(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_batch_delete_status(p_job_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_job RECORD;
  v_progress INTEGER;
BEGIN
  SELECT * INTO v_job
  FROM batch_delete_jobs
  WHERE id = p_job_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Job not found');
  END IF;

  -- Calculate progress
  IF v_job.status = 'completed' THEN
    v_progress := 100;
  ELSIF v_job.status = 'executing' AND v_job.total_records > 0 THEN
    v_progress := ROUND(((v_job.deleted_records + v_job.failed_records)::DECIMAL / v_job.total_records) * 100);
  ELSE
    v_progress := 0;
  END IF;

  RETURN jsonb_build_object(
    'job_id', v_job.id,
    'status', v_job.status,
    'progress', v_progress,
    'delete_type', v_job.delete_type,
    'total_records', v_job.total_records,
    'deleted_records', v_job.deleted_records,
    'failed_records', v_job.failed_records,
    'error_message', v_job.error_message
  );
END;
$$;


--
-- Name: get_batch_update_preview(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_batch_update_preview(p_job_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_preview JSONB;
BEGIN
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'test_case_id', tc.id,
        'case_number', tc.case_number,
        'title', tc.title,
        'changes', (
          SELECT COALESCE(jsonb_agg(
            jsonb_build_object(
              'field', c.field_name,
              'old_value', c.old_value,
              'new_value', c.new_value
            )
          ), '[]'::jsonb)
          FROM batch_update_changes c
          WHERE c.job_id = p_job_id
          AND c.test_case_id = tc.id
        )
      ) ORDER BY tc.case_number
    ),
    '[]'::jsonb
  ) INTO v_preview
  FROM test_cases tc
  WHERE tc.id IN (
    SELECT DISTINCT test_case_id
    FROM batch_update_changes
    WHERE job_id = p_job_id
  );

  RETURN v_preview;
END;
$$;


--
-- Name: get_batch_update_status(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_batch_update_status(p_job_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_job RECORD;
  v_progress INTEGER;
  v_total_changes INTEGER;
  v_applied_changes INTEGER;
BEGIN
  SELECT * INTO v_job
  FROM batch_update_jobs
  WHERE id = p_job_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Job not found');
  END IF;

  -- Calculate progress
  IF v_job.status = 'completed' THEN
    v_progress := 100;
  ELSIF v_job.status = 'executing' THEN
    SELECT COUNT(DISTINCT test_case_id) INTO v_total_changes
    FROM batch_update_changes
    WHERE job_id = p_job_id;
    
    SELECT COUNT(DISTINCT test_case_id) INTO v_applied_changes
    FROM batch_update_changes
    WHERE job_id = p_job_id AND applied = true;
    
    IF v_total_changes > 0 THEN
      v_progress := ROUND((v_applied_changes::DECIMAL / v_total_changes) * 100);
    ELSE
      v_progress := 0;
    END IF;
  ELSE
    v_progress := 0;
  END IF;

  RETURN jsonb_build_object(
    'job_id', v_job.id,
    'status', v_job.status,
    'progress', v_progress,
    'total_records', v_job.total_records,
    'updated_records', v_job.updated_records,
    'failed_records', v_job.failed_records,
    'error_message', v_job.error_message
  );
END;
$$;


--
-- Name: get_case_metrics(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_case_metrics(p_execution_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_result RECORD;
BEGIN
  SELECT
    er.id,
    er.started_at,
    er.completed_at,
    tc.id as test_case_id,
    tc.case_number,
    COALESCE(te.estimated_seconds, 300) as estimated_duration,
    COUNT(s.id) as total_steps,
    COUNT(sr.id) FILTER (WHERE sr.status IS NOT NULL AND sr.status != 'pending') as completed_steps,
    COUNT(sr.id) FILTER (WHERE sr.status = 'passed') as passed_steps,
    COUNT(sr.id) FILTER (WHERE sr.status = 'failed') as failed_steps,
    SUM(
      CASE 
        WHEN sr.completed_at IS NOT NULL THEN 
          EXTRACT(EPOCH FROM (sr.completed_at - sr.started_at))::INTEGER
        ELSE 0
      END
    ) as total_actual_time,
    SUM(COALESCE(ste.estimated_seconds, 60)) as total_estimated_time
  INTO v_result
  FROM test_execution_results er
  JOIN test_cases tc ON er.test_case_id = tc.id
  LEFT JOIN test_time_estimates te ON te.test_case_id = tc.id AND te.step_id IS NULL
  LEFT JOIN test_steps s ON s.test_case_id = tc.id
  LEFT JOIN test_execution_step_results sr ON sr.step_id = s.id AND sr.execution_id = er.id
  LEFT JOIN test_time_estimates ste ON ste.step_id = s.id
  WHERE er.id = p_execution_id
  GROUP BY er.id, tc.id, te.estimated_seconds;

  RETURN jsonb_build_object(
    'execution_id', v_result.id,
    'test_case_id', v_result.test_case_id,
    'case_number', v_result.case_number,
    'started_at', v_result.started_at,
    'completed_at', v_result.completed_at,
    'estimated_duration', v_result.estimated_duration,
    'total_steps', v_result.total_steps,
    'completed_steps', v_result.completed_steps,
    'passed_steps', v_result.passed_steps,
    'failed_steps', v_result.failed_steps,
    'total_actual_time', v_result.total_actual_time,
    'total_estimated_time', v_result.total_estimated_time,
    'completion_percentage', ROUND((v_result.completed_steps::DECIMAL / NULLIF(v_result.total_steps, 0)) * 100, 1)
  );
END;
$$;


--
-- Name: get_cc_defect_trends(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_cc_defect_trends(p_project_id uuid, p_days integer DEFAULT 7) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN (
    SELECT COALESCE(json_agg(daily_data), '[]'::json)
    FROM (
      SELECT 
        d::date as date,
        COALESCE((
          SELECT COUNT(*) FROM tm_defects def
          WHERE def.project_id = p_project_id
          AND def.created_at::date = d::date
        ), 0) as opened,
        COALESCE((
          SELECT COUNT(*) FROM tm_defects def
          WHERE def.project_id = p_project_id
          AND def.resolved_at::date = d::date
        ), 0) as closed
      FROM generate_series(
        CURRENT_DATE - (p_days || ' days')::interval,
        CURRENT_DATE,
        '1 day'::interval
      ) d
      ORDER BY d
    ) daily_data
  );
END;
$$;


--
-- Name: get_cc_team_performance(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_cc_team_performance(p_project_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN (
    SELECT COALESCE(json_agg(team_data ORDER BY tests_executed DESC), '[]'::json)
    FROM (
      SELECT 
        p.id,
        p.full_name as name,
        p.avatar_url,
        COUNT(DISTINCT tr.id) as tests_executed,
        COUNT(DISTINCT tr.id) FILTER (WHERE tr.status = 'passed') as tests_passed,
        CASE WHEN COUNT(DISTINCT tr.id) > 0 
          THEN ROUND((COUNT(DISTINCT tr.id) FILTER (WHERE tr.status = 'passed')::numeric / COUNT(DISTINCT tr.id)) * 100, 1)
          ELSE 0 
        END as pass_rate
      FROM profiles p
      JOIN tm_test_runs tr ON tr.executed_by = p.id
      JOIN tm_cycle_scope cs ON tr.cycle_scope_id = cs.id
      JOIN tm_test_cycles tc ON cs.cycle_id = tc.id
      WHERE tc.project_id = p_project_id
      AND tr.started_at >= CURRENT_DATE - INTERVAL '30 days'
      GROUP BY p.id, p.full_name, p.avatar_url
    ) team_data
  );
END;
$$;


--
-- Name: get_column_check(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_column_check() RETURNS TABLE(tbl text, col text, status text, data_type text)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  WITH expected AS (
    VALUES 
      ('kb_embeddings', 'source_type'),
      ('kb_embeddings', 'source_url'),
      ('kb_embeddings', 'metadata'),
      ('kb_embeddings', 'chunk_type'),
      ('kb_embeddings', 'content_hash'),
      ('kb_embeddings', 'embedding'),
      ('kb_embeddings', 'tags'),
      ('planner_tasks', 'title'),
      ('planner_tasks', 'description'),
      ('tm_test_cases', 'case_key'),
      ('tm_test_cases', 'title'),
      ('tm_test_cases', 'status'),
      ('planner_workstreams', 'name'),
      ('planner_workstreams', 'description'),
      ('planner_workstreams', 'is_active'),
      ('profiles', 'full_name'),
      ('profiles', 'role'),
      ('ph_issues', 'issue_key'),
      ('ph_issues', 'summary'),
      ('ph_issues', 'description_text'),
      ('incidents', 'incident_key'),
      ('incidents', 'title'),
      ('incidents', 'resolution_summary')
  )
  SELECT 
    e.column1 as tbl,
    e.column2 as col,
    CASE 
      WHEN c.column_name IS NOT NULL THEN 'exists'
      ELSE 'missing'
    END as status,
    COALESCE(c.data_type, '-') as data_type
  FROM expected e
  LEFT JOIN information_schema.columns c
    ON c.table_schema = 'public'
    AND c.table_name = e.column1
    AND c.column_name = e.column2
  ORDER BY e.column1, e.column2;
$$;


--
-- Name: get_command_center_kpis(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_command_center_kpis(p_project_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN (
    SELECT json_build_object(
      'active_releases', (
        SELECT COUNT(*) FROM releases 
        WHERE project_id = p_project_id 
        AND status NOT IN ('released', 'archived')
      ),
      'total_test_cases', (
        SELECT COALESCE(SUM(test_cases_total), 0) FROM releases 
        WHERE project_id = p_project_id 
        AND status NOT IN ('released', 'archived')
      ),
      'executed_test_cases', (
        SELECT COALESCE(SUM(test_cases_executed), 0) FROM releases 
        WHERE project_id = p_project_id 
        AND status NOT IN ('released', 'archived')
      ),
      'passed_test_cases', (
        SELECT COALESCE(SUM(test_cases_passed), 0) FROM releases 
        WHERE project_id = p_project_id 
        AND status NOT IN ('released', 'archived')
      ),
      'failed_test_cases', (
        SELECT COALESCE(SUM(test_cases_failed), 0) FROM releases 
        WHERE project_id = p_project_id 
        AND status NOT IN ('released', 'archived')
      ),
      'open_defects', (
        SELECT COALESCE(SUM(defects_open), 0) FROM releases
        WHERE project_id = p_project_id
        AND status NOT IN ('released', 'archived')
      ),
      'critical_defects', (
        SELECT COALESCE(SUM(critical_defects), 0) FROM releases
        WHERE project_id = p_project_id
        AND status NOT IN ('released', 'archived')
      ),
      'active_testers', (
        SELECT COUNT(DISTINCT tr.executed_by) FROM tm_test_runs tr
        JOIN tm_cycle_scope cs ON tr.cycle_scope_id = cs.id
        JOIN tm_test_cycles tc ON cs.cycle_id = tc.id
        WHERE tc.project_id = p_project_id
        AND tr.started_at >= CURRENT_DATE - INTERVAL '30 days'
      )
    )
  );
END;
$$;


--
-- Name: get_command_center_kpis_previous(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_command_center_kpis_previous(p_project_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  -- Returns KPIs based on snapshot data from 7 days ago
  -- Since we don't have historical snapshots, we approximate trends
  -- by comparing current values against a synthetic baseline
  RETURN (
    SELECT json_build_object(
      'active_releases', (
        SELECT COUNT(*) FROM releases 
        WHERE project_id = p_project_id 
        AND status NOT IN ('released', 'archived')
        AND created_at <= CURRENT_TIMESTAMP - INTERVAL '7 days'
      ),
      'total_test_cases', (
        SELECT COALESCE(SUM(test_cases_total), 0) FROM releases 
        WHERE project_id = p_project_id 
        AND status NOT IN ('released', 'archived')
      ),
      'executed_test_cases', (
        -- Approximate: count runs from 7-14 days ago
        SELECT COUNT(DISTINCT tr.id) FROM tm_test_runs tr
        JOIN tm_cycle_scope cs ON tr.cycle_scope_id = cs.id
        JOIN tm_test_cycles tc ON cs.cycle_id = tc.id
        WHERE tc.project_id = p_project_id
        AND tr.started_at < CURRENT_DATE - INTERVAL '7 days'
        AND tr.started_at >= CURRENT_DATE - INTERVAL '14 days'
      ),
      'passed_test_cases', (
        SELECT COUNT(DISTINCT tr.id) FROM tm_test_runs tr
        JOIN tm_cycle_scope cs ON tr.cycle_scope_id = cs.id
        JOIN tm_test_cycles tc ON cs.cycle_id = tc.id
        WHERE tc.project_id = p_project_id
        AND tr.status = 'passed'
        AND tr.started_at < CURRENT_DATE - INTERVAL '7 days'
        AND tr.started_at >= CURRENT_DATE - INTERVAL '14 days'
      ),
      'open_defects', (
        SELECT COALESCE(SUM(defects_open), 0) FROM releases
        WHERE project_id = p_project_id
        AND status NOT IN ('released', 'archived')
      ),
      'critical_defects', (
        SELECT COALESCE(SUM(critical_defects), 0) FROM releases
        WHERE project_id = p_project_id
        AND status NOT IN ('released', 'archived')
      ),
      'active_testers', (
        SELECT COUNT(DISTINCT tr.executed_by) FROM tm_test_runs tr
        JOIN tm_cycle_scope cs ON tr.cycle_scope_id = cs.id
        JOIN tm_test_cycles tc ON cs.cycle_id = tc.id
        WHERE tc.project_id = p_project_id
        AND tr.started_at < CURRENT_DATE - INTERVAL '7 days'
        AND tr.started_at >= CURRENT_DATE - INTERVAL '14 days'
      )
    )
  );
END;
$$;


--
-- Name: get_connectors(boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_connectors(p_include_inactive boolean DEFAULT false) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN jsonb_build_object(
    'success', true,
    'connectors', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', ac.id,
        'name', ac.name,
        'connector_type', ac.connector_type,
        'config', ac.config,
        'webhook_url', ac.webhook_url,
        'is_active', ac.is_active,
        'connection_status', ac.connection_status,
        'last_connected_at', ac.last_connected_at,
        'created_at', ac.created_at,
        'stats', jsonb_build_object(
          'total_imports', (SELECT COUNT(*) FROM automation_results WHERE connector_id = ac.id),
          'last_import', (SELECT MAX(imported_at) FROM automation_results WHERE connector_id = ac.id)
        )
      ) ORDER BY ac.name)
      FROM automation_connectors ac
      WHERE p_include_inactive OR ac.is_active = true
    ), '[]'::JSONB)
  );
END;
$$;


--
-- Name: get_coverage_stats(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_coverage_stats(p_project_id uuid, p_cycle_id uuid DEFAULT NULL::uuid) RETURNS TABLE(total_test_cases integer, executed_test_cases integer, execution_coverage_pct numeric, automated_test_cases integer, automation_rate_pct numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_total_cases INTEGER;
  v_executed_cases INTEGER;
  v_automated_cases INTEGER;
BEGIN
  -- Count total test cases
  SELECT COUNT(*) INTO v_total_cases
  FROM public.tm_test_cases WHERE project_id = p_project_id;
  
  -- Count executed test cases
  IF p_cycle_id IS NOT NULL THEN
    SELECT COUNT(DISTINCT test_case_id) INTO v_executed_cases
    FROM public.tm_cycle_scope
    WHERE cycle_id = p_cycle_id AND current_status NOT IN ('not_run');
  ELSE
    SELECT COUNT(DISTINCT test_case_id) INTO v_executed_cases
    FROM public.tm_cycle_scope cs
    JOIN public.tm_test_cycles tc ON cs.cycle_id = tc.id
    WHERE tc.project_id = p_project_id AND cs.current_status NOT IN ('not_run');
  END IF;
  
  -- Count automated test cases
  SELECT COUNT(*) INTO v_automated_cases
  FROM public.tm_test_cases
  WHERE project_id = p_project_id AND automation_status = 'automated';
  
  RETURN QUERY SELECT
    COALESCE(v_total_cases, 0),
    COALESCE(v_executed_cases, 0),
    CASE WHEN v_total_cases > 0 
      THEN ROUND((v_executed_cases::NUMERIC / v_total_cases::NUMERIC) * 100, 1)
      ELSE 0 END,
    COALESCE(v_automated_cases, 0),
    CASE WHEN v_total_cases > 0
      THEN ROUND((v_automated_cases::NUMERIC / v_total_cases::NUMERIC) * 100, 1)
      ELSE 0 END;
END;
$$;


--
-- Name: get_cycle_daily_executions(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_cycle_daily_executions(p_cycle_id uuid) RETURNS TABLE(execution_date date, passed bigint, failed bigint, blocked bigint, skipped bigint, total bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    DATE(ctc.executed_at),
    COUNT(*) FILTER (WHERE ctc.execution_status = 'passed')::BIGINT,
    COUNT(*) FILTER (WHERE ctc.execution_status = 'failed')::BIGINT,
    COUNT(*) FILTER (WHERE ctc.execution_status = 'blocked')::BIGINT,
    COUNT(*) FILTER (WHERE ctc.execution_status = 'skipped')::BIGINT,
    COUNT(*)::BIGINT
  FROM th_cycle_test_cases ctc
  WHERE ctc.cycle_id = p_cycle_id
    AND ctc.executed_at IS NOT NULL
  GROUP BY DATE(ctc.executed_at)
  ORDER BY DATE(ctc.executed_at) ASC;
END;
$$;


--
-- Name: get_cycle_failure_reasons(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_cycle_failure_reasons(p_cycle_id uuid) RETURNS TABLE(failure_reason text, count bigint)
    LANGUAGE sql STABLE
    AS $$
  SELECT
    COALESCE(ctc.failure_reason::text, 'unspecified') AS failure_reason,
    COUNT(*) AS count
  FROM th_cycle_test_cases ctc
  WHERE ctc.cycle_id = p_cycle_id
    AND ctc.execution_status = 'failed'
  GROUP BY COALESCE(ctc.failure_reason::text, 'unspecified')
  ORDER BY count DESC;
$$;


--
-- Name: get_cycle_pass_rates(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_cycle_pass_rates(p_limit integer DEFAULT 10) RETURNS TABLE(cycle_id uuid, cycle_key character varying, cycle_name character varying, status character varying, created_at timestamp with time zone, total_cases bigint, executed bigint, pass_rate numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    c.id,
    c.cycle_key,
    c.name,
    c.status,
    c.created_at,
    c.total_cases::BIGINT,
    (c.total_cases - c.not_run_count)::BIGINT,
    CASE 
      WHEN (c.total_cases - c.not_run_count) > 0 
      THEN ROUND(c.passed_count::NUMERIC * 100 / (c.total_cases - c.not_run_count), 1)
      ELSE 0
    END
  FROM th_test_cycles c
  WHERE c.total_cases > 0
  ORDER BY c.created_at DESC
  LIMIT p_limit;
END;
$$;


--
-- Name: get_cycle_progress(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_cycle_progress(p_cycle_id uuid) RETURNS json
    LANGUAGE plpgsql
    AS $$
DECLARE
  result JSON;
BEGIN
  SELECT json_build_object(
    'total', COUNT(*),
    'passed', COUNT(*) FILTER (WHERE status = 'passed'),
    'failed', COUNT(*) FILTER (WHERE status = 'failed'),
    'blocked', COUNT(*) FILTER (WHERE status = 'blocked'),
    'not_run', COUNT(*) FILTER (WHERE status = 'not_run'),
    'in_progress', COUNT(*) FILTER (WHERE status = 'in_progress'),
    'skipped', COUNT(*) FILTER (WHERE status = 'skipped')
  ) INTO result
  FROM test_runs
  WHERE test_cycle_id = p_cycle_id;
  
  RETURN result;
END;
$$;


--
-- Name: get_cycle_stats_by_priority(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_cycle_stats_by_priority(p_cycle_id uuid) RETURNS TABLE(priority text, total bigint, passed bigint, failed bigint, blocked bigint, skipped bigint, not_run bigint, executed bigint, pass_rate numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COALESCE(tc.priority, 'medium'),
    COUNT(*)::BIGINT,
    COUNT(*) FILTER (WHERE ctc.execution_status = 'passed')::BIGINT,
    COUNT(*) FILTER (WHERE ctc.execution_status = 'failed')::BIGINT,
    COUNT(*) FILTER (WHERE ctc.execution_status = 'blocked')::BIGINT,
    COUNT(*) FILTER (WHERE ctc.execution_status = 'skipped')::BIGINT,
    COUNT(*) FILTER (WHERE ctc.execution_status = 'not_run')::BIGINT,
    COUNT(*) FILTER (WHERE ctc.execution_status != 'not_run')::BIGINT,
    CASE 
      WHEN COUNT(*) FILTER (WHERE ctc.execution_status != 'not_run') > 0 
      THEN ROUND(
        COUNT(*) FILTER (WHERE ctc.execution_status = 'passed')::NUMERIC * 100 /
        COUNT(*) FILTER (WHERE ctc.execution_status != 'not_run'),
        1
      )
      ELSE 0
    END
  FROM th_cycle_test_cases ctc
  JOIN th_test_cases tc ON tc.id = ctc.test_case_id
  WHERE ctc.cycle_id = p_cycle_id
  GROUP BY tc.priority
  ORDER BY 
    CASE COALESCE(tc.priority, 'medium')
      WHEN 'critical' THEN 1
      WHEN 'high' THEN 2
      WHEN 'medium' THEN 3
      WHEN 'low' THEN 4
      ELSE 5
    END;
END;
$$;


--
-- Name: get_cycle_stats_by_tester(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_cycle_stats_by_tester(p_cycle_id uuid) RETURNS TABLE(tester_id uuid, tester_name text, total_assigned bigint, passed bigint, failed bigint, blocked bigint, skipped bigint, not_run bigint, executed bigint, pass_rate numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    p.id,
    COALESCE(p.full_name, 'Unassigned'),
    COUNT(*)::BIGINT,
    COUNT(*) FILTER (WHERE ctc.execution_status = 'passed')::BIGINT,
    COUNT(*) FILTER (WHERE ctc.execution_status = 'failed')::BIGINT,
    COUNT(*) FILTER (WHERE ctc.execution_status = 'blocked')::BIGINT,
    COUNT(*) FILTER (WHERE ctc.execution_status = 'skipped')::BIGINT,
    COUNT(*) FILTER (WHERE ctc.execution_status = 'not_run')::BIGINT,
    COUNT(*) FILTER (WHERE ctc.execution_status != 'not_run')::BIGINT,
    CASE 
      WHEN COUNT(*) FILTER (WHERE ctc.execution_status != 'not_run') > 0 
      THEN ROUND(
        COUNT(*) FILTER (WHERE ctc.execution_status = 'passed')::NUMERIC * 100 /
        COUNT(*) FILTER (WHERE ctc.execution_status != 'not_run'),
        1
      )
      ELSE 0
    END
  FROM th_cycle_test_cases ctc
  LEFT JOIN profiles p ON p.id = ctc.assigned_to
  WHERE ctc.cycle_id = p_cycle_id
  GROUP BY p.id, p.full_name
  ORDER BY COUNT(*) DESC;
END;
$$;


--
-- Name: get_dashboard_stats(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_dashboard_stats() RETURNS TABLE(total_test_cases bigint, total_cycles bigint, active_cycles bigint, completed_cycles bigint, executed_tests bigint, passed_tests bigint, failed_tests bigint, blocked_tests bigint, skipped_tests bigint, not_run_tests bigint, pass_rate numeric, automation_coverage numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    (SELECT COUNT(*) FROM tm_test_cases)::BIGINT,
    (SELECT COUNT(*) FROM tm_test_cycles)::BIGINT,
    (SELECT COUNT(*) FROM tm_test_cycles WHERE status = 'active')::BIGINT,
    (SELECT COUNT(*) FROM tm_test_cycles WHERE status = 'completed')::BIGINT,
    (SELECT COUNT(*) FROM tm_cycle_scope WHERE current_status IS DISTINCT FROM 'not_run')::BIGINT,
    (SELECT COUNT(*) FROM tm_cycle_scope WHERE current_status = 'passed')::BIGINT,
    (SELECT COUNT(*) FROM tm_cycle_scope WHERE current_status = 'failed')::BIGINT,
    (SELECT COUNT(*) FROM tm_cycle_scope WHERE current_status = 'blocked')::BIGINT,
    (SELECT COUNT(*) FROM tm_cycle_scope WHERE current_status = 'skipped')::BIGINT,
    (SELECT COUNT(*) FROM tm_cycle_scope WHERE current_status = 'not_run')::BIGINT,
    COALESCE(
      ROUND(
        (SELECT COUNT(*) FROM tm_cycle_scope WHERE current_status = 'passed')::NUMERIC * 100 /
        NULLIF((SELECT COUNT(*) FROM tm_cycle_scope WHERE current_status IN ('passed','failed','blocked')), 0),
        1
      ),
      0
    )::NUMERIC,
    COALESCE(
      ROUND(
        (SELECT COUNT(*) FROM tm_test_cases WHERE automation_status = 'automated')::NUMERIC * 100 /
        NULLIF((SELECT COUNT(*) FROM tm_test_cases), 0),
        1
      ),
      0
    )::NUMERIC;
END;
$$;


--
-- Name: get_dashboard_stats(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_dashboard_stats(p_project_id uuid) RETURNS json
    LANGUAGE plpgsql
    AS $$
DECLARE
  result JSON;
BEGIN
  SELECT json_build_object(
    'total_test_cases', (SELECT COUNT(*) FROM test_cases WHERE project_id = p_project_id),
    'draft_count', (SELECT COUNT(*) FROM test_cases WHERE project_id = p_project_id AND status = 'draft'),
    'ready_count', (SELECT COUNT(*) FROM test_cases WHERE project_id = p_project_id AND status = 'ready'),
    'approved_count', (SELECT COUNT(*) FROM test_cases WHERE project_id = p_project_id AND status = 'approved'),
    'total_cycles', (SELECT COUNT(*) FROM test_cycles WHERE project_id = p_project_id),
    'active_cycles', (SELECT COUNT(*) FROM test_cycles WHERE project_id = p_project_id AND status = 'in_progress'),
    'total_runs', (SELECT COUNT(*) FROM test_runs tr JOIN test_cycles tc ON tr.test_cycle_id = tc.id WHERE tc.project_id = p_project_id),
    'passed_runs', (SELECT COUNT(*) FROM test_runs tr JOIN test_cycles tc ON tr.test_cycle_id = tc.id WHERE tc.project_id = p_project_id AND tr.status = 'passed'),
    'failed_runs', (SELECT COUNT(*) FROM test_runs tr JOIN test_cycles tc ON tr.test_cycle_id = tc.id WHERE tc.project_id = p_project_id AND tr.status = 'failed'),
    'blocked_runs', (SELECT COUNT(*) FROM test_runs tr JOIN test_cycles tc ON tr.test_cycle_id = tc.id WHERE tc.project_id = p_project_id AND tr.status = 'blocked'),
    'not_run', (SELECT COUNT(*) FROM test_runs tr JOIN test_cycles tc ON tr.test_cycle_id = tc.id WHERE tc.project_id = p_project_id AND tr.status = 'not_run'),
    'open_defects', (SELECT COUNT(*) FROM defects WHERE project_id = p_project_id AND (status IS NULL OR status IN ('open', 'in_progress', 'reopened'))),
    'critical_defects', (SELECT COUNT(*) FROM defects WHERE project_id = p_project_id AND severity IN ('blocker', 'critical') AND (status IS NULL OR status NOT IN ('closed', 'verified')))
  ) INTO result;
  
  RETURN result;
END;
$$;


--
-- Name: get_defect_linked_tests(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_defect_linked_tests(p_defect_id uuid) RETURNS TABLE(link_id uuid, link_type text, test_case_id uuid, case_key text, title text, cycle_key text, execution_status text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    dl.id as link_id,
    dl.link_type::TEXT,
    tc.id as test_case_id,
    tc.case_key::TEXT,
    tc.title::TEXT,
    cyc.cycle_key::TEXT,
    ctc.execution_status::TEXT
  FROM th_defect_links dl
  LEFT JOIN th_cycle_test_cases ctc ON dl.link_type = 'cycle_test_case' AND dl.linked_id = ctc.id
  LEFT JOIN th_test_cases tc ON 
    (dl.link_type = 'test_case' AND dl.linked_id = tc.id) OR
    (dl.link_type = 'cycle_test_case' AND ctc.test_case_id = tc.id)
  LEFT JOIN th_test_cycles cyc ON ctc.cycle_id = cyc.id
  WHERE dl.defect_id = p_defect_id
  ORDER BY dl.created_at DESC;
END;
$$;


--
-- Name: get_defect_metrics(timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_defect_metrics(p_start_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_end_date timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  result jsonb;
BEGIN
  SELECT jsonb_build_object(
    'total', COALESCE(COUNT(*), 0),
    'open', COALESCE(COUNT(*) FILTER (WHERE d.workflow_status NOT IN ('closed', 'resolved', 'verified')), 0),
    'closed', COALESCE(COUNT(*) FILTER (WHERE d.workflow_status IN ('closed', 'resolved', 'verified')), 0),
    'critical', COALESCE(COUNT(*) FILTER (WHERE d.severity = 'critical'), 0),
    'high', COALESCE(COUNT(*) FILTER (WHERE d.severity = 'high'), 0),
    'medium', COALESCE(COUNT(*) FILTER (WHERE d.severity = 'medium'), 0),
    'low', COALESCE(COUNT(*) FILTER (WHERE d.severity = 'low'), 0),
    'new_this_period', COALESCE(COUNT(*) FILTER (WHERE d.created_at >= COALESCE(p_start_date, now() - interval '30 days')), 0),
    'closed_this_period', COALESCE(COUNT(*) FILTER (WHERE d.resolved_at >= COALESCE(p_start_date, now() - interval '30 days') AND d.workflow_status IN ('closed', 'resolved', 'verified')), 0)
  ) INTO result
  FROM defects d
  WHERE (p_start_date IS NULL OR d.created_at >= p_start_date)
     OR d.workflow_status NOT IN ('closed', 'resolved', 'verified');

  RETURN COALESCE(result, '{"total":0,"open":0,"closed":0,"critical":0,"high":0,"medium":0,"low":0,"new_this_period":0,"closed_this_period":0}'::jsonb);
END;
$$;


--
-- Name: get_defect_stats(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_defect_stats(p_project_id uuid) RETURNS json
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT json_build_object(
    'total',       COUNT(*),
    'open',        COUNT(*) FILTER (WHERE status::text = 'open'),
    'in_progress', COUNT(*) FILTER (WHERE status::text = 'in_progress'),
    'resolved',    COUNT(*) FILTER (WHERE status::text = 'resolved'),
    'verified',    0,
    'closed',      COUNT(*) FILTER (WHERE status::text = 'closed'),
    'critical',    COUNT(*) FILTER (WHERE severity::text = 'critical'),
    'high',        COUNT(*) FILTER (WHERE severity::text = 'major'),
    'medium',      COUNT(*) FILTER (WHERE severity::text = 'minor'),
    'low',         COUNT(*) FILTER (WHERE severity::text = 'trivial'),
    'unassigned',  COUNT(*) FILTER (WHERE assignee_id IS NULL),
    'overdue',     0
  )
  FROM tm_defects
  WHERE project_id = p_project_id;
$$;


--
-- Name: get_delete_dependencies(jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_delete_dependencies(p_test_case_ids jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_run_count INTEGER := 0;
  v_step_count INTEGER := 0;
  v_defect_count INTEGER := 0;
BEGIN
  -- Count test runs (if test_execution_results exists)
  BEGIN
    SELECT COUNT(*) INTO v_run_count
    FROM test_execution_results
    WHERE test_case_id = ANY(
      SELECT (jsonb_array_elements_text(p_test_case_ids))::UUID
    );
  EXCEPTION WHEN undefined_table THEN
    v_run_count := 0;
  END;

  -- Count test steps
  BEGIN
    SELECT COUNT(*) INTO v_step_count
    FROM test_steps
    WHERE test_case_id = ANY(
      SELECT (jsonb_array_elements_text(p_test_case_ids))::UUID
    );
  EXCEPTION WHEN undefined_table THEN
    v_step_count := 0;
  END;

  -- Count linked defects (if table exists)
  BEGIN
    SELECT COUNT(*) INTO v_defect_count
    FROM test_case_defects
    WHERE test_case_id = ANY(
      SELECT (jsonb_array_elements_text(p_test_case_ids))::UUID
    );
  EXCEPTION WHEN undefined_table THEN
    v_defect_count := 0;
  END;

  RETURN jsonb_build_object(
    'test_runs', v_run_count,
    'test_steps', v_step_count,
    'linked_defects', v_defect_count,
    'total_affected', v_run_count + v_step_count + v_defect_count
  );
END;
$$;


--
-- Name: get_deleted_items(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_deleted_items(p_project_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN (
    SELECT COALESCE(jsonb_agg(
      jsonb_build_object(
        'id', dil.id,
        'test_case_id', dil.test_case_id,
        'case_number', dil.test_case_data->>'case_number',
        'title', dil.test_case_data->>'title',
        'deleted_at', dil.deleted_at,
        'expires_at', dil.expires_at,
        'days_remaining', EXTRACT(DAY FROM (dil.expires_at - NOW()))::INTEGER
      )
    ), '[]'::jsonb)
    FROM deleted_items_log dil
    JOIN batch_delete_jobs bdj ON dil.job_id = bdj.id
    WHERE bdj.project_id = p_project_id
      AND dil.delete_type = 'soft'
      AND dil.restored_at IS NULL
      AND dil.expires_at > NOW()
    ORDER BY dil.deleted_at DESC
  );
END;
$$;


--
-- Name: get_dependency_counts(text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_dependency_counts(p_item_type text, p_item_id uuid) RETURNS TABLE(blocks_count integer, blocked_by_count integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        (SELECT COUNT(*)::INTEGER FROM work_item_dependencies 
         WHERE blocker_type = p_item_type AND blocker_id = p_item_id AND is_resolved = FALSE),
        (SELECT COUNT(*)::INTEGER FROM work_item_dependencies 
         WHERE dependent_type = p_item_type AND dependent_id = p_item_id AND is_resolved = FALSE);
END;
$$;


--
-- Name: get_entity_audit_history(character varying, uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_entity_audit_history(p_entity_type character varying, p_entity_id uuid, p_limit integer DEFAULT 50) RETURNS TABLE(id uuid, action character varying, user_name text, changed_fields text[], old_values jsonb, new_values jsonb, notes text, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    a.id,
    a.action,
    a.user_name,
    a.changed_fields,
    a.old_values,
    a.new_values,
    a.notes,
    a.created_at
