-- Name: get_environment_summary(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_environment_summary() RETURNS TABLE(total_environments bigint, active_count bigint, maintenance_count bigint, healthy_count bigint, degraded_count bigint, down_count bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COUNT(*)::BIGINT,
    COUNT(*) FILTER (WHERE e.status = 'active')::BIGINT,
    COUNT(*) FILTER (WHERE e.status = 'maintenance')::BIGINT,
    COUNT(*) FILTER (WHERE e.health_status = 'healthy')::BIGINT,
    COUNT(*) FILTER (WHERE e.health_status = 'degraded')::BIGINT,
    COUNT(*) FILTER (WHERE e.health_status = 'down')::BIGINT
  FROM th_environments e
  WHERE e.status != 'deprecated';
END;
$$;


--
-- Name: get_environments(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_environments(p_project_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_environments JSONB;
BEGIN
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', e.id,
        'name', e.name,
        'description', e.description,
        'url', e.url,
        'status', e.status,
        'capacity', e.capacity,
        'allocated', e.allocated,
        'available', e.capacity - e.allocated,
        'utilization_percentage', ROUND((e.allocated::DECIMAL / NULLIF(e.capacity, 0)) * 100, 1),
        'active_runs', (
          SELECT COUNT(*)
          FROM resource_allocations ra
          JOIN test_execution_runs r ON ra.run_id = r.id
          WHERE ra.environment_id = e.id
            AND r.status = 'running'
            AND ra.released_at IS NULL
        ),
        'metadata', e.metadata
      ) ORDER BY e.name
    ),
    '[]'::jsonb
  ) INTO v_environments
  FROM test_environments e
  WHERE e.project_id = p_project_id AND e.deleted_at IS NULL;

  RETURN v_environments;
END;
$$;


--
-- Name: get_execution_run(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_execution_run(p_run_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_run RECORD;
  v_progress RECORD;
  v_testers JSONB;
BEGIN
  -- Get run with project and creator info
  SELECT 
    r.*,
    p.name as project_name,
    u.full_name as creator_name,
    u.avatar_url as creator_avatar
  INTO v_run
  FROM test_execution_runs r
  LEFT JOIN projects p ON r.project_id = p.id
  LEFT JOIN profiles u ON r.created_by = u.id
  WHERE r.id = p_run_id AND r.deleted_at IS NULL;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Run not found');
  END IF;

  -- Calculate progress
  SELECT 
    COUNT(*) as total_cases,
    COUNT(*) FILTER (WHERE result_status = 'passed') as passed,
    COUNT(*) FILTER (WHERE result_status = 'failed') as failed,
    COUNT(*) FILTER (WHERE result_status = 'blocked') as blocked,
    COUNT(*) FILTER (WHERE result_status = 'skipped') as skipped,
    COUNT(*) FILTER (WHERE result_status = 'in_progress') as in_progress,
    COUNT(*) FILTER (WHERE result_status IS NULL) as not_run
  INTO v_progress
  FROM test_execution_results
  WHERE run_id = p_run_id;

  -- Get assigned testers with details
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', u.id,
        'name', u.full_name,
        'avatar', u.avatar_url
      )
    ),
    '[]'::jsonb
  ) INTO v_testers
  FROM profiles u
  WHERE u.id = ANY(v_run.assigned_testers);

  RETURN jsonb_build_object(
    'id', v_run.id,
    'project_id', v_run.project_id,
    'project_name', v_run.project_name,
    'run_number', v_run.run_number,
    'name', COALESCE(v_run.name, v_run.run_name),
    'description', v_run.description,
    'environment', COALESCE(v_run.environment, 'staging'),
    'configuration', COALESCE(v_run.configuration, '{}'::jsonb),
    'status', COALESCE(v_run.status, 'draft'),
    'scheduled_start', v_run.scheduled_start,
    'started_at', v_run.started_at,
    'completed_at', v_run.completed_at,
    'created_by', jsonb_build_object(
      'id', v_run.created_by,
      'name', v_run.creator_name,
      'avatar', v_run.creator_avatar
    ),
    'assigned_testers', v_testers,
    'progress', jsonb_build_object(
      'total_cases', COALESCE(v_progress.total_cases, 0),
      'passed', COALESCE(v_progress.passed, 0),
      'failed', COALESCE(v_progress.failed, 0),
      'blocked', COALESCE(v_progress.blocked, 0),
      'skipped', COALESCE(v_progress.skipped, 0),
      'in_progress', COALESCE(v_progress.in_progress, 0),
      'not_run', COALESCE(v_progress.not_run, 0),
      'completion_percentage', CASE 
        WHEN COALESCE(v_progress.total_cases, 0) > 0 
        THEN ROUND(((v_progress.total_cases - v_progress.not_run)::NUMERIC / v_progress.total_cases) * 100, 1)
        ELSE 0 
      END,
      'pass_rate', CASE 
        WHEN (COALESCE(v_progress.passed, 0) + COALESCE(v_progress.failed, 0) + COALESCE(v_progress.blocked, 0) + COALESCE(v_progress.skipped, 0)) > 0
        THEN ROUND((v_progress.passed::NUMERIC / (v_progress.passed + v_progress.failed + v_progress.blocked + v_progress.skipped)) * 100, 1)
        ELSE 0 
      END
    ),
    'created_at', v_run.created_at,
    'updated_at', v_run.updated_at
  );
END;
$$;


--
-- Name: get_execution_summary(uuid, date, date, uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_execution_summary(p_project_id uuid, p_start_date date, p_end_date date, p_cycle_ids uuid[] DEFAULT NULL::uuid[]) RETURNS TABLE(total_executions bigint, passed_count bigint, failed_count bigint, blocked_count bigint, skipped_count bigint, pass_rate numeric, total_duration_seconds bigint, defects_found bigint, unique_cases_executed bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    COALESCE(SUM(des.total_executions), 0)::BIGINT,
    COALESCE(SUM(des.passed_count), 0)::BIGINT,
    COALESCE(SUM(des.failed_count), 0)::BIGINT,
    COALESCE(SUM(des.blocked_count), 0)::BIGINT,
    COALESCE(SUM(des.skipped_count), 0)::BIGINT,
    CASE 
      WHEN SUM(des.total_executions) > 0 THEN
        ROUND((SUM(des.passed_count)::NUMERIC / SUM(des.total_executions)::NUMERIC) * 100, 2)
      ELSE 0
    END,
    COALESCE(SUM(des.total_duration_seconds), 0)::BIGINT,
    COALESCE(SUM(des.defects_found), 0)::BIGINT,
    COALESCE(SUM(des.unique_cases_executed), 0)::BIGINT
  FROM public.daily_execution_stats des
  WHERE des.project_id = p_project_id
    AND des.stat_date BETWEEN p_start_date AND p_end_date
    AND (p_cycle_ids IS NULL OR des.cycle_id = ANY(p_cycle_ids));
END;
$$;


--
-- Name: get_execution_trend(uuid, date, date, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_execution_trend(p_project_id uuid, p_start_date date, p_end_date date, p_grouping character varying DEFAULT 'day'::character varying) RETURNS TABLE(period_start date, total_executions bigint, passed_count bigint, failed_count bigint, blocked_count bigint, skipped_count bigint, pass_rate numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    CASE 
      WHEN p_grouping = 'day' THEN des.stat_date
      WHEN p_grouping = 'week' THEN DATE_TRUNC('week', des.stat_date)::DATE
      WHEN p_grouping = 'month' THEN DATE_TRUNC('month', des.stat_date)::DATE
      ELSE des.stat_date
    END as period_start,
    SUM(des.total_executions)::BIGINT,
    SUM(des.passed_count)::BIGINT,
    SUM(des.failed_count)::BIGINT,
    SUM(des.blocked_count)::BIGINT,
    SUM(des.skipped_count)::BIGINT,
    CASE 
      WHEN SUM(des.total_executions) > 0 THEN
        ROUND((SUM(des.passed_count)::NUMERIC / SUM(des.total_executions)::NUMERIC) * 100, 2)
      ELSE 0
    END as pass_rate
  FROM public.daily_execution_stats des
  WHERE des.project_id = p_project_id
    AND des.stat_date BETWEEN p_start_date AND p_end_date
  GROUP BY 1
  ORDER BY 1;
END;
$$;


--
-- Name: get_export_data(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_export_data(p_job_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_job RECORD;
  v_data JSONB;
BEGIN
  -- Get job
  SELECT * INTO v_job
  FROM export_jobs
  WHERE id = p_job_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Export job not found');
  END IF;

  -- Update status
  UPDATE export_jobs SET
    status = 'processing',
    started_at = NOW()
  WHERE id = p_job_id;

  -- Get test case data
  IF jsonb_array_length(COALESCE(v_job.test_case_ids, '[]'::jsonb)) > 0 THEN
    SELECT COALESCE(jsonb_agg(row_to_json(tc)), '[]'::jsonb) INTO v_data
    FROM test_cases tc
    WHERE tc.project_id = v_job.project_id 
      AND tc.deleted_at IS NULL
      AND tc.id IN (SELECT jsonb_array_elements_text(v_job.test_case_ids)::UUID);
  ELSE
    SELECT COALESCE(jsonb_agg(row_to_json(tc)), '[]'::jsonb) INTO v_data
    FROM test_cases tc
    WHERE tc.project_id = v_job.project_id 
      AND tc.deleted_at IS NULL;
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'data', v_data,
    'fields', v_job.fields,
    'format', v_job.format
  );
END;
$$;


--
-- Name: get_export_history(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_export_history(p_project_id uuid, p_limit integer DEFAULT 20) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_exports JSONB;
  v_actor UUID := auth.uid();
BEGIN
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', id,
        'format', format,
        'status', status,
        'file_name', file_name,
        'file_size', file_size,
        'file_url', file_url,
        'total_records', total_records,
        'created_at', created_at,
        'completed_at', completed_at,
        'expires_at', expires_at,
        'is_expired', (expires_at < NOW())
      ) ORDER BY created_at DESC
    ),
    '[]'::jsonb
  ) INTO v_exports
  FROM export_jobs
  WHERE project_id = p_project_id
    AND created_by = v_actor
  LIMIT p_limit;

  RETURN v_exports;
END;
$$;


--
-- Name: get_export_status(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_export_status(p_job_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_job RECORD;
  v_progress INTEGER;
BEGIN
  SELECT * INTO v_job
  FROM export_jobs
  WHERE id = p_job_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Export job not found');
  END IF;

  -- Calculate progress
  IF v_job.status = 'completed' THEN
    v_progress := 100;
  ELSIF v_job.status = 'processing' AND v_job.total_records > 0 THEN
    v_progress := ROUND((v_job.exported_records::DECIMAL / v_job.total_records) * 100);
  ELSE
    v_progress := 0;
  END IF;

  RETURN jsonb_build_object(
    'job_id', v_job.id,
    'status', v_job.status,
    'progress', v_progress,
    'format', v_job.format,
    'total_records', v_job.total_records,
    'exported_records', v_job.exported_records,
    'file_name', v_job.file_name,
    'file_size', v_job.file_size,
    'file_url', v_job.file_url,
    'error_message', v_job.error_message
  );
END;
$$;


--
-- Name: get_folder_descendants(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_folder_descendants(p_folder_id uuid) RETURNS uuid[]
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  result UUID[];
BEGIN
  WITH RECURSIVE descendants AS (
    SELECT id FROM test_folders WHERE id = p_folder_id
    UNION ALL
    SELECT f.id FROM test_folders f
    INNER JOIN descendants d ON f.parent_id = d.id
  )
  SELECT ARRAY_AGG(id) INTO result FROM descendants;
  
  RETURN COALESCE(result, ARRAY[]::UUID[]);
END;
$$;


--
-- Name: get_folder_tree(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_folder_tree(p_project_id uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN (
    WITH RECURSIVE folder_tree AS (
      SELECT 
        f.id,
        f.name,
        f.description,
        f.parent_id,
        f.sort_order,
        f.created_by,
        f.created_at,
        0 as depth,
        ARRAY[f.sort_order] as sort_path
      FROM test_folders f
      WHERE f.project_id = p_project_id
      AND f.parent_id IS NULL
      
      UNION ALL
      
      SELECT 
        f.id,
        f.name,
        f.description,
        f.parent_id,
        f.sort_order,
        f.created_by,
        f.created_at,
        ft.depth + 1,
        ft.sort_path || ARRAY[f.sort_order]
      FROM test_folders f
      INNER JOIN folder_tree ft ON f.parent_id = ft.id
      WHERE ft.depth < 10
    ),
    folder_counts AS (
      SELECT 
        folder_id,
        COUNT(*)::INTEGER as test_case_count
      FROM test_cases
      WHERE project_id = p_project_id
      AND folder_id IS NOT NULL
      GROUP BY folder_id
    )
    SELECT COALESCE(
      jsonb_agg(
        jsonb_build_object(
          'id', ft.id,
          'name', ft.name,
          'description', ft.description,
          'parentId', ft.parent_id,
          'sortOrder', ft.sort_order,
          'depth', ft.depth,
          'count', COALESCE(fc.test_case_count, 0),
          'createdBy', ft.created_by,
          'createdAt', ft.created_at
        ) ORDER BY ft.sort_path, ft.name
      ),
      '[]'::jsonb
    )
    FROM folder_tree ft
    LEFT JOIN folder_counts fc ON fc.folder_id = ft.id
  );
END;
$$;


--
-- Name: get_import_export_stats(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_import_export_stats() RETURNS TABLE(total_imports bigint, successful_imports bigint, failed_imports bigint, total_exports bigint, successful_exports bigint, records_imported bigint, records_exported bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    (SELECT COUNT(*) FROM th_import_jobs)::BIGINT,
    (SELECT COUNT(*) FROM th_import_jobs WHERE status = 'completed')::BIGINT,
    (SELECT COUNT(*) FROM th_import_jobs WHERE status = 'failed')::BIGINT,
    (SELECT COUNT(*) FROM th_export_jobs)::BIGINT,
    (SELECT COUNT(*) FROM th_export_jobs WHERE status = 'completed')::BIGINT,
    (SELECT COALESCE(SUM(success_count), 0) FROM th_import_jobs WHERE status = 'completed')::BIGINT,
    (SELECT COALESCE(SUM(total_items), 0) FROM th_export_jobs WHERE status = 'completed')::BIGINT;
END;
$$;


--
-- Name: get_import_history(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_import_history(p_connector_id uuid, p_limit integer DEFAULT 20) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN jsonb_build_object(
    'success', true,
    'imports', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', aij.id,
        'status', aij.status,
        'source_file_name', aij.source_file_name,
        'source_format', aij.source_format,
        'total_count', aij.total_count,
        'imported_count', aij.imported_count,
        'mapped_count', aij.mapped_count,
        'error_message', aij.error_message,
