--
-- Name: get_kb_chunks_summary(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_kb_chunks_summary() RETURNS TABLE(source_table text, chunk_type_val text, chunk_count bigint, unique_urls bigint)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT 
    COALESCE(metadata->>'table', source_type) as source_table,
    COALESCE(chunk_type, '(null)') as chunk_type_val,
    count(*) as chunk_count,
    count(DISTINCT source_url) as unique_urls
  FROM kb_embeddings
  GROUP BY metadata->>'table', source_type, chunk_type
  ORDER BY count(*) DESC;
$$;


--
-- Name: get_kb_sample_keys(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_kb_sample_keys() RETURNS TABLE(source_table text, source_key text, chunks bigint, preview text)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT 
    COALESCE(metadata->>'table', source_type) as source_table,
    COALESCE(source_url, '(none)') as source_key,
    count(*) as chunks,
    COALESCE(
      (metadata->>'title')::text,
      left(content, 100)
    ) as preview
  FROM kb_embeddings
  GROUP BY metadata->>'table', source_type, source_url, metadata->>'title', content
  ORDER BY count(*) DESC
  LIMIT 30;
$$;


--
-- Name: get_kb_source_type_check(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_kb_source_type_check() RETURNS TABLE(constraint_name text, allowed_values text)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT 
    conname as constraint_name,
    pg_get_constraintdef(oid) as allowed_values
  FROM pg_constraint 
  WHERE conrelid = 'public.kb_embeddings'::regclass 
  AND contype = 'c';
$$;


--
-- Name: get_linked_defects_for_step(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_linked_defects_for_step(p_step_result_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_defects JSONB;
BEGIN
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', d.id,
        'key', d.key,
        'title', d.title,
        'status', d.status,
        'severity', d.severity,
        'assignee', CASE 
          WHEN d.assigned_to IS NOT NULL THEN jsonb_build_object(
            'id', p.id,
            'name', p.full_name,
            'avatar', p.avatar_url
          )
          ELSE NULL
        END,
        'link_type', l.link_type,
        'linked_at', l.created_at,
        'created_at', d.created_at
      ) ORDER BY l.created_at DESC
    ),
    '[]'::jsonb
  ) INTO v_defects
  FROM tm_defect_links l
  JOIN tm_defects d ON l.defect_id = d.id
  LEFT JOIN profiles p ON d.assigned_to = p.id
  WHERE l.step_result_id = p_step_result_id;

  RETURN jsonb_build_object(
    'defects', v_defects,
    'count', jsonb_array_length(v_defects)
  );
END;
$$;


--
-- Name: get_module_groups(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_module_groups() RETURNS TABLE(group_name text, module_count bigint)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
  SELECT anm.group_name::TEXT, COUNT(*)::BIGINT
  FROM admin_nav_modules anm
  WHERE anm.is_active = true
  GROUP BY anm.group_name
  ORDER BY MIN(anm.sort_order);
END;
$$;


--
-- Name: get_module_matrix(text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_module_matrix(p_role_code text DEFAULT NULL::text, p_group_name text DEFAULT NULL::text, p_access_level text DEFAULT NULL::text, p_search text DEFAULT NULL::text) RETURNS TABLE(module_key text, module_name text, group_name text, sort_order integer, role_code text, role_name text, is_system_role boolean, access_level text)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    anm.module_key::TEXT,
    anm.name::TEXT as module_name,
    anm.group_name::TEXT,
    anm.sort_order,
    pr.code::TEXT as role_code,
    pr.name::TEXT as role_name,
    (pr.code = 'super_admin')::BOOLEAN as is_system_role,
    COALESCE(rmp.access_level, 'hidden')::TEXT as access_level
  FROM admin_nav_modules anm
  CROSS JOIN product_roles pr
  LEFT JOIN admin_role_module_permissions rmp 
    ON rmp.module_key = anm.module_key AND rmp.role_code = pr.code
  WHERE anm.is_active = true 
    AND pr.is_active = true
    AND (p_role_code IS NULL OR pr.code = p_role_code)
    AND (p_group_name IS NULL OR anm.group_name = p_group_name)
    AND (p_access_level IS NULL OR COALESCE(rmp.access_level, 'hidden') = p_access_level)
    AND (p_search IS NULL OR anm.name ILIKE '%' || p_search || '%')
  ORDER BY anm.sort_order, pr.name;
END;
$$;


--
-- Name: get_my_scope(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_my_scope(p_user_id uuid) RETURNS TABLE(cycle_test_case_id uuid, test_case_id uuid, case_key text, title text, priority text, execution_status text, cycle_id uuid, cycle_name text, release_id uuid, release_version text, release_name text, assigned_at timestamp with time zone, failure_reason text, notes text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ctc.id AS cycle_test_case_id,
    ctc.test_case_id,
    tc.case_key::text,
    tc.title::text,
    tc.priority::text,
    ctc.execution_status::text,
    c.id AS cycle_id,
    c.name::text AS cycle_name,
    NULL::uuid AS release_id,
    NULL::text AS release_version,
    NULL::text AS release_name,
    ctc.created_at AS assigned_at,
    ctc.failure_reason::text,
    ctc.notes::text
  FROM th_cycle_test_cases ctc
  JOIN th_test_cases tc ON ctc.test_case_id = tc.id
  JOIN th_test_cycles c ON ctc.cycle_id = c.id
  WHERE ctc.assigned_to = p_user_id
    AND c.status IN ('active', 'in_progress')
  ORDER BY
    CASE tc.priority
      WHEN 'critical' THEN 1
      WHEN 'high' THEN 2
      WHEN 'medium' THEN 3
      WHEN 'low' THEN 4
      ELSE 5
    END,
    tc.case_key;
END;
$$;


--
-- Name: get_my_scope(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_my_scope(p_user_id uuid, p_project_id uuid DEFAULT NULL::uuid) RETURNS TABLE(cycle_test_case_id uuid, test_case_id uuid, case_key text, title text, priority text, execution_status text, cycle_id uuid, cycle_name text, release_id uuid, release_version text, release_name text, assigned_at timestamp with time zone, failure_reason text, notes text, estimated_time integer, cycle_end_date date)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ctc.id AS cycle_test_case_id,
    ctc.test_case_id,
    tc.case_key::text,
    tc.title::text,
    tc.priority::text,
    ctc.execution_status::text,
    c.id AS cycle_id,
    c.name::text AS cycle_name,
    c.release_id,
    r.version::text AS release_version,
    r.name::text AS release_name,
    ctc.created_at AS assigned_at,
    ctc.failure_reason::text,
    ctc.notes::text,
    0 AS estimated_time,
    c.end_date AS cycle_end_date
  FROM th_cycle_test_cases ctc
  JOIN th_test_cases tc ON ctc.test_case_id = tc.id
  JOIN th_test_cycles c ON ctc.cycle_id = c.id
  LEFT JOIN releases r ON c.release_id = r.id
  WHERE ctc.assigned_to = p_user_id
    AND c.status IN ('active', 'in_progress')
  ORDER BY
    CASE tc.priority
      WHEN 'critical' THEN 1
      WHEN 'high' THEN 2
      WHEN 'medium' THEN 3
      WHEN 'low' THEN 4
      ELSE 5
    END,
    tc.case_key;
END;
$$;


--
-- Name: get_my_stats(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_my_stats(p_user_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_result JSON;
BEGIN
  SELECT json_build_object(
    'total_assigned', COUNT(*),
    'remaining', COUNT(*) FILTER (WHERE ctc.execution_status = 'not_run'),
    'passed_count', COUNT(*) FILTER (WHERE ctc.execution_status = 'passed'),
    'failed_count', COUNT(*) FILTER (WHERE ctc.execution_status = 'failed'),
    'blocked_count', COUNT(*) FILTER (WHERE ctc.execution_status = 'blocked'),
    'executed_today', COUNT(*) FILTER (WHERE ctc.executed_at::date = CURRENT_DATE),
    'executed_this_week', COUNT(*) FILTER (WHERE ctc.executed_at >= date_trunc('week', CURRENT_DATE)),
    'pass_rate', CASE 
      WHEN COUNT(*) FILTER (WHERE ctc.execution_status IN ('passed','failed')) > 0 
      THEN ROUND(
        COUNT(*) FILTER (WHERE ctc.execution_status = 'passed')::numeric / 
        NULLIF(COUNT(*) FILTER (WHERE ctc.execution_status IN ('passed','failed')), 0) * 100, 1
      )
      ELSE 0
    END
  ) INTO v_result
  FROM th_cycle_test_cases ctc
  JOIN th_test_cycles c ON ctc.cycle_id = c.id
  WHERE ctc.assigned_to = p_user_id
    AND c.status IN ('active', 'in_progress');

  RETURN COALESCE(v_result, '{"total_assigned":0,"remaining":0,"passed_count":0,"failed_count":0,"blocked_count":0,"executed_today":0,"executed_this_week":0,"pass_rate":0}'::json);
END;
$$;


--
-- Name: get_next_caty_message_sequence(uuid); Type: FUNCTION; Schema: public; Owner: -
--

