$$;


--
-- Name: get_next_test_in_cycle(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_next_test_in_cycle(p_cycle_id uuid, p_current_run_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_current_order TIMESTAMPTZ;
  v_next_run RECORD;
BEGIN
  -- Get current run timestamp if provided
  IF p_current_run_id IS NOT NULL THEN
    SELECT created_at INTO v_current_order
    FROM tm_test_runs
    WHERE id = p_current_run_id;
  END IF;

  -- Find next unexecuted or in-progress test
  SELECT 
    r.id as run_id,
    r.test_case_id,
    tc.key as case_number,
    tc.title
  INTO v_next_run
  FROM tm_test_runs r
  JOIN tm_test_cases tc ON r.test_case_id = tc.id
  WHERE r.cycle_id = p_cycle_id
    AND (p_current_run_id IS NULL OR r.created_at > v_current_order)
    AND r.status IN ('not_run', 'in_progress')
  ORDER BY r.created_at
  LIMIT 1;

  IF NOT FOUND THEN
    -- Check if all cases are complete
    IF EXISTS (
      SELECT 1 FROM tm_test_runs
      WHERE cycle_id = p_cycle_id AND status = 'not_run'
    ) THEN
      RETURN jsonb_build_object('status', 'has_remaining', 'message', 'There are remaining test cases');
    ELSE
      RETURN jsonb_build_object('status', 'all_complete', 'message', 'All test cases have been executed');
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'status', 'found',
    'run_id', v_next_run.run_id,
    'test_case_id', v_next_run.test_case_id,
    'case_number', v_next_run.case_number,
    'title', v_next_run.title
  );
END;
$$;


--
-- Name: get_parallel_run_progress(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_parallel_run_progress(p_run_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_progress RECORD;
  v_config RECORD;
  v_eta_seconds INTEGER;
BEGIN
  SELECT * INTO v_config
  FROM parallel_run_configs
  WHERE run_id = p_run_id;

  SELECT
    COUNT(*) as total,
    COUNT(*) FILTER (WHERE status = 'queued') as queued,
    COUNT(*) FILTER (WHERE status IN ('claimed', 'running')) as running,
    COUNT(*) FILTER (WHERE status = 'completed') as completed,
    COUNT(*) FILTER (WHERE status = 'failed') as failed,
    COUNT(*) FILTER (WHERE status = 'skipped') as skipped
  INTO v_progress
  FROM execution_queue
  WHERE run_id = p_run_id;

  SELECT 
    CASE 
      WHEN v_progress.completed > 0 THEN
        ((v_progress.queued + v_progress.running) * 
         (SUM(total_execution_time) / NULLIF(SUM(completed_count), 0)))::INTEGER
      ELSE NULL
    END INTO v_eta_seconds
  FROM parallel_workers
  WHERE run_id = p_run_id;

  RETURN jsonb_build_object(
    'run_id', p_run_id,
    'max_workers', COALESCE(v_config.max_workers, 0),
    'total', v_progress.total,
    'queued', v_progress.queued,
    'running', v_progress.running,
    'completed', v_progress.completed,
    'failed', v_progress.failed,
    'skipped', v_progress.skipped,
    'progress_percentage', ROUND((v_progress.completed::DECIMAL / NULLIF(v_progress.total, 0)) * 100, 1),
    'estimated_remaining_seconds', v_eta_seconds
  );
END;
$$;


--
