--
-- Name: get_plan_progress(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_plan_progress(p_plan_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_total        INT := 0;
  v_executed     INT := 0;
  v_passed       INT := 0;
  v_failed       INT := 0;
  v_blocked      INT := 0;
  v_progress_pct NUMERIC := 0;
  v_pass_rate    NUMERIC := 0;
BEGIN
  -- Total scope items across all cycles linked to this plan
  SELECT COUNT(*)
  INTO v_total
  FROM tm_cycle_scope cs
  WHERE cs.cycle_id IN (
    SELECT cycle_id FROM plan_test_cycles WHERE plan_id = p_plan_id
  );

  -- Passed
  SELECT COUNT(*)
  INTO v_passed
  FROM tm_cycle_scope cs
  WHERE cs.cycle_id IN (
    SELECT cycle_id FROM plan_test_cycles WHERE plan_id = p_plan_id
  )
  AND cs.current_status = 'passed';

  -- Failed
  SELECT COUNT(*)
  INTO v_failed
  FROM tm_cycle_scope cs
  WHERE cs.cycle_id IN (
    SELECT cycle_id FROM plan_test_cycles WHERE plan_id = p_plan_id
  )
  AND cs.current_status = 'failed';

  -- Blocked
  SELECT COUNT(*)
  INTO v_blocked
  FROM tm_cycle_scope cs
  WHERE cs.cycle_id IN (
    SELECT cycle_id FROM plan_test_cycles WHERE plan_id = p_plan_id
  )
  AND cs.current_status = 'blocked';

  -- Executed = passed + failed + blocked
  v_executed := v_passed + v_failed + v_blocked;

  -- Progress = executed / total × 100
  IF v_total > 0 THEN
    v_progress_pct := ROUND((v_executed::NUMERIC / v_total) * 100, 1);
  END IF;

  -- Pass rate = passed / executed × 100 (F-05 standard)
  IF v_executed > 0 THEN
    v_pass_rate := ROUND((v_passed::NUMERIC / v_executed) * 100, 1);
  END IF;

  RETURN json_build_object(
    'total_tests',       v_total,
    'executed',          v_executed,
    'passed',            v_passed,
    'failed',            v_failed,
    'blocked',           v_blocked,
    'remaining',         GREATEST(v_total - v_executed, 0),
    'progress_percent',  v_progress_pct,
    'pass_rate',         v_pass_rate
  );
END;
$$;


--
-- Name: get_plan_stats(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_plan_stats() RETURNS TABLE(total_plans bigint, draft_plans bigint, active_plans bigint, completed_plans bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COUNT(*)::BIGINT,
    COUNT(*) FILTER (WHERE status = 'draft')::BIGINT,
    COUNT(*) FILTER (WHERE status = 'active')::BIGINT,
    COUNT(*) FILTER (WHERE status = 'completed')::BIGINT
  FROM th_test_plans
  WHERE status != 'archived';
END;
$$;


--
-- Name: get_project_ai_context(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_project_ai_context(p_project_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  result JSONB;
  v_project JSONB;
  v_status_counts JSONB;
  v_overdue JSONB;
  v_blocked JSONB;
  v_velocity_current NUMERIC;
  v_velocity_previous NUMERIC;
  v_workload JSONB;
  v_total INTEGER;
  v_done INTEGER;
  v_remaining INTEGER;
BEGIN
  -- Use ph_projects (ProjectHub table)
  SELECT jsonb_build_object(
    'name', p.name,
    'project_key', p.key,
    'start_date', p.start_date,
    'target_date', p.end_date,
    'status', p.status
  ) INTO v_project
  FROM ph_projects p
  WHERE p.id = p_project_id;

  IF v_project IS NULL THEN
    RETURN jsonb_build_object('error', 'Project not found');
  END IF;

  -- Use ph_work_items (ProjectHub work items)
  SELECT COALESCE(jsonb_object_agg(status, cnt), '{}'::jsonb)
  INTO v_status_counts
  FROM (
    SELECT status, COUNT(*)::INTEGER as cnt
    FROM ph_work_items wi
    -- Find items belonging to this project via jira_project_id or parent linkage
    WHERE EXISTS (
      SELECT 1 FROM ph_work_items root
      WHERE root.id = wi.id
      AND (
        wi.item_key LIKE (SELECT key FROM ph_projects WHERE id = p_project_id) || '-%'
      )
    )
    GROUP BY status
  ) s;

  SELECT COUNT(*)::INTEGER INTO v_total
  FROM ph_work_items
  WHERE item_key LIKE (SELECT key FROM ph_projects WHERE id = p_project_id) || '-%';

  SELECT COUNT(*)::INTEGER INTO v_done
  FROM ph_work_items
  WHERE item_key LIKE (SELECT key FROM ph_projects WHERE id = p_project_id) || '-%'
    AND LOWER(status) IN ('done', 'cancelled', 'closed', 'resolved');

  v_remaining := v_total - v_done;

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'item_key', wi.item_key,
    'title', wi.summary,
    'due_date', wi.due_date,
    'priority', wi.priority,
    'assignee', COALESCE(pr.full_name, 'Unassigned'),
    'days_overdue', (CURRENT_DATE - wi.due_date::date)
  )), '[]'::jsonb)
  INTO v_overdue
  FROM ph_work_items wi
  LEFT JOIN profiles pr ON pr.id = wi.assignee_user_id
  WHERE wi.item_key LIKE (SELECT key FROM ph_projects WHERE id = p_project_id) || '-%'
    AND wi.due_date IS NOT NULL
    AND wi.due_date::date < CURRENT_DATE
    AND LOWER(wi.status) NOT IN ('done', 'cancelled', 'closed', 'resolved');

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'item_key', wi.item_key,
    'title', wi.summary,
    'priority', wi.priority,
    'assignee', COALESCE(pr.full_name, 'Unassigned')
  )), '[]'::jsonb)
  INTO v_blocked
  FROM ph_work_items wi
  LEFT JOIN profiles pr ON pr.id = wi.assignee_user_id
  WHERE wi.item_key LIKE (SELECT key FROM ph_projects WHERE id = p_project_id) || '-%'
    AND LOWER(wi.status) = 'blocked';

  SELECT COUNT(*)::NUMERIC / 2
  INTO v_velocity_current
  FROM ph_work_items
  WHERE item_key LIKE (SELECT key FROM ph_projects WHERE id = p_project_id) || '-%'
    AND LOWER(status) IN ('done', 'closed', 'resolved')
    AND completed_at >= (CURRENT_DATE - INTERVAL '14 days');

  SELECT COUNT(*)::NUMERIC / 2
  INTO v_velocity_previous
  FROM ph_work_items
  WHERE item_key LIKE (SELECT key FROM ph_projects WHERE id = p_project_id) || '-%'
    AND LOWER(status) IN ('done', 'closed', 'resolved')
    AND completed_at >= (CURRENT_DATE - INTERVAL '28 days')
    AND completed_at < (CURRENT_DATE - INTERVAL '14 days');

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'name', w.full_name,
    'active_items', w.cnt
  ) ORDER BY w.cnt DESC), '[]'::jsonb)
  INTO v_workload
  FROM (
    SELECT pr.full_name, COUNT(*)::INTEGER as cnt
    FROM ph_work_items wi
    JOIN profiles pr ON pr.id = wi.assignee_user_id
    WHERE wi.item_key LIKE (SELECT key FROM ph_projects WHERE id = p_project_id) || '-%'
      AND LOWER(wi.status) NOT IN ('done', 'cancelled', 'closed', 'resolved')
    GROUP BY pr.full_name
  ) w;

  result := jsonb_build_object(
    'project', v_project,
    'total_items', v_total,
    'done_items', v_done,
    'remaining_items', v_remaining,
    'completion_percent', CASE WHEN v_total > 0 THEN ROUND((v_done::NUMERIC / v_total) * 100) ELSE 0 END,
    'status_counts', v_status_counts,
    'overdue_items', v_overdue,
    'overdue_count', jsonb_array_length(v_overdue),
    'blocked_items', v_blocked,
    'blocked_count', jsonb_array_length(v_blocked),
    'velocity_current', ROUND(COALESCE(v_velocity_current, 0), 1),
    'velocity_previous', ROUND(COALESCE(v_velocity_previous, 0), 1),
    'workload', v_workload
  );

  RETURN result;
END;
$$;


--
-- Name: get_project_team(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_project_team(p_project_id uuid) RETURNS TABLE(user_id uuid, full_name text, email text, job_role text, department_name text, avatar_url text, country text, location text, project_role text)
    LANGUAGE sql SECURITY DEFINER
    AS $$
  SELECT 
    pr.id AS user_id,
    pr.full_name,
    pr.email,
    pr.role AS job_role,
    COALESCE(d.name, 'Unassigned') AS department_name,
    pr.avatar_url,
    pr.country,
    pr.location,
    pm.role AS project_role
  FROM project_members pm
  JOIN profiles pr ON pr.id = pm.user_id
  LEFT JOIN departments d ON d.id = pr.department_id
  WHERE pm.project_id = p_project_id
  ORDER BY pr.full_name;
$$;


--
-- Name: get_queue_items(uuid, text, text, text, text, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_queue_items(p_run_id uuid, p_priority_filter text DEFAULT NULL::text, p_search_query text DEFAULT NULL::text, p_sort_by text DEFAULT 'position'::text, p_sort_order text DEFAULT 'asc'::text, p_limit integer DEFAULT 100, p_offset integer DEFAULT 0) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_items JSONB;
  v_total INTEGER;
BEGIN
  -- Count total matching
  SELECT COUNT(*) INTO v_total
  FROM execution_queue eq
  JOIN test_cases tc ON eq.test_case_id = tc.id
  WHERE eq.run_id = p_run_id
    AND eq.status = 'queued'
    AND (p_priority_filter IS NULL OR tc.priority = p_priority_filter)
    AND (p_search_query IS NULL OR 
         tc.title ILIKE '%' || p_search_query || '%' OR
         tc.case_number ILIKE '%' || p_search_query || '%');

  -- Get items with dynamic ordering
  SELECT COALESCE(
    jsonb_agg(item ORDER BY sort_key),
    '[]'::jsonb
  ) INTO v_items
  FROM (
    SELECT 
      jsonb_build_object(
        'id', eq.id,
        'position', eq.position,
        'priority', eq.priority,
        'status', eq.status,
        'test_case', jsonb_build_object(
          'id', tc.id,
          'case_number', tc.case_number,
          'title', tc.title,
          'priority', tc.priority
        ),
        'estimated_time', 60,
        'created_at', eq.created_at
      ) as item,
      CASE p_sort_by
        WHEN 'position' THEN 
          CASE WHEN p_sort_order = 'asc' THEN eq.position ELSE -eq.position END
        WHEN 'priority' THEN 
          CASE WHEN p_sort_order = 'asc' THEN eq.priority ELSE -eq.priority END
        ELSE eq.position
      END as sort_key
    FROM execution_queue eq
    JOIN test_cases tc ON eq.test_case_id = tc.id
    WHERE eq.run_id = p_run_id
      AND eq.status = 'queued'
      AND (p_priority_filter IS NULL OR tc.priority = p_priority_filter)
      AND (p_search_query IS NULL OR 
           tc.title ILIKE '%' || p_search_query || '%' OR
           tc.case_number ILIKE '%' || p_search_query || '%')
    LIMIT p_limit
    OFFSET p_offset
  ) sub;

  RETURN jsonb_build_object(
    'items', v_items,
    'total', v_total,
    'limit', p_limit,
    'offset', p_offset
  );
END;
$$;


--
-- Name: get_recent_activity(uuid, character varying, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_recent_activity(p_user_id uuid DEFAULT NULL::uuid, p_entity_type character varying DEFAULT NULL::character varying, p_limit integer DEFAULT 50) RETURNS TABLE(id uuid, action character varying, entity_type character varying, entity_key text, entity_name text, user_name text, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    a.id,
    a.action,
    a.entity_type,
    a.entity_key,
    a.entity_name,
    a.user_name,
    a.created_at
  FROM th_audit_log a
  WHERE (p_user_id IS NULL OR a.user_id = p_user_id)
    AND (p_entity_type IS NULL OR a.entity_type = p_entity_type)
  ORDER BY a.created_at DESC
  LIMIT p_limit;
END;
$$;


--
-- Name: get_recent_results(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_recent_results(p_run_id uuid, p_limit integer DEFAULT 10) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_results JSONB;
BEGIN
  SELECT COALESCE(
    jsonb_agg(row_data ORDER BY completed_at DESC),
    '[]'::jsonb
  ) INTO v_results
  FROM (
    SELECT 
      jsonb_build_object(
        'id', er.id,
        'test_case_id', tc.id,
        'case_number', tc.case_number,
        'title', tc.title,
        'result', er.result_status,
        'duration_seconds', EXTRACT(EPOCH FROM (er.completed_at - er.started_at))::INTEGER,
        'completed_at', er.completed_at,
        'executed_by', jsonb_build_object(
          'id', COALESCE(p.id, '00000000-0000-0000-0000-000000000000'),
          'name', COALESCE(p.full_name, p.email, 'Unknown')
        )
      ) as row_data,
      er.completed_at
    FROM test_execution_results er
    JOIN test_cases tc ON er.test_case_id = tc.id
    LEFT JOIN profiles p ON er.executed_by = p.id
    WHERE er.run_id = p_run_id
      AND er.result_status IS NOT NULL
      AND er.completed_at IS NOT NULL
    ORDER BY er.completed_at DESC
    LIMIT p_limit
  ) sub;

  RETURN v_results;
END;
$$;


--
-- Name: get_release_execution_trend(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_release_execution_trend(p_release_id uuid, p_days integer DEFAULT 14) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN jsonb_build_object(
    'success', true,
    'trend', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'date', day::DATE,
        'passed', passed,
        'failed', failed,
        'blocked', blocked
      ) ORDER BY day)
      FROM (
        SELECT 
          DATE_TRUNC('day', te.executed_at) AS day,
          COUNT(*) FILTER (WHERE te.status = 'passed') AS passed,
          COUNT(*) FILTER (WHERE te.status = 'failed') AS failed,
          COUNT(*) FILTER (WHERE te.status = 'blocked') AS blocked
        FROM test_executions te
        JOIN test_runs tr ON tr.id = te.run_id
        JOIN test_cycles tc ON tc.id = tr.cycle_id
        WHERE tc.release_id = p_release_id
          AND te.executed_at >= now() - (p_days || ' days')::INTERVAL
        GROUP BY DATE_TRUNC('day', te.executed_at)
      ) daily
    ), '[]'::JSONB)
  );
END;
$$;


--
-- Name: get_release_quality_metrics(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_release_quality_metrics(p_release_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_metrics JSONB;
  v_test_total INTEGER := 0;
  v_test_passed INTEGER := 0;
  v_test_failed INTEGER := 0;
  v_test_blocked INTEGER := 0;
  v_test_not_run INTEGER := 0;
  v_defects_open INTEGER := 0;
  v_defects_closed INTEGER := 0;
  v_defects_blocker INTEGER := 0;
  v_defects_critical INTEGER := 0;
  v_coverage_percent NUMERIC := 0;
  v_automation_rate NUMERIC := 0;
  v_pass_rate NUMERIC := 0;
BEGIN
  -- Get test execution counts from test_executions linked to release
  SELECT 
    COUNT(*),
    COUNT(*) FILTER (WHERE status = 'passed'),
    COUNT(*) FILTER (WHERE status = 'failed'),
    COUNT(*) FILTER (WHERE status = 'blocked'),
    COUNT(*) FILTER (WHERE status IN ('not_run', 'pending', 'skipped'))
  INTO v_test_total, v_test_passed, v_test_failed, v_test_blocked, v_test_not_run
  FROM test_executions te
  JOIN test_runs tr ON tr.id = te.run_id
  JOIN test_cycles tc ON tc.id = tr.cycle_id
  WHERE tc.release_id = p_release_id;

  -- If no executions, count test cases assigned to release
  IF v_test_total = 0 THEN
    SELECT COUNT(*) INTO v_test_total
    FROM test_cases WHERE release_id = p_release_id;
    v_test_not_run := v_test_total;
  END IF;

  -- Calculate pass rate
  IF (v_test_passed + v_test_failed) > 0 THEN
    v_pass_rate := ROUND((v_test_passed::NUMERIC / (v_test_passed + v_test_failed)) * 100, 1);
  END IF;

  -- Calculate coverage (executed / total)
  IF v_test_total > 0 THEN
    v_coverage_percent := ROUND(((v_test_total - v_test_not_run)::NUMERIC / v_test_total) * 100, 1);
  END IF;

  -- Get defect counts from defects table linked to release
  SELECT 
    COUNT(*) FILTER (WHERE status NOT IN ('closed', 'resolved', 'rejected')),
    COUNT(*) FILTER (WHERE status IN ('closed', 'resolved')),
    COUNT(*) FILTER (WHERE severity = 'blocker' AND status NOT IN ('closed', 'resolved', 'rejected')),
    COUNT(*) FILTER (WHERE severity = 'critical' AND status NOT IN ('closed', 'resolved', 'rejected'))
  INTO v_defects_open, v_defects_closed, v_defects_blocker, v_defects_critical
  FROM defects WHERE release_id = p_release_id;

  -- Get automation rate from test_cases
  SELECT 
    CASE WHEN COUNT(*) > 0 
      THEN ROUND((COUNT(*) FILTER (WHERE automation_status = 'automated')::NUMERIC / COUNT(*)) * 100, 1)
      ELSE 0 
    END
  INTO v_automation_rate
  FROM test_cases WHERE release_id = p_release_id;

  -- Build metrics object
  v_metrics := jsonb_build_object(
    'success', true,
    'release_id', p_release_id,
    'test_execution', jsonb_build_object(
      'total', v_test_total,
      'passed', v_test_passed,
      'failed', v_test_failed,
      'blocked', v_test_blocked,
      'not_run', v_test_not_run,
      'pass_rate', v_pass_rate,
      'coverage_percent', v_coverage_percent
    ),
    'defects', jsonb_build_object(
      'open', v_defects_open,
      'closed', v_defects_closed,
      'blocker', v_defects_blocker,
      'critical', v_defects_critical,
      'total', v_defects_open + v_defects_closed
    ),
    'automation', jsonb_build_object(
      'rate', v_automation_rate,
      'automated_count', (SELECT COUNT(*) FROM test_cases WHERE release_id = p_release_id AND automation_status = 'automated'),
      'manual_count', (SELECT COUNT(*) FROM test_cases WHERE release_id = p_release_id AND (automation_status IS NULL OR automation_status = 'manual'))
    ),
    'calculated_at', now()
  );

  RETURN v_metrics;
END;
$$;


--
-- Name: get_report_coverage_metrics(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_report_coverage_metrics() RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_total INTEGER;
  v_executed INTEGER;
  v_automated INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_total
  FROM th_test_cases;
  
  SELECT COUNT(DISTINCT test_case_id) INTO v_executed
  FROM th_cycle_test_cases
  WHERE execution_status IS NOT NULL AND execution_status != 'not_run';
  
  SELECT COUNT(*) INTO v_automated
  FROM th_test_cases 
  WHERE automation = 'automated';
  
  RETURN json_build_object(
    'total_tests', COALESCE(v_total, 0),
    'executed_tests', COALESCE(v_executed, 0),
    'execution_coverage', COALESCE(ROUND(v_executed * 100.0 / NULLIF(v_total, 0), 1), 0),
    'automated_tests', COALESCE(v_automated, 0),
    'automation_coverage', COALESCE(ROUND(v_automated * 100.0 / NULLIF(v_total, 0), 1), 0),
    'manual_tests', COALESCE(v_total - v_automated, 0)
  );
END;
$$;


--
-- Name: get_report_execution_metrics(timestamp with time zone, timestamp with time zone, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_report_execution_metrics(p_start_date timestamp with time zone DEFAULT (now() - '30 days'::interval), p_end_date timestamp with time zone DEFAULT now(), p_cycle_id uuid DEFAULT NULL::uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_result JSON;
BEGIN
  SELECT json_build_object(
    'total_executed', COALESCE(COUNT(*), 0),
    'passed', COALESCE(COUNT(*) FILTER (WHERE execution_status = 'passed'), 0),
    'failed', COALESCE(COUNT(*) FILTER (WHERE execution_status = 'failed'), 0),
    'blocked', COALESCE(COUNT(*) FILTER (WHERE execution_status = 'blocked'), 0),
    'skipped', COALESCE(COUNT(*) FILTER (WHERE execution_status = 'skipped'), 0),
    'not_run', COALESCE(COUNT(*) FILTER (WHERE execution_status = 'not_run' OR execution_status IS NULL), 0),
    'pass_rate', COALESCE(ROUND(
      COUNT(*) FILTER (WHERE execution_status = 'passed') * 100.0 / 
      NULLIF(COUNT(*) FILTER (WHERE execution_status IN ('passed', 'failed')), 0), 1
    ), 0),
    'execution_rate', COALESCE(ROUND(
      COUNT(*) FILTER (WHERE execution_status NOT IN ('not_run') AND execution_status IS NOT NULL) * 100.0 / 
      NULLIF(COUNT(*), 0), 1
    ), 0),
    'avg_execution_time', COALESCE(ROUND(AVG(execution_time_seconds)::numeric, 0), 0)
  ) INTO v_result
  FROM th_cycle_test_cases
  WHERE executed_at BETWEEN p_start_date AND p_end_date
    AND (p_cycle_id IS NULL OR cycle_id = p_cycle_id);
  
  RETURN COALESCE(v_result, '{"total_executed":0,"passed":0,"failed":0,"blocked":0,"skipped":0,"not_run":0,"pass_rate":0,"execution_rate":0,"avg_execution_time":0}'::json);
END;
$$;


--
-- Name: get_report_execution_trend(timestamp with time zone, timestamp with time zone, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_report_execution_trend(p_start_date timestamp with time zone DEFAULT (now() - '30 days'::interval), p_end_date timestamp with time zone DEFAULT now(), p_interval text DEFAULT 'day'::text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN COALESCE((
    SELECT json_agg(row_to_json(t) ORDER BY t.period)
    FROM (
      SELECT 
        date_trunc(p_interval, executed_at)::date as period,
        COUNT(*) as total,
        COUNT(*) FILTER (WHERE execution_status = 'passed') as passed,
        COUNT(*) FILTER (WHERE execution_status = 'failed') as failed,
        COUNT(*) FILTER (WHERE execution_status = 'blocked') as blocked,
        ROUND(
          COUNT(*) FILTER (WHERE execution_status = 'passed') * 100.0 / 
          NULLIF(COUNT(*) FILTER (WHERE execution_status IN ('passed', 'failed')), 0), 1
        ) as pass_rate
      FROM th_cycle_test_cases
      WHERE executed_at BETWEEN p_start_date AND p_end_date
        AND executed_at IS NOT NULL
      GROUP BY date_trunc(p_interval, executed_at)::date
    ) t
  ), '[]'::json);
END;
$$;


--
-- Name: get_report_results_by_folder(timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_report_results_by_folder(p_start_date timestamp with time zone DEFAULT (now() - '30 days'::interval), p_end_date timestamp with time zone DEFAULT now()) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN COALESCE((
    SELECT json_agg(row_to_json(t) ORDER BY t.total DESC)
    FROM (
      SELECT 
        f.id as folder_id,
        f.name as folder_name,
        COUNT(*) as total,
        COUNT(*) FILTER (WHERE ctc.execution_status = 'passed') as passed,
        COUNT(*) FILTER (WHERE ctc.execution_status = 'failed') as failed,
        ROUND(
          COUNT(*) FILTER (WHERE ctc.execution_status = 'passed') * 100.0 / 
          NULLIF(COUNT(*) FILTER (WHERE ctc.execution_status IN ('passed', 'failed')), 0), 1
        ) as pass_rate
      FROM th_cycle_test_cases ctc
      JOIN th_test_cases tc ON ctc.test_case_id = tc.id
      LEFT JOIN th_folders f ON tc.folder_id = f.id
      WHERE ctc.executed_at BETWEEN p_start_date AND p_end_date
        AND ctc.executed_at IS NOT NULL
      GROUP BY f.id, f.name
    ) t
  ), '[]'::json);
END;
$$;


--
-- Name: get_report_results_by_priority(timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_report_results_by_priority(p_start_date timestamp with time zone DEFAULT (now() - '30 days'::interval), p_end_date timestamp with time zone DEFAULT now()) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN COALESCE((
    SELECT json_agg(row_to_json(t))
    FROM (
      SELECT 
        tc.priority,
        COUNT(*) as total,
        COUNT(*) FILTER (WHERE ctc.execution_status = 'passed') as passed,
        COUNT(*) FILTER (WHERE ctc.execution_status = 'failed') as failed,
        ROUND(
          COUNT(*) FILTER (WHERE ctc.execution_status = 'passed') * 100.0 / 
          NULLIF(COUNT(*) FILTER (WHERE ctc.execution_status IN ('passed', 'failed')), 0), 1
        ) as pass_rate
      FROM th_cycle_test_cases ctc
      JOIN th_test_cases tc ON ctc.test_case_id = tc.id
      WHERE ctc.executed_at BETWEEN p_start_date AND p_end_date
        AND ctc.executed_at IS NOT NULL
      GROUP BY tc.priority
      ORDER BY 
        CASE tc.priority 
          WHEN 'critical' THEN 1 
          WHEN 'high' THEN 2 
          WHEN 'medium' THEN 3 
          WHEN 'low' THEN 4 
          ELSE 5
        END
    ) t
  ), '[]'::json);
END;
$$;


--
-- Name: get_report_stats(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_report_stats() RETURNS TABLE(total_reports bigint, ready_reports bigint, this_month bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COUNT(*)::BIGINT,
    COUNT(*) FILTER (WHERE status = 'ready')::BIGINT,
    COUNT(*) FILTER (WHERE created_at >= DATE_TRUNC('month', CURRENT_DATE))::BIGINT
  FROM th_reports
  WHERE status != 'archived';
END;
$$;


--
-- Name: get_report_tester_performance(timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_report_tester_performance(p_start_date timestamp with time zone DEFAULT (now() - '30 days'::interval), p_end_date timestamp with time zone DEFAULT now()) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN COALESCE((
    SELECT json_agg(row_to_json(t) ORDER BY t.total_executed DESC)
    FROM (
      SELECT 
        p.id as user_id,
        p.full_name,
        p.avatar_url,
        COUNT(*) as total_executed,
        COUNT(*) FILTER (WHERE ctc.execution_status = 'passed') as passed,
        COUNT(*) FILTER (WHERE ctc.execution_status = 'failed') as failed,
        ROUND(
          COUNT(*) FILTER (WHERE ctc.execution_status = 'passed') * 100.0 / 
          NULLIF(COUNT(*) FILTER (WHERE ctc.execution_status IN ('passed', 'failed')), 0), 1
        ) as pass_rate,
        ROUND(AVG(ctc.execution_time_seconds)::numeric, 0) as avg_time_seconds
      FROM th_cycle_test_cases ctc
      JOIN profiles p ON ctc.executed_by = p.id
      WHERE ctc.executed_at BETWEEN p_start_date AND p_end_date
        AND ctc.executed_at IS NOT NULL
      GROUP BY p.id, p.full_name, p.avatar_url
      LIMIT 10
    ) t
  ), '[]'::json);
END;
$$;


--
-- Name: get_requirement_tests(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_requirement_tests(p_requirement_id uuid) RETURNS TABLE(link_id uuid, test_case_id uuid, case_key text, title text, priority text, latest_status text, last_executed timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    rt.id as link_id,
    tc.id as test_case_id,
    tc.case_key::TEXT,
    tc.title::TEXT,
    tc.priority::TEXT,
    (
      SELECT ctc.execution_status::TEXT
      FROM th_cycle_test_cases ctc 
      WHERE ctc.test_case_id = tc.id 
      ORDER BY ctc.executed_at DESC NULLS LAST 
      LIMIT 1
    ) as latest_status,
    (
      SELECT ctc.executed_at 
      FROM th_cycle_test_cases ctc 
      WHERE ctc.test_case_id = tc.id 
      ORDER BY ctc.executed_at DESC NULLS LAST 
      LIMIT 1
    ) as last_executed
  FROM th_requirement_tests rt
  JOIN th_test_cases tc ON tc.id = rt.test_case_id
  WHERE rt.requirement_id = p_requirement_id
  ORDER BY tc.case_key;
END;
$$;


--
-- Name: get_requirements_coverage_summary(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_requirements_coverage_summary() RETURNS TABLE(total_requirements bigint, fully_covered bigint, partially_covered bigint, not_covered bigint, avg_coverage_percent numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COUNT(*)::BIGINT,
    COUNT(*) FILTER (WHERE r.coverage_percent = 100)::BIGINT,
    COUNT(*) FILTER (WHERE r.coverage_percent > 0 AND r.coverage_percent < 100)::BIGINT,
    COUNT(*) FILTER (WHERE r.coverage_percent = 0 OR r.total_linked_tests = 0)::BIGINT,
    ROUND(AVG(r.coverage_percent), 1)
  FROM th_requirements r
  WHERE r.status != 'deprecated';
END;
$$;


--
-- Name: get_resource_summary(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_resource_summary(p_project_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_env_summary RECORD;
  v_pool_summary RECORD;
  v_active_runs INTEGER;
BEGIN
  SELECT
    COUNT(*) as total,
    COUNT(*) FILTER (WHERE status = 'available') as available,
    COALESCE(SUM(capacity), 0) as total_capacity,
    COALESCE(SUM(allocated), 0) as total_allocated
  INTO v_env_summary
  FROM test_environments
  WHERE project_id = p_project_id AND deleted_at IS NULL;

  SELECT
    COUNT(*) as total_pools,
    COALESCE(SUM(total_workers), 0) as total_workers,
    COALESCE(SUM(available_workers), 0) as available_workers,
    COALESCE(SUM(assigned_workers), 0) as assigned_workers
  INTO v_pool_summary
  FROM worker_pools
  WHERE project_id = p_project_id;

  SELECT COUNT(*) INTO v_active_runs
  FROM test_execution_runs r
  JOIN resource_allocations ra ON ra.run_id = r.id
  WHERE r.project_id = p_project_id
    AND r.status = 'running'
    AND ra.released_at IS NULL;

  RETURN jsonb_build_object(
    'environments', jsonb_build_object(
      'total', COALESCE(v_env_summary.total, 0),
      'available', COALESCE(v_env_summary.available, 0),
      'total_capacity', COALESCE(v_env_summary.total_capacity, 0),
      'total_allocated', COALESCE(v_env_summary.total_allocated, 0),
      'utilization_percentage', CASE 
        WHEN COALESCE(v_env_summary.total_capacity, 0) > 0 
        THEN ROUND((COALESCE(v_env_summary.total_allocated, 0)::DECIMAL / v_env_summary.total_capacity) * 100, 1)
        ELSE 0
      END
    ),
    'worker_pools', jsonb_build_object(
      'total_pools', COALESCE(v_pool_summary.total_pools, 0),
      'total_workers', COALESCE(v_pool_summary.total_workers, 0),
      'available_workers', COALESCE(v_pool_summary.available_workers, 0),
      'assigned_workers', COALESCE(v_pool_summary.assigned_workers, 0)
    ),
    'active_runs', COALESCE(v_active_runs, 0)
  );
END;
$$;


--
-- Name: get_run_metrics(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_run_metrics(p_run_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_run RECORD;
  v_metrics RECORD;
  v_velocity DECIMAL;
  v_eta_seconds INTEGER;
BEGIN
  SELECT * INTO v_run
  FROM test_execution_runs
  WHERE id = p_run_id AND deleted_at IS NULL;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Run not found');
  END IF;

  SELECT
    COUNT(*) as total_cases,
    COUNT(*) FILTER (WHERE result_status IS NOT NULL) as completed_cases,
    COUNT(*) FILTER (WHERE result_status = 'passed') as passed_cases,
    COUNT(*) FILTER (WHERE result_status = 'failed') as failed_cases,
    COUNT(*) FILTER (WHERE result_status = 'blocked') as blocked_cases,
    COUNT(*) FILTER (WHERE result_status = 'skipped') as skipped_cases,
    SUM(EXTRACT(EPOCH FROM (COALESCE(completed_at, NOW()) - started_at)))::INTEGER as total_execution_time,
    AVG(EXTRACT(EPOCH FROM (completed_at - started_at)))::INTEGER as avg_case_duration
  INTO v_metrics
  FROM test_execution_results
  WHERE run_id = p_run_id;

  IF v_metrics.total_execution_time > 0 AND v_metrics.completed_cases > 0 THEN
    v_velocity := ROUND((v_metrics.completed_cases::DECIMAL / v_metrics.total_execution_time) * 3600, 1);
  ELSE
    v_velocity := 0;
  END IF;

  IF v_velocity > 0 THEN
    v_eta_seconds := ((v_metrics.total_cases - v_metrics.completed_cases) / v_velocity * 3600)::INTEGER;
  ELSE
    v_eta_seconds := NULL;
  END IF;

  RETURN jsonb_build_object(
    'run_id', p_run_id,
    'run_number', v_run.run_number,
    'started_at', v_run.started_at,
    'total_cases', v_metrics.total_cases,
    'completed_cases', v_metrics.completed_cases,
    'remaining_cases', v_metrics.total_cases - v_metrics.completed_cases,
    'passed_cases', v_metrics.passed_cases,
    'failed_cases', v_metrics.failed_cases,
    'blocked_cases', v_metrics.blocked_cases,
    'skipped_cases', v_metrics.skipped_cases,
    'pass_rate', CASE 
      WHEN v_metrics.completed_cases > 0 
      THEN ROUND((v_metrics.passed_cases::DECIMAL / v_metrics.completed_cases) * 100, 1)
      ELSE 0
    END,
    'total_execution_time', v_metrics.total_execution_time,
    'avg_case_duration', v_metrics.avg_case_duration,
    'velocity_per_hour', v_velocity,
    'estimated_remaining_seconds', v_eta_seconds,
    'estimated_completion_time', CASE 
      WHEN v_eta_seconds IS NOT NULL 
      THEN NOW() + (v_eta_seconds * INTERVAL '1 second')
      ELSE NULL
    END
  );
END;
$$;


--
-- Name: get_run_progress(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_run_progress(p_run_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN (
    SELECT jsonb_build_object(
      'total_cases', COUNT(*),
      'passed', COUNT(*) FILTER (WHERE result_status = 'passed'),
      'failed', COUNT(*) FILTER (WHERE result_status = 'failed'),
      'blocked', COUNT(*) FILTER (WHERE result_status = 'blocked'),
      'skipped', COUNT(*) FILTER (WHERE result_status = 'skipped'),
      'in_progress', COUNT(*) FILTER (WHERE result_status = 'in_progress'),
      'not_run', COUNT(*) FILTER (WHERE result_status IS NULL),
      'completion_percentage', CASE 
        WHEN COUNT(*) > 0 
        THEN ROUND(((COUNT(*) - COUNT(*) FILTER (WHERE result_status IS NULL))::NUMERIC / COUNT(*)) * 100, 1)
        ELSE 0 
      END,
      'pass_rate', CASE 
        WHEN COUNT(*) FILTER (WHERE result_status IN ('passed', 'failed', 'blocked', 'skipped')) > 0
        THEN ROUND((COUNT(*) FILTER (WHERE result_status = 'passed')::NUMERIC / 
          COUNT(*) FILTER (WHERE result_status IN ('passed', 'failed', 'blocked', 'skipped'))) * 100, 1)
        ELSE 0 
      END,
      'avg_execution_time', COALESCE(
        AVG(EXTRACT(EPOCH FROM (completed_at - started_at)))::INTEGER, 
        0
      ),
      'total_execution_time', COALESCE(
        SUM(EXTRACT(EPOCH FROM (completed_at - started_at)))::INTEGER, 
        0
      )
    )
    FROM test_execution_results
    WHERE run_id = p_run_id
  );
END;
$$;


--
-- Name: get_run_progress_summary(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_run_progress_summary(p_run_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_run RECORD;
  v_progress RECORD;
  v_elapsed_seconds INTEGER;
  v_velocity DECIMAL;
  v_eta_seconds INTEGER;
BEGIN
  -- Get run info
  SELECT * INTO v_run
  FROM test_execution_runs
  WHERE id = p_run_id AND deleted_at IS NULL;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Run not found');
  END IF;

  -- Calculate progress
  SELECT
    COUNT(*) as total,
    COUNT(*) FILTER (WHERE result_status IS NOT NULL) as completed,
    COUNT(*) FILTER (WHERE result_status = 'passed') as passed,
    COUNT(*) FILTER (WHERE result_status = 'failed') as failed,
    COUNT(*) FILTER (WHERE result_status = 'blocked') as blocked,
    COUNT(*) FILTER (WHERE result_status = 'skipped') as skipped,
    COUNT(*) FILTER (WHERE result_status IS NULL AND started_at IS NOT NULL) as running,
    COUNT(*) FILTER (WHERE result_status IS NULL AND started_at IS NULL) as queued
  INTO v_progress
  FROM test_execution_results
  WHERE run_id = p_run_id;

  -- Calculate elapsed time
  v_elapsed_seconds := EXTRACT(EPOCH FROM (COALESCE(v_run.completed_at, NOW()) - v_run.started_at))::INTEGER;

  -- Calculate velocity (tests per hour)
  IF v_elapsed_seconds > 0 AND v_progress.completed > 0 THEN
    v_velocity := ROUND((v_progress.completed::DECIMAL / v_elapsed_seconds) * 3600, 2);
  ELSE
    v_velocity := 0;
  END IF;

  -- Calculate ETA
  IF v_velocity > 0 THEN
    v_eta_seconds := ROUND(((v_progress.queued + v_progress.running) / v_velocity) * 3600);
  ELSE
    v_eta_seconds := NULL;
  END IF;

  RETURN jsonb_build_object(
    'run_id', p_run_id,
    'run_number', v_run.run_number,
    'name', v_run.name,
    'environment', v_run.environment,
    'status', v_run.status,
    'started_at', v_run.started_at,
    'completed_at', v_run.completed_at,
    'total', v_progress.total,
    'completed', v_progress.completed,
    'passed', v_progress.passed,
    'failed', v_progress.failed,
    'blocked', v_progress.blocked,
    'skipped', v_progress.skipped,
    'running', v_progress.running,
    'queued', v_progress.queued,
    'completion_percentage', CASE 
      WHEN v_progress.total > 0 
      THEN ROUND((v_progress.completed::DECIMAL / v_progress.total) * 100, 1)
      ELSE 0
    END,
    'pass_rate', CASE 
      WHEN (v_progress.passed + v_progress.failed + v_progress.blocked) > 0 
      THEN ROUND((v_progress.passed::DECIMAL / (v_progress.passed + v_progress.failed + v_progress.blocked)) * 100, 1)
      ELSE 0
    END,
    'elapsed_seconds', v_elapsed_seconds,
    'velocity_per_hour', v_velocity,
    'eta_seconds', v_eta_seconds
  );
END;
$$;


--
-- Name: get_schema_check(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_schema_check() RETURNS TABLE(table_name text, status text, row_count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  t text;
  cnt bigint;
BEGIN
  FOREACH t IN ARRAY ARRAY[
    'planner_tasks', 'tm_test_cases', 'planner_workstreams', 'profiles', 
    'ph_issues', 'epics', 'stories', 'business_requests', 'incidents',
    'wiki_domains', 'wiki_categories', 'wiki_pages', 'wiki_sections',
    'wiki_references', 'wiki_documents', 'wiki_bookmarks', 'wiki_read_log',
    'wiki_sync_runs', 'kb_embeddings', 'kb_sources', 'kb_training_questions', 'kb_cache'
  ]
  LOOP
    IF EXISTS (SELECT 1 FROM pg_tables WHERE schemaname = 'public' AND tablename = t) THEN
      EXECUTE format('SELECT count(*) FROM %I', t) INTO cnt;
      table_name := t;
      status := 'exists';
      row_count := cnt;
      RETURN NEXT;
    ELSE
      table_name := t;
      status := 'missing';
      row_count := 0;
      RETURN NEXT;
    END IF;
  END LOOP;
END;
$$;


--
-- Name: get_slack_config_safe(); Type: FUNCTION; Schema: public; Owner: -
