--
-- Name: get_slack_integration_stats(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_slack_integration_stats() RETURNS TABLE(total_connected_users bigint, active_connected_users bigint, total_notifications_sent bigint, notifications_last_24h bigint, notifications_last_7d bigint, failed_notifications_24h bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        (SELECT COUNT(*) FROM user_integrations WHERE integration_type = 'slack')::BIGINT,
        (SELECT COUNT(*) FROM user_integrations WHERE integration_type = 'slack' AND is_active = true)::BIGINT,
        (SELECT COUNT(*) FROM notification_delivery_log WHERE channel = 'slack' AND status = 'delivered')::BIGINT,
        (SELECT COUNT(*) FROM notification_delivery_log WHERE channel = 'slack' AND status = 'delivered' AND delivered_at > now() - interval '24 hours')::BIGINT,
        (SELECT COUNT(*) FROM notification_delivery_log WHERE channel = 'slack' AND status = 'delivered' AND delivered_at > now() - interval '7 days')::BIGINT,
        (SELECT COUNT(*) FROM notification_delivery_log WHERE channel = 'slack' AND status = 'failed' AND created_at > now() - interval '24 hours')::BIGINT;
END;
$$;


--
-- Name: get_status_breakdown(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_status_breakdown(p_run_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_breakdown JSONB;
  v_total INTEGER;
BEGIN
  -- Get total
  SELECT COUNT(*) INTO v_total
  FROM test_execution_results
  WHERE run_id = p_run_id;

  IF v_total = 0 THEN
    RETURN jsonb_build_object('error', 'No tests in run');
  END IF;

  -- Calculate breakdown
  SELECT jsonb_build_object(
    'total', v_total,
    'statuses', jsonb_agg(
      jsonb_build_object(
        'status', status,
        'count', cnt,
        'percentage', ROUND((cnt::DECIMAL / v_total) * 100, 1)
      )
    )
  ) INTO v_breakdown
  FROM (
    SELECT 
      COALESCE(result_status, 
        CASE WHEN started_at IS NOT NULL THEN 'running' ELSE 'queued' END
      ) as status,
      COUNT(*) as cnt
    FROM test_execution_results
    WHERE run_id = p_run_id
    GROUP BY 1
    ORDER BY 
      CASE COALESCE(result_status, CASE WHEN started_at IS NOT NULL THEN 'running' ELSE 'queued' END)
        WHEN 'passed' THEN 1
        WHEN 'failed' THEN 2
        WHEN 'blocked' THEN 3
        WHEN 'skipped' THEN 4
        WHEN 'running' THEN 5
        WHEN 'queued' THEN 6
      END
  ) s;

  RETURN v_breakdown;
END;
$$;


--
-- Name: get_step_evidence(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_step_evidence(p_step_result_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_evidence JSONB;
BEGIN
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', e.id,
        'type', e.type,
        'filename', e.filename,
        'original_filename', e.original_filename,
        'storage_path', e.storage_path,
        'file_size', e.file_size,
        'mime_type', e.mime_type,
        'width', e.width,
        'height', e.height,
        'thumbnail_path', e.thumbnail_path,
        'metadata', e.metadata,
        'uploaded_by', jsonb_build_object(
          'id', p.id,
          'name', p.full_name
        ),
        'created_at', e.created_at
      ) ORDER BY e.created_at DESC
    ),
    '[]'::jsonb
  ) INTO v_evidence
  FROM test_step_evidence e
  LEFT JOIN profiles p ON e.uploaded_by = p.id
  WHERE e.step_result_id = p_step_result_id
    AND e.deleted_at IS NULL;

  RETURN jsonb_build_object(
    'evidence', v_evidence,
    'count', jsonb_array_length(v_evidence)
  );
END;
$$;


--
-- Name: get_step_metrics(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_step_metrics(p_execution_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_metrics JSONB;
BEGIN
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'step_id', s.id,
        'step_number', s.step_order,
        'actual_duration', CASE 
          WHEN sr.completed_at IS NOT NULL THEN 
            EXTRACT(EPOCH FROM (sr.completed_at - sr.started_at))::INTEGER
          WHEN sr.is_timer_running THEN
            EXTRACT(EPOCH FROM (NOW() - sr.timer_started_at))::INTEGER - COALESCE(sr.timer_total_paused, 0)
          WHEN sr.timer_paused_at IS NOT NULL THEN
            EXTRACT(EPOCH FROM (sr.timer_paused_at - sr.timer_started_at))::INTEGER - COALESCE(sr.timer_total_paused, 0)
          ELSE NULL
        END,
        'estimated_duration', COALESCE(te.estimated_seconds, 60),
        'result', sr.status,
        'is_timer_running', COALESCE(sr.is_timer_running, false)
      ) ORDER BY s.step_order
    ),
    '[]'::jsonb
  ) INTO v_metrics
  FROM test_steps s
  JOIN test_execution_results er ON s.test_case_id = er.test_case_id
  LEFT JOIN test_execution_step_results sr ON sr.step_id = s.id AND sr.execution_id = er.id
  LEFT JOIN test_time_estimates te ON te.step_id = s.id
  WHERE er.id = p_execution_id;

  RETURN v_metrics;
END;
$$;


--
-- Name: get_tag_stats(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_tag_stats() RETURNS TABLE(total_tags bigint, used_tags bigint, categories bigint, most_used_tag text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COUNT(*)::BIGINT,
    COUNT(*) FILTER (WHERE usage_count > 0)::BIGINT,
    COUNT(DISTINCT category) FILTER (WHERE category IS NOT NULL)::BIGINT,
    (SELECT t2.name FROM th_tags t2 ORDER BY t2.usage_count DESC LIMIT 1)::TEXT
  FROM th_tags;
END;
$$;


--
-- Name: get_test_automation_history(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_test_automation_history(p_test_case_id uuid, p_limit integer DEFAULT 10) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN jsonb_build_object(
    'success', true,
    'results', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', ar.id,
        'status', ar.status,
        'duration_ms', ar.duration_ms,
        'error_message', ar.error_message,
        'run_timestamp', ar.run_timestamp,
        'imported_at', ar.imported_at,
        'connector_name', ac.name,
        'connector_type', ac.connector_type
      ) ORDER BY ar.run_timestamp DESC)
      FROM automation_results ar
      JOIN automation_connectors ac ON ac.id = ar.connector_id
      WHERE ar.test_case_id = p_test_case_id
      LIMIT p_limit
    ), '[]'::JSONB)
  );
END;
$$;


--
-- Name: get_test_case_for_execution_v2(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_test_case_for_execution_v2(p_run_id uuid, p_test_case_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_case RECORD;
  v_steps JSONB;
  v_run RECORD;
BEGIN
  -- Get run info
  SELECT * INTO v_run
  FROM tm_test_runs
  WHERE id = p_run_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Run not found');
  END IF;

  -- Get test case
  SELECT 
    tc.*,
    f.name as folder_name
  INTO v_case
  FROM tm_test_cases tc
  LEFT JOIN tm_folders f ON tc.folder_id = f.id
  WHERE tc.id = p_test_case_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Test case not found');
  END IF;

  -- Get steps with any existing step results
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', s.id,
        'step_number', s.step_number,
        'action', s.action,
        'expected_result', s.expected_result,
        'test_data', s.test_data,
        'result', sr.status,
        'actual_result', sr.actual_result,
        'notes', NULL,
        'duration', sr.duration_seconds,
        'evidence', COALESCE(
          (SELECT jsonb_agg(jsonb_build_object(
            'id', e.id,
            'type', e.mime_type,
            'filename', e.file_name,
            'url', e.storage_path
          ))
          FROM step_result_attachments e
          WHERE e.step_result_id = sr.id),
          '[]'::jsonb
        )
      ) ORDER BY s.step_number
    ),
    '[]'::jsonb
  ) INTO v_steps
  FROM tm_test_steps s
  LEFT JOIN tm_step_results sr ON sr.test_step_id = s.id AND sr.test_run_id = p_run_id
  WHERE s.test_case_id = p_test_case_id;

  RETURN jsonb_build_object(
    'id', v_case.id,
    'case_number', v_case.key,
    'title', v_case.title,
    'description', v_case.objective,
    'priority', v_case.priority,
    'suite_name', COALESCE(v_case.folder_name, 'Uncategorized'),
    'preconditions', COALESCE(v_case.preconditions, ''),
    'steps', v_steps,
    'execution', jsonb_build_object(
      'id', v_run.id,
      'execution_order', 1,
      'overall_result', v_run.status,
      'started_at', v_run.executed_at,
      'completed_at', CASE WHEN v_run.status IN ('passed', 'failed', 'blocked') THEN v_run.executed_at END,
      'total_duration', v_run.duration_seconds
    ),
    'run', jsonb_build_object(
      'id', v_run.id,
      'run_number', 1,
      'name', v_case.title,
      'environment', COALESCE(v_run.environment_details, 'default'),
      'configuration', jsonb_build_object()
    )
  );
END;
$$;


--
-- Name: get_test_case_tags(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_test_case_tags(p_test_case_id uuid) RETURNS TABLE(tag_id uuid, name text, slug text, color text, category text)
