-- Name: get_test_requirements(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_test_requirements(p_test_case_id uuid) RETURNS TABLE(link_id uuid, requirement_id uuid, req_key text, title text, type text, priority text, status text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    rt.id as link_id,
    r.id as requirement_id,
    r.req_key::TEXT,
    r.title::TEXT,
    r.type::TEXT,
    r.priority::TEXT,
    r.status::TEXT
