--
-- Name: get_top_failing_tests(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_top_failing_tests(p_limit integer DEFAULT 10) RETURNS TABLE(test_case_id uuid, case_key text, title text, priority text, failure_count bigint, last_failed timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    tc.id,
    tc.case_key::TEXT,
    tc.title::TEXT,
    tc.priority::TEXT,
    COUNT(*)::BIGINT,
    MAX(ctc.executed_at)
  FROM th_cycle_test_cases ctc
  JOIN th_test_cases tc ON tc.id = ctc.test_case_id
  WHERE ctc.execution_status = 'failed'
  GROUP BY tc.id, tc.case_key, tc.title, tc.priority
  ORDER BY COUNT(*) DESC, MAX(ctc.executed_at) DESC
  LIMIT p_limit;
END;
$$;


--
-- Name: get_trend_data(uuid, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_trend_data(p_run_id uuid, p_interval_minutes integer DEFAULT 5, p_points integer DEFAULT 12) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_run RECORD;
  v_trend JSONB;
BEGIN
  -- Get run start time
  SELECT * INTO v_run
  FROM test_execution_runs
  WHERE id = p_run_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Run not found');
  END IF;

  -- Generate time series data
  WITH time_buckets AS (
    SELECT generate_series(
      date_trunc('minute', v_run.started_at),
      NOW(),
      (p_interval_minutes || ' minutes')::INTERVAL
    ) as bucket_time
  ),
  bucket_stats AS (
    SELECT 
      tb.bucket_time,
      COUNT(*) FILTER (WHERE er.completed_at <= tb.bucket_time AND er.result_status = 'passed') as passed,
      COUNT(*) FILTER (WHERE er.completed_at <= tb.bucket_time AND er.result_status IN ('passed', 'failed', 'blocked')) as total_completed
    FROM time_buckets tb
    LEFT JOIN test_execution_results er ON er.run_id = p_run_id
    GROUP BY tb.bucket_time
    ORDER BY tb.bucket_time DESC
    LIMIT p_points
  )
  SELECT jsonb_build_object(
    'data_points', COALESCE(jsonb_agg(
      jsonb_build_object(
        'timestamp', bucket_time,
        'pass_rate', CASE 
          WHEN total_completed > 0 
          THEN ROUND((passed::DECIMAL / total_completed) * 100, 1)
          ELSE 0
        END,
        'completed', total_completed
      ) ORDER BY bucket_time ASC
    ), '[]'::jsonb)
  ) INTO v_trend
  FROM bucket_stats;

  RETURN COALESCE(v_trend, jsonb_build_object('data_points', '[]'::jsonb));
END;
$$;


--
-- Name: get_unassigned_cycles(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_unassigned_cycles() RETURNS TABLE(id uuid, cycle_key text, name text, status text, total_cases integer, progress_percent integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    c.id,
    c.cycle_key,
    c.name,
    c.status::TEXT,
    c.total_cases,
    c.progress_percent
  FROM th_test_cycles c
  WHERE NOT EXISTS (
    SELECT 1 FROM th_plan_cycles pc WHERE pc.cycle_id = c.id
  )
  ORDER BY c.created_at DESC;
END;
$$;


--
-- Name: get_unassigned_cycles(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_unassigned_cycles(p_project_id uuid, p_plan_id uuid) RETURNS TABLE(id uuid, cycle_key text, name text, status text, total_cases integer, passed_count integer, failed_count integer, blocked_count integer)
    LANGUAGE sql STABLE
    AS $$
  SELECT
    c.id,
    c.cycle_key::TEXT,
    c.name::TEXT,
    c.status::TEXT,
    COALESCE(c.total_cases, 0)::INT,
    COALESCE(c.passed_count, 0)::INT,
    COALESCE(c.failed_count, 0)::INT,
    COALESCE(c.blocked_count, 0)::INT
  FROM th_test_cycles c
  WHERE c.id NOT IN (SELECT pc.cycle_id FROM th_plan_cycles pc WHERE pc.plan_id = p_plan_id)
  ORDER BY c.created_at DESC;
$$;


--
-- Name: get_unassigned_task_count(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_unassigned_task_count() RETURNS integer
    LANGUAGE sql STABLE
    AS $$
  SELECT COUNT(*)::INTEGER
  FROM planner_tasks pt
  JOIN planner_statuses ps ON pt.status_id = ps.id
  WHERE pt.assignee_id IS NULL
    AND ps.is_completed_status = false
    AND pt.deleted_at IS NULL;
$$;


--
-- Name: get_unlinked_test_cases(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_unlinked_test_cases() RETURNS TABLE(id uuid, case_key text, title text, priority text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT tc.id, tc.case_key::TEXT, tc.title::TEXT, tc.priority::TEXT
  FROM th_test_cases tc
  WHERE NOT EXISTS (
    SELECT 1 FROM th_requirement_tests rt WHERE rt.test_case_id = tc.id
  )
  ORDER BY tc.case_key;
END;
$$;


--
-- Name: get_unmapped_tests(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_unmapped_tests(p_connector_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN jsonb_build_object(
    'success', true,
    'unmapped', COALESCE((
      SELECT jsonb_agg(row_data ORDER BY run_count DESC)
      FROM (
        SELECT jsonb_build_object(
          'external_test_id', ar.external_test_id,
          'external_test_name', MAX(ar.external_test_name),
          'last_status', (array_agg(ar.status ORDER BY ar.imported_at DESC))[1],
          'run_count', COUNT(*)::INTEGER
        ) as row_data, COUNT(*) as run_count
        FROM automation_results ar
        WHERE ar.connector_id = p_connector_id AND ar.test_case_id IS NULL
        GROUP BY ar.external_test_id
      ) sub
    ), '[]'::JSONB)
  );
END;
$$;


