--
-- Name: th_user_preferences; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.th_user_preferences (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    user_id uuid NOT NULL,
    theme character varying(20) DEFAULT 'light'::character varying,
    density character varying(20) DEFAULT 'comfortable'::character varying,
    sidebar_collapsed boolean DEFAULT false,
    default_landing_page character varying(100) DEFAULT '/testhub/dashboard'::character varying,
    default_page_size integer DEFAULT 25,
    show_archived boolean DEFAULT false,
    auto_advance_on_status boolean DEFAULT true,
    confirm_status_change boolean DEFAULT true,
    default_cycle_view character varying(20) DEFAULT 'list'::character varying,
    email_on_assignment boolean DEFAULT true,
    email_on_cycle_complete boolean DEFAULT true,
    email_on_defect_update boolean DEFAULT false,
