    updated_at timestamp with time zone DEFAULT now()
);


--
-- Name: get_user_preferences(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_preferences(p_user_id uuid) RETURNS SETOF public.th_user_preferences
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_prefs th_user_preferences;
BEGIN
  SELECT * INTO v_prefs FROM th_user_preferences WHERE user_id = p_user_id;
  
  IF NOT FOUND THEN
    INSERT INTO th_user_preferences (user_id) VALUES (p_user_id)
    RETURNING * INTO v_prefs;
  END IF;
  
  RETURN NEXT v_prefs;
END;
$$;


