--
-- Name: get_wiki_diagnostic_summary(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_wiki_diagnostic_summary() RETURNS jsonb
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT jsonb_build_object(
    'total_chunks', (SELECT count(*) FROM kb_embeddings),
    'source_types', (SELECT count(DISTINCT source_type) FROM kb_embeddings),
    'source_tables', (SELECT count(DISTINCT metadata->>'table') FROM kb_embeddings),
    'domains', (SELECT count(*) FROM wiki_domains),
    'categories', (SELECT count(*) FROM wiki_categories),
    'pages', (SELECT count(*) FROM wiki_pages),
    'published_pages', (SELECT count(*) FROM wiki_pages WHERE status = 'published'),
    'sections', (SELECT count(*) FROM wiki_sections),
    'references', (SELECT count(*) FROM wiki_references),
    'documents', (SELECT count(*) FROM wiki_documents),
    'bookmarks', (SELECT count(*) FROM wiki_bookmarks),
    'read_log', (SELECT count(*) FROM wiki_read_log),
    'sync_runs', (SELECT count(*) FROM wiki_sync_runs),
    'last_sync', (SELECT max(started_at) FROM wiki_sync_runs),
    'last_sync_status', (SELECT status FROM wiki_sync_runs ORDER BY started_at DESC LIMIT 1)
  );
$$;


--
-- Name: get_wiki_domain_cards(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_wiki_domain_cards() RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE result JSON;
BEGIN
  SELECT json_agg(row_data ORDER BY d.sort_order) INTO result
  FROM wiki_domains d
  CROSS JOIN LATERAL (
    SELECT json_build_object(
      'code', d.domain_code, 'name', d.name, 'name_ar', d.name_ar,
      'description', d.description, 'icon', d.icon, 'tag', d.tag,
      'article_count', (SELECT COUNT(*) FROM wiki_pages WHERE domain_code = d.domain_code AND deleted_at IS NULL),
      'document_count', (SELECT COUNT(*) FROM wiki_documents WHERE domain_code = d.domain_code),
      'view_count', (SELECT COALESCE(SUM(view_count), 0) FROM wiki_pages WHERE domain_code = d.domain_code AND deleted_at IS NULL),
      'knowledge_gaps', (SELECT COUNT(*) FROM wiki_knowledge_requests WHERE domain_code = d.domain_code AND status IN ('open', 'in_progress') AND deleted_at IS NULL),
      'freshness_percent', (
        SELECT CASE WHEN COUNT(*) = 0 THEN 100
          ELSE ROUND(100.0 * COUNT(*) FILTER (WHERE updated_at > now() - interval '90 days') / COUNT(*), 0)
        END FROM wiki_pages WHERE domain_code = d.domain_code AND deleted_at IS NULL
      ),
      'coverage_percent', (
        SELECT CASE WHEN COUNT(*) = 0 THEN 0
          ELSE ROUND(100.0 * COUNT(*) FILTER (WHERE verification_status = 'verified') / COUNT(*), 0)
        END FROM wiki_pages WHERE domain_code = d.domain_code AND deleted_at IS NULL
      )
    ) AS row_data
  ) sub;
  RETURN COALESCE(result, '[]'::json);
END; $$;


--
-- Name: get_wiki_home_stats(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_wiki_home_stats() RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE result JSON;
BEGIN
  SELECT json_build_object(
    'total_articles', (SELECT COUNT(*) FROM wiki_pages WHERE deleted_at IS NULL AND status = 'published'),
    'total_documents', (SELECT COUNT(*) FROM wiki_documents),
    'verified_articles', (SELECT COUNT(*) FROM wiki_pages WHERE deleted_at IS NULL AND verification_status = 'verified'),
    'needs_review', (SELECT COUNT(*) FROM wiki_pages WHERE deleted_at IS NULL AND verification_status = 'needs_review'),
    'unverified', (SELECT COUNT(*) FROM wiki_pages WHERE deleted_at IS NULL AND verification_status = 'unverified'),
    'stale_articles', (SELECT COUNT(*) FROM wiki_pages WHERE deleted_at IS NULL AND updated_at < now() - interval '90 days'),
    'open_requests', (SELECT COUNT(*) FROM wiki_knowledge_requests WHERE status IN ('open', 'in_progress') AND deleted_at IS NULL),
    'avg_helpfulness', (SELECT COALESCE(ROUND(AVG(helpfulness_score), 1), 0) FROM wiki_pages WHERE deleted_at IS NULL AND helpfulness_votes > 0),
    'avg_confidence', (SELECT COALESCE(ROUND(AVG(ai_confidence), 1), 0) FROM wiki_pages WHERE deleted_at IS NULL AND ai_confidence > 0),
    'verified_percent', (
      SELECT CASE WHEN COUNT(*) = 0 THEN 0
        ELSE ROUND(100.0 * COUNT(*) FILTER (WHERE verification_status = 'verified') / COUNT(*), 1)
      END FROM wiki_pages WHERE deleted_at IS NULL
    )
  ) INTO result;
  RETURN result;
END; $$;


--
-- Name: get_worker_activity(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_worker_activity(p_run_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_workers JSONB;
BEGIN
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', w.id,
        'worker_number', w.worker_number,
        'status', w.status,
        'current_test', CASE 
          WHEN w.current_test_id IS NOT NULL THEN jsonb_build_object(
            'id', tc.id,
            'case_number', tc.case_number,
            'title', tc.title
          )
          ELSE NULL
        END,
        'progress', CASE
          WHEN w.current_execution_id IS NOT NULL AND w.claimed_at IS NOT NULL THEN
            LEAST(
              ROUND(
                (EXTRACT(EPOCH FROM (NOW() - w.claimed_at)) / 120) * 100
              ),
              99
            )
          ELSE 0
        END,
        'claimed_at', w.claimed_at,
        'last_heartbeat', w.last_heartbeat,
        'completed_count', w.completed_count,
        'failed_count', w.failed_count,
        'is_healthy', (w.last_heartbeat > NOW() - INTERVAL '60 seconds')
      ) ORDER BY w.worker_number
    ),
    '[]'::jsonb
  ) INTO v_workers
  FROM parallel_workers w
  LEFT JOIN test_cases tc ON w.current_test_id = tc.id
  WHERE w.run_id = p_run_id;

  RETURN v_workers;
END;
$$;


--
-- Name: get_worker_pools(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_worker_pools(p_project_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_pools JSONB;
BEGIN
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', p.id,
        'name', p.name,
        'description', p.description,
        'total_workers', p.total_workers,
        'available_workers', p.available_workers,
        'assigned_workers', p.assigned_workers,
        'utilization_percentage', ROUND((p.assigned_workers::DECIMAL / NULLIF(p.total_workers, 0)) * 100, 1),
        'priority', p.priority,
        'is_default', p.is_default
      ) ORDER BY p.priority DESC, p.name
    ),
    '[]'::jsonb
  ) INTO v_pools
  FROM worker_pools p
  WHERE p.project_id = p_project_id;

  RETURN v_pools;
END;
$$;


--
-- Name: get_worker_status(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_worker_status(p_run_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_workers JSONB;
BEGIN
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', w.id,
        'worker_number', w.worker_number,
        'status', w.status,
        'current_test', CASE 
          WHEN w.current_test_id IS NOT NULL THEN jsonb_build_object(
            'id', tc.id,
            'case_number', tc.case_number,
            'title', tc.title
          )
          ELSE NULL
        END,
        'claimed_at', w.claimed_at,
        'last_heartbeat', w.last_heartbeat,
        'completed_count', w.completed_count,
        'failed_count', w.failed_count,
        'total_execution_time', w.total_execution_time,
        'is_healthy', (w.last_heartbeat > NOW() - INTERVAL '60 seconds')
      ) ORDER BY w.worker_number
    ),
    '[]'::jsonb
  ) INTO v_workers
  FROM parallel_workers w
  LEFT JOIN test_cases tc ON w.current_test_id = tc.id
  WHERE w.run_id = p_run_id;

  RETURN v_workers;
END;
$$;


--
-- Name: governance_exclusion_check(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.governance_exclusion_check(p_item_key text) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1 FROM governance_closure_log
    WHERE item_key = p_item_key
      AND restored_at IS NULL
  );
$$;


--
-- Name: governance_force_close(uuid, text, uuid, text, integer, text, text, boolean, boolean, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.governance_force_close(p_issue_id uuid, p_item_key text, p_closed_by uuid, p_category text, p_stale_days integer, p_closure_reason text, p_original_status text, p_jira_attempted boolean DEFAULT false, p_jira_success boolean DEFAULT false, p_jira_error text DEFAULT NULL::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
  v_log_id UUID;
  v_restore_deadline TIMESTAMPTZ := now() + INTERVAL '90 days';
BEGIN
  -- Insert governance lock
  INSERT INTO governance_closure_log (
    item_key, issue_id, closed_by, closed_at,
    governance_category, stale_days, closure_reason,
    restore_deadline, original_status, restored_at,
    metadata
  ) VALUES (
    p_item_key, p_issue_id, p_closed_by, now(),
    CASE WHEN p_category ~ '^\d+$' THEN p_category::INT ELSE NULL END,
    p_stale_days, p_closure_reason,
    v_restore_deadline, p_original_status, NULL,
    jsonb_build_object(
      'jira_attempted', p_jira_attempted,
      'jira_success', p_jira_success,
      'jira_error', p_jira_error
    )
  )
  RETURNING id INTO v_log_id;

  -- Update ph_issues to governance-closed status
  UPDATE ph_issues SET
    status = 'GOVERNANCE_CLOSED',
    status_category = 'done'
  WHERE id = p_issue_id;

  -- Also update catalyst_issues if row exists
  UPDATE catalyst_issues SET
    status = 'done',
    closure_method = 'force_bypass',
    force_closed_by = p_closed_by,
    force_closed_at = now(),
    force_close_reason = p_closure_reason,
    restore_deadline = v_restore_deadline
  WHERE id = p_issue_id;

  RETURN v_log_id;
END;
$_$;


--
-- Name: governance_locked_keys(text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.governance_locked_keys(p_item_keys text[]) RETURNS TABLE(locked_key text)
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT item_key AS locked_key
  FROM governance_closure_log
  WHERE item_key = ANY(p_item_keys)
    AND restored_at IS NULL;
$$;


--
-- Name: governance_restore(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.governance_restore(p_log_id uuid, p_restored_by uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_issue_id UUID;
  v_original_status TEXT;
BEGIN
  -- Mark as restored
  UPDATE governance_closure_log
  SET restored_at = now(), restored_by = p_restored_by
  WHERE id = p_log_id AND restored_at IS NULL
  RETURNING issue_id, original_status
  INTO v_issue_id, v_original_status;

  IF v_issue_id IS NULL THEN
    RAISE EXCEPTION 'Log entry not found or already restored';
  END IF;

  -- Restore ph_issues status
  UPDATE ph_issues SET
    status = COALESCE(v_original_status, 'To Do'),
    status_category = 'new'
  WHERE id = v_issue_id;

  -- Restore catalyst_issues if exists
  UPDATE catalyst_issues SET
    status = COALESCE(v_original_status, 'To Do'),
    closure_method = 'normal',
    force_closed_by = NULL,
    force_closed_at = NULL
  WHERE id = v_issue_id;
END;
$$;


