--
-- Name: hi_validate_hierarchy_move(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.hi_validate_hierarchy_move(p_node_id uuid, p_new_parent_id uuid) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
declare
    node_level int;
    parent_level int;
begin
    select hierarchy_level into node_level from hi_work_items where id = p_node_id;
    select hierarchy_level into parent_level from hi_work_items where id = p_new_parent_id;
    case node_level
        when 2 then if parent_level != 1 then return false; end if;
        when 3 then if parent_level not in (1, 2) then return false; end if;
        when 4 then if parent_level != 3 then return false; end if;
        else return false;
    end case;
    if exists (
        with recursive ancestors as (
            select id, parent_id from hi_work_items where id = p_new_parent_id
            union all
            select wi.id, wi.parent_id from hi_work_items wi join ancestors a on wi.id = a.parent_id
        )
        select 1 from ancestors where id = p_node_id
    ) then return false; end if;
    return true;
end;
$$;


--
-- Name: hi_validate_parent_level(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.hi_validate_parent_level() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
declare
    parent_level int;
begin
    if new.parent_id is null then
        if new.hierarchy_level != 1 then
            raise exception 'Only Epics (level 1) can exist without a parent';
        end if;
        return new;
    end if;
    select hierarchy_level into parent_level from hi_work_items where id = new.parent_id;
    case new.hierarchy_level
        when 2 then
            if parent_level != 1 then
                raise exception 'Feature must be child of Epic (got level %)', parent_level;
            end if;
        when 3 then
            if parent_level not in (1, 2) then
                raise exception 'Story must be child of Epic or Feature (got level %)', parent_level;
            end if;
        when 4 then
            if parent_level != 3 then
                raise exception 'Sub-task must be child of Story (got level %)', parent_level;
            end if;
        else null;
    end case;
    return new;
end;
$$;


--
-- Name: import_automation_results(uuid, jsonb, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.import_automation_results(p_connector_id uuid, p_results jsonb, p_source_file_name text DEFAULT NULL::text, p_source_format text DEFAULT 'junit'::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_job_id UUID;
  v_result JSONB;
  v_test_case_id UUID;
  v_imported INTEGER := 0;
  v_mapped INTEGER := 0;
BEGIN
  -- Create import job
  INSERT INTO automation_import_jobs (connector_id, status, source_file_name, source_format, total_count, created_by)
  VALUES (p_connector_id, 'processing', p_source_file_name, p_source_format, jsonb_array_length(p_results), auth.uid())
  RETURNING id INTO v_job_id;

  -- Process each result
  FOR v_result IN SELECT * FROM jsonb_array_elements(p_results)
  LOOP
    -- Check for existing mapping
    SELECT test_case_id INTO v_test_case_id
    FROM automation_test_mappings
    WHERE connector_id = p_connector_id AND external_test_id = v_result->>'external_test_id';

    -- Insert result
    INSERT INTO automation_results (
      connector_id, test_case_id, external_test_id, external_test_name,
      status, duration_ms, error_message, stack_trace, metadata, run_timestamp
    ) VALUES (
      p_connector_id, v_test_case_id, v_result->>'external_test_id', v_result->>'external_test_name',
      v_result->>'status', (v_result->>'duration_ms')::INTEGER,
      v_result->>'error_message', v_result->>'stack_trace',
      COALESCE(v_result->'metadata', '{}'), COALESCE((v_result->>'run_timestamp')::TIMESTAMPTZ, now())
    );

    v_imported := v_imported + 1;
    IF v_test_case_id IS NOT NULL THEN v_mapped := v_mapped + 1; END IF;
  END LOOP;

  -- Update job
  UPDATE automation_import_jobs SET
    status = 'completed',
    imported_count = v_imported,
    mapped_count = v_mapped,
    completed_at = now()
  WHERE id = v_job_id;

  RETURN jsonb_build_object(
    'success', true,
    'job_id', v_job_id,
    'imported', v_imported,
    'mapped', v_mapped
  );
END;
$$;


--
-- Name: import_test_cases_from_json(uuid, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.import_test_cases_from_json(p_job_id uuid, p_data jsonb) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_row JSONB;
  v_success INTEGER := 0;
  v_errors INTEGER := 0;
  v_error_list JSONB := '[]'::JSONB;
  v_case_id UUID;
  v_row_num INTEGER := 0;
BEGIN
  FOR v_row IN SELECT * FROM jsonb_array_elements(p_data)
  LOOP
    v_row_num := v_row_num + 1;
    BEGIN
      INSERT INTO th_test_cases (
        title, description, priority, status, preconditions, expected_result, folder_id
      ) VALUES (
        v_row->>'title',
        v_row->>'description',
        COALESCE(v_row->>'priority', 'medium'),
        COALESCE(v_row->>'status', 'draft'),
        v_row->>'preconditions',
        v_row->>'expected_result',
        (v_row->>'folder_id')::UUID
      )
      RETURNING id INTO v_case_id;
      v_success := v_success + 1;
    EXCEPTION WHEN OTHERS THEN
      v_errors := v_errors + 1;
      v_error_list := v_error_list || jsonb_build_object('row', v_row_num, 'error', SQLERRM, 'data', v_row);
    END;
  END LOOP;

  UPDATE th_import_jobs SET
    status = 'completed',
    processed_rows = v_row_num,
    success_count = v_success,
    error_count = v_errors,
    errors = v_error_list,
    completed_at = NOW()
  WHERE id = p_job_id;

  RETURN jsonb_build_object('success', v_success, 'errors', v_errors, 'total', v_row_num);
END;
$$;


