--
-- Name: invite_project_member(uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.invite_project_member(p_project_id uuid, p_email text, p_role text DEFAULT 'member'::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_invitation_id UUID;
  v_existing_user_id UUID;
BEGIN
  -- Check if inviter is admin
  IF NOT EXISTS (
    SELECT 1 FROM public.project_members 
    WHERE project_id = p_project_id 
    AND user_id = v_user_id 
    AND role = 'admin'
  ) THEN
    RAISE EXCEPTION 'Only admins can invite members';
  END IF;
  
  -- Check if user with this email already exists and is already a member
  SELECT id INTO v_existing_user_id FROM public.profiles WHERE email = p_email;
  
  IF v_existing_user_id IS NOT NULL THEN
    IF EXISTS (
      SELECT 1 FROM public.project_members 
      WHERE project_id = p_project_id AND user_id = v_existing_user_id
    ) THEN
      RAISE EXCEPTION 'User is already a member of this project';
    END IF;
    
    -- Add existing user directly
    INSERT INTO public.project_members (project_id, user_id, role, invited_by)
    VALUES (p_project_id, v_existing_user_id, p_role, v_user_id);
    
    RETURN NULL; -- No invitation needed
  END IF;
  
  -- Create invitation for non-existing user
  INSERT INTO public.project_invitations (project_id, email, role, invited_by)
  VALUES (p_project_id, p_email, p_role, v_user_id)
  ON CONFLICT (project_id, email) DO UPDATE 
  SET role = p_role, invited_by = v_user_id, expires_at = NOW() + INTERVAL '7 days'
  RETURNING id INTO v_invitation_id;
  
  RETURN v_invitation_id;
END;
$$;


