--
-- Name: jsonb_to_text_array(jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.jsonb_to_text_array(val jsonb) RETURNS text[]
    LANGUAGE sql IMMUTABLE
    SET search_path TO 'public'
    AS $$
  SELECT CASE
    WHEN val IS NULL OR val = 'null'::JSONB THEN NULL
    WHEN jsonb_typeof(val) = 'array' THEN ARRAY(SELECT jsonb_array_elements_text(val))
    ELSE NULL
  END;
$$;


--
-- Name: kb_cache_hit(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.kb_cache_hit(p_query_hash text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  cached_response JSONB;
BEGIN
  UPDATE public.kb_cache
  SET hit_count = hit_count + 1, last_hit_at = now()
  WHERE query_hash = p_query_hash
    AND created_at > now() - (ttl_hours || ' hours')::INTERVAL
  RETURNING response_json INTO cached_response;
  RETURN cached_response;
END;
$$;


