--
-- Name: kb_match_embeddings(extensions.vector, double precision, integer, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.kb_match_embeddings(query_embedding extensions.vector, match_threshold double precision DEFAULT 0.5, match_count integer DEFAULT 10, filter_source text DEFAULT NULL::text) RETURNS TABLE(id uuid, content text, source_type text, source_url text, metadata jsonb, similarity double precision)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    e.id,
    e.content,
    e.source_type,
    e.source_url,
    e.metadata,
    (1 - (e.embedding::vector(1536) <=> query_embedding::vector(1536)))::float AS similarity
  FROM public.kb_embeddings e
  WHERE (filter_source IS NULL OR e.source_type = filter_source)
    AND (1 - (e.embedding::vector(1536) <=> query_embedding::vector(1536))) > match_threshold
  ORDER BY e.embedding::vector(1536) <=> query_embedding::vector(1536)
  LIMIT match_count;
END;
$$;


--
-- Name: kb_match_training(extensions.vector, double precision, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.kb_match_training(query_embedding extensions.vector, match_threshold double precision DEFAULT 0.85, match_count integer DEFAULT 5) RETURNS TABLE(id uuid, question_number integer, question text, category text, expected_answer text, similarity double precision)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    t.id,
    t.question_number,
    t.question,
    t.category,
    t.expected_answer,
    (1 - (t.embedding::vector(1536) <=> query_embedding::vector(1536)))::double precision AS similarity
  FROM public.kb_training_questions t
  WHERE t.embedding IS NOT NULL
    AND (1 - (t.embedding::vector(1536) <=> query_embedding::vector(1536))) > match_threshold
  ORDER BY t.embedding::vector(1536) <=> query_embedding::vector(1536)
  LIMIT match_count;
END;
$$;


