--
-- Name: link_defect_to_step_v2(uuid, uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.link_defect_to_step_v2(p_defect_id uuid, p_step_result_id uuid, p_run_id uuid DEFAULT NULL::uuid, p_link_type text DEFAULT 'manual'::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_link_id UUID;
  v_actor UUID := auth.uid();
  v_defect_key TEXT;
BEGIN
  -- Validate defect exists
  SELECT key INTO v_defect_key
  FROM tm_defects
  WHERE id = p_defect_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Defect not found');
  END IF;

  -- Validate step result exists
  IF NOT EXISTS (SELECT 1 FROM tm_step_results WHERE id = p_step_result_id) THEN
    RETURN jsonb_build_object('error', 'Step result not found');
  END IF;

  -- Check if already linked
  IF EXISTS (
    SELECT 1 FROM tm_defect_links 
    WHERE defect_id = p_defect_id AND step_result_id = p_step_result_id
  ) THEN
    RETURN jsonb_build_object('error', 'Defect is already linked to this step');
  END IF;

  -- Create link
  INSERT INTO tm_defect_links (
    defect_id,
    step_result_id,
    run_id,
    linked_by,
    link_type
  ) VALUES (
    p_defect_id,
    p_step_result_id,
    p_run_id,
    v_actor,
    COALESCE(p_link_type, 'manual')
  )
  RETURNING id INTO v_link_id;

  RETURN jsonb_build_object(
    'success', true,
    'link_id', v_link_id,
    'defect_key', v_defect_key
  );
END;
$$;


--
-- Name: log_activity(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_activity() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Only log if there's an authenticated user
  IF auth.uid() IS NULL THEN
    RETURN NEW;
  END IF;

  -- Insert activity log
  INSERT INTO public.activity_logs (
    entity_type,
    entity_id,
    action,
    actor_id,
    before_json,
    after_json
  ) VALUES (
    TG_TABLE_NAME,
    COALESCE(NEW.id, OLD.id),
    TG_OP,
    auth.uid(),
    CASE WHEN TG_OP IN ('UPDATE', 'DELETE') THEN row_to_json(OLD) ELSE NULL END,
    CASE WHEN TG_OP IN ('INSERT', 'UPDATE') THEN row_to_json(NEW) ELSE NULL END
  );

  RETURN NEW;
END;
$$;


--
-- Name: log_audit_event(character varying, character varying, uuid, text, text, jsonb, jsonb, text[], character varying, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_audit_event(p_action character varying, p_entity_type character varying, p_entity_id uuid DEFAULT NULL::uuid, p_entity_key text DEFAULT NULL::text, p_entity_name text DEFAULT NULL::text, p_old_values jsonb DEFAULT NULL::jsonb, p_new_values jsonb DEFAULT NULL::jsonb, p_changed_fields text[] DEFAULT NULL::text[], p_parent_type character varying DEFAULT NULL::character varying, p_parent_id uuid DEFAULT NULL::uuid, p_notes text DEFAULT NULL::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
  v_user_email TEXT;
  v_user_name TEXT;
  v_audit_id UUID;
BEGIN
  v_user_id := auth.uid();
  
  IF v_user_id IS NOT NULL THEN
    SELECT email, full_name INTO v_user_email, v_user_name
    FROM profiles WHERE id = v_user_id;
  END IF;

  INSERT INTO th_audit_log (
    user_id, user_email, user_name,
    action, entity_type, entity_id, entity_key, entity_name,
    old_values, new_values, changed_fields,
    parent_entity_type, parent_entity_id, notes
  ) VALUES (
    v_user_id, v_user_email, v_user_name,
    p_action, p_entity_type, p_entity_id, p_entity_key, p_entity_name,
    p_old_values, p_new_values, p_changed_fields,
    p_parent_type, p_parent_id, p_notes
  )
  RETURNING id INTO v_audit_id;

  RETURN v_audit_id;
END;
$$;


--
-- Name: log_budget_changes(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_budget_changes() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO ph_initiative_audit_log(initiative_id, user_id, action, entity_type, entity_id, metadata)
    VALUES (NEW.initiative_id, auth.uid(), 'budget_item_added', 'budget_item', NEW.id,
      jsonb_build_object('category', NEW.category, 'expense_type', NEW.expense_type, 
        'planned_amount', NEW.planned_amount::TEXT, 'description', NEW.description));
    RETURN NEW;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    IF OLD.status IS DISTINCT FROM NEW.status THEN
      INSERT INTO ph_initiative_audit_log(initiative_id, user_id, action, entity_type, entity_id, field_name, old_value, new_value, metadata)
      VALUES (NEW.initiative_id, auth.uid(), 'updated', 'budget_item', NEW.id, 'status', OLD.status, NEW.status,
        jsonb_build_object('description', NEW.description, 'planned_amount', NEW.planned_amount::TEXT));
    END IF;
    IF OLD.actual_amount IS DISTINCT FROM NEW.actual_amount THEN
      INSERT INTO ph_initiative_audit_log(initiative_id, user_id, action, entity_type, entity_id, field_name, old_value, new_value, metadata)
      VALUES (NEW.initiative_id, auth.uid(), 'updated', 'budget_item', NEW.id, 'actual_amount', 
        OLD.actual_amount::TEXT, NEW.actual_amount::TEXT,
        jsonb_build_object('description', NEW.description));
    END IF;
    RETURN NEW;
  END IF;

  IF TG_OP = 'DELETE' THEN
    INSERT INTO ph_initiative_audit_log(initiative_id, user_id, action, entity_type, entity_id, metadata)
    VALUES (OLD.initiative_id, auth.uid(), 'deleted', 'budget_item', OLD.id,
      jsonb_build_object('description', OLD.description, 'planned_amount', OLD.planned_amount::TEXT));
    RETURN OLD;
  END IF;

  RETURN NULL;
END;
$$;


