--
-- Name: log_committee_status_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_committee_status_change() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Log when status changes to Committee
  IF NEW.status = 'to_committee' AND (OLD.status IS NULL OR OLD.status != 'to_committee') THEN
    INSERT INTO public.incident_history (
      incident_id,
      field_name,
      old_value,
      new_value,
      changed_by,
      changed_at
    ) VALUES (
      NEW.id,
      'status',
      OLD.status::text,
      'to_committee',
      auth.uid(),
      NOW()
    );
  END IF;
  
  -- Log when committee_id changes (approvers configured)
  IF NEW.committee_id IS DISTINCT FROM OLD.committee_id AND NEW.committee_id IS NOT NULL THEN
    INSERT INTO public.incident_history (
      incident_id,
      field_name,
      old_value,
      new_value,
      changed_by,
      changed_at
    ) VALUES (
      NEW.id,
      'committee_approvers',
      CASE WHEN OLD.committee_id IS NULL THEN 'None' ELSE OLD.committee_id::text END,
      'Committee configured: ' || NEW.committee_id::text,
      auth.uid(),
      NOW()
    );
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- Name: log_defect_history(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_defect_history() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF OLD.status IS DISTINCT FROM NEW.status THEN
    INSERT INTO th_defect_history (defect_id, field_changed, old_value, new_value, changed_by)
    VALUES (NEW.id, 'status', OLD.status, NEW.status, NEW.assigned_to);
  END IF;
  IF OLD.severity IS DISTINCT FROM NEW.severity THEN
    INSERT INTO th_defect_history (defect_id, field_changed, old_value, new_value, changed_by)
    VALUES (NEW.id, 'severity', OLD.severity, NEW.severity, NEW.assigned_to);
  END IF;
  IF OLD.priority IS DISTINCT FROM NEW.priority THEN
    INSERT INTO th_defect_history (defect_id, field_changed, old_value, new_value, changed_by)
    VALUES (NEW.id, 'priority', OLD.priority, NEW.priority, NEW.assigned_to);
  END IF;
  IF OLD.assigned_to IS DISTINCT FROM NEW.assigned_to THEN
    INSERT INTO th_defect_history (defect_id, field_changed, old_value, new_value, changed_by)
    VALUES (NEW.id, 'assigned_to', OLD.assigned_to::TEXT, NEW.assigned_to::TEXT, NEW.assigned_to);
  END IF;
  NEW.updated_at := NOW();
  IF NEW.status = 'fixed' AND OLD.status != 'fixed' THEN
    NEW.resolved_at := NOW();
  END IF;
  IF NEW.status = 'verified' AND OLD.status != 'verified' THEN
    NEW.verified_at := NOW();
  END IF;
  IF NEW.status = 'reopened' THEN
    NEW.resolved_at := NULL;
    NEW.verified_at := NULL;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: log_dependency_changes(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_dependency_changes() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO public.dependency_audit_log (dependency_id, changed_by, action, notes)
    VALUES (NEW.id, auth.uid(), 'created', 'Dependency created');
  ELSIF TG_OP = 'UPDATE' THEN
    -- Log status changes
    IF OLD.status IS DISTINCT FROM NEW.status THEN
      INSERT INTO public.dependency_audit_log (dependency_id, changed_by, action, field_changed, old_value, new_value)
      VALUES (NEW.id, auth.uid(), 'status_changed', 'status', OLD.status::text, NEW.status::text);
    END IF;
    -- Log commitment
    IF OLD.committed_by_date IS NULL AND NEW.committed_by_date IS NOT NULL THEN
      INSERT INTO public.dependency_audit_log (dependency_id, changed_by, action, notes)
      VALUES (NEW.id, auth.uid(), 'committed', 'Dependency committed to date: ' || NEW.committed_by_date::text);
    END IF;
    -- Log source blocked changes
    IF OLD.source_blocked IS DISTINCT FROM NEW.source_blocked THEN
      INSERT INTO public.dependency_audit_log (dependency_id, changed_by, action, field_changed, old_value, new_value, notes)
      VALUES (NEW.id, auth.uid(), 'blocked_changed', 'source_blocked', 
              COALESCE(OLD.source_blocked::text, 'false'), 
              COALESCE(NEW.source_blocked::text, 'false'),
              NEW.source_blocked_reason);
    END IF;
    -- Log target delayed changes
    IF OLD.target_delayed IS DISTINCT FROM NEW.target_delayed THEN
      INSERT INTO public.dependency_audit_log (dependency_id, changed_by, action, field_changed, old_value, new_value, notes)
      VALUES (NEW.id, auth.uid(), 'delayed_changed', 'target_delayed', 
              COALESCE(OLD.target_delayed::text, 'false'), 
              COALESCE(NEW.target_delayed::text, 'false'),
              NEW.target_delayed_reason);
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


