--
-- Name: log_initiative_changes(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_initiative_changes() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  user_uuid UUID;
BEGIN
  user_uuid := auth.uid();

  IF TG_OP = 'INSERT' THEN
    INSERT INTO ph_initiative_audit_log(initiative_id, user_id, action, entity_type, entity_id, metadata)
    VALUES (NEW.id, user_uuid, 'created', 'initiative', NEW.id, 
      jsonb_build_object('initiative_key', NEW.initiative_key, 'title', NEW.title));
    RETURN NEW;
  END IF;

  IF TG_OP = 'DELETE' THEN
    INSERT INTO ph_initiative_audit_log(initiative_id, user_id, action, entity_type, entity_id)
    VALUES (OLD.id, user_uuid, 'deleted', 'initiative', OLD.id);
    RETURN OLD;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    IF OLD.status IS DISTINCT FROM NEW.status THEN
      INSERT INTO ph_initiative_audit_log(initiative_id, user_id, action, entity_type, entity_id, field_name, old_value, new_value)
      VALUES (NEW.id, user_uuid, 'status_changed', 'initiative', NEW.id, 'status', OLD.status, NEW.status);
    END IF;

    IF OLD.title IS DISTINCT FROM NEW.title THEN
      INSERT INTO ph_initiative_audit_log(initiative_id, user_id, action, entity_type, entity_id, field_name, old_value, new_value)
      VALUES (NEW.id, user_uuid, 'updated', 'initiative', NEW.id, 'title', OLD.title, NEW.title);
    END IF;

    IF OLD.progress IS DISTINCT FROM NEW.progress THEN
      INSERT INTO ph_initiative_audit_log(initiative_id, user_id, action, entity_type, entity_id, field_name, old_value, new_value)
      VALUES (NEW.id, user_uuid, 'updated', 'initiative', NEW.id, 'progress', OLD.progress::TEXT, NEW.progress::TEXT);
    END IF;

    IF OLD.description IS DISTINCT FROM NEW.description THEN
      INSERT INTO ph_initiative_audit_log(initiative_id, user_id, action, entity_type, entity_id, field_name, old_value, new_value)
      VALUES (NEW.id, user_uuid, 'updated', 'initiative', NEW.id, 'description', LEFT(OLD.description, 200), LEFT(NEW.description, 200));
    END IF;

    IF OLD.assignee_id IS DISTINCT FROM NEW.assignee_id THEN
      INSERT INTO ph_initiative_audit_log(initiative_id, user_id, action, entity_type, entity_id, field_name, old_value, new_value)
      VALUES (NEW.id, user_uuid, 'updated', 'initiative', NEW.id, 'assignee_id', OLD.assignee_id::TEXT, NEW.assignee_id::TEXT);
    END IF;

    IF OLD.department_id IS DISTINCT FROM NEW.department_id THEN
      INSERT INTO ph_initiative_audit_log(initiative_id, user_id, action, entity_type, entity_id, field_name, old_value, new_value)
      VALUES (NEW.id, user_uuid, 'updated', 'initiative', NEW.id, 'department_id', OLD.department_id::TEXT, NEW.department_id::TEXT);
    END IF;

    IF OLD.business_owner_id IS DISTINCT FROM NEW.business_owner_id THEN
      INSERT INTO ph_initiative_audit_log(initiative_id, user_id, action, entity_type, entity_id, field_name, old_value, new_value)
      VALUES (NEW.id, user_uuid, 'updated', 'initiative', NEW.id, 'business_owner_id', OLD.business_owner_id::TEXT, NEW.business_owner_id::TEXT);
    END IF;

    IF OLD.target_quarter IS DISTINCT FROM NEW.target_quarter THEN
      INSERT INTO ph_initiative_audit_log(initiative_id, user_id, action, entity_type, entity_id, field_name, old_value, new_value)
      VALUES (NEW.id, user_uuid, 'updated', 'initiative', NEW.id, 'target_quarter', OLD.target_quarter, NEW.target_quarter);
    END IF;

    IF OLD.budget_allocated IS DISTINCT FROM NEW.budget_allocated THEN
      INSERT INTO ph_initiative_audit_log(initiative_id, user_id, action, entity_type, entity_id, field_name, old_value, new_value)
      VALUES (NEW.id, user_uuid, 'updated', 'initiative', NEW.id, 'budget_allocated', OLD.budget_allocated::TEXT, NEW.budget_allocated::TEXT);
    END IF;

    RETURN NEW;
  END IF;

  RETURN NULL;
END;
$$;


--
-- Name: log_injira_issue_changes(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_injira_issue_changes() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_changelog_group_id UUID;
  v_field_changes JSONB;
BEGIN
  -- Skip if no actual changes
  IF OLD IS NOT DISTINCT FROM NEW THEN
    RETURN NEW;
  END IF;

  -- Create changelog group
  INSERT INTO public.injira_changelog_groups (tenant_id, issue_id, author_id)
  VALUES (NEW.tenant_id, NEW.id, auth.uid())
  RETURNING id INTO v_changelog_group_id;

  -- Log individual field changes
  IF OLD.summary IS DISTINCT FROM NEW.summary THEN
    INSERT INTO public.injira_changelog_items (tenant_id, changelog_group_id, field_name, field_type, from_value, to_value)
    VALUES (NEW.tenant_id, v_changelog_group_id, 'summary', 'jira', OLD.summary, NEW.summary);
  END IF;

  IF OLD.status_id IS DISTINCT FROM NEW.status_id THEN
    INSERT INTO public.injira_changelog_items (tenant_id, changelog_group_id, field_name, field_type, from_value, to_value)
    VALUES (NEW.tenant_id, v_changelog_group_id, 'status', 'jira', OLD.status_id::text, NEW.status_id::text);
  END IF;

  IF OLD.assignee_id IS DISTINCT FROM NEW.assignee_id THEN
    INSERT INTO public.injira_changelog_items (tenant_id, changelog_group_id, field_name, field_type, from_value, to_value)
    VALUES (NEW.tenant_id, v_changelog_group_id, 'assignee', 'jira', OLD.assignee_id::text, NEW.assignee_id::text);
  END IF;

  IF OLD.priority IS DISTINCT FROM NEW.priority THEN
    INSERT INTO public.injira_changelog_items (tenant_id, changelog_group_id, field_name, field_type, from_value, to_value)
    VALUES (NEW.tenant_id, v_changelog_group_id, 'priority', 'jira', OLD.priority, NEW.priority);
  END IF;

  IF OLD.sprint_id IS DISTINCT FROM NEW.sprint_id THEN
    INSERT INTO public.injira_changelog_items (tenant_id, changelog_group_id, field_name, field_type, from_value, to_value)
    VALUES (NEW.tenant_id, v_changelog_group_id, 'sprint', 'jira', OLD.sprint_id::text, NEW.sprint_id::text);
  END IF;

  IF OLD.story_points IS DISTINCT FROM NEW.story_points THEN
    INSERT INTO public.injira_changelog_items (tenant_id, changelog_group_id, field_name, field_type, from_value, to_value)
    VALUES (NEW.tenant_id, v_changelog_group_id, 'Story Points', 'jira', OLD.story_points::text, NEW.story_points::text);
  END IF;

  IF OLD.resolution_id IS DISTINCT FROM NEW.resolution_id THEN
    INSERT INTO public.injira_changelog_items (tenant_id, changelog_group_id, field_name, field_type, from_value, to_value)
    VALUES (NEW.tenant_id, v_changelog_group_id, 'resolution', 'jira', OLD.resolution_id::text, NEW.resolution_id::text);
  END IF;

  -- Increment optimistic lock version
  NEW.optimistic_lock_version := OLD.optimistic_lock_version + 1;

  RETURN NEW;
END;
$$;


