-- Name: map_test_to_case(uuid, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.map_test_to_case(p_connector_id uuid, p_external_test_id text, p_test_case_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  INSERT INTO automation_test_mappings (connector_id, external_test_id, test_case_id)
  VALUES (p_connector_id, p_external_test_id, p_test_case_id)
  ON CONFLICT (connector_id, external_test_id) DO UPDATE
  SET test_case_id = EXCLUDED.test_case_id;

  -- Update existing results
  UPDATE automation_results
  SET test_case_id = p_test_case_id
  WHERE connector_id = p_connector_id AND external_test_id = p_external_test_id;

  RETURN jsonb_build_object('success', true);
END;
$$;


--
-- Name: merge_ideas(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.merge_ideas(p_target_id uuid, p_source_id uuid, p_user_id uuid DEFAULT auth.uid()) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  UPDATE ph_idea_evidence SET idea_id = p_target_id WHERE idea_id = p_source_id;
  UPDATE ph_idea_comments SET idea_id = p_target_id WHERE idea_id = p_source_id;
  UPDATE ph_ideas SET parent_idea_id = p_target_id WHERE parent_idea_id = p_source_id;
  DELETE FROM ph_idea_votes WHERE idea_id = p_source_id AND user_id IN (SELECT user_id FROM ph_idea_votes WHERE idea_id = p_target_id);
  UPDATE ph_idea_votes SET idea_id = p_target_id WHERE idea_id = p_source_id;
  UPDATE ph_ideas SET status = 'Archived', is_deleted = TRUE, updated_at = now() WHERE id = p_source_id;
  INSERT INTO ph_idea_audit_log (idea_id, action, field_changed, old_value, new_value, changed_by)
  VALUES
    (p_target_id, 'MERGED', 'merged_from', NULL, p_source_id::TEXT, p_user_id),
    (p_source_id, 'MERGED', 'merged_into', NULL, p_target_id::TEXT, p_user_id);
END;
$$;


--
-- Name: migrate_tasks_to_workstream_keys(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.migrate_tasks_to_workstream_keys() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  ws RECORD;
  t RECORD;
  v_seq INTEGER;
BEGIN
  -- For each workstream
  FOR ws IN SELECT id, key_prefix FROM planner_workstreams LOOP
    v_seq := 0;
    
    -- Get all tasks for this workstream ordered by creation
    FOR t IN 
      SELECT id 
      FROM planner_tasks 
      WHERE workstream_id = ws.id 
      ORDER BY created_at
    LOOP
      v_seq := v_seq + 1;
      
      -- Update task key
      UPDATE planner_tasks 
      SET task_key = ws.key_prefix || '-' || v_seq
      WHERE id = t.id;
    END LOOP;
    
    -- Update the sequence counter
    UPDATE workstream_task_key_sequences
    SET last_sequence = v_seq, updated_at = now()
    WHERE workstream_id = ws.id;
    
    -- Insert if not exists
    IF NOT FOUND THEN
      INSERT INTO workstream_task_key_sequences (workstream_id, last_sequence)
      VALUES (ws.id, v_seq);
    END IF;
  END LOOP;
END;
$$;


--
-- Name: move_items_to_bottom(uuid, uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.move_items_to_bottom(p_run_id uuid, p_item_ids uuid[]) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_item_count INTEGER;
  v_max_position INTEGER;
BEGIN
  v_item_count := array_length(p_item_ids, 1);
  IF v_item_count IS NULL OR v_item_count = 0 THEN
    RETURN jsonb_build_object('error', 'No items specified');
  END IF;

  -- Get current max position (excluding moved items)
  SELECT COALESCE(MAX(position), 0) INTO v_max_position
  FROM execution_queue
  WHERE run_id = p_run_id
    AND status = 'queued'
    AND id != ALL(p_item_ids);

  -- Compact remaining items
  WITH ranked AS (
    SELECT id, ROW_NUMBER() OVER (ORDER BY position) as new_pos
    FROM execution_queue
    WHERE run_id = p_run_id
      AND status = 'queued'
      AND id != ALL(p_item_ids)
  )
  UPDATE execution_queue eq SET
    position = r.new_pos
  FROM ranked r
  WHERE eq.id = r.id;

  -- Get new max after compaction
  SELECT COALESCE(MAX(position), 0) INTO v_max_position
  FROM execution_queue
  WHERE run_id = p_run_id
    AND status = 'queued'
    AND id != ALL(p_item_ids);

  -- Assign new positions to moved items at the end
  WITH ranked AS (
    SELECT id, ROW_NUMBER() OVER (ORDER BY position) as idx
    FROM execution_queue
    WHERE id = ANY(p_item_ids)
  )
  UPDATE execution_queue eq SET
    position = v_max_position + r.idx
  FROM ranked r
  WHERE eq.id = r.id;

  RETURN jsonb_build_object('success', true, 'moved_count', v_item_count);
END;
$$;


--
-- Name: move_items_to_top(uuid, uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.move_items_to_top(p_run_id uuid, p_item_ids uuid[]) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_item_count INTEGER;
BEGIN
  v_item_count := array_length(p_item_ids, 1);
  IF v_item_count IS NULL OR v_item_count = 0 THEN
    RETURN jsonb_build_object('error', 'No items specified');
  END IF;

  -- Shift all other items down by the count of moved items
  UPDATE execution_queue SET
    position = position + v_item_count
  WHERE run_id = p_run_id
    AND status = 'queued'
    AND id != ALL(p_item_ids);

  -- Assign new positions to moved items (maintaining their relative order)
  WITH ranked AS (
    SELECT id, ROW_NUMBER() OVER (ORDER BY position) as new_pos
    FROM execution_queue
    WHERE id = ANY(p_item_ids)
  )
  UPDATE execution_queue eq SET
    position = r.new_pos
  FROM ranked r
  WHERE eq.id = r.id;

  RETURN jsonb_build_object('success', true, 'moved_count', v_item_count);
END;
$$;


--
-- Name: next_defect_key(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.next_defect_key() RETURNS character varying
    LANGUAGE sql
    SET search_path TO 'public'
    AS $$
  SELECT 'DEF-' || LPAD((COALESCE(MAX(CAST(SUBSTRING(defect_key FROM 5) AS INTEGER)), 0) + 1)::TEXT, 4, '0')
  FROM public.tm_defects;
$$;


--
-- Name: next_issue_key(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.next_issue_key(p_project_id uuid) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_key TEXT;
  v_num INTEGER;
  v_prefix TEXT;
BEGIN
  SELECT key INTO v_prefix FROM projects WHERE id = p_project_id;
  INSERT INTO project_sequences (project_id, last_number)
  VALUES (p_project_id, 1)
  ON CONFLICT (project_id)
  DO UPDATE SET last_number = project_sequences.last_number + 1
  RETURNING last_number INTO v_num;
  RETURN v_prefix || '-' || v_num;
END;
$$;


--
-- Name: notify_catalyst_issue_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.notify_catalyst_issue_change() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NEW.last_modified_by_system = 'catalyst' AND NEW.sync_enabled = true THEN
    IF EXISTS (
      SELECT 1 FROM sync_entity_map sem
      JOIN sync_connections sc ON sc.project_id = NEW.project_id
      WHERE sem.catalyst_entity_type = 'issue'
        AND sem.catalyst_entity_id = NEW.id
        AND sc.is_active = true
        AND sc.sync_direction IN ('bi', 'catalyst_to_jira')
    ) THEN
      INSERT INTO sync_events (
        direction, origin_system, event_type, entity_type,
        entity_id, idempotency_key, payload, status
      ) VALUES (
        'outbound',
        'catalyst',
        CASE WHEN TG_OP = 'INSERT' THEN 'catalyst:issue_created'
             WHEN TG_OP = 'UPDATE' THEN 'catalyst:issue_updated'
             ELSE 'catalyst:issue_deleted' END,
        'issue',
        NEW.id::TEXT,
        'catalyst:issue:' || NEW.id::TEXT || ':' || extract(epoch from now())::TEXT,
        jsonb_build_object(
          'issue_id', NEW.id,
          'project_id', NEW.project_id,
          'title', NEW.title,
          'description', NEW.description,
          'status', NEW.status,
          'priority', NEW.priority,
          'assignee_id', NEW.assignee_id,
          'issue_type', NEW.issue_type,
          'story_points', NEW.story_points,
          'operation', TG_OP
        ),
        'pending'
      );
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: notify_lead_note_mentions(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.notify_lead_note_mentions() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
  mention_match TEXT;
  mentioned_user_id UUID;
  actor_id UUID;
  task_title TEXT;
  notification_content TEXT;
BEGIN
  -- Get the actor
  actor_id := auth.uid();
  
  -- Only process if content changed or is new
  IF TG_OP = 'INSERT' OR (TG_OP = 'UPDATE' AND OLD.content IS DISTINCT FROM NEW.content) THEN
    
    -- Get task title for notification
    SELECT title INTO task_title 
    FROM public.planner_tasks 
    WHERE id = NEW.task_id 
    LIMIT 1;
    
    task_title := COALESCE(task_title, 'Untitled Task');
    
    -- Extract and process @mentions
    FOR mention_match IN 
      SELECT (regexp_matches(COALESCE(NEW.content, ''), '@([a-zA-Z0-9._-]+)', 'g'))[1]
    LOOP
      -- Skip if this mention was already in the old content (for updates)
      IF TG_OP = 'UPDATE' AND COALESCE(OLD.content, '') ~ ('@' || mention_match || '(\s|$)') THEN
        CONTINUE;
      END IF;
      
      -- Try to find user
      SELECT p.id INTO mentioned_user_id
      FROM public.profiles p
      WHERE LOWER(SPLIT_PART(p.email, '@', 1)) = LOWER(mention_match)
         OR LOWER(REPLACE(p.full_name, ' ', '_')) = LOWER(mention_match)
         OR LOWER(p.full_name) = LOWER(REPLACE(mention_match, '_', ' '))
      LIMIT 1;
      
      -- If found, create notification (skip self-mentions)
      IF mentioned_user_id IS NOT NULL AND mentioned_user_id IS DISTINCT FROM actor_id THEN
        notification_content := 'You were mentioned in a note on: ' || task_title;
        
        INSERT INTO public.user_notifications (
          user_id,
          type,
          title,
          content,
          link,
          is_read,
          idempotency_key,
          created_at
        ) VALUES (
          mentioned_user_id,
          'mention',
          'Mentioned in a note',
          notification_content,
          '/taskhub/my-tasks?taskId=' || NEW.task_id,
          false,
          'lead_note_mention_' || NEW.id || '_' || mentioned_user_id || '_' || EXTRACT(EPOCH FROM NOW())::TEXT,
          NOW()
        )
        ON CONFLICT (idempotency_key) DO NOTHING;
      END IF;
    END LOOP;
  END IF;
  
  RETURN NEW;
END;
$_$;


--
-- Name: notify_risk_escalation(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.notify_risk_escalation() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Notify owner when risk impact or probability increases
  IF NEW.owner_id IS NOT NULL AND (
    (NEW.impact > OLD.impact) OR 
    (NEW.probability > OLD.probability)
  ) THEN
    PERFORM public.create_notification(
      NEW.owner_id,
      'Risk Escalated',
      'Risk "' || NEW.name || '" has been escalated',
      'alert',
      'risks',
      NEW.id
    );
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: notify_status_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.notify_status_change() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Notify assignee when status changes to 'done'
  IF NEW.status = 'done' AND OLD.status != 'done' AND NEW.assignee_id IS NOT NULL THEN
    PERFORM public.create_notification(
      NEW.assignee_id,
      'Work Item Completed',
      'Your ' || TG_TABLE_NAME || ' "' || NEW.name || '" has been marked as done',
      'status_change',
      TG_TABLE_NAME,
      NEW.id
    );
  END IF;

  RETURN NEW;
END;
$$;


