--
-- Name: notify_subtask_assignment(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.notify_subtask_assignment() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Notify when subtask is assigned to a user
  IF NEW.assignee_id IS NOT NULL AND (OLD.assignee_id IS NULL OR OLD.assignee_id != NEW.assignee_id) THEN
    PERFORM public.create_notification(
      NEW.assignee_id,
      'Subtask Assigned',
      'You have been assigned to subtask: ' || NEW.name,
      'assignment',
      'subtasks',
      NEW.id
    );
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: notify_t10_item_assignment(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.notify_t10_item_assignment() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  item_title TEXT;
  list_name TEXT;
  list_id UUID;
  actor_name TEXT;
BEGIN
  -- Get item and list details
  SELECT i.title, l.name, l.id INTO item_title, list_name, list_id
  FROM t10_items i
  JOIN t10_weeks w ON w.id = i.week_id
  JOIN t10_lists l ON l.id = w.list_id
  WHERE i.id = NEW.id;

  -- Get actor name (use full_name instead of display_name)
  SELECT COALESCE(p.full_name, p.email, 'Someone') INTO actor_name
  FROM profiles p
  WHERE p.id = auth.uid();

  -- Notify new assignee (if different from actor and not null)
  IF NEW.assignee_id IS NOT NULL 
     AND NEW.assignee_id != COALESCE(auth.uid(), '00000000-0000-0000-0000-000000000000'::uuid) THEN
    
    IF OLD.assignee_id IS NULL OR OLD.assignee_id != NEW.assignee_id THEN
      INSERT INTO user_notifications (
        user_id, type, title, message, link, entity_type, entity_id, actor_id, channel, severity, idempotency_key
      ) VALUES (
        NEW.assignee_id,
        'task_assigned',
        'New Task10 Assignment',
        format('%s assigned you to "%s" in %s', actor_name, item_title, list_name),
        format('/task10?listId=%s&itemId=%s', list_id, NEW.id),
        't10_item',
        NEW.id,
        auth.uid(),
        'in_app',
        'info',
        format('t10_assign_%s_%s_%s', NEW.id, NEW.assignee_id, NOW()::date)
      );
    END IF;
  END IF;

  -- Notify previous assignee of unassignment
  IF TG_OP = 'UPDATE' 
     AND OLD.assignee_id IS NOT NULL 
     AND OLD.assignee_id != NEW.assignee_id
     AND OLD.assignee_id != COALESCE(auth.uid(), '00000000-0000-0000-0000-000000000000'::uuid) THEN
    
    INSERT INTO user_notifications (
      user_id, type, title, message, link, entity_type, entity_id, actor_id, channel, severity, idempotency_key
    ) VALUES (
      OLD.assignee_id,
      'task_unassigned',
      'Task10 Unassignment',
      format('%s removed you from "%s" in %s', actor_name, item_title, list_name),
      format('/task10?listId=%s', list_id),
      't10_item',
      NEW.id,
      auth.uid(),
      'in_app',
      'info',
      format('t10_unassign_%s_%s_%s', NEW.id, OLD.assignee_id, NOW()::date)
    );
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: notify_t10_item_mentions(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.notify_t10_item_mentions() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  item_title TEXT;
  list_name TEXT;
  list_id UUID;
  actor_name TEXT;
  mention_match TEXT;
  mentioned_user_id UUID;
  mentioned_users UUID[] := ARRAY[]::UUID[];
  old_mentioned_users UUID[] := ARRAY[]::UUID[];
BEGIN
  -- Only process if description changed
  IF TG_OP = 'UPDATE' AND OLD.description = NEW.description THEN
    RETURN NEW;
  END IF;
  
  -- Get item and list details
  SELECT i.title, l.name, l.id INTO item_title, list_name, list_id
  FROM t10_items i
  JOIN t10_weeks w ON w.id = i.week_id
  JOIN t10_lists l ON l.id = w.list_id
  WHERE i.id = NEW.id;

  -- Get actor name (use full_name instead of display_name)
  SELECT COALESCE(p.full_name, p.email, 'Someone') INTO actor_name
  FROM profiles p
  WHERE p.id = auth.uid();

  -- Extract @mentions from new description
  IF NEW.description IS NOT NULL THEN
    FOR mention_match IN SELECT (regexp_matches(NEW.description, '@([a-zA-Z0-9._-]+)', 'g'))[1]
    LOOP
      -- Find user by email prefix or handle
      SELECT id INTO mentioned_user_id
      FROM profiles
      WHERE LOWER(SPLIT_PART(email, '@', 1)) = LOWER(mention_match)
         OR LOWER(REPLACE(full_name, ' ', '_')) = LOWER(mention_match)
      LIMIT 1;
      
      IF mentioned_user_id IS NOT NULL THEN
        mentioned_users := array_append(mentioned_users, mentioned_user_id);
      END IF;
    END LOOP;
  END IF;

  -- Extract @mentions from old description (to avoid re-notifying)
  IF TG_OP = 'UPDATE' AND OLD.description IS NOT NULL THEN
    FOR mention_match IN SELECT (regexp_matches(OLD.description, '@([a-zA-Z0-9._-]+)', 'g'))[1]
    LOOP
      SELECT id INTO mentioned_user_id
      FROM profiles
      WHERE LOWER(SPLIT_PART(email, '@', 1)) = LOWER(mention_match)
         OR LOWER(REPLACE(full_name, ' ', '_')) = LOWER(mention_match)
      LIMIT 1;
      
      IF mentioned_user_id IS NOT NULL THEN
        old_mentioned_users := array_append(old_mentioned_users, mentioned_user_id);
      END IF;
    END LOOP;
  END IF;

  -- Notify newly mentioned users
  FOR mentioned_user_id IN SELECT UNNEST(mentioned_users)
  LOOP
    -- Skip if already mentioned in old description
    IF mentioned_user_id = ANY(old_mentioned_users) THEN
      CONTINUE;
    END IF;
    
    -- Skip self-mentions
    IF mentioned_user_id = auth.uid() THEN
      CONTINUE;
    END IF;
    
    INSERT INTO user_notifications (
      user_id, type, title, message, link, entity_type, entity_id, actor_id, channel, severity, idempotency_key
    ) VALUES (
      mentioned_user_id,
      'mention',
      'You were mentioned in Task10',
      format('%s mentioned you in "%s" (%s)', actor_name, item_title, list_name),
      format('/task10?listId=%s&itemId=%s', list_id, NEW.id),
      't10_item',
      NEW.id,
      auth.uid(),
      'in_app',
      'info',
      format('t10_mention_%s_%s_%s', NEW.id, mentioned_user_id, NOW()::date)
    );
  END LOOP;

  RETURN NEW;
END;
$$;


--
-- Name: notify_task_assignment(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.notify_task_assignment() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_task_key TEXT;
  v_task_title TEXT;
  v_actor_name TEXT;
  v_link TEXT;
BEGIN
  -- Only proceed if assignee_id changed and new assignee exists
  IF (TG_OP = 'UPDATE' AND NEW.assignee_id IS DISTINCT FROM OLD.assignee_id AND NEW.assignee_id IS NOT NULL) 
     OR (TG_OP = 'INSERT' AND NEW.assignee_id IS NOT NULL) THEN
    
    -- Get task details
    v_task_key := COALESCE(NEW.task_key, 'TASK');
    v_task_title := COALESCE(NEW.title, 'Untitled Task');
    
    -- Get actor name (the person who made the assignment)
    SELECT COALESCE(full_name, email, 'Someone') INTO v_actor_name
    FROM profiles
    WHERE id = auth.uid();
    
    -- Build deep link to task
    v_link := '/taskhub/my-tasks?taskId=' || NEW.id::text;
    
    -- Don't notify if user assigned task to themselves
    IF NEW.assignee_id = auth.uid() THEN
      RETURN NEW;
    END IF;
    
    -- Insert notification for the new assignee
    INSERT INTO user_notifications (
      user_id,
      type,
      title,
      message,
      link,
      entity_type,
      entity_id,
      actor_id,
      severity,
      channel,
      idempotency_key
    ) VALUES (
      NEW.assignee_id,
      'assignment',
      'Task Assigned: ' || v_task_key,
      COALESCE(v_actor_name, 'Someone') || ' assigned you to "' || v_task_title || '"',
      v_link,
      'task',
      NEW.id,
      auth.uid(),
      'info',
      'in_app',
      'task_assign_' || NEW.id::text || '_' || NEW.assignee_id::text || '_' || EXTRACT(EPOCH FROM now())::text
    )
    ON CONFLICT DO NOTHING;
    
    -- If there was an old assignee (reassignment), notify them of unassignment
    IF TG_OP = 'UPDATE' AND OLD.assignee_id IS NOT NULL AND OLD.assignee_id != auth.uid() THEN
      INSERT INTO user_notifications (
        user_id,
        type,
        title,
        message,
        link,
        entity_type,
        entity_id,
        actor_id,
        severity,
        channel,
        idempotency_key
      ) VALUES (
        OLD.assignee_id,
        'unassignment',
        'Task Unassigned: ' || v_task_key,
        COALESCE(v_actor_name, 'Someone') || ' removed you from "' || v_task_title || '"',
        v_link,
        'task',
        NEW.id,
        auth.uid(),
        'info',
        'in_app',
        'task_unassign_' || NEW.id::text || '_' || OLD.assignee_id::text || '_' || EXTRACT(EPOCH FROM now())::text
      )
      ON CONFLICT DO NOTHING;
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- Name: on_space_created(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.on_space_created() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
    -- Ensure RLS does not block provisioning inserts inside this function
    PERFORM set_config('row_security', 'off', true);

    -- Add creator as administrator first
    IF NEW.created_by IS NOT NULL THEN
        INSERT INTO public.space_members (space_id, user_id, role, added_by)
        VALUES (NEW.id, NEW.created_by, 'administrator', NEW.created_by)
        ON CONFLICT (space_id, user_id) DO NOTHING;
    END IF;

    -- Create default features
    INSERT INTO public.space_features (space_id)
    VALUES (NEW.id)
    ON CONFLICT (space_id) DO NOTHING;

    -- Create default permissions
    PERFORM public.create_default_space_permissions(NEW.id);

    RETURN NEW;
END;
$$;


--
-- Name: pause_step_timer(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.pause_step_timer(p_execution_id uuid, p_step_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_result RECORD;
BEGIN
  UPDATE test_execution_step_results SET
    timer_paused_at = NOW(),
    is_timer_running = false
  WHERE execution_id = p_execution_id 
    AND step_id = p_step_id
    AND is_timer_running = true
  RETURNING id, timer_started_at, timer_paused_at, timer_total_paused INTO v_result;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'No active timer found for this step');
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'paused_at', v_result.timer_paused_at,
    'elapsed_seconds', EXTRACT(EPOCH FROM (v_result.timer_paused_at - v_result.timer_started_at))::INTEGER - COALESCE(v_result.timer_total_paused, 0)
  );
END;
$$;


