-- Name: ph_jira_connection_updated(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ph_jira_connection_updated() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN NEW.updated_at = now(); RETURN NEW; END;
$$;


--
-- Name: ph_parse_and_update_versions(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ph_parse_and_update_versions() RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE ph_versions SET parsed_date = ph_parse_version_name(name)
  WHERE release_date IS NULL AND parsed_date IS NULL;
END;
$$;


--
-- Name: ph_parse_version_name(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ph_parse_version_name(vname text) RETURNS date
    LANGUAGE plpgsql IMMUTABLE
    AS $_$
DECLARE yr INT; mn INT; qr INT;
BEGIN
  IF vname ~ '^\d{4}\s+\d{1,2}$' THEN
    yr := (regexp_match(vname, '^(\d{4})'))[1]::INT;
    mn := (regexp_match(vname, '\s+(\d{1,2})$'))[1]::INT;
    IF mn BETWEEN 1 AND 12 THEN
      RETURN (make_date(yr, mn, 1) + interval '1 month - 1 day')::DATE;
    END IF;
  END IF;
  IF vname ~* '^\d{4}\s+Q[1-4]$' THEN
    yr := (regexp_match(vname, '^(\d{4})'))[1]::INT;
    qr := (regexp_match(vname, 'Q(\d)'))[1]::INT;
    mn := qr * 3;
    RETURN (make_date(yr, mn, 1) + interval '1 month - 1 day')::DATE;
  END IF;
  RETURN NULL;
END;
$_$;


--
-- Name: ph_prevent_default_status_delete(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ph_prevent_default_status_delete() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF OLD.is_default = true THEN
    RAISE EXCEPTION 'Cannot delete the default status. Set another status as default first.';
  END IF;
  RETURN OLD;
END;
$$;


--
-- Name: ph_prune_stale(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ph_prune_stale(window_months integer DEFAULT 6) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE pruned INT;
BEGIN
  DELETE FROM ph_issues
  WHERE jira_updated_at < now() - (window_months || ' months')::interval
    AND status_category = 'Done';
  GET DIAGNOSTICS pruned = ROW_COUNT;
  RETURN pruned;
END;
$$;


--
-- Name: ph_recompute_all(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ph_recompute_all() RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE max_level INT; cur_level INT;
BEGIN
  SELECT COALESCE(max(hierarchy_level), 3) INTO max_level FROM ph_issues;
  FOR cur_level IN 1..max_level LOOP
    UPDATE ph_issues i SET
      effective_due_date = COALESCE(
        i.due_date,
        (SELECT min(COALESCE(v.release_date, v.parsed_date))
         FROM ph_versions v
         WHERE v.jira_id IN (
           SELECT (elem->>'id') FROM jsonb_array_elements(i.fix_versions) AS elem
         ) AND COALESCE(v.release_date, v.parsed_date) IS NOT NULL),
        (SELECT p.effective_due_date FROM ph_issues p WHERE p.issue_key = i.parent_key)
      ),
      effective_due_source = CASE
        WHEN i.due_date IS NOT NULL THEN 'Due Date'
        WHEN (SELECT min(COALESCE(v.release_date, v.parsed_date))
              FROM ph_versions v
              WHERE v.jira_id IN (
                SELECT (elem->>'id') FROM jsonb_array_elements(i.fix_versions) AS elem
              ) AND COALESCE(v.release_date, v.parsed_date) IS NOT NULL) IS NOT NULL
          THEN 'FixVersion (' || (
            SELECT v.name FROM ph_versions v
            WHERE v.jira_id IN (
              SELECT (elem->>'id') FROM jsonb_array_elements(i.fix_versions) AS elem
            ) AND COALESCE(v.release_date, v.parsed_date) IS NOT NULL
            ORDER BY COALESCE(v.release_date, v.parsed_date) LIMIT 1
          ) || ')'
        WHEN (SELECT p.effective_due_date FROM ph_issues p WHERE p.issue_key = i.parent_key) IS NOT NULL
          THEN 'Inherited from ' || i.parent_key
        ELSE 'Unscheduled'
      END
    WHERE i.hierarchy_level = cur_level;
  END LOOP;
END;
$$;


--
-- Name: ph_seed_default_field_layouts(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ph_seed_default_field_layouts(p_project_id uuid) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_type RECORD;
BEGIN
  FOR v_type IN SELECT id, name FROM ph_work_types WHERE project_id = p_project_id
  LOOP
    INSERT INTO ph_type_field_layouts (type_id, field_name, field_type, is_required, position) VALUES
      (v_type.id, 'Title',       'text',         true,  0),
      (v_type.id, 'Type',        'select',       true,  1),
      (v_type.id, 'Status',      'select',       true,  2),
      (v_type.id, 'Assignee',    'user-picker',  false, 3),
      (v_type.id, 'Priority',    'select',       false, 4),
      (v_type.id, 'Labels',      'multi-select', false, 5),
      (v_type.id, 'Components',  'multi-select', false, 6),
      (v_type.id, 'Due Date',    'date',         false, 7),
      (v_type.id, 'Description', 'rich-text',    false, 8),
      (v_type.id, 'Attachments', 'file-upload',  false, 9);

    IF v_type.name = 'Epic' THEN
      INSERT INTO ph_type_field_layouts (type_id, field_name, field_type, is_type_specific, position) VALUES
        (v_type.id, 'Target Start Date', 'date',   true, 10),
        (v_type.id, 'Target End Date',   'date',   true, 11),
        (v_type.id, 'Business Value',    'select', true, 12);
    ELSIF v_type.name = 'Feature' THEN
      INSERT INTO ph_type_field_layouts (type_id, field_name, field_type, is_type_specific, position) VALUES
        (v_type.id, 'Target Start Date', 'date', true, 10),
        (v_type.id, 'Target End Date',   'date', true, 11);
    ELSIF v_type.name IN ('Story', 'Task', 'Subtask') THEN
      INSERT INTO ph_type_field_layouts (type_id, field_name, field_type, is_type_specific, position) VALUES
        (v_type.id, 'Story Points', 'number', true, 10);
      IF v_type.name = 'Story' THEN
        INSERT INTO ph_type_field_layouts (type_id, field_name, field_type, is_type_specific, position) VALUES
          (v_type.id, 'Acceptance Criteria', 'checklist', true, 11);
      END IF;
    ELSIF v_type.name = 'Bug' THEN
      INSERT INTO ph_type_field_layouts (type_id, field_name, field_type, is_type_specific, position) VALUES
        (v_type.id, 'Severity',           'select',    true, 10),
        (v_type.id, 'Steps to Reproduce', 'rich-text', true, 11),
        (v_type.id, 'Expected Behavior',  'rich-text', true, 12),
        (v_type.id, 'Actual Behavior',    'rich-text', true, 13);
    END IF;
  END LOOP;
END;
$$;


