--
-- Name: ph_update_cycle_time(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ph_update_cycle_time() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF OLD.status_id IS DISTINCT FROM NEW.status_id THEN
    NEW.status_changed_at := now();
    IF OLD.status_changed_at IS NOT NULL THEN
      NEW.cycle_time_days := EXTRACT(DAY FROM now() - OLD.status_changed_at)::INTEGER;
    END IF;
  END IF;
  NEW.updated_at := now();
  RETURN NEW;
END; $$;


