--
-- Name: planner_task_list_stats(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.planner_task_list_stats(p_workstream_id uuid DEFAULT NULL::uuid, p_assignee_id uuid DEFAULT NULL::uuid) RETURNS TABLE(total_count bigint, overdue_count bigint, in_progress_count bigint, done_count bigint)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COUNT(*)::BIGINT as total_count,
    COUNT(*) FILTER (
      WHERE t.due_date < CURRENT_DATE 
      AND COALESCE(s.is_done, false) = false
    )::BIGINT as overdue_count,
    COUNT(*) FILTER (
      WHERE s.slug = 'progress'
    )::BIGINT as in_progress_count,
    COUNT(*) FILTER (
      WHERE COALESCE(s.is_done, false) = true
    )::BIGINT as done_count
  FROM planner_tasks t
  LEFT JOIN planner_statuses s ON t.status_id = s.id
  WHERE t.deleted_at IS NULL
    AND (p_workstream_id IS NULL OR t.workstream_id = p_workstream_id)
    AND (p_assignee_id IS NULL OR t.assignee_id = p_assignee_id);
END;
$$;


