--
-- Name: populate_r360_weekly_snapshots(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.populate_r360_weekly_snapshots() RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
  inserted_count integer;
BEGIN

  INSERT INTO r360_weekly_snapshots (
    resource_id,
    week_number,
    week_start,
    week_end,
    total_open,
    closed_this_week,
    in_review,
    pickup_speed_hours,
    in_progress_concurrent,
    closed_of_touched,
    total_touched,
    avg_cycle_time_days,
    oldest_item_age_days,
    oldest_item_key,
    closure_rate_pct
  )
  WITH

  -- Step 1: Closed items with Saudi week start (Sunday)
  closed_items AS (
    SELECT
      i.assignee_display_name,
      i.issue_key,
      i.jira_created_at,
      i.jira_updated_at,
      (i.jira_updated_at AT TIME ZONE 'Asia/Riyadh')::date
        - (EXTRACT(DOW FROM (i.jira_updated_at AT TIME ZONE 'Asia/Riyadh'))::int) AS week_start
    FROM ph_issues i
    WHERE i.status IN ('Done', 'In Production', 'ready for production')
      AND i.assignee_display_name IS NOT NULL
      AND i.jira_removed_at IS NULL
  ),

  -- Step 2: Aggregate per assignee per Saudi week
  weekly_agg AS (
    SELECT
      ci.assignee_display_name,
      ci.week_start,
      (ci.week_start + 4) AS week_end,
      (EXTRACT(YEAR FROM ci.week_start)::int * 100 +
       EXTRACT(WEEK FROM ci.week_start + INTERVAL '1 day')::int) AS week_number,
      COUNT(*) AS closed_this_week,
      ROUND(AVG(
        EXTRACT(EPOCH FROM (ci.jira_updated_at - ci.jira_created_at)) / 86400.0
      )::numeric, 1) AS avg_cycle_time_days
    FROM closed_items ci
    GROUP BY ci.assignee_display_name, ci.week_start
  ),

  -- Step 3: Join to r360_resources (NOT profiles — FK target is r360_resources.id)
  with_resource AS (
    SELECT
      r.id AS resource_id,
      wa.week_number,
      wa.week_start,
      wa.week_end,
      wa.closed_this_week,
      wa.avg_cycle_time_days
    FROM weekly_agg wa
    JOIN r360_resources r
      ON r.full_name = wa.assignee_display_name
     AND r.deleted_at IS NULL
  ),

  -- Step 4: Current open/in-review/in-progress per resource
  open_counts AS (
    SELECT
      r.id AS resource_id,
      COUNT(*) FILTER (
        WHERE i.status NOT IN ('Done','In Production','ready for production')
      ) AS total_open,
      COUNT(*) FILTER (WHERE i.status = 'In Review')      AS in_review,
      COUNT(*) FILTER (WHERE i.status = 'In-Progress')    AS in_progress_concurrent,
      MAX(CURRENT_DATE - i.jira_created_at::date) FILTER (
        WHERE i.status NOT IN ('Done','In Production','ready for production')
      ) AS oldest_item_age_days,
      (ARRAY_AGG(i.issue_key ORDER BY i.jira_created_at ASC) FILTER (
        WHERE i.status NOT IN ('Done','In Production','ready for production')
      ))[1] AS oldest_item_key
    FROM ph_issues i
    JOIN r360_resources r
      ON r.full_name = i.assignee_display_name
     AND r.deleted_at IS NULL
    WHERE i.jira_removed_at IS NULL
    GROUP BY r.id
  )

  -- Step 5: Final upsert
  SELECT
    wr.resource_id,
    wr.week_number,
    wr.week_start,
    wr.week_end,
    COALESCE(oc.total_open, 0)               AS total_open,
    wr.closed_this_week,
    COALESCE(oc.in_review, 0)               AS in_review,
    0                                        AS pickup_speed_hours,
    COALESCE(oc.in_progress_concurrent, 0)  AS in_progress_concurrent,
    wr.closed_this_week                      AS closed_of_touched,
    wr.closed_this_week                      AS total_touched,
    COALESCE(wr.avg_cycle_time_days, 0)     AS avg_cycle_time_days,
    COALESCE(oc.oldest_item_age_days, 0)    AS oldest_item_age_days,
    oc.oldest_item_key,
    CASE
      WHEN (wr.closed_this_week + COALESCE(oc.total_open, 0)) > 0
      THEN ROUND(
        (wr.closed_this_week::numeric /
         (wr.closed_this_week + COALESCE(oc.total_open, 0))) * 100, 1)
      ELSE 0
    END AS closure_rate_pct

  FROM with_resource wr
  LEFT JOIN open_counts oc ON oc.resource_id = wr.resource_id

  ON CONFLICT (resource_id, week_number) DO UPDATE SET
    closed_this_week       = EXCLUDED.closed_this_week,
    avg_cycle_time_days    = EXCLUDED.avg_cycle_time_days,
    total_open             = EXCLUDED.total_open,
    in_review              = EXCLUDED.in_review,
    in_progress_concurrent = EXCLUDED.in_progress_concurrent,
    oldest_item_age_days   = EXCLUDED.oldest_item_age_days,
    oldest_item_key        = EXCLUDED.oldest_item_key,
    closure_rate_pct       = EXCLUDED.closure_rate_pct;

  GET DIAGNOSTICS inserted_count = ROW_COUNT;
  RETURN inserted_count;

END;
$$;


--
-- Name: populate_step_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.populate_step_number() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.step_number IS NULL THEN
    SELECT step_number INTO NEW.step_number
    FROM public.tm_test_steps
    WHERE id = NEW.test_step_id;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: prevent_artifact_modification(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.prevent_artifact_modification() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'UPDATE' THEN
    RAISE EXCEPTION 'ai_assist_artifacts is append-only. Updates are not allowed.';
  ELSIF TG_OP = 'DELETE' THEN
    RAISE EXCEPTION 'ai_assist_artifacts is append-only. Deletes are not allowed.';
  END IF;
  RETURN NULL;
END;
$$;


--
-- Name: pri_checkout_week(uuid, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.pri_checkout_week(p_week_id uuid, p_decisions jsonb) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_list_id UUID;
  v_new_week_id UUID;
  v_new_start DATE;
  v_new_end DATE;
  v_decision JSONB;
  v_item_id UUID;
  v_action TEXT;
  v_new_item_id UUID;
  v_item RECORD;
BEGIN
  -- Get list_id from week
  SELECT list_id INTO v_list_id FROM pri_weeks WHERE id = p_week_id;

  IF v_list_id IS NULL THEN
    RAISE EXCEPTION 'Week not found: %', p_week_id;
  END IF;

  -- Mark current week as checked out
  UPDATE pri_weeks
  SET status = 'checked_out',
      checked_out_at = now(),
      checked_out_by = auth.uid()
  WHERE id = p_week_id;

  -- Create next week
  SELECT week_end + INTERVAL '2 days' INTO v_new_start
  FROM pri_weeks WHERE id = p_week_id;
  v_new_end := v_new_start + INTERVAL '4 days';

  INSERT INTO pri_weeks (list_id, week_start, week_end, status)
  VALUES (v_list_id, v_new_start, v_new_end, 'active')
  RETURNING id INTO v_new_week_id;

  -- Process each decision
  FOR v_decision IN SELECT * FROM jsonb_array_elements(p_decisions)
  LOOP
    v_item_id := (v_decision->>'item_id')::UUID;
    v_action := v_decision->>'decision';

    IF v_action = 'resolved' THEN
      -- Mark as completed if not already
      UPDATE pri_items SET status = 'completed' WHERE id = v_item_id;

      INSERT INTO pri_item_history (item_id, actor_id, action, new_value)
      VALUES (v_item_id, auth.uid(), 'checked_out', 'resolved');

    ELSIF v_action = 'carry' THEN
      -- Create carryover item in new week
      SELECT * INTO v_item FROM pri_items WHERE id = v_item_id;

      INSERT INTO pri_items (
        list_id, week_id, title, description, status,
        rank, assignee_id, task_key, is_carryover, source_item_id
      ) VALUES (
        v_list_id, v_new_week_id, v_item.title, v_item.description, 'todo',
        v_item.rank, v_item.assignee_id, v_item.task_key, true, v_item_id
      ) RETURNING id INTO v_new_item_id;

      -- Copy labels
      INSERT INTO pri_item_labels (item_id, label_id)
      SELECT v_new_item_id, label_id
      FROM pri_item_labels WHERE item_id = v_item_id;

      -- Audit
      INSERT INTO pri_item_history (item_id, actor_id, action, new_value)
      VALUES (v_item_id, auth.uid(), 'checked_out', 'carried_over');

      INSERT INTO pri_item_history (item_id, actor_id, action, old_value)
      VALUES (v_new_item_id, auth.uid(), 'carried_over', v_item_id::text);

    ELSIF v_action = 'leave' THEN
      -- Leave in checked-out week, no action needed
      INSERT INTO pri_item_history (item_id, actor_id, action, new_value)
      VALUES (v_item_id, auth.uid(), 'checked_out', 'left');
    END IF;
  END LOOP;

  RETURN v_new_week_id;
END;
$$;


--
-- Name: pri_cycle_item_status(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.pri_cycle_item_status(p_item_id uuid, p_actor_id uuid DEFAULT NULL::uuid) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_current TEXT;
  v_next TEXT;
BEGIN
  SELECT status INTO v_current FROM pri_items WHERE id = p_item_id;

  IF v_current IS NULL THEN
    RAISE EXCEPTION 'Item not found: %', p_item_id;
  END IF;

  -- Cycle: todo → in_progress → completed → todo
  v_next := CASE v_current
    WHEN 'todo' THEN 'in_progress'
    WHEN 'in_progress' THEN 'completed'
    WHEN 'completed' THEN 'todo'
  END;

  UPDATE pri_items SET status = v_next WHERE id = p_item_id;

  -- Audit trail
  INSERT INTO pri_item_history (item_id, actor_id, action, old_value, new_value)
  VALUES (p_item_id, COALESCE(p_actor_id, auth.uid()), 'status_changed', v_current, v_next);

  RETURN v_next;
END;
$$;


--
-- Name: pri_get_or_create_current_week(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.pri_get_or_create_current_week(p_list_id uuid) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_week_id UUID;
  v_week_start DATE;
  v_week_end DATE;
BEGIN
  -- Calculate current week boundaries (Sunday-based)
  v_week_start := date_trunc('week', CURRENT_DATE)::date;
  v_week_end := v_week_start + INTERVAL '4 days'; -- Friday

  -- Try to find existing active week
  SELECT id INTO v_week_id
  FROM pri_weeks
  WHERE list_id = p_list_id
    AND status = 'active'
    AND week_start = v_week_start;

  -- Create if not found
  IF v_week_id IS NULL THEN
    INSERT INTO pri_weeks (list_id, week_start, week_end, status)
    VALUES (p_list_id, v_week_start, v_week_end, 'active')
    RETURNING id INTO v_week_id;
  END IF;

  RETURN v_week_id;
END;
$$;


--
-- Name: pri_reorder_items(uuid, uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.pri_reorder_items(p_week_id uuid, p_item_ids uuid[]) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_rank INT := 1;
  v_item_id UUID;
BEGIN
  FOREACH v_item_id IN ARRAY p_item_ids
  LOOP
    UPDATE pri_items
    SET rank = v_rank
    WHERE id = v_item_id AND week_id = p_week_id;

    v_rank := v_rank + 1;
  END LOOP;
END;
$$;


--
-- Name: pri_update_timestamp(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.pri_update_timestamp() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$;


--
-- Name: process_sync_events(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.process_sync_events(batch_size integer DEFAULT 25) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  evt RECORD;
  jira_issue JSONB;
  mapped_status TEXT;
  mapped_lozenge TEXT;
  mapped_user_id UUID;
  mapped_reporter_id UUID;
  catalyst_proj_id UUID;
  existing_issue_id UUID;
  new_key TEXT;
  processed_count INTEGER := 0;
  failed_count INTEGER := 0;
  skipped_count INTEGER := 0;
BEGIN
  FOR evt IN
    SELECT * FROM sync_events
    WHERE status = 'pending'
    ORDER BY created_at ASC
    LIMIT batch_size
    FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      UPDATE sync_events SET status = 'processing' WHERE id = evt.id;

      IF evt.entity_type != 'issue' THEN
        UPDATE sync_events SET status = 'processed', processed_at = now() WHERE id = evt.id;
        skipped_count := skipped_count + 1;
        CONTINUE;
      END IF;

      jira_issue := evt.payload->'issue';
      IF jira_issue IS NULL THEN
        UPDATE sync_events SET status = 'failed', error_message = 'No issue in payload' WHERE id = evt.id;
        failed_count := failed_count + 1;
        CONTINUE;
      END IF;

      SELECT sc.project_id INTO catalyst_proj_id
      FROM sync_connections sc
      WHERE sc.jira_project_key = jira_issue->'fields'->'project'->>'key'
        AND sc.is_active = true
      LIMIT 1;

      IF catalyst_proj_id IS NULL THEN
        UPDATE sync_events SET status = 'failed', error_message = 'No matching project connection' WHERE id = evt.id;
        failed_count := failed_count + 1;
        CONTINUE;
      END IF;

      IF EXISTS (
        SELECT 1 FROM sync_cooldowns
        WHERE entity_key = 'issue:' || (jira_issue->>'id')
          AND expires_at > now()
      ) THEN
        UPDATE sync_events SET status = 'processed', processed_at = now(),
          error_message = 'Skipped: cooldown active (echo prevention)' WHERE id = evt.id;
        skipped_count := skipped_count + 1;
        CONTINUE;
      END IF;

      SELECT ssm.catalyst_status, ssm.catalyst_lozenge_color
      INTO mapped_status, mapped_lozenge
      FROM sync_status_map ssm
      WHERE ssm.project_id = catalyst_proj_id
        AND ssm.jira_status_name = jira_issue->'fields'->'status'->>'name'
      LIMIT 1;

      IF mapped_status IS NULL THEN
        mapped_status := CASE (jira_issue->'fields'->'status'->>'statusCategory')
          WHEN 'new' THEN 'To Do'
          WHEN 'indeterminate' THEN 'In Progress'
          WHEN 'done' THEN 'Done'
          ELSE 'To Do'
        END;
      END IF;

      SELECT sum.catalyst_user_id INTO mapped_user_id
      FROM sync_user_map sum
      WHERE sum.jira_account_id = jira_issue->'fields'->'assignee'->>'accountId'
        AND sum.is_active = true
      LIMIT 1;

      SELECT sum.catalyst_user_id INTO mapped_reporter_id
      FROM sync_user_map sum
      WHERE sum.jira_account_id = jira_issue->'fields'->'reporter'->>'accountId'
        AND sum.is_active = true
      LIMIT 1;

      SELECT sem.catalyst_entity_id INTO existing_issue_id
      FROM sync_entity_map sem
      WHERE sem.jira_entity_type = 'issue'
        AND sem.jira_entity_id = jira_issue->>'id';

      IF evt.event_type = 'jira:issue_deleted' THEN
        IF existing_issue_id IS NOT NULL THEN
          UPDATE catalyst_issues SET sync_enabled = false, updated_at = now()
          WHERE id = existing_issue_id;
        END IF;
      ELSIF existing_issue_id IS NOT NULL THEN
        UPDATE catalyst_issues SET
          title = COALESCE(jira_issue->'fields'->>'summary', title),
          description = COALESCE(
            jira_issue->'fields'->'description'->>'text',
            jira_issue->'fields'->>'description',
            description
          ),
          description_adf_raw = CASE
            WHEN jsonb_typeof(jira_issue->'fields'->'description') = 'object'
            THEN jira_issue->'fields'->'description'
            ELSE description_adf_raw
          END,
          status = COALESCE(mapped_status, status),
          priority = COALESCE(jira_issue->'fields'->'priority'->>'name', priority),
          assignee_id = mapped_user_id,
          reporter_id = COALESCE(mapped_reporter_id, reporter_id),
          issue_type = COALESCE(jira_issue->'fields'->'issuetype'->>'name', issue_type),
          sprint_name = jira_issue->'fields'->'sprint'->>'name',
          story_points = (jira_issue->'fields'->>'customfield_10016')::NUMERIC,
          last_modified_by_system = 'jira',
          updated_at = now()
        WHERE id = existing_issue_id;

        UPDATE sync_entity_map SET
          last_synced_at = now(),
          last_sync_status = 'synced',
          sync_version = sync_version + 1
        WHERE catalyst_entity_type = 'issue'
          AND catalyst_entity_id = existing_issue_id;
      ELSE
        new_key := next_issue_key(catalyst_proj_id);

        INSERT INTO catalyst_issues (
          project_id, issue_key, title, description, description_adf_raw,
          issue_type, status, priority, assignee_id, reporter_id,
          story_points, sprint_name, last_modified_by_system
        ) VALUES (
          catalyst_proj_id,
          new_key,
          COALESCE(jira_issue->'fields'->>'summary', 'Untitled'),
          COALESCE(jira_issue->'fields'->'description'->>'text', jira_issue->'fields'->>'description'),
          CASE WHEN jsonb_typeof(jira_issue->'fields'->'description') = 'object'
            THEN jira_issue->'fields'->'description' ELSE NULL END,
          COALESCE(jira_issue->'fields'->'issuetype'->>'name', 'Task'),
          COALESCE(mapped_status, 'To Do'),
          COALESCE(jira_issue->'fields'->'priority'->>'name', 'Medium'),
          mapped_user_id,
          mapped_reporter_id,
          (jira_issue->'fields'->>'customfield_10016')::NUMERIC,
          jira_issue->'fields'->'sprint'->>'name',
          'jira'
        )
        RETURNING id INTO existing_issue_id;

        INSERT INTO sync_entity_map (
          catalyst_entity_type, catalyst_entity_id,
          jira_entity_type, jira_entity_id, jira_entity_key,
          jira_self_url, sync_direction,
          last_synced_at, last_sync_status
        ) VALUES (
          'issue', existing_issue_id,
          'issue', jira_issue->>'id', jira_issue->>'key',
          jira_issue->>'self', 'bi',
          now(), 'synced'
        );
      END IF;

      INSERT INTO sync_cooldowns (entity_key, expires_at)
      VALUES ('issue:' || (jira_issue->>'id'), now() + interval '5 seconds')
      ON CONFLICT (entity_key) DO UPDATE SET expires_at = now() + interval '5 seconds';

      UPDATE sync_events SET status = 'processed', processed_at = now() WHERE id = evt.id;
      processed_count := processed_count + 1;

    EXCEPTION WHEN OTHERS THEN
      UPDATE sync_events SET
        status = CASE WHEN evt.retry_count >= 3 THEN 'dead' ELSE 'failed' END,
        retry_count = evt.retry_count + 1,
        error_message = SQLERRM
      WHERE id = evt.id;

      IF evt.retry_count >= 3 THEN
        INSERT INTO sync_dead_letter (original_event_id, payload, error_message)
        VALUES (evt.id, evt.payload, SQLERRM);
      END IF;

      failed_count := failed_count + 1;
    END;
  END LOOP;

  DELETE FROM sync_cooldowns WHERE expires_at < now();

  INSERT INTO sync_health (project_id, check_type, status, events_received, events_processed, events_failed, checked_at)
  SELECT DISTINCT
    sc.project_id,
    'queue_processing',
    CASE WHEN failed_count > 0 THEN 'degraded' ELSE 'healthy' END,
    processed_count + failed_count + skipped_count,
    processed_count,
    failed_count,
    now()
  FROM sync_connections sc WHERE sc.is_active = true
  LIMIT 1;

  RETURN jsonb_build_object(
    'processed', processed_count,
    'failed', failed_count,
    'skipped', skipped_count
  );
END;
$$;


--
-- Name: promote_to_roadmap(uuid, uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.promote_to_roadmap(p_initiative_id uuid, p_user_id uuid DEFAULT NULL::uuid, p_roadmap_priority integer DEFAULT NULL::integer) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_result JSONB;
BEGIN
  UPDATE ph_initiatives SET
    on_roadmap = true,
    roadmap_added_at = now(),
    roadmap_added_by = COALESCE(p_user_id, roadmap_added_by),
    roadmap_priority = COALESCE(p_roadmap_priority, roadmap_priority),
    updated_at = now()
  WHERE id = p_initiative_id
  RETURNING jsonb_build_object(
    'id', id, 'title', title, 'on_roadmap', on_roadmap, 'roadmap_added_at', roadmap_added_at
  ) INTO v_result;
  RETURN v_result;
END;
$$;


--
-- Name: prune_user_recent_items(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.prune_user_recent_items() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  DELETE FROM public.user_recent_items
  WHERE id IN (
    SELECT id FROM public.user_recent_items
    WHERE user_id = NEW.user_id AND project_id = NEW.project_id
    ORDER BY visited_at DESC
    OFFSET 10
  );
  RETURN NEW;
END;
$$;


--
-- Name: publish_ai_brief(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.publish_ai_brief(brief_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_scope TEXT;
  v_entity_id UUID;
  v_next_version INTEGER;
BEGIN
  -- Verify caller is admin
  IF NOT public.is_ai_brief_admin(auth.uid()) THEN
    RAISE EXCEPTION 'Only admins can publish briefs';
  END IF;

  -- Get the scope of the brief being published
  SELECT scope, scope_entity_id INTO v_scope, v_entity_id
  FROM public.ai_briefs WHERE id = brief_id AND status = 'draft';
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Brief not found or not in draft status';
  END IF;
  
  -- Archive the current published brief for this scope
  UPDATE public.ai_briefs 
  SET status = 'archived', updated_at = NOW()
  WHERE scope = v_scope 
    AND (scope_entity_id IS NOT DISTINCT FROM v_entity_id)
    AND status = 'published';
  
  -- Get next version number
  SELECT COALESCE(MAX(version), 0) + 1 INTO v_next_version
  FROM public.ai_briefs 
  WHERE scope = v_scope 
    AND (scope_entity_id IS NOT DISTINCT FROM v_entity_id);
  
  -- Publish the new brief
  UPDATE public.ai_briefs 
  SET 
    status = 'published',
    version = v_next_version,
    published_at = NOW(),
    published_by = auth.uid(),
    updated_at = NOW()
  WHERE id = brief_id;
END;
$$;


--
-- Name: purge_old_sync_activity(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.purge_old_sync_activity() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  DELETE FROM public.jira_sync_activity
  WHERE created_at < now() - INTERVAL '30 days';
END;
$$;


--
-- Name: quick_create_defect_v2(uuid, uuid, uuid, text, text, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.quick_create_defect_v2(p_project_id uuid, p_step_result_id uuid, p_run_id uuid DEFAULT NULL::uuid, p_title text DEFAULT NULL::text, p_description text DEFAULT NULL::text, p_severity text DEFAULT 'major'::text, p_assigned_to uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
  v_defect_id UUID;
  v_defect_key TEXT;
  v_link_id UUID;
  v_actor UUID := auth.uid();
  v_next_number INTEGER;
BEGIN
  -- Validate project
  IF NOT EXISTS (SELECT 1 FROM projects WHERE id = p_project_id AND deleted_at IS NULL) THEN
    RETURN jsonb_build_object('error', 'Project not found');
  END IF;

  -- Validate title
  IF TRIM(COALESCE(p_title, '')) = '' THEN
    RETURN jsonb_build_object('error', 'Defect title is required');
  END IF;

  -- Generate defect key
  SELECT COALESCE(MAX(CAST(SUBSTRING(key FROM '[0-9]+$') AS INTEGER)), 0) + 1
  INTO v_next_number
  FROM tm_defects
  WHERE project_id = p_project_id;

  v_defect_key := 'DEF-' || LPAD(v_next_number::TEXT, 4, '0');

  -- Create defect
  INSERT INTO tm_defects (
    project_id,
    key,
    title,
    description,
    severity,
    status,
    assigned_to,
    reported_by,
    auto_created
  ) VALUES (
    p_project_id,
    v_defect_key,
    TRIM(p_title),
    NULLIF(TRIM(COALESCE(p_description, '')), ''),
    COALESCE(p_severity, 'major'),
    'open',
    p_assigned_to,
    v_actor,
    true
  )
  RETURNING id INTO v_defect_id;

  -- Auto-link to step if provided
  IF p_step_result_id IS NOT NULL THEN
    INSERT INTO tm_defect_links (
      defect_id,
      step_result_id,
      run_id,
      linked_by,
      link_type
    ) VALUES (
      v_defect_id,
      p_step_result_id,
      p_run_id,
      v_actor,
      'auto'
    )
    RETURNING id INTO v_link_id;
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'defect_id', v_defect_id,
    'defect_key', v_defect_key,
    'link_id', v_link_id
  );
END;
$_$;


--
-- Name: r360_compute_completion_pct(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.r360_compute_completion_pct() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.total_items > 0 THEN
    NEW.completion_pct = ROUND((NEW.done_count::NUMERIC / NEW.total_items) * 100, 2);
  ELSE
    NEW.completion_pct = 0;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: r360_detect_significant_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.r360_detect_significant_change() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_resource_id TEXT;
  v_department TEXT;
  v_is_significant BOOLEAN := FALSE;
  v_reason TEXT;
BEGIN
  IF TG_OP = 'INSERT' THEN
    v_resource_id := NEW.assignee_account_id;
    v_is_significant := TRUE;
    v_reason := 'new_issue_assigned';
  ELSIF TG_OP = 'UPDATE' THEN
    IF OLD.status IS DISTINCT FROM NEW.status THEN
      v_is_significant := TRUE;
      v_reason := 'status_changed:' || COALESCE(OLD.status,'null') || '->' || NEW.status;
      v_resource_id := NEW.assignee_account_id;
    END IF;
    IF OLD.assignee_account_id IS DISTINCT FROM NEW.assignee_account_id THEN
      v_is_significant := TRUE;
      v_reason := 'reassigned';
      IF OLD.assignee_account_id IS NOT NULL THEN
        PERFORM public.r360_mark_resource_stale(OLD.assignee_account_id, 'reassigned_away');
      END IF;
      v_resource_id := NEW.assignee_account_id;
    END IF;
    IF OLD.jira_removed_at IS NULL AND NEW.jira_removed_at IS NOT NULL THEN
      v_is_significant := TRUE;
      v_reason := 'soft_deleted';
      v_resource_id := NEW.assignee_account_id;
    END IF;
  ELSIF TG_OP = 'DELETE' THEN
    v_resource_id := OLD.assignee_account_id;
    v_is_significant := TRUE;
    v_reason := 'hard_deleted';
  END IF;

  IF v_is_significant AND v_resource_id IS NOT NULL THEN
    SELECT department_name INTO v_department
    FROM public.resource_inventory
    WHERE id::text = v_resource_id
    LIMIT 1;

    PERFORM public.r360_mark_resource_stale(v_resource_id, v_reason);

    IF v_department IS NOT NULL THEN
      PERFORM public.r360_mark_department_stale(v_department, v_reason);
    END IF;
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: r360_effective_due_date(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.r360_effective_due_date(p_work_item_id uuid) RETURNS date
    LANGUAGE sql STABLE
    AS $$
  SELECT COALESCE(wi.due_date, rel.end_date)
  FROM r360_work_items wi
  LEFT JOIN r360_releases rel ON rel.id = wi.release_id
  WHERE wi.id = p_work_item_id;
$$;


--
-- Name: r360_mark_department_stale(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.r360_mark_department_stale(p_department text, p_reason text DEFAULT 'unknown'::text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  UPDATE public.r360_ai_cache
  SET status = 'stale',
      is_stale = TRUE,
      stale_at = NOW(),
      stale_reason = p_reason,
      updated_at = NOW()
  WHERE scope_type = 'department'
    AND scope_id = p_department
    AND status = 'fresh';
END;
$$;


--
-- Name: r360_mark_resource_stale(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.r360_mark_resource_stale(p_resource_id text, p_reason text DEFAULT 'unknown'::text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  UPDATE public.r360_ai_cache
  SET status = 'stale',
      is_stale = TRUE,
      stale_at = NOW(),
      stale_reason = p_reason,
      updated_at = NOW()
  WHERE scope_type = 'resource'
    AND scope_id = p_resource_id
    AND status = 'fresh';

  UPDATE public.r360_ai_resource_index
  SET cache_status = 'stale', updated_at = NOW()
  WHERE resource_id = p_resource_id;
END;
$$;


