--
-- Name: ra_generate_item_display_id(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ra_generate_item_display_id() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
DECLARE
    prefix TEXT;
    next_num INTEGER;
BEGIN
    CASE NEW.item_type
        WHEN 'prd' THEN prefix := 'PRD-';
        WHEN 'epic' THEN prefix := 'EPIC-';
        WHEN 'feature' THEN prefix := 'FEAT-';
        WHEN 'story' THEN prefix := 'US-';
    END CASE;
    
    SELECT COALESCE(MAX(
        CAST(SUBSTRING(display_id FROM '[0-9]+$') AS INTEGER)
    ), 0) + 1
    INTO next_num
    FROM ra_generated_items
    WHERE item_type = NEW.item_type;
    
    NEW.display_id := prefix || LPAD(next_num::TEXT, 3, '0');
    RETURN NEW;
END;
$_$;


