--
-- Name: refresh_dynamic_test_set(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.refresh_dynamic_test_set(p_set_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_set tm_test_sets%ROWTYPE;
  v_criteria JSONB;
  v_added_count INTEGER;
  v_removed_count INTEGER;
  v_priority_ids UUID[];
BEGIN
  SELECT * INTO v_set FROM tm_test_sets WHERE id = p_set_id;
  IF v_set.id IS NULL THEN RAISE EXCEPTION 'Test set not found'; END IF;
  IF v_set.membership_type != 'dynamic' THEN RAISE EXCEPTION 'Not a dynamic set'; END IF;
  v_criteria := v_set.dynamic_criteria;
  IF v_criteria IS NULL THEN RAISE EXCEPTION 'No criteria defined'; END IF;

  IF v_criteria->'priority' IS NOT NULL AND jsonb_array_length(v_criteria->'priority') > 0 THEN
    SELECT ARRAY_AGG(cp.id) INTO v_priority_ids
    FROM tm_case_priorities cp
    WHERE LOWER(cp.name) = ANY(SELECT LOWER(jsonb_array_elements_text(v_criteria->'priority')));
  END IF;

  SELECT COUNT(*) INTO v_removed_count FROM tm_test_set_cases WHERE test_set_id = p_set_id;
  DELETE FROM tm_test_set_cases WHERE test_set_id = p_set_id;

  INSERT INTO tm_test_set_cases (test_set_id, test_case_id, sort_order, added_by)
  SELECT p_set_id, tc.id, ROW_NUMBER() OVER (ORDER BY tc.case_key)::integer, v_set.owner_id
  FROM tm_test_cases tc
  WHERE tc.project_id = v_set.project_id
  AND tc.status != 'deprecated'
  AND (v_priority_ids IS NULL OR tc.priority_id = ANY(v_priority_ids))
  AND (v_criteria->>'folder_id' IS NULL OR v_criteria->>'folder_id' = ''
       OR tc.folder_id = (v_criteria->>'folder_id')::uuid);

  GET DIAGNOSTICS v_added_count = ROW_COUNT;
  RETURN json_build_object('set_id', p_set_id, 'added', v_added_count, 'removed', v_removed_count, 'refreshed_at', NOW());
END;
$$;


--
-- Name: refresh_home_user_summary(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.refresh_home_user_summary(p_user_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_operations JSONB;
  v_delivery JSONB;
  v_planner JSONB;
BEGIN
  -- Calculate Operations counts
  SELECT jsonb_build_object(
    'total_incidents', COUNT(*) FILTER (WHERE status NOT IN ('resolved', 'closed')),
    'major_incidents', COUNT(*) FILTER (WHERE is_major_incident = true AND status NOT IN ('resolved', 'closed')),
    'sla_at_risk', COUNT(*) FILTER (WHERE severity IN ('SEV1', 'SEV2') AND status NOT IN ('resolved', 'closed')),
    'awaiting_me', COUNT(*) FILTER (WHERE assignee_id = p_user_id AND status NOT IN ('resolved', 'closed')),
    'blocked', 0,
    'active_releases', 0
  ) INTO v_operations
  FROM incidents
  WHERE deleted_at IS NULL
    AND (assignee_id = p_user_id OR reporter_id = p_user_id);

  -- Calculate Delivery counts
  WITH delivery_items AS (
    SELECT 'epic' as item_type, id, assignee_id, updated_at 
    FROM epics WHERE deleted_at IS NULL AND assignee_id = p_user_id
    UNION ALL
    SELECT 'feature', id, assignee_id, updated_at 
    FROM features WHERE deleted_at IS NULL AND assignee_id = p_user_id
    UNION ALL
    SELECT 'story', id, assignee_id, updated_at 
    FROM stories WHERE deleted_at IS NULL AND assignee_id = p_user_id
    UNION ALL
    SELECT 'task', id, assignee_id, updated_at 
    FROM work_manager_tasks WHERE assignee_id = p_user_id
  ),
  starred AS (
    SELECT COUNT(*) as cnt FROM starred_items WHERE user_id = p_user_id
  ),
  worked_on AS (
    SELECT COUNT(DISTINCT work_item_id) as cnt 
    FROM work_item_activity 
    WHERE user_id = p_user_id 
      AND occurred_at > NOW() - INTERVAL '7 days'
  )
  SELECT jsonb_build_object(
    'assigned', (SELECT COUNT(*) FROM delivery_items),
    'worked_on', COALESCE((SELECT cnt FROM worked_on), 0),
    'starred', COALESCE((SELECT cnt FROM starred), 0),
    'by_type', jsonb_build_object(
      'epic', (SELECT COUNT(*) FROM delivery_items WHERE item_type = 'epic'),
      'feature', (SELECT COUNT(*) FROM delivery_items WHERE item_type = 'feature'),
      'story', (SELECT COUNT(*) FROM delivery_items WHERE item_type = 'story'),
      'task', (SELECT COUNT(*) FROM delivery_items WHERE item_type = 'task')
    )
  ) INTO v_delivery;

  -- Calculate Planner counts
  SELECT jsonb_build_object(
    'planned', COUNT(*) FILTER (WHERE status = 'planned'),
    'upcoming', COUNT(*) FILTER (WHERE status = 'upcoming' OR (due_date BETWEEN NOW() AND NOW() + INTERVAL '14 days')),
    'pending_review', COUNT(*) FILTER (WHERE status = 'pending_review')
  ) INTO v_planner
  FROM work_manager_tasks
  WHERE created_by = p_user_id OR assignee_id = p_user_id;

  -- Upsert summary
  INSERT INTO home_user_summary (user_id, operations_counts, delivery_counts, planner_counts, last_computed_at, updated_at)
  VALUES (p_user_id, v_operations, v_delivery, v_planner, NOW(), NOW())
  ON CONFLICT (user_id) 
  DO UPDATE SET
    operations_counts = EXCLUDED.operations_counts,
    delivery_counts = EXCLUDED.delivery_counts,
    planner_counts = EXCLUDED.planner_counts,
    last_computed_at = NOW(),
    updated_at = NOW();
END;
$$;


--
-- Name: remove_from_queue(uuid, uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.remove_from_queue(p_run_id uuid, p_item_ids uuid[]) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_removed_count INTEGER;
BEGIN
  -- Mark as skipped (soft delete from queue)
  WITH updated AS (
    UPDATE execution_queue SET
      status = 'skipped',
      completed_at = NOW()
    WHERE run_id = p_run_id
      AND id = ANY(p_item_ids)
      AND status = 'queued'
    RETURNING id
  )
  SELECT COUNT(*) INTO v_removed_count FROM updated;

  -- Recompact positions
  WITH ranked AS (
    SELECT id, ROW_NUMBER() OVER (ORDER BY position) as new_pos
    FROM execution_queue
    WHERE run_id = p_run_id
      AND status = 'queued'
  )
  UPDATE execution_queue eq SET
    position = r.new_pos
  FROM ranked r
  WHERE eq.id = r.id;

  RETURN jsonb_build_object('success', true, 'removed_count', v_removed_count);
END;
$$;


