END;
$$;


--
-- Name: remove_project_member(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.remove_project_member(p_project_id uuid, p_user_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_admin_count INTEGER;
BEGIN
  -- Check if remover is admin
  IF NOT EXISTS (
    SELECT 1 FROM public.project_members 
    WHERE project_id = p_project_id 
    AND user_id = v_user_id 
    AND role = 'admin'
  ) THEN
    RAISE EXCEPTION 'Only admins can remove members';
  END IF;
  
  -- Prevent removing the last admin
  SELECT COUNT(*) INTO v_admin_count
  FROM public.project_members 
  WHERE project_id = p_project_id AND role = 'admin';
  
  IF v_admin_count <= 1 AND EXISTS (
    SELECT 1 FROM public.project_members 
    WHERE project_id = p_project_id AND user_id = p_user_id AND role = 'admin'
  ) THEN
    RAISE EXCEPTION 'Cannot remove the last admin';
  END IF;
  
  DELETE FROM public.project_members 
  WHERE project_id = p_project_id AND user_id = p_user_id;
  
  RETURN TRUE;
END;
$$;


--
-- Name: reorder_planner_tasks_down(uuid, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reorder_planner_tasks_down(p_status_id uuid, p_old_position integer, p_new_position integer) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  UPDATE public.planner_tasks
  SET position = position - 1
  WHERE status_id = p_status_id
    AND position > p_old_position
    AND position <= p_new_position
    AND deleted_at IS NULL;
END;
$$;


--
-- Name: reorder_planner_tasks_up(uuid, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reorder_planner_tasks_up(p_status_id uuid, p_old_position integer, p_new_position integer) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  UPDATE public.planner_tasks
  SET position = position + 1
  WHERE status_id = p_status_id
    AND position >= p_new_position
    AND position < p_old_position
    AND deleted_at IS NULL;
END;
$$;


--
-- Name: reorder_queue_item(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reorder_queue_item(p_queue_item_id uuid, p_new_position integer) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_item RECORD;
  v_run_id UUID;
  v_old_position INTEGER;
  v_max_position INTEGER;
BEGIN
  -- Get current item
  SELECT * INTO v_item
  FROM execution_queue
  WHERE id = p_queue_item_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Queue item not found');
  END IF;

  v_run_id := v_item.run_id;
  v_old_position := v_item.position;

  -- Get max position
  SELECT MAX(position) INTO v_max_position
  FROM execution_queue
  WHERE run_id = v_run_id AND status = 'queued';

  -- Clamp new position
  p_new_position := GREATEST(1, LEAST(p_new_position, COALESCE(v_max_position, 1)));

  IF v_old_position = p_new_position THEN
    RETURN jsonb_build_object('success', true, 'message', 'Position unchanged');
  END IF;

  -- Shift other items
  IF p_new_position < v_old_position THEN
    -- Moving up: shift items down
    UPDATE execution_queue SET
      position = position + 1
    WHERE run_id = v_run_id
      AND position >= p_new_position
      AND position < v_old_position
      AND id != p_queue_item_id;
  ELSE
    -- Moving down: shift items up
    UPDATE execution_queue SET
      position = position - 1
    WHERE run_id = v_run_id
      AND position > v_old_position
      AND position <= p_new_position
      AND id != p_queue_item_id;
  END IF;

  -- Update item position
  UPDATE execution_queue SET
    position = p_new_position
  WHERE id = p_queue_item_id;

  RETURN jsonb_build_object(
    'success', true,
    'old_position', v_old_position,
    'new_position', p_new_position
  );
END;
$$;


--
-- Name: reorder_remaining_steps(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reorder_remaining_steps(p_test_case_id uuid, p_deleted_order integer) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE test_steps
  SET step_order = step_order - 1
  WHERE test_case_id = p_test_case_id AND step_order > p_deleted_order;
END;
$$;


--
-- Name: reorder_test_steps(uuid, uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reorder_test_steps(p_test_case_id uuid, p_step_ids uuid[]) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  i INTEGER;
BEGIN
  -- Temporarily set all orders to negative to avoid unique constraint
  UPDATE test_steps SET step_order = -step_order WHERE test_case_id = p_test_case_id;
  
  -- Set new orders
  FOR i IN 1..array_length(p_step_ids, 1) LOOP
    UPDATE test_steps
    SET step_order = i
    WHERE id = p_step_ids[i] AND test_case_id = p_test_case_id;
  END LOOP;
  
  -- Log activity
  PERFORM log_test_case_activity(
    p_test_case_id,
    'step_reordered',
    'Steps reordered',
    jsonb_build_object('step_ids', p_step_ids)
  );
END;
$$;


--
-- Name: requeue_abandoned_tests(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.requeue_abandoned_tests(p_run_id uuid, p_timeout_seconds integer DEFAULT 300) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_requeued INTEGER := 0;
  v_worker RECORD;
BEGIN
  FOR v_worker IN
    SELECT w.*, eq.id as queue_item_id
    FROM parallel_workers w
    JOIN execution_queue eq ON eq.claimed_by = w.id
    WHERE w.run_id = p_run_id
      AND w.status = 'running'
      AND w.last_heartbeat < NOW() - (p_timeout_seconds * INTERVAL '1 second')
      AND eq.status = 'claimed'
  LOOP
    UPDATE execution_queue SET
      status = 'queued',
      claimed_by = NULL,
      claimed_at = NULL,
      retry_count = retry_count + 1
    WHERE id = v_worker.queue_item_id;

    UPDATE parallel_workers SET
      status = 'error',
      current_test_id = NULL,
      current_execution_id = NULL,
      claimed_at = NULL
    WHERE id = v_worker.id;

    v_requeued := v_requeued + 1;
  END LOOP;

  RETURN jsonb_build_object('requeued_count', v_requeued);
END;
$$;


--
-- Name: restore_deleted_items(jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.restore_deleted_items(p_test_case_ids jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_item RECORD;
  v_restored INTEGER := 0;
  v_actor UUID := auth.uid();
BEGIN
  FOR v_item IN 
    SELECT * FROM deleted_items_log
    WHERE test_case_id = ANY(
      SELECT (jsonb_array_elements_text(p_test_case_ids))::UUID
    )
    AND delete_type = 'soft'
    AND restored_at IS NULL
    AND expires_at > NOW()
  LOOP
    -- Restore test case
    UPDATE test_cases SET
      deleted_at = NULL
    WHERE id = v_item.test_case_id;

    -- Mark as restored
    UPDATE deleted_items_log SET
      restored_at = NOW(),
      restored_by = v_actor
    WHERE id = v_item.id;

    v_restored := v_restored + 1;
  END LOOP;

  RETURN jsonb_build_object(
    'success', true,
    'restored', v_restored
  );
END;
$$;


--
-- Name: resume_step_timer(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.resume_step_timer(p_execution_id uuid, p_step_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_result RECORD;
  v_pause_duration INTEGER;
BEGIN
  SELECT * INTO v_result
  FROM test_execution_step_results
  WHERE execution_id = p_execution_id 
    AND step_id = p_step_id
    AND timer_paused_at IS NOT NULL;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'No paused timer found for this step');
  END IF;

  v_pause_duration := EXTRACT(EPOCH FROM (NOW() - v_result.timer_paused_at))::INTEGER;

  UPDATE test_execution_step_results SET
    timer_paused_at = NULL,
    timer_total_paused = COALESCE(timer_total_paused, 0) + v_pause_duration,
    is_timer_running = true
  WHERE id = v_result.id;

  RETURN jsonb_build_object(
    'success', true,
    'resumed_at', NOW(),
    'total_paused_seconds', COALESCE(v_result.timer_total_paused, 0) + v_pause_duration
  );
END;
$$;


--
-- Name: retry_failed_sync_events(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.retry_failed_sync_events() RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  retried INTEGER;
BEGIN
  UPDATE sync_events
  SET status = 'pending'
  WHERE status = 'failed'
    AND retry_count < 3
    AND created_at > now() - interval '24 hours';
  GET DIAGNOSTICS retried = ROW_COUNT;
  RETURN retried;
END;
$$;


--
-- Name: rh_import_jira_versions(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rh_import_jira_versions(p_project_key text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_idempotency_key text;
  v_existing_count  int;
BEGIN
  v_idempotency_key := 'catalyst:import:versions:' ||
                        p_project_key || ':' ||
                        to_char(now(), 'YYYY-MM-DD-HH24');

  SELECT COUNT(*) INTO v_existing_count
  FROM sync_events
  WHERE idempotency_key = v_idempotency_key;

  IF v_existing_count > 0 THEN
    RETURN jsonb_build_object(
      'queued', false,
      'reason', 'Import already requested this hour'
    );
  END IF;

  INSERT INTO sync_events (
    direction, origin_system, event_type,
    entity_type, entity_id, idempotency_key,
    payload, status
  ) VALUES (
    'inbound', 'jira', 'import_versions',
    'rh_release', p_project_key, v_idempotency_key,
    jsonb_build_object('project_key', p_project_key),
    'pending'
  );

  RETURN jsonb_build_object('queued', true, 'project_key', p_project_key);
END;
$$;


--
-- Name: rh_release_outbound_trigger_fn(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rh_release_outbound_trigger_fn() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF NEW.jira_key IS NOT NULL THEN
    RETURN NEW;
  END IF;

  INSERT INTO sync_events (
    direction, origin_system, event_type,
    entity_type, entity_id, idempotency_key,
    payload, status
  ) VALUES (
    'outbound', 'catalyst', 'release_created',
    'rh_release', NEW.id::text,
    'catalyst:release:' || NEW.id::text || ':created',
    jsonb_build_object(
      'id',          NEW.id,
      'name',        NEW.name,
      'description', NEW.description,
      'target_date', NEW.target_date,
      'status',      NEW.status,
      'project_id',  NEW.project_id
    ),
    'pending'
  )
  ON CONFLICT (idempotency_key) DO NOTHING;

  RETURN NEW;
END;
$$;


--
-- Name: rh_release_status_activity_fn(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rh_release_status_activity_fn() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF OLD.status IS NOT DISTINCT FROM NEW.status THEN
    RETURN NEW;
  END IF;

  INSERT INTO rh_release_activity_log (
    release_id, actor_name, actor_initials, action, detail, is_ai, created_at
  ) VALUES (
    NEW.id,
    'System',
    'SY',
    'Status changed',
    'Status changed from ' || OLD.status || ' to ' || NEW.status,
    false,
    now()
  );

  RETURN NEW;
END;
$$;


