--
-- Name: save_entity_snapshot(character varying, uuid, jsonb, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.save_entity_snapshot(p_entity_type character varying, p_entity_id uuid, p_snapshot jsonb, p_change_reason text DEFAULT NULL::text) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_version INTEGER;
BEGIN
  SELECT COALESCE(MAX(version), 0) + 1 INTO v_version
  FROM th_entity_history
  WHERE entity_type = p_entity_type AND entity_id = p_entity_id;

  INSERT INTO th_entity_history (
    entity_type, entity_id, version, snapshot, changed_by, change_reason
  ) VALUES (
    p_entity_type, p_entity_id, v_version, p_snapshot, auth.uid(), p_change_reason
  );

  RETURN v_version;
END;
$$;


--
-- Name: save_step_notes_v2(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.save_step_notes_v2(p_run_id uuid, p_step_id uuid, p_actual_result text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
BEGIN
  -- Update or insert notes (using actual_result field since tm_step_results doesn't have notes)
  INSERT INTO tm_step_results (
    test_run_id,
    test_step_id,
    actual_result,
    executed_by,
    executed_at
  ) VALUES (
    p_run_id,
    p_step_id,
    NULLIF(TRIM(COALESCE(p_actual_result, '')), ''),
    v_actor,
    NOW()
  )
  ON CONFLICT (test_run_id, test_step_id) DO UPDATE SET
    actual_result = EXCLUDED.actual_result,
    updated_at = NOW();

  RETURN jsonb_build_object('success', true);
END;
$$;


--
-- Name: save_step_result_with_evidence(uuid, uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.save_step_result_with_evidence(p_execution_id uuid, p_step_id uuid, p_actual_result text DEFAULT NULL::text, p_notes text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_step_result_id UUID;
  v_step_order INTEGER;
  v_step_description TEXT;
  v_expected_result TEXT;
BEGIN
  -- Get step details
  SELECT step_order, action, expected_result INTO v_step_order, v_step_description, v_expected_result
  FROM test_steps
  WHERE id = p_step_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Step not found');
  END IF;

  -- Upsert step result
  INSERT INTO test_execution_step_results (
    id,
    execution_id,
    step_order,
    step_description,
    expected_result,
    actual_result,
    comments,
    status
  ) VALUES (
    gen_random_uuid(),
    p_execution_id,
    v_step_order,
    v_step_description,
    v_expected_result,
    NULLIF(TRIM(COALESCE(p_actual_result, '')), ''),
    NULLIF(TRIM(COALESCE(p_notes, '')), ''),
    'pending'
  )
  ON CONFLICT (execution_id, step_order) DO UPDATE SET
    actual_result = COALESCE(EXCLUDED.actual_result, test_execution_step_results.actual_result),
    comments = COALESCE(EXCLUDED.comments, test_execution_step_results.comments)
  RETURNING id INTO v_step_result_id;

  RETURN jsonb_build_object(
    'success', true,
    'step_result_id', v_step_result_id
  );
END;
$$;


--
-- Name: save_test_data(uuid, jsonb, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.save_test_data(p_test_case_id uuid, p_parameters jsonb, p_rows jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_param record;
  v_row record;
  v_inserted_params int := 0;
  v_inserted_rows int := 0;
  v_user_id uuid;
  v_project_id uuid;
  v_user_role text;
BEGIN
  -- Get the current user
  v_user_id := auth.uid();
  
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;
  
  -- Get the project_id from the test case
  SELECT project_id INTO v_project_id
  FROM tm_test_cases
  WHERE id = p_test_case_id;
  
  IF v_project_id IS NULL THEN
    RAISE EXCEPTION 'Test case not found';
  END IF;
  
  -- Check if user is admin OR is a project member
  SELECT role INTO v_user_role FROM profiles WHERE id = v_user_id;
  
  IF v_user_role != 'admin' AND NOT is_project_member(v_user_id, v_project_id) THEN
    RAISE EXCEPTION 'Access denied - not a project member';
  END IF;

  -- Delete existing parameters and rows for this test case (atomic within transaction)
  DELETE FROM test_data_parameters WHERE test_case_id = p_test_case_id;
  DELETE FROM test_data_rows WHERE test_case_id = p_test_case_id;
  
  -- Insert new parameters
  IF p_parameters IS NOT NULL AND jsonb_array_length(p_parameters) > 0 THEN
    FOR v_param IN SELECT * FROM jsonb_array_elements(p_parameters)
    LOOP
      INSERT INTO test_data_parameters (
        test_case_id,
        parameter_name,
        parameter_type,
        column_order,
        created_at,
        updated_at
      ) VALUES (
        p_test_case_id,
        v_param.value->>'parameter_name',
        COALESCE(v_param.value->>'parameter_type', 'text'),
        COALESCE((v_param.value->>'column_order')::int, 0),
        now(),
        now()
      );
      v_inserted_params := v_inserted_params + 1;
    END LOOP;
  END IF;
  
  -- Insert new rows
  IF p_rows IS NOT NULL AND jsonb_array_length(p_rows) > 0 THEN
    FOR v_row IN SELECT * FROM jsonb_array_elements(p_rows)
    LOOP
      INSERT INTO test_data_rows (
        test_case_id,
        row_data,
        row_order,
        created_at,
        updated_at
      ) VALUES (
        p_test_case_id,
        v_row.value->'row_data',
        COALESCE((v_row.value->>'row_order')::int, 0),
        now(),
        now()
      );
      v_inserted_rows := v_inserted_rows + 1;
    END LOOP;
  END IF;
  
  RETURN jsonb_build_object(
    'success', true,
    'parameters_saved', v_inserted_params,
    'rows_saved', v_inserted_rows
  );
END;
$$;


--
-- Name: test_evidence; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.test_evidence (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    execution_step_id uuid NOT NULL,
    file_name character varying(255) NOT NULL,
    file_type character varying(50) NOT NULL,
    file_path text NOT NULL,
    file_size bigint NOT NULL,
    mime_type character varying(100) NOT NULL,
    uploaded_by uuid NOT NULL,
    created_at timestamp with time zone DEFAULT now(),
    capture_method text DEFAULT 'file_browser'::text,
    width integer,
    height integer,
    original_file_name text,
    storage_path text,
    is_deleted boolean DEFAULT false,
    deleted_at timestamp with time zone,
    deleted_by uuid,
    ocr_text text,
    ocr_confidence numeric(5,4),
    ocr_processed_at timestamp with time zone,
    ai_analysis jsonb,
    ai_analyzed_at timestamp with time zone,
    annotations jsonb DEFAULT '[]'::jsonb,
    annotations_updated_at timestamp with time zone,
    annotated_file_path text,
    CONSTRAINT test_evidence_capture_method_check CHECK ((capture_method = ANY (ARRAY['screen_capture'::text, 'clipboard_paste'::text, 'drag_drop'::text, 'file_browser'::text]))),
    CONSTRAINT test_evidence_file_type_check CHECK (((file_type)::text = ANY (ARRAY[('image'::character varying)::text, ('video'::character varying)::text, ('document'::character varying)::text, ('log'::character varying)::text])))
);


--
-- Name: search_evidence_by_ocr(text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.search_evidence_by_ocr(search_query text, execution_step_id uuid DEFAULT NULL::uuid) RETURNS SETOF public.test_evidence
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT *
  FROM public.test_evidence
  WHERE 
    is_deleted = false
    AND ocr_text IS NOT NULL
    AND to_tsvector('english', ocr_text) @@ plainto_tsquery('english', search_query)
    AND (execution_step_id IS NULL OR test_evidence.execution_step_id = search_evidence_by_ocr.execution_step_id)
  ORDER BY created_at DESC;
$$;


--
-- Name: search_test_cases_by_tags(uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.search_test_cases_by_tags(p_tag_ids uuid[]) RETURNS TABLE(test_case_id uuid, case_key text, title text, priority text, matching_tags bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    tc.id,
    tc.case_key,
    tc.title,
    tc.priority,
    COUNT(tct.tag_id)::BIGINT as matching_tags
  FROM th_test_cases tc
  JOIN th_test_case_tags tct ON tct.test_case_id = tc.id
  WHERE tct.tag_id = ANY(p_tag_ids)
  GROUP BY tc.id, tc.case_key, tc.title, tc.priority
  ORDER BY matching_tags DESC, tc.case_key;
END;
$$;


--
-- Name: search_tm_defects(uuid, text, text[], integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.search_tm_defects(p_project_id uuid, p_query text DEFAULT NULL::text, p_status text[] DEFAULT NULL::text[], p_limit integer DEFAULT 20) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
  v_results JSONB;
BEGIN
  -- Handle defect key search (DEF-XXXX or similar)
  IF p_query IS NOT NULL AND TRIM(p_query) != '' AND p_query ~* '^[A-Z]+-\d+$' THEN
    SELECT COALESCE(
      jsonb_agg(
        jsonb_build_object(
          'id', d.id,
          'key', d.key,
          'title', d.title,
          'status', d.status,
          'severity', d.severity,
          'assignee', CASE 
            WHEN d.assigned_to IS NOT NULL THEN jsonb_build_object(
              'id', p.id,
              'name', p.full_name
            )
            ELSE NULL
          END,
          'created_at', d.created_at
        )
      ),
      '[]'::jsonb
    ) INTO v_results
    FROM tm_defects d
    LEFT JOIN profiles p ON d.assigned_to = p.id
    WHERE d.project_id = p_project_id
      AND d.key ILIKE p_query || '%'
      AND (p_status IS NULL OR d.status = ANY(p_status))
    LIMIT p_limit;
  ELSIF p_query IS NOT NULL AND TRIM(p_query) != '' THEN
    -- Text search on title/description
    SELECT COALESCE(
      jsonb_agg(
        jsonb_build_object(
          'id', d.id,
          'key', d.key,
          'title', d.title,
          'status', d.status,
          'severity', d.severity,
          'assignee', CASE 
            WHEN d.assigned_to IS NOT NULL THEN jsonb_build_object(
              'id', p.id,
              'name', p.full_name
            )
            ELSE NULL
          END,
          'created_at', d.created_at
        ) ORDER BY d.created_at DESC
      ),
      '[]'::jsonb
    ) INTO v_results
    FROM tm_defects d
    LEFT JOIN profiles p ON d.assigned_to = p.id
    WHERE d.project_id = p_project_id
      AND (
        d.title ILIKE '%' || p_query || '%'
        OR d.description ILIKE '%' || p_query || '%'
      )
      AND (p_status IS NULL OR d.status = ANY(p_status))
    LIMIT p_limit;
  ELSE
    -- Return recent defects if no query
    SELECT COALESCE(
      jsonb_agg(
        jsonb_build_object(
          'id', d.id,
          'key', d.key,
          'title', d.title,
          'status', d.status,
          'severity', d.severity,
          'assignee', CASE 
            WHEN d.assigned_to IS NOT NULL THEN jsonb_build_object(
              'id', p.id,
              'name', p.full_name
            )
            ELSE NULL
          END,
          'created_at', d.created_at
        ) ORDER BY d.created_at DESC
      ),
      '[]'::jsonb
    ) INTO v_results
    FROM tm_defects d
    LEFT JOIN profiles p ON d.assigned_to = p.id
    WHERE d.project_id = p_project_id
      AND (p_status IS NULL OR d.status = ANY(p_status))
    LIMIT p_limit;
  END IF;

  RETURN jsonb_build_object(
    'results', v_results,
    'count', jsonb_array_length(v_results)
  );
END;
$_$;


