-- Name: shift_steps_down(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.shift_steps_down(p_test_case_id uuid, p_after_order integer) RETURNS void
    LANGUAGE plpgsql
    AS $$
