  SET step_order = step_order + 1
  WHERE test_case_id = p_test_case_id AND step_order > p_after_order;
END;
$$;


--
-- Name: soft_delete_incident(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.soft_delete_incident(p_incident_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_project_id uuid;
  v_created_by uuid;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  SELECT project_id, created_by
  INTO v_project_id, v_created_by
  FROM public.incidents
  WHERE id = p_incident_id;

  IF v_created_by IS NULL THEN
    RAISE EXCEPTION 'Incident not found';
  END IF;

  -- Authorization:
  -- 1) If incident has a project, user must be in that project (admins included via user_in_project)
  -- 2) If incident has no project (legacy), allow creator or admin
  IF v_project_id IS NOT NULL THEN
    IF NOT public.user_in_project(auth.uid(), v_project_id) THEN
      RAISE EXCEPTION 'Not authorized to delete this incident';
    END IF;
  ELSE
    IF auth.uid() <> v_created_by AND NOT public.has_role(auth.uid(), 'admin') THEN
      RAISE EXCEPTION 'Not authorized to delete this incident';
    END IF;
  END IF;

  UPDATE public.incidents
  SET
    deleted_at = now(),
    updated_by = auth.uid(),
    updated_at = now()
  WHERE id = p_incident_id
    AND deleted_at IS NULL;
END;
$$;


--
-- Name: soft_delete_planner_task(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.soft_delete_planner_task(p_task_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  UPDATE public.planner_tasks
  SET deleted_at = now(),
      updated_at = now()
  WHERE id = p_task_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Task not found';
  END IF;
END;
$$;


--
-- Name: soft_delete_planner_tasks(uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.soft_delete_planner_tasks(p_task_ids uuid[]) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  affected integer;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  UPDATE public.planner_tasks
  SET deleted_at = now(),
      updated_at = now()
  WHERE id = ANY(p_task_ids);

  GET DIAGNOSTICS affected = ROW_COUNT;
  RETURN affected;
END;
$$;


--
-- Name: sort_queue_by_priority(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sort_queue_by_priority(p_run_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Reassign positions by priority
  WITH ranked AS (
    SELECT id, ROW_NUMBER() OVER (
      ORDER BY priority DESC, position ASC
    ) as new_pos
    FROM execution_queue
    WHERE run_id = p_run_id
      AND status = 'queued'
  )
  UPDATE execution_queue eq SET
    position = r.new_pos
  FROM ranked r
  WHERE eq.id = r.id;

  RETURN jsonb_build_object('success', true);
END;
$$;


--
-- Name: start_step_timer(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.start_step_timer(p_execution_id uuid, p_step_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_step_result_id UUID;
  v_actor UUID := auth.uid();
BEGIN
  -- Update existing step result with timer start
  UPDATE test_execution_step_results SET
    timer_started_at = CASE 
      WHEN timer_started_at IS NULL THEN NOW()
      ELSE timer_started_at
    END,
    timer_paused_at = NULL,
    is_timer_running = true,
    step_id = p_step_id,
    executed_by = v_actor
  WHERE execution_id = p_execution_id 
    AND (step_id = p_step_id OR step_id IS NULL)
  RETURNING id INTO v_step_result_id;

  -- If no existing row, try insert
  IF v_step_result_id IS NULL THEN
    INSERT INTO test_execution_step_results (
      execution_id,
      step_id,
      step_order,
      step_description,
      status,
      timer_started_at,
      is_timer_running,
      executed_by
    ) 
    SELECT 
      p_execution_id,
      ts.id,
      ts.step_order,
      ts.action,
      'pending',
      NOW(),
      true,
      v_actor
    FROM test_steps ts
    WHERE ts.id = p_step_id
    RETURNING id INTO v_step_result_id;
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'step_result_id', v_step_result_id,
    'started_at', NOW()
  );
END;
$$;


--
-- Name: sync_automation_status_on_mapping(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_automation_status_on_mapping() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Update test case automation_status to 'automated' when mapped
  UPDATE test_cases
  SET automation_status = 'automated',
      automation_id = NEW.external_test_id,
      updated_at = now()
  WHERE id = NEW.test_case_id
    AND (automation_status IS NULL OR automation_status != 'automated');
  
  RETURN NEW;
END;
$$;


--
-- Name: sync_avatar_urls(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_avatar_urls() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  UPDATE resource_inventory ri
  SET avatar_url = p.avatar_url
  FROM profiles p
  WHERE ri.profile_id = p.id
    AND p.avatar_url IS NOT NULL
    AND (ri.avatar_url IS DISTINCT FROM p.avatar_url);
END;
$$;


--
-- Name: sync_cycle_scope_counters(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_cycle_scope_counters() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_cycle_id UUID;
  v_total INT;
  v_passed INT;
  v_failed INT;
  v_blocked INT;
  v_skipped INT;
  v_not_run INT;
BEGIN
  -- Determine which cycle_id to update
  IF TG_OP = 'DELETE' THEN
    v_cycle_id := OLD.cycle_id;
  ELSE
    v_cycle_id := NEW.cycle_id;
  END IF;

  -- Count stats from tm_cycle_scope (source of truth)
  SELECT 
    COUNT(*),
    COUNT(*) FILTER (WHERE current_status = 'passed'),
    COUNT(*) FILTER (WHERE current_status = 'failed'),
    COUNT(*) FILTER (WHERE current_status = 'blocked'),
    COUNT(*) FILTER (WHERE current_status = 'skipped'),
    COUNT(*) FILTER (WHERE current_status IS NULL OR current_status = 'not_run')
  INTO v_total, v_passed, v_failed, v_blocked, v_skipped, v_not_run
  FROM tm_cycle_scope
  WHERE cycle_id = v_cycle_id;

  -- Update the cached counters on tm_test_cycles
  UPDATE tm_test_cycles
  SET 
    total_cases = v_total,
    passed_count = v_passed,
    failed_count = v_failed,
    blocked_count = v_blocked,
    skipped_count = v_skipped,
    not_run_count = v_not_run,
    updated_at = NOW()
  WHERE id = v_cycle_id;

  RETURN COALESCE(NEW, OLD);
END;
$$;


