--
-- Name: t10_checkout_week(uuid, uuid[], uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.t10_checkout_week(p_week_id uuid, p_carry_forward_item_ids uuid[] DEFAULT ARRAY[]::uuid[], p_drop_item_ids uuid[] DEFAULT ARRAY[]::uuid[]) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_completed_count INTEGER;
  v_carried_count INTEGER;
  v_dropped_count INTEGER;
  v_total_count INTEGER;
  v_next_week_id UUID;
  v_list_id UUID;
BEGIN
  -- Get list_id for this week
  SELECT list_id INTO v_list_id FROM t10_weeks WHERE id = p_week_id;
  
  -- Mark completed items (done but not in carry/drop lists)
  UPDATE t10_items
  SET 
    status = 'completed',
    completed_at = now(),
    updated_at = now()
  WHERE week_id = p_week_id
    AND status = 'done'
    AND id != ALL(p_carry_forward_item_ids)
    AND id != ALL(p_drop_item_ids);
  
  -- Mark carried forward items
  UPDATE t10_items
  SET 
    status = 'carried_forward',
    updated_at = now()
  WHERE week_id = p_week_id
    AND id = ANY(p_carry_forward_item_ids);
  
  -- Mark dropped items
  UPDATE t10_items
  SET 
    status = 'dropped',
    updated_at = now()
  WHERE week_id = p_week_id
    AND id = ANY(p_drop_item_ids);
  
  -- Mark remaining todo items as carried forward
  UPDATE t10_items
  SET 
    status = 'carried_forward',
    updated_at = now()
  WHERE week_id = p_week_id
    AND status = 'todo';
  
  -- Count outcomes
  SELECT 
    COUNT(*) FILTER (WHERE status = 'completed'),
    COUNT(*) FILTER (WHERE status = 'carried_forward'),
    COUNT(*) FILTER (WHERE status = 'dropped'),
    COUNT(*)
  INTO v_completed_count, v_carried_count, v_dropped_count, v_total_count
  FROM t10_items
  WHERE week_id = p_week_id;
  
  -- Update week record
  UPDATE t10_weeks
  SET 
    status = 'completed',
    is_current = false,
    checkout_at = now(),
    checkout_by = auth.uid(),
    completed_count = v_completed_count,
    carried_forward_count = v_carried_count,
    dropped_count = v_dropped_count,
    total_count = v_total_count,
    updated_at = now()
  WHERE id = p_week_id;
  
  -- Create next week and carry forward items (if any)
  IF v_carried_count > 0 THEN
    -- Create next week
    INSERT INTO t10_weeks (list_id, week_start, week_end, is_current, status)
    SELECT 
      v_list_id,
      week_end + INTERVAL '1 day',
      week_end + INTERVAL '7 days',
      true,
      'active'
    FROM t10_weeks
    WHERE id = p_week_id
    RETURNING id INTO v_next_week_id;
    
    -- Copy carried forward items to new week
    INSERT INTO t10_items (
      week_id, rank, title, description, taskhub_key, 
      assignee_id, due_date, status, carryover_count, 
      is_buffer, created_by, carried_from_week_id
    )
    SELECT 
      v_next_week_id,
      ROW_NUMBER() OVER (ORDER BY rank),
      title,
      description,
      taskhub_key,
      assignee_id,
      NULL, -- Clear due date for new week
      'todo',
      carryover_count + 1,
      is_buffer,
      created_by,
      p_week_id
    FROM t10_items
    WHERE week_id = p_week_id
      AND status = 'carried_forward'
    ORDER BY rank;
  END IF;
  
  -- Return summary
  RETURN json_build_object(
    'week_id', p_week_id,
    'completed_count', v_completed_count,
    'carried_forward_count', v_carried_count,
    'dropped_count', v_dropped_count,
    'total_count', v_total_count,
    'next_week_id', v_next_week_id,
    'checkout_at', now()
  );
END;
$$;


--
-- Name: t10_create_list(text, text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.t10_create_list(p_name text, p_description text DEFAULT NULL::text, p_week_offset integer DEFAULT 0) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_list_id UUID;
  v_week_id UUID;
  v_key TEXT;
  v_week_start DATE;
  v_week_end DATE;
  v_this_monday DATE;
  v_is_current BOOLEAN;
  v_is_upcoming BOOLEAN;
  v_next_key_num INTEGER;
BEGIN
  -- Validate offset (0-4 weeks ahead)
  IF p_week_offset < 0 THEN
    RAISE EXCEPTION 'Cannot create lists for past weeks';
  END IF;
  
  IF p_week_offset > 4 THEN
    RAISE EXCEPTION 'Cannot create lists more than 4 weeks in advance';
  END IF;

  -- Calculate this Monday (1 = Monday for DOW where 0 = Sunday)
  -- EXTRACT(DOW) returns 0 for Sunday, 1 for Monday, etc.
  v_this_monday := CURRENT_DATE - ((EXTRACT(DOW FROM CURRENT_DATE)::int + 6) % 7);
  
  -- If today is Saturday(6) or Sunday(0), "this week" means the coming Monday
  IF EXTRACT(DOW FROM CURRENT_DATE) IN (0, 6) THEN
    v_this_monday := CURRENT_DATE + (8 - EXTRACT(DOW FROM CURRENT_DATE)::int) % 7;
  END IF;
  
  -- Calculate target week
  v_week_start := v_this_monday + (p_week_offset * 7);
  v_week_end := v_week_start + 4; -- Friday
  
  -- Determine is_current vs is_upcoming
  IF v_week_start <= CURRENT_DATE AND CURRENT_DATE <= v_week_end THEN
    v_is_current := true;
    v_is_upcoming := false;
  ELSE
    v_is_current := false;
    v_is_upcoming := true;
  END IF;

  -- Generate next list key for this user
  SELECT COALESCE(MAX(
    CAST(NULLIF(REGEXP_REPLACE(key, '[^0-9]', '', 'g'), '') AS INTEGER)
  ), 0) + 1 INTO v_next_key_num
  FROM t10_lists
  WHERE created_by = auth.uid();
  
  v_key := 'T10-' || LPAD(v_next_key_num::TEXT, 3, '0');

  -- Create list
  INSERT INTO t10_lists (key, name, description, created_by, status)
  VALUES (v_key, p_name, p_description, auth.uid(), 'active')
  RETURNING id INTO v_list_id;

  -- Create initial week
  INSERT INTO t10_weeks (list_id, week_start, week_end, is_current, is_upcoming, status)
  VALUES (v_list_id, v_week_start, v_week_end, v_is_current, v_is_upcoming, 'active')
  RETURNING id INTO v_week_id;

  -- Return created data
  RETURN json_build_object(
    'list_id', v_list_id,
    'list_key', v_key,
    'list_name', p_name,
    'week_id', v_week_id,
    'week_start', v_week_start,
    'week_end', v_week_end,
    'is_current', v_is_current,
    'is_upcoming', v_is_upcoming
  );
END;
$$;


--
-- Name: t10_promote_upcoming_weeks(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.t10_promote_upcoming_weeks() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Find upcoming weeks whose start date has arrived
  UPDATE t10_weeks
  SET 
    is_upcoming = false,
    is_current = true,
    updated_at = NOW()
  WHERE 
    is_upcoming = true
    AND week_start <= CURRENT_DATE;
    
  -- Demote old current weeks for same list
  UPDATE t10_weeks w1
  SET is_current = false
  WHERE w1.is_current = true
    AND EXISTS (
      SELECT 1 FROM t10_weeks w2
      WHERE w2.list_id = w1.list_id
        AND w2.is_current = true
        AND w2.week_start > w1.week_start
    )
    AND w1.week_start < (
      SELECT MAX(w3.week_start)
      FROM t10_weeks w3
      WHERE w3.list_id = w1.list_id
        AND w3.is_current = true
    );
END;
$$;


