--
-- Name: test_connector(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_connector(p_connector_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_connector RECORD;
BEGIN
  SELECT * INTO v_connector FROM automation_connectors WHERE id = p_connector_id;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Connector not found');
  END IF;

  -- Update last connection attempt
  UPDATE automation_connectors
  SET last_connected_at = now(), connection_status = 'connected'
  WHERE id = p_connector_id;

  RETURN jsonb_build_object(
    'success', true,
    'status', 'connected',
    'message', 'Connection test successful'
  );
END;
$$;


--
-- Name: tg_catalyst_comment_audit(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tg_catalyst_comment_audit() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO public.catalyst_activity_log(work_item_id, action, user_id, metadata)
    VALUES (NEW.work_item_id, 'comment_added', NEW.author_id, jsonb_build_object('comment_id', NEW.id));
  ELSIF TG_OP = 'UPDATE' AND OLD.body IS DISTINCT FROM NEW.body THEN
    INSERT INTO public.catalyst_activity_log(work_item_id, action, user_id, metadata)
    VALUES (NEW.work_item_id, 'comment_edited', auth.uid(), jsonb_build_object('comment_id', NEW.id));
  ELSIF TG_OP = 'DELETE' THEN
    INSERT INTO public.catalyst_activity_log(work_item_id, action, user_id, metadata)
    VALUES (OLD.work_item_id, 'comment_deleted', auth.uid(), jsonb_build_object('comment_id', OLD.id));
  END IF;
  RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: tg_catalyst_issue_audit(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tg_catalyst_issue_audit() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
  f text;
  fields text[] := ARRAY[
    'title','description','description_adf_raw','status','status_category',
    'priority','assignee_id','reporter_id','parent_id','parent_key',
    'story_points','sprint_name','release_id','labels','fix_versions',
    'acceptance_criteria','issue_type'
  ];
  oldv text; newv text;
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO public.catalyst_activity_log(work_item_id, action, user_id)
    VALUES (NEW.id, 'created', COALESCE(auth.uid(), NEW.reporter_id));
    RETURN NEW;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    -- soft delete / restore
    IF OLD.deleted_at IS DISTINCT FROM NEW.deleted_at THEN
      INSERT INTO public.catalyst_activity_log(work_item_id, action, user_id)
      VALUES (NEW.id, CASE WHEN NEW.deleted_at IS NULL THEN 'restored' ELSE 'deleted' END, auth.uid());
    END IF;

    FOREACH f IN ARRAY fields LOOP
      EXECUTE format('SELECT ($1).%I::text, ($2).%I::text', f, f)
        INTO oldv, newv USING OLD, NEW;
      IF oldv IS DISTINCT FROM newv THEN
        INSERT INTO public.catalyst_activity_log(
          work_item_id, action, field_name, old_value, new_value, user_id
        )
        VALUES (NEW.id, 'updated', f, oldv, newv, auth.uid());
      END IF;
    END LOOP;
  END IF;

  RETURN NEW;
END;
$_$;


