--
-- Name: th_capture_test_case_version(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.th_capture_test_case_version() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_changes JSONB := '{}'::jsonb;
  v_has_changes BOOLEAN := false;
BEGIN
  IF OLD.title IS DISTINCT FROM NEW.title THEN
    v_changes := v_changes || jsonb_build_object('title', jsonb_build_object('old', OLD.title, 'new', NEW.title));
    v_has_changes := true;
  END IF;
  IF OLD.objective IS DISTINCT FROM NEW.objective THEN
    v_changes := v_changes || jsonb_build_object('objective', jsonb_build_object('old', OLD.objective, 'new', NEW.objective));
    v_has_changes := true;
  END IF;
  IF OLD.preconditions IS DISTINCT FROM NEW.preconditions THEN
    v_changes := v_changes || jsonb_build_object('preconditions', jsonb_build_object('old', OLD.preconditions, 'new', NEW.preconditions));
    v_has_changes := true;
  END IF;
  IF OLD.priority IS DISTINCT FROM NEW.priority THEN
    v_changes := v_changes || jsonb_build_object('priority', jsonb_build_object('old', OLD.priority, 'new', NEW.priority));
    v_has_changes := true;
  END IF;
  IF OLD.status IS DISTINCT FROM NEW.status THEN
    v_changes := v_changes || jsonb_build_object('status', jsonb_build_object('old', OLD.status, 'new', NEW.status));
    v_has_changes := true;
  END IF;
  IF OLD.folder_id IS DISTINCT FROM NEW.folder_id THEN
    v_changes := v_changes || jsonb_build_object('folder_id', jsonb_build_object('old', OLD.folder_id, 'new', NEW.folder_id));
    v_has_changes := true;
  END IF;

  IF v_has_changes THEN
    NEW.version := COALESCE(OLD.version, 1) + 1;
    
    INSERT INTO th_test_case_versions (
      test_case_id,
      version,
      changes,
      changed_by,
      changed_at
    ) VALUES (
      OLD.id,
      COALESCE(OLD.version, 1),
      v_changes,
      auth.uid(),
      NOW()
    );
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: tm_add_attachment(uuid, uuid, text, text, integer, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_add_attachment(p_case_id uuid, p_step_id uuid, p_file_name text, p_file_path text, p_file_size integer, p_mime_type text, p_attachment_type text DEFAULT 'general'::text, p_description text DEFAULT NULL::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_id UUID;
BEGIN
  INSERT INTO tm_test_attachments (
    test_case_id,
    test_step_id,
    file_name,
    file_path,
    file_size,
    mime_type,
    attachment_type,
    description,
    uploaded_by
  ) VALUES (
    p_case_id,
    p_step_id,
    p_file_name,
    p_file_path,
    p_file_size,
    p_mime_type,
    p_attachment_type,
    p_description,
    auth.uid()
  )
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


--
-- Name: tm_apply_signoff_template(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_apply_signoff_template(p_release_id uuid, p_template_id uuid, p_requested_by uuid DEFAULT NULL::uuid) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_roles JSONB;
  v_role JSONB;
  v_count INTEGER := 0;
BEGIN
  -- Get template roles
  SELECT roles INTO v_roles
  FROM tm_signoff_templates
  WHERE id = p_template_id;
  
  IF v_roles IS NULL THEN
    RAISE EXCEPTION 'Template not found';
  END IF;
  
  -- Create signoff requests for each role
  FOR v_role IN SELECT * FROM jsonb_array_elements(v_roles)
  LOOP
    -- Find users with matching role or create placeholder
    INSERT INTO tm_release_signoffs (
      release_id, stakeholder_id, stakeholder_role, 
      requested_by, is_required, sort_order
    )
    SELECT 
      p_release_id,
      p.id,
      v_role->>'role',
      p_requested_by,
      COALESCE((v_role->>'is_required')::boolean, true),
      COALESCE((v_role->>'sort_order')::integer, v_count)
    FROM profiles p
    WHERE p.role = v_role->>'role'
    LIMIT 1
    ON CONFLICT (release_id, stakeholder_id) DO NOTHING;
    
    v_count := v_count + 1;
  END LOOP;
  
  RETURN v_count;
END;
$$;


--
-- Name: tm_approve_release_readiness(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_approve_release_readiness(p_snapshot_id uuid, p_user_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  UPDATE tm_release_readiness
  SET 
    overall_status = 'approved',
    approved_by = p_user_id,
    approved_at = now()
  WHERE id = p_snapshot_id;
  
  RETURN FOUND;
END;
$$;


--
-- Name: tm_assign_cases_to_run(uuid, uuid[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_assign_cases_to_run(p_run_id uuid, p_case_ids uuid[], p_assigned_tester_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_case_id UUID;
  v_priority INTEGER := 0;
  v_assigned_count INTEGER := 0;
BEGIN
  -- Validate run exists
  IF NOT EXISTS (SELECT 1 FROM test_execution_runs WHERE id = p_run_id AND deleted_at IS NULL) THEN
    RETURN jsonb_build_object('error', 'Run not found');
  END IF;
  
  -- Get current max priority
  SELECT COALESCE(MAX(priority), 0) INTO v_priority
  FROM tm_run_case_assignments
  WHERE run_id = p_run_id;
  
  -- Insert assignments
  FOREACH v_case_id IN ARRAY p_case_ids
  LOOP
    v_priority := v_priority + 1;
    
    INSERT INTO tm_run_case_assignments (run_id, test_case_id, assigned_tester_id, priority)
    VALUES (p_run_id, v_case_id, p_assigned_tester_id, v_priority)
    ON CONFLICT (run_id, test_case_id) DO NOTHING;
    
    IF FOUND THEN
      v_assigned_count := v_assigned_count + 1;
    END IF;
  END LOOP;
  
  RETURN jsonb_build_object(
    'success', true,
    'assigned_count', v_assigned_count,
    'run_id', p_run_id
  );
END;
$$;


--
-- Name: tm_assign_scope_item(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_assign_scope_item(p_scope_id uuid, p_assigned_to uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  UPDATE tm_cycle_scope SET assigned_to = p_assigned_to WHERE id = p_scope_id;
  RETURN jsonb_build_object('success', true);
END;
$$;


--
-- Name: tm_assign_tester_to_cycle(uuid, uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_assign_tester_to_cycle(p_cycle_id uuid, p_user_id uuid, p_role text DEFAULT 'tester'::text, p_notes text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_assignment_id UUID;
BEGIN
  INSERT INTO tm_cycle_assignments (cycle_id, user_id, role, notes, assigned_by)
  VALUES (p_cycle_id, p_user_id, p_role, p_notes, auth.uid())
  ON CONFLICT (cycle_id, user_id) 
  DO UPDATE SET role = EXCLUDED.role, notes = EXCLUDED.notes
  RETURNING id INTO v_assignment_id;
  
  RETURN jsonb_build_object('success', true, 'assignment_id', v_assignment_id);
END;
$$;


--
-- Name: tm_auto_create_defect_on_failure(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_auto_create_defect_on_failure() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_cycle_scope tm_cycle_scope%ROWTYPE;
  v_test_case tm_test_cases%ROWTYPE;
  v_cycle tm_test_cycles%ROWTYPE;
  v_defect_id UUID;
  v_defect_key VARCHAR(20);
  v_severity TEXT;
  v_priority_name TEXT;
BEGIN
  -- Only trigger on status change to 'failed'
  IF NEW.status = 'failed' AND (OLD.status IS NULL OR OLD.status != 'failed') THEN
    
    -- Get cycle scope details
    SELECT * INTO v_cycle_scope FROM tm_cycle_scope WHERE id = NEW.cycle_scope_id;
    
    -- Get test case details
    SELECT * INTO v_test_case FROM tm_test_cases WHERE id = v_cycle_scope.test_case_id;
    
    -- Get cycle details
    SELECT * INTO v_cycle FROM tm_test_cycles WHERE id = v_cycle_scope.cycle_id;
    
    -- Get priority name for severity mapping
    SELECT name INTO v_priority_name FROM tm_case_priorities WHERE id = v_test_case.priority_id;
    
    -- Map priority to severity
    v_severity := CASE LOWER(COALESCE(v_priority_name, 'medium'))
      WHEN 'critical' THEN 'blocker'
      WHEN 'high' THEN 'critical'
      WHEN 'medium' THEN 'major'
      WHEN 'low' THEN 'minor'
      ELSE 'major'
    END;
    
    -- Generate defect key
    v_defect_key := 'DEF-' || LPAD((SELECT COALESCE(MAX(CAST(SUBSTRING(defect_key FROM 5) AS INTEGER)), 0) + 1 FROM tm_defects)::TEXT, 5, '0');
    
    -- Create defect
    INSERT INTO tm_defects (
      project_id,
      defect_key,
      title,
      description,
      severity,
      status,
      source_test_run_id,
      source_test_case_id,
      source_test_plan_id,
      expected_result,
      actual_result,
      steps_to_reproduce,
      reporter_id,
      auto_created,
      found_during
    ) VALUES (
      v_test_case.project_id,
      v_defect_key,
      'Test Failed: ' || COALESCE(v_test_case.title, 'Unknown Test'),
      COALESCE(NEW.notes, 'Automated defect from failed test execution'),
      v_severity::tm_defect_severity,
      'open',
      NEW.id,
      v_cycle_scope.test_case_id,
      v_cycle.test_plan_id,
      v_test_case.expected_result,
      NEW.notes,
      v_test_case.preconditions,
      NEW.executed_by,
      true,
      'test_execution'
    ) RETURNING id INTO v_defect_id;
    
    -- Update test run with defect reference
    NEW.auto_created_defect_id := v_defect_id;
    
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- Name: tm_bulk_add_cases_to_cycle(uuid, uuid[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_bulk_add_cases_to_cycle(p_cycle_id uuid, p_test_case_ids uuid[], p_assigned_to uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_case_id UUID;
  v_order INTEGER;
  v_added INTEGER := 0;
BEGIN
  -- Get current max sort order
  SELECT COALESCE(MAX(sort_order), 0) INTO v_order
  FROM tm_cycle_scope WHERE cycle_id = p_cycle_id;
  
  -- Insert each case
  FOREACH v_case_id IN ARRAY p_test_case_ids
  LOOP
    IF NOT EXISTS (SELECT 1 FROM tm_cycle_scope WHERE cycle_id = p_cycle_id AND test_case_id = v_case_id) THEN
      v_order := v_order + 1;
      INSERT INTO tm_cycle_scope (cycle_id, test_case_id, assigned_to, sort_order, current_status)
      VALUES (p_cycle_id, v_case_id, p_assigned_to, v_order, 'not_run');
      v_added := v_added + 1;
    END IF;
  END LOOP;
  
  -- Update cycle totals
  UPDATE tm_test_cycles 
  SET total_cases = (SELECT COUNT(*) FROM tm_cycle_scope WHERE cycle_id = p_cycle_id),
      not_run_count = (SELECT COUNT(*) FROM tm_cycle_scope WHERE cycle_id = p_cycle_id AND current_status = 'not_run'),
      updated_at = now()
  WHERE id = p_cycle_id;
  
  RETURN jsonb_build_object('success', true, 'added', v_added);
END;
$$;


--
-- Name: tm_bulk_assign_tester(uuid, uuid[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_bulk_assign_tester(p_run_id uuid, p_assignment_ids uuid[], p_tester_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_updated_count INTEGER;
BEGIN
  UPDATE tm_run_case_assignments
  SET 
    assigned_tester_id = p_tester_id,
    updated_at = now()
  WHERE run_id = p_run_id
  AND id = ANY(p_assignment_ids)
  AND status = 'pending';
  
  GET DIAGNOSTICS v_updated_count = ROW_COUNT;
  
  RETURN jsonb_build_object(
    'success', true,
    'updated_count', v_updated_count
  );
END;
$$;


--
-- Name: tm_bulk_update_steps(uuid, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_bulk_update_steps(p_case_id uuid, p_steps jsonb) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_step JSONB;
  v_count INTEGER := 0;
BEGIN
  FOR v_step IN SELECT * FROM jsonb_array_elements(p_steps)
  LOOP
    UPDATE tm_test_steps SET
      step_number = COALESCE((v_step->>'step_number')::INTEGER, step_number),
      step_type = COALESCE(v_step->>'step_type', step_type),
      action = COALESCE(v_step->>'action', action),
      expected_result = COALESCE(v_step->>'expected_result', expected_result),
      test_data = COALESCE(v_step->>'test_data', test_data),
      notes = COALESCE(v_step->>'notes', notes),
      is_optional = COALESCE((v_step->>'is_optional')::BOOLEAN, is_optional),
      estimated_time_seconds = COALESCE((v_step->>'estimated_time_seconds')::INTEGER, estimated_time_seconds),
      updated_at = now()
    WHERE id = (v_step->>'id')::UUID AND case_id = p_case_id;
    
    v_count := v_count + 1;
  END LOOP;
  
  RETURN v_count;
END;
$$;


--
-- Name: tm_calculate_run_status(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_calculate_run_status(p_run_id uuid) RETURNS public.tm_execution_status
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_status tm_execution_status;
BEGIN
  SELECT 
    CASE
      WHEN COUNT(*) FILTER (WHERE status = 'failed') > 0 THEN 'failed'::tm_execution_status
      WHEN COUNT(*) FILTER (WHERE status = 'blocked') > 0 THEN 'blocked'::tm_execution_status
      WHEN COUNT(*) FILTER (WHERE status = 'in_progress') > 0 THEN 'in_progress'::tm_execution_status
      WHEN COUNT(*) FILTER (WHERE status = 'not_run') = COUNT(*) THEN 'not_run'::tm_execution_status
      WHEN COUNT(*) FILTER (WHERE status IN ('passed', 'skipped')) = COUNT(*) THEN 'passed'::tm_execution_status
      ELSE 'in_progress'::tm_execution_status
    END INTO v_status
  FROM tm_step_results
  WHERE test_run_id = p_run_id;
  
  RETURN COALESCE(v_status, 'not_run');
END;
$$;


--
-- Name: tm_check_circular_folder(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_check_circular_folder(p_folder_id uuid, p_new_parent_id uuid) RETURNS boolean
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_current_id UUID;
BEGIN
  IF p_new_parent_id IS NULL THEN
    RETURN FALSE;
  END IF;
  
  IF p_folder_id = p_new_parent_id THEN
    RETURN TRUE;
  END IF;
  
  v_current_id := p_new_parent_id;
  WHILE v_current_id IS NOT NULL LOOP
    IF v_current_id = p_folder_id THEN
      RETURN TRUE;
    END IF;
    SELECT parent_id INTO v_current_id FROM tm_folders WHERE id = v_current_id;
  END LOOP;
  
  RETURN FALSE;
END;
$$;


--
-- Name: tm_clone_step(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_clone_step(p_step_id uuid, p_insert_after integer DEFAULT NULL::integer) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_new_step_id UUID;
  v_case_id UUID;
  v_new_order INTEGER;
BEGIN
  -- Get source step info
  SELECT case_id INTO v_case_id FROM tm_test_steps WHERE id = p_step_id;
  
  IF v_case_id IS NULL THEN
    RAISE EXCEPTION 'Step not found';
  END IF;
  
  -- Determine new order
  IF p_insert_after IS NOT NULL THEN
    v_new_order := p_insert_after + 1;
    -- Shift subsequent steps
    UPDATE tm_test_steps 
    SET step_number = step_number + 1 
    WHERE case_id = v_case_id AND step_number >= v_new_order;
  ELSE
    SELECT COALESCE(MAX(step_number), 0) + 1 INTO v_new_order 
    FROM tm_test_steps WHERE case_id = v_case_id;
  END IF;
  
  -- Clone the step
  INSERT INTO tm_test_steps (
    case_id, step_number, step_type, action, 
    expected_result, test_data, notes, is_optional, estimated_time_seconds
  )
  SELECT 
    case_id, v_new_order, step_type, action,
    expected_result, test_data, notes, is_optional, estimated_time_seconds
  FROM tm_test_steps
  WHERE id = p_step_id
  RETURNING id INTO v_new_step_id;
  
  RETURN v_new_step_id;
END;
$$;


--
-- Name: tm_clone_test_case(uuid, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_clone_test_case(p_case_id uuid, p_new_title text DEFAULT NULL::text, p_target_folder_id uuid DEFAULT NULL::uuid) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_case RECORD;
  v_new_id UUID;
  v_new_key TEXT;
  v_step RECORD;
BEGIN
  -- Get source case
  SELECT * INTO v_case FROM tm_test_cases WHERE id = p_case_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Test case not found';
  END IF;

  -- Generate new key
  SELECT 'TC-' || LPAD((COALESCE(MAX(NULLIF(REGEXP_REPLACE(key, '[^0-9]', '', 'g'), '')::integer), 0) + 1)::text, 5, '0')
  INTO v_new_key
  FROM tm_test_cases
  WHERE project_id = v_case.project_id;

  -- Create new case
  INSERT INTO tm_test_cases (
    project_id,
    folder_id,
    key,
    title,
    description,
    description_html,
    preconditions,
    preconditions_html,
    postconditions,
    postconditions_html,
    status,
    priority,
    type,
    test_format,
    gherkin_feature,
    gherkin_scenario,
    cloned_from_id,
    version,
    created_by
  ) VALUES (
    v_case.project_id,
    COALESCE(p_target_folder_id, v_case.folder_id),
    v_new_key,
    COALESCE(p_new_title, v_case.title || ' (Copy)'),
    v_case.description,
    v_case.description_html,
    v_case.preconditions,
    v_case.preconditions_html,
    v_case.postconditions,
    v_case.postconditions_html,
    'draft',
    v_case.priority,
    v_case.type,
    v_case.test_format,
    v_case.gherkin_feature,
    v_case.gherkin_scenario,
    p_case_id,
    1,
    auth.uid()
  )
  RETURNING id INTO v_new_id;

  -- Clone steps
  FOR v_step IN 
    SELECT * FROM tm_test_steps 
    WHERE test_case_id = p_case_id 
    ORDER BY step_number
  LOOP
    INSERT INTO tm_test_steps (
      test_case_id,
      step_number,
      step_type,
      action,
      action_html,
      expected_result,
      expected_result_html,
      test_data,
      notes,
      is_optional,
      estimated_time_seconds
    ) VALUES (
      v_new_id,
      v_step.step_number,
      v_step.step_type,
      v_step.action,
      v_step.action_html,
      v_step.expected_result,
      v_step.expected_result_html,
      v_step.test_data,
      v_step.notes,
      v_step.is_optional,
      v_step.estimated_time_seconds
    );
  END LOOP;

  -- Clone requirement links
  INSERT INTO tm_requirement_links (
    test_case_id,
    requirement_type,
    requirement_id,
    external_key,
    external_url,
    external_title,
    link_type,
    notes,
    created_by
  )
  SELECT 
    v_new_id,
    requirement_type,
    requirement_id,
    external_key,
    external_url,
    external_title,
    link_type,
    notes,
    auth.uid()
  FROM tm_requirement_links
  WHERE test_case_id = p_case_id;

  RETURN v_new_id;
END;
$$;


--
-- Name: tm_compare_cycles(uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_compare_cycles(p_cycle_ids uuid[]) RETURNS TABLE(cycle_id uuid, cycle_name text, cycle_key text, status text, start_date date, end_date date, total_cases bigint, passed bigint, failed bigint, blocked bigint, not_run bigint, execution_rate numeric, pass_rate numeric, defect_density numeric, avg_execution_time numeric, active_testers bigint, total_defects bigint, health_score numeric, health_level text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    c.id as cycle_id,
    c.name::TEXT as cycle_name,
    c.cycle_key::TEXT as cycle_key,
    c.status::TEXT,
    c.planned_start as start_date,
    c.planned_end as end_date,
    COALESCE(c.total_cases, 0)::BIGINT as total_cases,
    COALESCE(c.passed_count, 0)::BIGINT as passed,
    COALESCE(c.failed_count, 0)::BIGINT as failed,
    COALESCE(c.blocked_count, 0)::BIGINT as blocked,
    COALESCE(c.not_run_count, 0)::BIGINT as not_run,
    CASE 
      WHEN COALESCE(c.total_cases, 0) = 0 THEN 0
      ELSE ROUND((COALESCE(c.passed_count, 0) + COALESCE(c.failed_count, 0) + COALESCE(c.blocked_count, 0))::NUMERIC / c.total_cases * 100, 1)
    END as execution_rate,
    CASE 
      WHEN (COALESCE(c.passed_count, 0) + COALESCE(c.failed_count, 0) + COALESCE(c.blocked_count, 0)) = 0 THEN 0
      ELSE ROUND(COALESCE(c.passed_count, 0)::NUMERIC / (c.passed_count + c.failed_count + c.blocked_count) * 100, 1)
    END as pass_rate,
    CASE 
      WHEN COALESCE(c.total_cases, 0) = 0 THEN 0
      ELSE ROUND(COALESCE(c.failed_count, 0)::NUMERIC / c.total_cases * 100, 2)
    END as defect_density,
    COALESCE((
      SELECT AVG(tr.duration_seconds)::NUMERIC
      FROM tm_test_runs tr
      JOIN tm_cycle_scope cs ON tr.cycle_scope_id = cs.id
      WHERE cs.cycle_id = c.id AND tr.duration_seconds IS NOT NULL
    ), 0) as avg_execution_time,
    COALESCE((
      SELECT COUNT(DISTINCT cs.assigned_to)::BIGINT
      FROM tm_cycle_scope cs
      WHERE cs.cycle_id = c.id AND cs.assigned_to IS NOT NULL
    ), 0) as active_testers,
    COALESCE((
      SELECT SUM(tr.defects_found)::BIGINT
      FROM tm_test_runs tr
      JOIN tm_cycle_scope cs ON tr.cycle_scope_id = cs.id
      WHERE cs.cycle_id = c.id
    ), 0) as total_defects,
    -- Health score calculation (0-100)
    CASE 
      WHEN COALESCE(c.total_cases, 0) = 0 THEN 0
      ELSE ROUND(
        (COALESCE(c.passed_count, 0)::NUMERIC / c.total_cases * 50) + -- Pass contribution (50%)
        ((COALESCE(c.total_cases, 0) - COALESCE(c.failed_count, 0) - COALESCE(c.blocked_count, 0))::NUMERIC / c.total_cases * 30) + -- No failures contribution (30%)
        ((COALESCE(c.passed_count, 0) + COALESCE(c.failed_count, 0) + COALESCE(c.blocked_count, 0))::NUMERIC / c.total_cases * 20) -- Execution progress (20%)
      , 1)
    END as health_score,
    CASE 
      WHEN COALESCE(c.total_cases, 0) = 0 THEN 'unknown'
      WHEN (COALESCE(c.passed_count, 0)::NUMERIC / NULLIF(c.passed_count + c.failed_count + c.blocked_count, 0)) >= 0.9 THEN 'excellent'
      WHEN (COALESCE(c.passed_count, 0)::NUMERIC / NULLIF(c.passed_count + c.failed_count + c.blocked_count, 0)) >= 0.7 THEN 'good'
      WHEN (COALESCE(c.passed_count, 0)::NUMERIC / NULLIF(c.passed_count + c.failed_count + c.blocked_count, 0)) >= 0.5 THEN 'fair'
      ELSE 'poor'
    END::TEXT as health_level
  FROM tm_test_cycles c
  WHERE c.id = ANY(p_cycle_ids)
  ORDER BY c.planned_start DESC NULLS LAST;
END;
$$;


--
-- Name: tm_convert_to_bdd(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_convert_to_bdd(p_case_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_step RECORD;
  v_keyword TEXT;
  v_step_num INTEGER := 1;
  v_last_keyword TEXT := 'Given';
BEGIN
  -- Delete existing gherkin steps
  DELETE FROM tm_gherkin_steps WHERE test_case_id = p_case_id;

  -- Convert each classic step
  FOR v_step IN 
    SELECT * FROM tm_test_steps 
    WHERE test_case_id = p_case_id 
    ORDER BY step_number
  LOOP
    -- Determine keyword based on step type
    CASE v_step.step_type
      WHEN 'setup' THEN v_keyword := 'Given';
      WHEN 'action' THEN 
        IF v_last_keyword = 'Given' THEN v_keyword := 'When';
        ELSE v_keyword := 'And';
        END IF;
      WHEN 'verification' THEN 
        IF v_last_keyword IN ('Given', 'When') THEN v_keyword := 'Then';
        ELSE v_keyword := 'And';
        END IF;
      WHEN 'teardown' THEN v_keyword := 'And';
      ELSE v_keyword := 'And';
    END CASE;

    INSERT INTO tm_gherkin_steps (
      test_case_id,
      step_number,
      keyword,
      step_text,
      doc_string
    ) VALUES (
      p_case_id,
      v_step_num,
      v_keyword,
      v_step.action,
      v_step.expected_result
    );

    v_last_keyword := v_keyword;
    v_step_num := v_step_num + 1;
  END LOOP;

  -- Update test case format
  UPDATE tm_test_cases
  SET test_format = 'bdd', updated_at = now()
  WHERE id = p_case_id;

  RETURN jsonb_build_object(
    'success', true,
    'steps_converted', v_step_num - 1
  );
END;
$$;


--
-- Name: tm_create_audit_log(uuid, character varying, character varying, uuid, character varying, jsonb, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_create_audit_log(p_project_id uuid, p_action character varying, p_entity_type character varying, p_entity_id uuid DEFAULT NULL::uuid, p_entity_name character varying DEFAULT NULL::character varying, p_changes jsonb DEFAULT NULL::jsonb, p_metadata jsonb DEFAULT '{}'::jsonb) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID;
  v_user_email VARCHAR;
  v_user_name VARCHAR;
  v_log_id UUID;
BEGIN
  SELECT id, email, COALESCE(full_name, email) 
  INTO v_user_id, v_user_email, v_user_name
  FROM public.profiles
  WHERE id = auth.uid();
  
  INSERT INTO public.tm_audit_logs (
    project_id, user_id, user_email, user_name,
    action, entity_type, entity_id, entity_name,
    changes, metadata
  ) VALUES (
    p_project_id, v_user_id, v_user_email, v_user_name,
    p_action, p_entity_type, p_entity_id, p_entity_name,
    p_changes, p_metadata
  )
  RETURNING id INTO v_log_id;
  
  RETURN v_log_id;
END;
$$;


--
-- Name: tm_create_cycle_milestone(uuid, text, date, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_create_cycle_milestone(p_cycle_id uuid, p_name text, p_target_date date, p_description text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_milestone_id UUID;
  v_sort_order INTEGER;
BEGIN
  -- Get next sort order
  SELECT COALESCE(MAX(sort_order), 0) + 1 INTO v_sort_order
  FROM tm_cycle_milestones WHERE cycle_id = p_cycle_id;
  
  -- Insert milestone
  INSERT INTO tm_cycle_milestones (cycle_id, name, target_date, description, sort_order)
  VALUES (p_cycle_id, p_name, p_target_date, p_description, v_sort_order)
  RETURNING id INTO v_milestone_id;
  
  RETURN jsonb_build_object('success', true, 'milestone_id', v_milestone_id);
END;
$$;


--
-- Name: tm_create_readiness_snapshot(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_create_readiness_snapshot(p_release_id uuid, p_user_id uuid DEFAULT NULL::uuid, p_recommendation text DEFAULT NULL::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_evaluation JSONB;
  v_status TEXT;
  v_snapshot_id UUID;
BEGIN
  -- Evaluate gates
  v_evaluation := tm_evaluate_release_gates(p_release_id, p_user_id);
  
  -- Determine status
  IF (v_evaluation->'summary'->>'all_blocking_passed')::boolean THEN
    IF (v_evaluation->'summary'->>'passed_gates')::int = (v_evaluation->'summary'->>'total_gates')::int THEN
      v_status := 'ready';
    ELSE
      v_status := 'at_risk';
    END IF;
  ELSE
    v_status := 'not_ready';
  END IF;
  
  -- Create snapshot
  INSERT INTO tm_release_readiness (
    release_id,
    overall_status,
    gates_passed,
    gates_total,
    blocking_gates_passed,
    blocking_gates_total,
    test_execution_pct,
    test_pass_pct,
    open_blockers,
    open_criticals,
    recommendation,
    created_by
  ) VALUES (
    p_release_id,
    v_status,
    (v_evaluation->'summary'->>'passed_gates')::int,
    (v_evaluation->'summary'->>'total_gates')::int,
    (v_evaluation->'summary'->>'blocking_passed')::int,
    (v_evaluation->'summary'->>'blocking_total')::int,
    (v_evaluation->'test_summary'->'totals'->>'execution_pct')::numeric,
    (v_evaluation->'test_summary'->'totals'->>'pass_pct')::numeric,
    (v_evaluation->'test_summary'->'defects'->>'blockers')::int,
    (v_evaluation->'test_summary'->'defects'->>'criticals')::int,
    p_recommendation,
    p_user_id
  ) RETURNING id INTO v_snapshot_id;
  
  RETURN v_snapshot_id;
END;
$$;


--
-- Name: tm_create_run_from_template(uuid, text, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_create_run_from_template(p_template_id uuid, p_name text DEFAULT NULL::text, p_scheduled_start timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_template RECORD;
  v_run_id UUID;
  v_run_number INTEGER;
  v_case_ids UUID[];
BEGIN
  -- Get template
  SELECT * INTO v_template
  FROM tm_run_templates
  WHERE id = p_template_id AND is_active = true;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Template not found');
  END IF;
  
  -- Generate run number
  SELECT COALESCE(MAX(run_number), 0) + 1 INTO v_run_number
  FROM test_execution_runs
  WHERE project_id = v_template.project_id;
  
  -- Create run
  INSERT INTO test_execution_runs (
    project_id, 
    run_number, 
    run_name,
    name,
    description, 
    environment, 
    configuration,
    scheduled_start,
    status,
    created_by
  )
  VALUES (
    v_template.project_id,
    v_run_number,
    COALESCE(p_name, v_template.name || ' #' || v_run_number),
    COALESCE(p_name, v_template.name || ' #' || v_run_number),
    v_template.description,
    v_template.environment,
    v_template.configuration,
    p_scheduled_start,
    'draft',
    auth.uid()
  )
  RETURNING id INTO v_run_id;
  
  -- Apply test case filter if present
  IF v_template.test_case_filter IS NOT NULL AND v_template.test_case_filter != '{}'::jsonb THEN
    -- Get matching case IDs based on filter criteria
    SELECT array_agg(tc.id) INTO v_case_ids
    FROM tm_test_cases tc
    WHERE tc.project_id = v_template.project_id
    AND tc.is_active = true
    AND (
      (v_template.test_case_filter->>'folder_id' IS NULL OR 
       tc.folder_id = (v_template.test_case_filter->>'folder_id')::UUID)
      AND
      (v_template.test_case_filter->>'priority' IS NULL OR 
       tc.priority = v_template.test_case_filter->>'priority')
      AND
      (v_template.test_case_filter->>'type' IS NULL OR 
       tc.type = v_template.test_case_filter->>'type')
    );
    
    -- Assign cases to run
    IF v_case_ids IS NOT NULL AND array_length(v_case_ids, 1) > 0 THEN
      PERFORM tm_assign_cases_to_run(v_run_id, v_case_ids, NULL);
    END IF;
  END IF;
  
  RETURN jsonb_build_object(
    'success', true,
    'run_id', v_run_id,
    'run_number', v_run_number,
    'cases_assigned', COALESCE(array_length(v_case_ids, 1), 0)
  );
END;
$$;


--
-- Name: tm_create_version_snapshot(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_create_version_snapshot(p_case_id uuid, p_change_summary text DEFAULT NULL::text) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_case RECORD;
  v_steps JSONB;
  v_snapshot JSONB;
  v_version INTEGER;
BEGIN
  -- Get current case
  SELECT * INTO v_case FROM tm_test_cases WHERE id = p_case_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Test case not found';
  END IF;

  -- Get current steps
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'step_number', step_number,
      'step_type', step_type,
      'action', action,
      'action_html', action_html,
      'expected_result', expected_result,
      'expected_result_html', expected_result_html,
      'test_data', test_data,
      'notes', notes,
      'is_optional', is_optional,
      'estimated_time_seconds', estimated_time_seconds
    ) ORDER BY step_number
  ), '[]'::jsonb)
  INTO v_steps
  FROM tm_test_steps WHERE test_case_id = p_case_id;

  -- Build snapshot
  v_snapshot := jsonb_build_object(
    'title', v_case.title,
    'description', v_case.description,
    'description_html', v_case.description_html,
    'preconditions', v_case.preconditions,
    'preconditions_html', v_case.preconditions_html,
    'postconditions', v_case.postconditions,
    'postconditions_html', v_case.postconditions_html,
    'status', v_case.status,
    'priority', v_case.priority,
    'type', v_case.type,
    'test_format', v_case.test_format,
    'gherkin_feature', v_case.gherkin_feature,
    'gherkin_scenario', v_case.gherkin_scenario,
    'folder_id', v_case.folder_id,
    'steps', v_steps
  );

  -- Get next version number
  SELECT COALESCE(MAX(version_number), 0) + 1 INTO v_version
  FROM tm_test_case_versions WHERE test_case_id = p_case_id;

  -- Insert version
  INSERT INTO tm_test_case_versions (
    test_case_id,
    version_number,
    snapshot,
    change_summary,
    changed_by
  ) VALUES (
    p_case_id,
    v_version,
    v_snapshot,
    p_change_summary,
    auth.uid()
  );

  -- Update case version
  UPDATE tm_test_cases
  SET version = v_version, updated_at = now()
  WHERE id = p_case_id;

  RETURN v_version;
END;
$$;


--
-- Name: tm_cycle_scope_delete_trigger(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_cycle_scope_delete_trigger() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_status text;
BEGIN
  v_status := COALESCE(OLD.current_status, 'not_run');
  
  UPDATE tm_test_cycles
  SET 
    total_cases = GREATEST(COALESCE(total_cases, 0) - 1, 0),
    not_run_count = CASE WHEN v_status = 'not_run' THEN GREATEST(COALESCE(not_run_count, 0) - 1, 0) ELSE not_run_count END,
    in_progress_count = CASE WHEN v_status = 'in_progress' THEN GREATEST(COALESCE(in_progress_count, 0) - 1, 0) ELSE in_progress_count END,
    passed_count = CASE WHEN v_status = 'passed' THEN GREATEST(COALESCE(passed_count, 0) - 1, 0) ELSE passed_count END,
    failed_count = CASE WHEN v_status = 'failed' THEN GREATEST(COALESCE(failed_count, 0) - 1, 0) ELSE failed_count END,
    blocked_count = CASE WHEN v_status = 'blocked' THEN GREATEST(COALESCE(blocked_count, 0) - 1, 0) ELSE blocked_count END,
    skipped_count = CASE WHEN v_status = 'skipped' THEN GREATEST(COALESCE(skipped_count, 0) - 1, 0) ELSE skipped_count END,
    updated_at = now()
  WHERE id = OLD.cycle_id;
  
  RETURN OLD;
END;
$$;


--
-- Name: tm_cycle_scope_insert_trigger(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_cycle_scope_insert_trigger() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_status text;
BEGIN
  v_status := COALESCE(NEW.current_status, 'not_run');
  
  UPDATE tm_test_cycles
  SET 
    total_cases = COALESCE(total_cases, 0) + 1,
    not_run_count = CASE WHEN v_status = 'not_run' THEN COALESCE(not_run_count, 0) + 1 ELSE not_run_count END,
    in_progress_count = CASE WHEN v_status = 'in_progress' THEN COALESCE(in_progress_count, 0) + 1 ELSE in_progress_count END,
    passed_count = CASE WHEN v_status = 'passed' THEN COALESCE(passed_count, 0) + 1 ELSE passed_count END,
    failed_count = CASE WHEN v_status = 'failed' THEN COALESCE(failed_count, 0) + 1 ELSE failed_count END,
    blocked_count = CASE WHEN v_status = 'blocked' THEN COALESCE(blocked_count, 0) + 1 ELSE blocked_count END,
    skipped_count = CASE WHEN v_status = 'skipped' THEN COALESCE(skipped_count, 0) + 1 ELSE skipped_count END,
    updated_at = now()
  WHERE id = NEW.cycle_id;
  
  RETURN NEW;
END;
$$;


--
-- Name: tm_cycle_scope_update_trigger(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_cycle_scope_update_trigger() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_old_status text;
  v_new_status text;
BEGIN
  IF OLD.current_status IS DISTINCT FROM NEW.current_status THEN
    v_old_status := COALESCE(OLD.current_status, 'not_run');
    v_new_status := COALESCE(NEW.current_status, 'not_run');
    
    -- Decrement old status counter
    UPDATE tm_test_cycles
    SET 
      not_run_count = CASE WHEN v_old_status = 'not_run' THEN GREATEST(COALESCE(not_run_count, 0) - 1, 0) ELSE not_run_count END,
      in_progress_count = CASE WHEN v_old_status = 'in_progress' THEN GREATEST(COALESCE(in_progress_count, 0) - 1, 0) ELSE in_progress_count END,
      passed_count = CASE WHEN v_old_status = 'passed' THEN GREATEST(COALESCE(passed_count, 0) - 1, 0) ELSE passed_count END,
      failed_count = CASE WHEN v_old_status = 'failed' THEN GREATEST(COALESCE(failed_count, 0) - 1, 0) ELSE failed_count END,
      blocked_count = CASE WHEN v_old_status = 'blocked' THEN GREATEST(COALESCE(blocked_count, 0) - 1, 0) ELSE blocked_count END,
      skipped_count = CASE WHEN v_old_status = 'skipped' THEN GREATEST(COALESCE(skipped_count, 0) - 1, 0) ELSE skipped_count END,
      updated_at = now()
    WHERE id = NEW.cycle_id;
    
    -- Increment new status counter
    UPDATE tm_test_cycles
    SET 
      not_run_count = CASE WHEN v_new_status = 'not_run' THEN COALESCE(not_run_count, 0) + 1 ELSE not_run_count END,
      in_progress_count = CASE WHEN v_new_status = 'in_progress' THEN COALESCE(in_progress_count, 0) + 1 ELSE in_progress_count END,
      passed_count = CASE WHEN v_new_status = 'passed' THEN COALESCE(passed_count, 0) + 1 ELSE passed_count END,
      failed_count = CASE WHEN v_new_status = 'failed' THEN COALESCE(failed_count, 0) + 1 ELSE failed_count END,
      blocked_count = CASE WHEN v_new_status = 'blocked' THEN COALESCE(blocked_count, 0) + 1 ELSE blocked_count END,
      skipped_count = CASE WHEN v_new_status = 'skipped' THEN COALESCE(skipped_count, 0) + 1 ELSE skipped_count END,
      updated_at = now()
    WHERE id = NEW.cycle_id;
  END IF;
  
  RETURN NEW;
END;
$$;


