--
-- Name: tm_delete_step(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_delete_step(p_step_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_case_id UUID;
  v_step_number INTEGER;
BEGIN
  -- Get step info
  SELECT case_id, step_number INTO v_case_id, v_step_number 
  FROM tm_test_steps WHERE id = p_step_id;
  
  IF v_case_id IS NULL THEN
    RETURN false;
  END IF;
  
  -- Delete step
  DELETE FROM tm_test_steps WHERE id = p_step_id;
  
  -- Reorder remaining steps
  UPDATE tm_test_steps 
  SET step_number = step_number - 1 
  WHERE case_id = v_case_id AND step_number > v_step_number;
  
  RETURN true;
END;
$$;


--
-- Name: tm_evaluate_quality_gates(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_evaluate_quality_gates(p_release_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_gate RECORD;
  v_value NUMERIC;
  v_new_status TEXT;
  v_release RECORD;
  v_results JSON[];
  v_total_gates INT := 0;
  v_passed_gates INT := 0;
  v_blocking_total INT := 0;
  v_blocking_passed INT := 0;
BEGIN
  -- Get release metrics
  SELECT * INTO v_release FROM releases WHERE id = p_release_id;
  IF NOT FOUND THEN
    RETURN json_build_object('error', 'Release not found');
  END IF;

  FOR v_gate IN
    SELECT * FROM tm_release_quality_gates
    WHERE release_id = p_release_id AND (status IS NULL OR status != 'waived')
  LOOP
    v_total_gates := v_total_gates + 1;
    IF v_gate.is_blocking THEN
      v_blocking_total := v_blocking_total + 1;
    END IF;

    -- Calculate metric value based on gate type
    v_value := CASE v_gate.gate_type
      WHEN 'pass_rate' THEN
        CASE WHEN COALESCE(v_release.test_cases_executed, 0) > 0
          THEN ROUND((COALESCE(v_release.test_cases_passed, 0)::numeric / v_release.test_cases_executed) * 100, 2)
          ELSE 0 END
      WHEN 'execution_rate' THEN
        CASE WHEN COALESCE(v_release.test_cases_total, 0) > 0
          THEN ROUND((COALESCE(v_release.test_cases_executed, 0)::numeric / v_release.test_cases_total) * 100, 2)
          ELSE 0 END
      WHEN 'defect_count' THEN COALESCE(v_release.defects_open, 0)
      WHEN 'blocker_count' THEN COALESCE(v_release.critical_defects, 0)
      WHEN 'coverage' THEN COALESCE(v_release.coverage_percent, 0)
      ELSE 0
    END;

    -- Evaluate against threshold
    v_new_status := CASE
      WHEN v_gate.threshold_operator = '>=' AND v_value >= v_gate.threshold_value THEN 'passed'
      WHEN v_gate.threshold_operator = '<=' AND v_value <= v_gate.threshold_value THEN 'passed'
      WHEN v_gate.threshold_operator = '=' AND v_value = v_gate.threshold_value THEN 'passed'
      WHEN v_gate.threshold_operator = '>' AND v_value > v_gate.threshold_value THEN 'passed'
      WHEN v_gate.threshold_operator = '<' AND v_value < v_gate.threshold_value THEN 'passed'
      ELSE 'failed'
    END;

    IF v_new_status = 'passed' THEN
      v_passed_gates := v_passed_gates + 1;
      IF v_gate.is_blocking THEN
        v_blocking_passed := v_blocking_passed + 1;
      END IF;
    END IF;

    -- Record history if status changed
    IF v_gate.status IS DISTINCT FROM v_new_status THEN
      INSERT INTO tm_gate_evaluation_history (
        gate_id, previous_status, new_status, metric_value, threshold_value, evaluation_type
      ) VALUES (
        v_gate.id, v_gate.status, v_new_status, v_value, v_gate.threshold_value, 'automatic'
      );
    END IF;

    -- Update gate
    UPDATE tm_release_quality_gates SET
      current_value = v_value,
      status = v_new_status,
      last_evaluated_at = NOW()
    WHERE id = v_gate.id;

    v_results := array_append(v_results, json_build_object(
      'gate_id', v_gate.id,
      'name', v_gate.gate_name,
      'status', v_new_status,
      'value', v_value,
      'threshold', v_gate.threshold_value
    ));
  END LOOP;

  -- Also update waived gates with expired waivers
  UPDATE tm_release_quality_gates SET
    status = 'pending',
    waived_at = NULL,
    waived_by = NULL,
    waiver_reason = NULL,
    waiver_expires_at = NULL
  WHERE release_id = p_release_id
    AND status = 'waived'
    AND waiver_expires_at IS NOT NULL
    AND waiver_expires_at < NOW();

  RETURN json_build_object(
    'release_id', p_release_id,
    'evaluated_at', NOW(),
    'gates', COALESCE(v_results, ARRAY[]::JSON[]),
    'total_gates', v_total_gates,
    'passed_gates', v_passed_gates,
    'blocking_total', v_blocking_total,
    'blocking_passed', v_blocking_passed,
    'all_blocking_passed', (v_blocking_passed = v_blocking_total)
  );
END;
$$;


--
-- Name: tm_evaluate_release_gates(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_evaluate_release_gates(p_release_id uuid, p_user_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_gate RECORD;
  v_actual NUMERIC;
  v_passed BOOLEAN;
  v_results JSONB := '[]'::jsonb;
  v_summary JSONB;
  v_test_summary JSONB;
BEGIN
  -- Get test summary first
  v_test_summary := tm_get_release_test_summary(p_release_id);
  
  -- Evaluate each gate
  FOR v_gate IN 
    SELECT * FROM tm_release_quality_gates 
    WHERE release_id = p_release_id 
    ORDER BY sort_order
  LOOP
    -- Calculate actual value based on gate type
    CASE v_gate.gate_type
      WHEN 'pass_rate' THEN
        v_actual := (v_test_summary->'totals'->>'pass_pct')::NUMERIC;
      WHEN 'execution_rate' THEN
        v_actual := (v_test_summary->'totals'->>'execution_pct')::NUMERIC;
      WHEN 'defect_count' THEN
        v_actual := (v_test_summary->'defects'->>'open')::NUMERIC;
      WHEN 'blocker_count' THEN
        v_actual := (v_test_summary->'defects'->>'blockers')::NUMERIC;
      WHEN 'coverage' THEN
        v_actual := (v_test_summary->'totals'->>'total_cases')::NUMERIC;
      ELSE
        v_actual := 0;
    END CASE;
    
    -- Evaluate threshold
    CASE v_gate.threshold_operator
      WHEN '>=' THEN v_passed := v_actual >= v_gate.threshold_value;
      WHEN '<=' THEN v_passed := v_actual <= v_gate.threshold_value;
      WHEN '>' THEN v_passed := v_actual > v_gate.threshold_value;
      WHEN '<' THEN v_passed := v_actual < v_gate.threshold_value;
      WHEN '=' THEN v_passed := v_actual = v_gate.threshold_value;
      ELSE v_passed := false;
    END CASE;
    
    -- Insert result
    INSERT INTO tm_release_gate_results (release_id, gate_id, actual_value, passed, evaluated_by)
    VALUES (p_release_id, v_gate.id, v_actual, v_passed, p_user_id);
    
    -- Add to results array
    v_results := v_results || jsonb_build_object(
      'gate_id', v_gate.id,
      'gate_name', v_gate.gate_name,
      'gate_type', v_gate.gate_type,
      'threshold', v_gate.threshold_operator || ' ' || v_gate.threshold_value,
      'actual_value', v_actual,
      'passed', v_passed,
      'is_blocking', v_gate.is_blocking
    );
  END LOOP;
  
  -- Build summary
  SELECT jsonb_build_object(
    'release_id', p_release_id,
    'evaluated_at', now(),
    'gates', v_results,
    'summary', jsonb_build_object(
      'total_gates', jsonb_array_length(v_results),
      'passed_gates', (SELECT COUNT(*) FROM jsonb_array_elements(v_results) g WHERE (g->>'passed')::boolean),
      'blocking_passed', (SELECT COUNT(*) FROM jsonb_array_elements(v_results) g WHERE (g->>'passed')::boolean AND (g->>'is_blocking')::boolean),
      'blocking_total', (SELECT COUNT(*) FROM jsonb_array_elements(v_results) g WHERE (g->>'is_blocking')::boolean),
      'all_blocking_passed', NOT EXISTS (
        SELECT 1 FROM jsonb_array_elements(v_results) g 
        WHERE (g->>'is_blocking')::boolean AND NOT (g->>'passed')::boolean
      )
    ),
    'test_summary', v_test_summary
  ) INTO v_summary;
  
  RETURN v_summary;
END;
$$;


--
-- Name: tm_get_case_attachments(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_case_attachments(p_case_id uuid) RETURNS TABLE(id uuid, test_case_id uuid, test_step_id uuid, file_name text, file_path text, file_size integer, mime_type text, attachment_type text, description text, uploaded_by uuid, uploader_name text, created_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    a.id,
    a.test_case_id,
    a.test_step_id,
    a.file_name,
    a.file_path,
    a.file_size,
    a.mime_type,
    a.attachment_type,
    a.description,
    a.uploaded_by,
    COALESCE(p.full_name, p.email, 'Unknown') as uploader_name,
    a.created_at
  FROM tm_test_attachments a
  LEFT JOIN profiles p ON p.id = a.uploaded_by
  WHERE a.test_case_id = p_case_id
  ORDER BY a.created_at DESC;
END;
$$;


--
-- Name: tm_get_case_requirements(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_case_requirements(p_case_id uuid) RETURNS TABLE(id uuid, test_case_id uuid, requirement_type text, requirement_id uuid, external_key text, external_url text, external_title text, link_type text, coverage_status text, notes text, requirement_title text, requirement_status text, created_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    rl.id,
    rl.test_case_id,
    rl.requirement_type,
    rl.requirement_id,
    rl.external_key,
    rl.external_url,
    rl.external_title,
    rl.link_type,
    rl.coverage_status,
    rl.notes,
    CASE 
      WHEN rl.requirement_type = 'story' THEN s.title
      WHEN rl.requirement_type = 'epic' THEN e.name
      WHEN rl.requirement_type = 'feature' THEN f.name
      WHEN rl.requirement_type = 'business_request' THEN br.title
      ELSE rl.external_title
    END as requirement_title,
    CASE 
      WHEN rl.requirement_type = 'story' THEN s.status
      WHEN rl.requirement_type = 'epic' THEN e.status
      WHEN rl.requirement_type = 'feature' THEN f.status
      WHEN rl.requirement_type = 'business_request' THEN br.process_step
      ELSE NULL
    END as requirement_status,
    rl.created_at
  FROM tm_requirement_links rl
  LEFT JOIN stories s ON rl.requirement_type = 'story' AND rl.requirement_id = s.id
  LEFT JOIN epics e ON rl.requirement_type = 'epic' AND rl.requirement_id = e.id
  LEFT JOIN features f ON rl.requirement_type = 'feature' AND rl.requirement_id = f.id
  LEFT JOIN business_requests br ON rl.requirement_type = 'business_request' AND rl.requirement_id = br.id
  WHERE rl.test_case_id = p_case_id
  ORDER BY rl.created_at DESC;
END;
$$;


--
-- Name: tm_get_case_steps(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_case_steps(p_case_id uuid) RETURNS TABLE(id uuid, step_number integer, step_type text, action text, expected_result text, test_data text, notes text, is_optional boolean, estimated_time_seconds integer, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    s.id,
    s.step_number,
    s.step_type::TEXT,
    s.action,
    s.expected_result,
    s.test_data,
    s.notes,
    COALESCE(s.is_optional, false),
    s.estimated_time_seconds,
    s.created_at,
    s.updated_at
  FROM tm_test_steps s
  WHERE s.case_id = p_case_id
  ORDER BY s.step_number;
END;
$$;


--
-- Name: tm_get_counter_column(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_counter_column(p_status text) RETURNS text
    LANGUAGE plpgsql IMMUTABLE
    AS $$
BEGIN
  RETURN CASE p_status
    WHEN 'not_run' THEN 'not_run_count'
    WHEN 'in_progress' THEN 'in_progress_count'
    WHEN 'passed' THEN 'passed_count'
    WHEN 'failed' THEN 'failed_count'
    WHEN 'blocked' THEN 'blocked_count'
    WHEN 'skipped' THEN 'skipped_count'
    ELSE NULL
  END;
END;
$$;


--
-- Name: tm_get_cycle_activity_feed(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_cycle_activity_feed(p_cycle_id uuid, p_limit integer DEFAULT 20) RETURNS TABLE(id uuid, action_type text, actor_id uuid, actor_name text, actor_initials text, test_case_key text, test_case_title text, from_status text, to_status text, defect_key text, metadata jsonb, created_at timestamp with time zone, time_ago text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    a.id,
    a.action_type,
    a.actor_id,
    COALESCE(a.actor_name, 'System')::TEXT as actor_name,
    UPPER(SUBSTRING(COALESCE(a.actor_name, 'S') FROM 1 FOR 1) || 
          COALESCE(SUBSTRING(COALESCE(a.actor_name, '') FROM POSITION(' ' IN COALESCE(a.actor_name, '') || ' ') + 1 FOR 1), ''))::TEXT as actor_initials,
    a.test_case_key,
    a.test_case_title,
    a.from_status,
    a.to_status,
    a.defect_key,
    a.metadata,
    a.created_at,
    CASE 
      WHEN a.created_at > NOW() - INTERVAL '1 minute' THEN 'just now'
      WHEN a.created_at > NOW() - INTERVAL '1 hour' THEN EXTRACT(MINUTE FROM NOW() - a.created_at)::TEXT || 'm ago'
      WHEN a.created_at > NOW() - INTERVAL '1 day' THEN EXTRACT(HOUR FROM NOW() - a.created_at)::TEXT || 'h ago'
      ELSE TO_CHAR(a.created_at, 'Mon DD')
    END::TEXT as time_ago
  FROM tm_cycle_execution_audit a
  WHERE a.cycle_id = p_cycle_id
  ORDER BY a.created_at DESC
  LIMIT p_limit;
END;
$$;


--
-- Name: tm_get_cycle_defect_trends(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_cycle_defect_trends(p_cycle_id uuid, p_days integer DEFAULT 14) RETURNS TABLE(date_key date, date_label text, blocker_count bigint, critical_count bigint, major_count bigint, minor_count bigint, total_defects bigint, cumulative_total bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_start_date DATE;
BEGIN
  v_start_date := CURRENT_DATE - p_days;
  
  RETURN QUERY
  WITH date_series AS (
    SELECT generate_series(v_start_date, CURRENT_DATE, '1 day'::INTERVAL)::DATE as d
  ),
  defect_counts AS (
    -- From tm_test_runs that recorded defects
    SELECT 
      tr.completed_at::DATE as defect_date,
      COUNT(*) FILTER (WHERE tr.status = 'failed') as total_failures
    FROM tm_test_runs tr
    JOIN tm_cycle_scope cs ON tr.cycle_scope_id = cs.id
    WHERE cs.cycle_id = p_cycle_id
      AND tr.completed_at IS NOT NULL
      AND tr.completed_at::DATE >= v_start_date
      AND tr.status = 'failed'
    GROUP BY tr.completed_at::DATE
  )
  SELECT 
    ds.d as date_key,
    TO_CHAR(ds.d, 'Mon DD')::TEXT as date_label,
    -- Distribute defects by severity (simulated - would be from actual defect table)
    ROUND(COALESCE(dc.total_failures, 0) * 0.1)::BIGINT as blocker_count,
    ROUND(COALESCE(dc.total_failures, 0) * 0.2)::BIGINT as critical_count,
    ROUND(COALESCE(dc.total_failures, 0) * 0.4)::BIGINT as major_count,
    ROUND(COALESCE(dc.total_failures, 0) * 0.3)::BIGINT as minor_count,
    COALESCE(dc.total_failures, 0)::BIGINT as total_defects,
    SUM(COALESCE(dc.total_failures, 0)) OVER (ORDER BY ds.d)::BIGINT as cumulative_total
  FROM date_series ds
  LEFT JOIN defect_counts dc ON ds.d = dc.defect_date
  ORDER BY ds.d;
END;
$$;


--
-- Name: tm_get_cycle_details(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_cycle_details(p_cycle_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_result JSONB;
BEGIN
  SELECT jsonb_build_object(
    'success', true,
    'cycle', jsonb_build_object(
      'id', c.id,
      'project_id', c.project_id,
      'cycle_key', c.cycle_key,
      'name', c.name,
      'description', c.description,
      'status', c.status,
      'planned_start', c.planned_start,
      'planned_end', c.planned_end,
      'actual_start', c.actual_start,
      'actual_end', c.actual_end,
      'test_plan_id', c.test_plan_id,
      'created_at', c.created_at,
      'stats', jsonb_build_object(
        'total', c.total_cases,
        'passed', c.passed_count,
        'failed', c.failed_count,
        'blocked', c.blocked_count,
        'skipped', c.skipped_count,
        'not_run', c.not_run_count
      )
    ),
    'milestones', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', m.id,
        'name', m.name,
        'target_date', m.target_date,
        'description', m.description,
        'is_completed', m.is_completed,
        'completed_at', m.completed_at
      ) ORDER BY m.target_date, m.sort_order)
      FROM tm_cycle_milestones m WHERE m.cycle_id = c.id
    ), '[]'::JSONB),
    'assignments', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'id', a.id,
        'user_id', a.user_id,
        'user_name', p.full_name,
        'user_avatar', p.avatar_url,
        'role', a.role,
        'assigned_at', a.assigned_at,
        'workload', (
          SELECT jsonb_build_object(
            'assigned', COUNT(*),
            'completed', COUNT(*) FILTER (WHERE cs.current_status IN ('passed', 'failed', 'blocked', 'skipped')),
            'passed', COUNT(*) FILTER (WHERE cs.current_status = 'passed'),
            'failed', COUNT(*) FILTER (WHERE cs.current_status = 'failed')
          )
          FROM tm_cycle_scope cs WHERE cs.cycle_id = c.id AND cs.assigned_to = a.user_id
        )
      ))
      FROM tm_cycle_assignments a
      JOIN profiles p ON p.id = a.user_id
      WHERE a.cycle_id = c.id
    ), '[]'::JSONB)
  ) INTO v_result
  FROM tm_test_cycles c
  WHERE c.id = p_cycle_id;
  
  RETURN v_result;
END;
$$;


--
-- Name: tm_get_cycle_execution_summary(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_cycle_execution_summary(p_cycle_id uuid) RETURNS TABLE(total_cases bigint, passed bigint, failed bigint, blocked bigint, in_progress bigint, not_started bigint, skipped bigint, execution_rate numeric, pass_rate numeric, avg_duration_seconds numeric, total_duration_hours numeric, active_testers bigint, defects_found bigint, tests_with_evidence bigint, velocity_today bigint, velocity_avg_7d numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_today DATE := CURRENT_DATE;
  v_7d_ago DATE := CURRENT_DATE - 7;
BEGIN
  RETURN QUERY
  WITH scope_stats AS (
    SELECT 
      COUNT(*)::BIGINT as total,
      COUNT(*) FILTER (WHERE cs.status = 'passed')::BIGINT as passed,
      COUNT(*) FILTER (WHERE cs.status = 'failed')::BIGINT as failed,
      COUNT(*) FILTER (WHERE cs.status = 'blocked')::BIGINT as blocked,
      COUNT(*) FILTER (WHERE cs.status = 'in_progress')::BIGINT as in_progress,
      COUNT(*) FILTER (WHERE cs.status IN ('not_run', 'pending'))::BIGINT as not_started,
      COUNT(*) FILTER (WHERE cs.status = 'skipped')::BIGINT as skipped,
      COUNT(DISTINCT cs.assigned_to) FILTER (WHERE cs.assigned_to IS NOT NULL)::BIGINT as active_testers
    FROM tm_cycle_scope cs
    WHERE cs.cycle_id = p_cycle_id
  ),
  run_stats AS (
    SELECT 
      AVG(tr.duration_seconds)::NUMERIC as avg_duration,
      SUM(tr.duration_seconds)::NUMERIC / 3600 as total_hours,
      SUM(tr.defects_found)::BIGINT as defects,
      COUNT(*) FILTER (WHERE EXISTS (
        SELECT 1 FROM tm_cycle_execution_audit cea 
        WHERE cea.test_run_id = tr.id AND cea.action_type = 'evidence_uploaded'
      ))::BIGINT as with_evidence
    FROM tm_test_runs tr
    JOIN tm_cycle_scope cs ON tr.cycle_scope_id = cs.id
    WHERE cs.cycle_id = p_cycle_id
  ),
  velocity_stats AS (
    SELECT 
      COUNT(*) FILTER (WHERE tr.completed_at::DATE = v_today)::BIGINT as today,
      ROUND(COUNT(*) FILTER (WHERE tr.completed_at::DATE >= v_7d_ago)::NUMERIC / 7, 1) as avg_7d
    FROM tm_test_runs tr
    JOIN tm_cycle_scope cs ON tr.cycle_scope_id = cs.id
    WHERE cs.cycle_id = p_cycle_id AND tr.completed_at IS NOT NULL
  )
  SELECT 
    ss.total as total_cases,
    ss.passed,
    ss.failed,
    ss.blocked,
    ss.in_progress,
    ss.not_started,
    ss.skipped,
    CASE WHEN ss.total = 0 THEN 0 ELSE ROUND((ss.passed + ss.failed + ss.blocked + ss.skipped)::NUMERIC / ss.total * 100, 1) END as execution_rate,
    CASE WHEN (ss.passed + ss.failed + ss.blocked) = 0 THEN 0 ELSE ROUND(ss.passed::NUMERIC / (ss.passed + ss.failed + ss.blocked) * 100, 1) END as pass_rate,
    COALESCE(rs.avg_duration, 0) as avg_duration_seconds,
    COALESCE(rs.total_hours, 0) as total_duration_hours,
    ss.active_testers,
    COALESCE(rs.defects, 0) as defects_found,
    COALESCE(rs.with_evidence, 0) as tests_with_evidence,
    vs.today as velocity_today,
    vs.avg_7d as velocity_avg_7d
  FROM scope_stats ss
  CROSS JOIN run_stats rs
  CROSS JOIN velocity_stats vs;
END;
$$;


--
-- Name: tm_get_cycle_execution_velocity(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_cycle_execution_velocity(p_cycle_id uuid, p_days integer DEFAULT 14) RETURNS TABLE(date_key date, date_label text, executed_count bigint, passed_count bigint, failed_count bigint, blocked_count bigint, cumulative_executed bigint, velocity_per_day numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_start_date DATE;
  v_running_total BIGINT := 0;
BEGIN
  v_start_date := CURRENT_DATE - p_days;
  
  RETURN QUERY
  WITH date_series AS (
    SELECT generate_series(v_start_date, CURRENT_DATE, '1 day'::INTERVAL)::DATE as d
  ),
  daily_counts AS (
    SELECT 
      tr.completed_at::DATE as run_date,
      COUNT(*) as executed,
      COUNT(*) FILTER (WHERE tr.status = 'passed') as passed,
      COUNT(*) FILTER (WHERE tr.status = 'failed') as failed,
      COUNT(*) FILTER (WHERE tr.status = 'blocked') as blocked
    FROM tm_test_runs tr
    JOIN tm_cycle_scope cs ON tr.cycle_scope_id = cs.id
    WHERE cs.cycle_id = p_cycle_id
      AND tr.completed_at IS NOT NULL
      AND tr.completed_at::DATE >= v_start_date
    GROUP BY tr.completed_at::DATE
  ),
  joined AS (
    SELECT 
      ds.d as date_key,
      TO_CHAR(ds.d, 'Mon DD')::TEXT as date_label,
      COALESCE(dc.executed, 0)::BIGINT as executed_count,
      COALESCE(dc.passed, 0)::BIGINT as passed_count,
      COALESCE(dc.failed, 0)::BIGINT as failed_count,
      COALESCE(dc.blocked, 0)::BIGINT as blocked_count
    FROM date_series ds
    LEFT JOIN daily_counts dc ON ds.d = dc.run_date
    ORDER BY ds.d
  )
  SELECT 
    j.date_key,
    j.date_label,
    j.executed_count,
    j.passed_count,
    j.failed_count,
    j.blocked_count,
    SUM(j.executed_count) OVER (ORDER BY j.date_key) as cumulative_executed,
    CASE 
      WHEN ROW_NUMBER() OVER (ORDER BY j.date_key) <= 3 THEN j.executed_count::NUMERIC
      ELSE ROUND(AVG(j.executed_count) OVER (ORDER BY j.date_key ROWS BETWEEN 2 PRECEDING AND CURRENT ROW), 1)
    END as velocity_per_day
  FROM joined j;
END;
$$;


--
-- Name: tm_get_cycle_quality_trends(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_cycle_quality_trends(p_cycle_id uuid, p_days integer DEFAULT 14) RETURNS TABLE(date_key date, date_label text, pass_rate numeric, execution_rate numeric, defect_rate numeric, cumulative_passed bigint, cumulative_failed bigint, cumulative_blocked bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_start_date DATE;
BEGIN
  v_start_date := CURRENT_DATE - p_days;
  
  RETURN QUERY
  WITH date_series AS (
    SELECT generate_series(v_start_date, CURRENT_DATE, '1 day'::INTERVAL)::DATE as d
  ),
  daily_stats AS (
    SELECT 
      tr.completed_at::DATE as run_date,
      COUNT(*) FILTER (WHERE tr.status = 'passed') as passed,
      COUNT(*) FILTER (WHERE tr.status = 'failed') as failed,
      COUNT(*) FILTER (WHERE tr.status = 'blocked') as blocked,
      COUNT(*) as total_executed
    FROM tm_test_runs tr
    JOIN tm_cycle_scope cs ON tr.cycle_scope_id = cs.id
    WHERE cs.cycle_id = p_cycle_id
      AND tr.completed_at IS NOT NULL
      AND tr.completed_at::DATE >= v_start_date
    GROUP BY tr.completed_at::DATE
  ),
  scope_total AS (
    SELECT COUNT(*)::NUMERIC as total FROM tm_cycle_scope WHERE cycle_id = p_cycle_id
  )
  SELECT 
    ds.d as date_key,
    TO_CHAR(ds.d, 'Mon DD')::TEXT as date_label,
    CASE 
      WHEN COALESCE(dc.total_executed, 0) = 0 THEN 0
      ELSE ROUND(COALESCE(dc.passed, 0)::NUMERIC / dc.total_executed * 100, 1)
    END as pass_rate,
    CASE 
      WHEN st.total = 0 THEN 0
      ELSE ROUND(SUM(COALESCE(dc.total_executed, 0)) OVER (ORDER BY ds.d)::NUMERIC / st.total * 100, 1)
    END as execution_rate,
    CASE 
      WHEN COALESCE(dc.total_executed, 0) = 0 THEN 0
      ELSE ROUND(COALESCE(dc.failed, 0)::NUMERIC / dc.total_executed * 100, 1)
    END as defect_rate,
    SUM(COALESCE(dc.passed, 0)) OVER (ORDER BY ds.d)::BIGINT as cumulative_passed,
    SUM(COALESCE(dc.failed, 0)) OVER (ORDER BY ds.d)::BIGINT as cumulative_failed,
    SUM(COALESCE(dc.blocked, 0)) OVER (ORDER BY ds.d)::BIGINT as cumulative_blocked
  FROM date_series ds
  LEFT JOIN daily_stats dc ON ds.d = dc.run_date
  CROSS JOIN scope_total st
  ORDER BY ds.d;
END;
$$;


--
-- Name: tm_get_cycle_team_workload(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_cycle_team_workload(p_cycle_id uuid) RETURNS TABLE(user_id uuid, user_name text, user_initials text, avatar_url text, total_tests bigint, passed bigint, failed bigint, blocked bigint, in_progress bigint, not_started bigint, workload_status text, avg_completion_rate numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_avg_tests_per_user NUMERIC;
BEGIN
  -- Calculate average tests per user for workload status
  SELECT AVG(test_count)::NUMERIC INTO v_avg_tests_per_user
  FROM (
    SELECT COUNT(*) as test_count
    FROM tm_cycle_scope
    WHERE cycle_id = p_cycle_id AND assigned_to IS NOT NULL
    GROUP BY assigned_to
  ) counts;

  RETURN QUERY
  SELECT 
    p.id as user_id,
    COALESCE(p.full_name, p.email, 'Unknown')::TEXT as user_name,
    UPPER(SUBSTRING(COALESCE(p.full_name, p.email, 'U') FROM 1 FOR 1) || 
          COALESCE(SUBSTRING(COALESCE(p.full_name, '') FROM POSITION(' ' IN COALESCE(p.full_name, '') || ' ') + 1 FOR 1), ''))::TEXT as user_initials,
    p.avatar_url::TEXT,
    COUNT(cs.id)::BIGINT as total_tests,
    COUNT(*) FILTER (WHERE cs.status = 'passed')::BIGINT as passed,
    COUNT(*) FILTER (WHERE cs.status = 'failed')::BIGINT as failed,
    COUNT(*) FILTER (WHERE cs.status = 'blocked')::BIGINT as blocked,
    COUNT(*) FILTER (WHERE cs.status = 'in_progress')::BIGINT as in_progress,
    COUNT(*) FILTER (WHERE cs.status IN ('not_run', 'pending'))::BIGINT as not_started,
    CASE 
      WHEN v_avg_tests_per_user IS NULL OR v_avg_tests_per_user = 0 THEN 'normal'
      WHEN COUNT(cs.id) > v_avg_tests_per_user * 1.5 THEN 'overloaded'
      WHEN COUNT(cs.id) > v_avg_tests_per_user * 1.2 THEN 'high'
      ELSE 'normal'
    END::TEXT as workload_status,
    CASE 
      WHEN COUNT(cs.id) = 0 THEN 0
      ELSE ROUND((COUNT(*) FILTER (WHERE cs.status IN ('passed', 'failed', 'blocked', 'skipped'))::NUMERIC / COUNT(cs.id)) * 100, 1)
    END as avg_completion_rate
  FROM tm_cycle_scope cs
  JOIN profiles p ON cs.assigned_to = p.id
  WHERE cs.cycle_id = p_cycle_id AND cs.assigned_to IS NOT NULL
  GROUP BY p.id, p.full_name, p.email, p.avatar_url
  ORDER BY total_tests DESC;
END;
$$;


--
-- Name: tm_get_defect_trend(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_defect_trend(p_project_id uuid, p_days integer DEFAULT 30) RETURNS TABLE(date date, opened integer, closed integer, cumulative_open integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  WITH dates AS (
    SELECT generate_series(
      CURRENT_DATE - (p_days - 1),
      CURRENT_DATE,
      '1 day'::INTERVAL
    )::DATE AS date
  ),
  daily_stats AS (
    SELECT
      d.date,
      COALESCE(COUNT(*) FILTER (WHERE def.created_at::DATE = d.date), 0)::INTEGER AS opened,
      COALESCE(COUNT(*) FILTER (WHERE def.resolved_at::DATE = d.date), 0)::INTEGER AS closed
    FROM dates d
    LEFT JOIN tm_defects def ON def.project_id = p_project_id
      AND (def.created_at::DATE = d.date OR def.resolved_at::DATE = d.date)
    GROUP BY d.date
  )
  SELECT
    ds.date,
    ds.opened,
    ds.closed,
    SUM(ds.opened - ds.closed) OVER (ORDER BY ds.date)::INTEGER AS cumulative_open
  FROM daily_stats ds
  ORDER BY ds.date;
END;
$$;


--
-- Name: tm_get_gate_history(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_gate_history(p_gate_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN (
    SELECT json_agg(row_to_json(h))
    FROM (
      SELECT 
        h.id,
        h.previous_status,
        h.new_status,
        h.metric_value,
        h.threshold_value,
        h.evaluation_type,
        h.notes,
        h.created_at,
        p.full_name as evaluated_by_name
      FROM tm_gate_evaluation_history h
      LEFT JOIN profiles p ON p.id = h.evaluated_by
      WHERE h.gate_id = p_gate_id
      ORDER BY h.created_at DESC
      LIMIT 50
    ) h
  );
END;
$$;


--
-- Name: tm_get_gherkin_scenario(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_gherkin_scenario(p_case_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_case RECORD;
  v_steps JSONB;
BEGIN
  SELECT gherkin_feature, gherkin_scenario, test_format
  INTO v_case
  FROM tm_test_cases
  WHERE id = p_case_id;

  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'id', gs.id,
      'step_number', gs.step_number,
      'keyword', gs.keyword,
      'step_text', gs.step_text,
      'data_table', gs.data_table,
      'doc_string', gs.doc_string,
      'definition_id', gs.step_definition_id
    ) ORDER BY gs.step_number
  ), '[]'::jsonb)
  INTO v_steps
  FROM tm_gherkin_steps gs
  WHERE gs.test_case_id = p_case_id;

  RETURN jsonb_build_object(
    'feature', v_case.gherkin_feature,
    'scenario', v_case.gherkin_scenario,
    'format', v_case.test_format,
    'steps', v_steps
  );
END;
$$;


--
-- Name: tm_get_plan_analytics(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_plan_analytics(p_plan_id uuid) RETURNS TABLE(plan_id uuid, plan_name text, total_cycles bigint, active_cycles bigint, completed_cycles bigint, total_test_cases bigint, total_passed bigint, total_failed bigint, total_blocked bigint, overall_pass_rate numeric, overall_execution_rate numeric, avg_cycle_duration_days numeric, total_defects_found bigint, plan_health_score numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    tp.id as plan_id,
    tp.name::TEXT as plan_name,
    COUNT(DISTINCT c.id)::BIGINT as total_cycles,
    COUNT(DISTINCT c.id) FILTER (WHERE c.status = 'in_progress')::BIGINT as active_cycles,
    COUNT(DISTINCT c.id) FILTER (WHERE c.status = 'completed')::BIGINT as completed_cycles,
    COALESCE(SUM(c.total_cases), 0)::BIGINT as total_test_cases,
    COALESCE(SUM(c.passed_count), 0)::BIGINT as total_passed,
    COALESCE(SUM(c.failed_count), 0)::BIGINT as total_failed,
    COALESCE(SUM(c.blocked_count), 0)::BIGINT as total_blocked,
    CASE 
      WHEN COALESCE(SUM(c.passed_count), 0) + COALESCE(SUM(c.failed_count), 0) + COALESCE(SUM(c.blocked_count), 0) = 0 THEN 0
      ELSE ROUND(SUM(c.passed_count)::NUMERIC / (SUM(c.passed_count) + SUM(c.failed_count) + SUM(c.blocked_count)) * 100, 1)
    END as overall_pass_rate,
    CASE 
      WHEN COALESCE(SUM(c.total_cases), 0) = 0 THEN 0
      ELSE ROUND((SUM(c.passed_count) + SUM(c.failed_count) + SUM(c.blocked_count))::NUMERIC / SUM(c.total_cases) * 100, 1)
    END as overall_execution_rate,
    COALESCE(AVG(
      CASE WHEN c.planned_start IS NOT NULL AND c.planned_end IS NOT NULL 
           THEN (c.planned_end - c.planned_start)::NUMERIC 
           ELSE NULL END
    ), 0) as avg_cycle_duration_days,
    COALESCE((
      SELECT SUM(tr.defects_found)::BIGINT
      FROM tm_test_runs tr
      JOIN tm_cycle_scope cs ON tr.cycle_scope_id = cs.id
      JOIN tm_test_cycles cyc ON cs.cycle_id = cyc.id
      WHERE cyc.plan_id = tp.id
    ), 0) as total_defects_found,
    -- Plan health score
    CASE 
      WHEN COALESCE(SUM(c.total_cases), 0) = 0 THEN 0
      ELSE ROUND(
        (SUM(c.passed_count)::NUMERIC / NULLIF(SUM(c.passed_count) + SUM(c.failed_count) + SUM(c.blocked_count), 0) * 60) + -- Pass rate weight
        (COUNT(DISTINCT c.id) FILTER (WHERE c.status = 'completed')::NUMERIC / NULLIF(COUNT(DISTINCT c.id), 0) * 40) -- Completion weight
      , 1)
    END as plan_health_score
  FROM tm_test_plans tp
  LEFT JOIN tm_test_cycles c ON c.plan_id = tp.id
  WHERE tp.id = p_plan_id
  GROUP BY tp.id, tp.name;
END;
$$;


--
-- Name: tm_get_plan_burndown(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_plan_burndown(p_test_plan_id uuid, p_days integer DEFAULT 7) RETURNS TABLE(date date, passed integer, failed integer, blocked integer, remaining integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  WITH dates AS (
    SELECT generate_series(
      CURRENT_DATE - (p_days - 1),
      CURRENT_DATE,
      '1 day'::INTERVAL
    )::DATE AS date
  ),
  daily_counts AS (
    SELECT
      d.date,
      COUNT(*) FILTER (WHERE tr.status = 'passed' AND tr.completed_at::DATE <= d.date) AS passed,
      COUNT(*) FILTER (WHERE tr.status = 'failed' AND tr.completed_at::DATE <= d.date) AS failed,
      COUNT(*) FILTER (WHERE tr.status = 'blocked' AND tr.completed_at::DATE <= d.date) AS blocked
    FROM dates d
    CROSS JOIN tm_test_plan_cases tpc
    LEFT JOIN tm_test_cycles c ON c.test_plan_id = tpc.test_plan_id
    LEFT JOIN tm_cycle_scope cs ON cs.cycle_id = c.id AND cs.test_case_id = tpc.test_case_id
    LEFT JOIN tm_test_runs tr ON tr.cycle_scope_id = cs.id
    WHERE tpc.test_plan_id = p_test_plan_id
    GROUP BY d.date
  ),
  total_tests AS (
    SELECT COUNT(*) AS total FROM tm_test_plan_cases WHERE test_plan_id = p_test_plan_id
  )
  SELECT
    dc.date,
    dc.passed::INTEGER,
    dc.failed::INTEGER,
    dc.blocked::INTEGER,
    (tt.total - dc.passed - dc.failed - dc.blocked)::INTEGER AS remaining
  FROM daily_counts dc
  CROSS JOIN total_tests tt
  ORDER BY dc.date;
END;
$$;


--
-- Name: tm_get_plan_stats(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_plan_stats(p_test_plan_id uuid) RETURNS TABLE(total_tests bigint, passed bigint, failed bigint, blocked bigint, skipped bigint, not_run bigint, pass_rate numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  WITH cycle_runs AS (
    SELECT DISTINCT ON (cs.test_case_id) 
      tr.status
    FROM tm_test_cycles c
    JOIN tm_cycle_scope cs ON cs.cycle_id = c.id
    LEFT JOIN tm_test_runs tr ON tr.cycle_scope_id = cs.id
    WHERE c.test_plan_id = p_test_plan_id
    ORDER BY cs.test_case_id, tr.created_at DESC
  )
  SELECT
    (SELECT COUNT(*) FROM tm_test_plan_cases WHERE test_plan_id = p_test_plan_id)::BIGINT AS total_tests,
    COALESCE(COUNT(*) FILTER (WHERE status = 'passed'), 0)::BIGINT AS passed,
    COALESCE(COUNT(*) FILTER (WHERE status = 'failed'), 0)::BIGINT AS failed,
    COALESCE(COUNT(*) FILTER (WHERE status = 'blocked'), 0)::BIGINT AS blocked,
    COALESCE(COUNT(*) FILTER (WHERE status = 'skipped'), 0)::BIGINT AS skipped,
    COALESCE(COUNT(*) FILTER (WHERE status IS NULL OR status = 'not_run'), 0)::BIGINT AS not_run,
    CASE 
      WHEN COUNT(*) > 0 THEN ROUND((COUNT(*) FILTER (WHERE status = 'passed')::NUMERIC / COUNT(*)) * 100, 2)
      ELSE 0
    END AS pass_rate
  FROM cycle_runs;
END;
$$;


--
-- Name: tm_get_release_readiness_history(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_release_readiness_history(p_release_id uuid) RETURNS TABLE(id uuid, snapshot_at timestamp with time zone, overall_status text, gates_passed integer, gates_total integer, blocking_gates_passed integer, blocking_gates_total integer, test_execution_pct numeric, test_pass_pct numeric, open_blockers integer, open_criticals integer, recommendation text, created_by_name text, approved_by_name text, approved_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    r.id,
    r.snapshot_at,
    r.overall_status,
    r.gates_passed,
    r.gates_total,
    r.blocking_gates_passed,
    r.blocking_gates_total,
    r.test_execution_pct,
    r.test_pass_pct,
    r.open_blockers,
    r.open_criticals,
    r.recommendation,
    pc.full_name as created_by_name,
    pa.full_name as approved_by_name,
    r.approved_at
  FROM tm_release_readiness r
  LEFT JOIN profiles pc ON pc.id = r.created_by
  LEFT JOIN profiles pa ON pa.id = r.approved_by
  WHERE r.release_id = p_release_id
  ORDER BY r.snapshot_at DESC;
END;
$$;


--
-- Name: tm_get_release_signoff_status(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_release_signoff_status(p_release_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_result JSONB;
  v_signoffs JSONB;
  v_summary JSONB;
BEGIN
  -- Get all signoffs with stakeholder info
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'id', s.id,
      'stakeholder_id', s.stakeholder_id,
      'stakeholder_name', COALESCE(p.display_name, p.email, 'Unknown'),
      'stakeholder_email', p.email,
      'stakeholder_role', s.stakeholder_role,
      'decision', s.decision,
      'comments', s.comments,
      'requested_at', s.requested_at,
      'decided_at', s.decided_at,
      'is_required', s.is_required
    ) ORDER BY s.sort_order, s.requested_at
  ), '[]'::jsonb)
  INTO v_signoffs
  FROM tm_release_signoffs s
  LEFT JOIN profiles p ON p.id = s.stakeholder_id
  WHERE s.release_id = p_release_id;
  
  -- Calculate summary
  SELECT jsonb_build_object(
    'total', COUNT(*),
    'pending', COUNT(*) FILTER (WHERE decision = 'pending'),
    'approved', COUNT(*) FILTER (WHERE decision = 'approve'),
    'rejected', COUNT(*) FILTER (WHERE decision = 'reject'),
    'abstained', COUNT(*) FILTER (WHERE decision = 'abstain'),
    'required_total', COUNT(*) FILTER (WHERE is_required = true),
    'required_approved', COUNT(*) FILTER (WHERE is_required = true AND decision = 'approve'),
    'all_required_approved', 
      COUNT(*) FILTER (WHERE is_required = true) = COUNT(*) FILTER (WHERE is_required = true AND decision = 'approve'),
    'has_rejections', COUNT(*) FILTER (WHERE decision = 'reject') > 0
  )
  INTO v_summary
  FROM tm_release_signoffs
  WHERE release_id = p_release_id;
  
  RETURN jsonb_build_object(
    'release_id', p_release_id,
    'signoffs', v_signoffs,
    'summary', v_summary
  );
END;
$$;


--
-- Name: tm_get_release_test_summary(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_release_test_summary(p_release_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_result JSONB;
BEGIN
  SELECT jsonb_build_object(
    'release_id', p_release_id,
    'cycles', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'cycle_id', c.id,
        'cycle_name', c.name,
        'status', c.status,
        'total_cases', COALESCE(stats.total, 0),
        'passed', COALESCE(stats.passed, 0),
        'failed', COALESCE(stats.failed, 0),
        'blocked', COALESCE(stats.blocked, 0),
        'not_run', COALESCE(stats.not_run, 0),
        'execution_pct', CASE WHEN COALESCE(stats.total, 0) > 0 
          THEN ROUND(((COALESCE(stats.total, 0) - COALESCE(stats.not_run, 0))::NUMERIC / stats.total) * 100, 1)
          ELSE 0 END,
        'pass_pct', CASE WHEN COALESCE(stats.total, 0) - COALESCE(stats.not_run, 0) > 0
          THEN ROUND((COALESCE(stats.passed, 0)::NUMERIC / (stats.total - stats.not_run)) * 100, 1)
          ELSE 0 END
      ) ORDER BY c.start_date)
      FROM tm_test_cycles c
      LEFT JOIN LATERAL (
        SELECT 
          COUNT(*) as total,
          COUNT(*) FILTER (WHERE status = 'passed') as passed,
          COUNT(*) FILTER (WHERE status = 'failed') as failed,
          COUNT(*) FILTER (WHERE status = 'blocked') as blocked,
          COUNT(*) FILTER (WHERE status = 'not_run') as not_run
        FROM tm_cycle_scope WHERE cycle_id = c.id
      ) stats ON true
      WHERE c.release_id = p_release_id
    ), '[]'::jsonb),
    'totals', (
      SELECT jsonb_build_object(
        'total_cases', COALESCE(SUM(total), 0),
        'passed', COALESCE(SUM(passed), 0),
        'failed', COALESCE(SUM(failed), 0),
        'blocked', COALESCE(SUM(blocked), 0),
        'not_run', COALESCE(SUM(not_run), 0),
        'execution_pct', CASE WHEN COALESCE(SUM(total), 0) > 0
          THEN ROUND(((SUM(total) - SUM(not_run))::NUMERIC / SUM(total)) * 100, 1)
          ELSE 0 END,
        'pass_pct', CASE WHEN COALESCE(SUM(total), 0) - COALESCE(SUM(not_run), 0) > 0
          THEN ROUND((SUM(passed)::NUMERIC / (SUM(total) - SUM(not_run))) * 100, 1)
          ELSE 0 END
      )
      FROM (
        SELECT 
          COUNT(*) as total,
          COUNT(*) FILTER (WHERE cs.status = 'passed') as passed,
          COUNT(*) FILTER (WHERE cs.status = 'failed') as failed,
          COUNT(*) FILTER (WHERE cs.status = 'blocked') as blocked,
          COUNT(*) FILTER (WHERE cs.status = 'not_run') as not_run
        FROM tm_test_cycles c
        JOIN tm_cycle_scope cs ON cs.cycle_id = c.id
        WHERE c.release_id = p_release_id
      ) agg
    ),
    'defects', (
      SELECT jsonb_build_object(
        'total', COUNT(*),
        'open', COUNT(*) FILTER (WHERE d.status NOT IN ('closed', 'resolved', 'verified')),
        'blockers', COUNT(*) FILTER (WHERE d.severity = 'blocker' AND d.status NOT IN ('closed', 'resolved', 'verified')),
        'criticals', COUNT(*) FILTER (WHERE d.severity = 'critical' AND d.status NOT IN ('closed', 'resolved', 'verified'))
      )
      FROM tm_test_cycles c
      JOIN tm_cycle_scope cs ON cs.cycle_id = c.id
      JOIN defects d ON d.test_case_id = cs.test_case_id
      WHERE c.release_id = p_release_id
    )
  ) INTO v_result;
  
  RETURN v_result;
END;
$$;


--
-- Name: tm_get_requirement_test_cases(text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_requirement_test_cases(p_requirement_type text, p_requirement_id uuid) RETURNS TABLE(link_id uuid, test_case_id uuid, test_case_key text, test_case_title text, test_case_status text, test_case_priority text, link_type text, coverage_status text, last_execution_status text, last_execution_date timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    rl.id as link_id,
    tc.id as test_case_id,
    tc.key as test_case_key,
    tc.title as test_case_title,
    tc.status as test_case_status,
    tc.priority as test_case_priority,
    rl.link_type,
    rl.coverage_status,
    (
      SELECT te.status 
      FROM tm_test_executions te 
      WHERE te.test_case_id = tc.id 
      ORDER BY te.executed_at DESC NULLS LAST, te.created_at DESC 
      LIMIT 1
    ) as last_execution_status,
    (
      SELECT te.executed_at 
      FROM tm_test_executions te 
      WHERE te.test_case_id = tc.id 
      ORDER BY te.executed_at DESC NULLS LAST, te.created_at DESC 
      LIMIT 1
    ) as last_execution_date
  FROM tm_requirement_links rl
  JOIN tm_test_cases tc ON tc.id = rl.test_case_id
  WHERE rl.requirement_type = p_requirement_type
    AND rl.requirement_id = p_requirement_id
  ORDER BY tc.key;
END;
$$;


--
-- Name: tm_get_run_assignments(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_run_assignments(p_run_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_assignments JSONB;
  v_summary JSONB;
BEGIN
  -- Get assignments with case details
  SELECT jsonb_agg(
    jsonb_build_object(
      'id', a.id,
      'test_case_id', a.test_case_id,
      'case_key', tc.case_key,
      'case_title', tc.title,
      'case_priority', tc.priority,
      'assigned_tester_id', a.assigned_tester_id,
      'assigned_tester_name', p.full_name,
      'priority', a.priority,
      'status', a.status,
      'started_at', a.started_at,
      'completed_at', a.completed_at,
      'duration_seconds', a.duration_seconds,
      'notes', a.notes
    ) ORDER BY a.priority
  )
  INTO v_assignments
  FROM tm_run_case_assignments a
  JOIN tm_test_cases tc ON tc.id = a.test_case_id
  LEFT JOIN profiles p ON p.id = a.assigned_tester_id
  WHERE a.run_id = p_run_id;
  
  -- Get summary
  SELECT jsonb_build_object(
    'total', COUNT(*),
    'pending', COUNT(*) FILTER (WHERE status = 'pending'),
    'in_progress', COUNT(*) FILTER (WHERE status = 'in_progress'),
    'passed', COUNT(*) FILTER (WHERE status = 'passed'),
    'failed', COUNT(*) FILTER (WHERE status = 'failed'),
    'blocked', COUNT(*) FILTER (WHERE status = 'blocked'),
    'skipped', COUNT(*) FILTER (WHERE status = 'skipped')
  )
  INTO v_summary
  FROM tm_run_case_assignments
  WHERE run_id = p_run_id;
  
  RETURN jsonb_build_object(
    'assignments', COALESCE(v_assignments, '[]'::jsonb),
    'summary', v_summary
  );
END;
$$;


--
-- Name: tm_get_step_suggestions(uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_step_suggestions(p_project_id uuid, p_keyword text, p_partial_text text DEFAULT ''::text) RETURNS TABLE(id uuid, keyword text, pattern text, description text, usage_count integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    sd.id,
    sd.keyword,
    sd.pattern,
    sd.description,
    sd.usage_count
  FROM tm_step_definitions sd
  WHERE sd.project_id = p_project_id
    AND (p_keyword IS NULL OR sd.keyword = p_keyword)
    AND (p_partial_text = '' OR sd.pattern ILIKE '%' || p_partial_text || '%')
  ORDER BY sd.usage_count DESC, sd.pattern
  LIMIT 20;
END;
$$;


--
-- Name: tm_get_tester_performance(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_tester_performance(p_cycle_id uuid) RETURNS TABLE(user_id uuid, user_name text, user_initials text, tests_assigned bigint, tests_completed bigint, tests_passed bigint, tests_failed bigint, completion_rate numeric, pass_rate numeric, avg_execution_time numeric, defects_found bigint, productivity_score numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    p.id as user_id,
    COALESCE(p.full_name, p.email, 'Unknown')::TEXT as user_name,
    UPPER(SUBSTRING(COALESCE(p.full_name, 'U') FROM 1 FOR 1) || 
          COALESCE(SUBSTRING(COALESCE(p.full_name, '') FROM POSITION(' ' IN COALESCE(p.full_name, '') || ' ') + 1 FOR 1), ''))::TEXT as user_initials,
    COUNT(cs.id)::BIGINT as tests_assigned,
    COUNT(*) FILTER (WHERE cs.status IN ('passed', 'failed', 'blocked', 'skipped'))::BIGINT as tests_completed,
    COUNT(*) FILTER (WHERE cs.status = 'passed')::BIGINT as tests_passed,
    COUNT(*) FILTER (WHERE cs.status = 'failed')::BIGINT as tests_failed,
    CASE 
      WHEN COUNT(cs.id) = 0 THEN 0
      ELSE ROUND(COUNT(*) FILTER (WHERE cs.status IN ('passed', 'failed', 'blocked', 'skipped'))::NUMERIC / COUNT(cs.id) * 100, 1)
    END as completion_rate,
    CASE 
      WHEN COUNT(*) FILTER (WHERE cs.status IN ('passed', 'failed', 'blocked')) = 0 THEN 0
      ELSE ROUND(COUNT(*) FILTER (WHERE cs.status = 'passed')::NUMERIC / COUNT(*) FILTER (WHERE cs.status IN ('passed', 'failed', 'blocked')) * 100, 1)
    END as pass_rate,
    COALESCE((
      SELECT AVG(tr.duration_seconds)::NUMERIC
      FROM tm_test_runs tr
      WHERE tr.cycle_scope_id = ANY(ARRAY_AGG(cs.id)) AND tr.duration_seconds IS NOT NULL
    ), 0) as avg_execution_time,
    COALESCE((
      SELECT SUM(tr.defects_found)::BIGINT
      FROM tm_test_runs tr
      WHERE tr.cycle_scope_id = ANY(ARRAY_AGG(cs.id))
    ), 0) as defects_found,
    -- Productivity score: weighted combination of completion rate, pass rate, and defect finding
    CASE 
      WHEN COUNT(cs.id) = 0 THEN 0
      ELSE ROUND(
        (COUNT(*) FILTER (WHERE cs.status IN ('passed', 'failed', 'blocked', 'skipped'))::NUMERIC / COUNT(cs.id) * 40) + -- Completion (40%)
        (COUNT(*) FILTER (WHERE cs.status = 'passed')::NUMERIC / NULLIF(COUNT(*) FILTER (WHERE cs.status IN ('passed', 'failed', 'blocked')), 0) * 40) + -- Pass rate (40%)
        LEAST(COUNT(*) FILTER (WHERE cs.status = 'failed')::NUMERIC * 2, 20) -- Defect finding bonus (up to 20%)
      , 1)
    END as productivity_score
  FROM tm_cycle_scope cs
  JOIN profiles p ON cs.assigned_to = p.id
  WHERE cs.cycle_id = p_cycle_id AND cs.assigned_to IS NOT NULL
  GROUP BY p.id, p.full_name, p.email
  ORDER BY productivity_score DESC NULLS LAST;
END;
$$;


--
-- Name: tm_get_traceability_matrix(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_traceability_matrix(p_project_id uuid) RETURNS TABLE(requirement_type text, requirement_id uuid, requirement_title text, requirement_status text, total_test_cases bigint, passed_count bigint, failed_count bigint, blocked_count bigint, not_run_count bigint, coverage_pct numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  WITH linked_cases AS (
    SELECT 
      rl.requirement_type,
      rl.requirement_id,
      rl.test_case_id,
      (
        SELECT cs.current_status 
        FROM tm_cycle_scope cs
        WHERE cs.test_case_id = rl.test_case_id 
        ORDER BY cs.updated_at DESC NULLS LAST 
        LIMIT 1
      ) as last_status
    FROM tm_requirement_links rl
    JOIN tm_test_cases tc ON tc.id = rl.test_case_id
    WHERE tc.project_id = p_project_id
      AND rl.requirement_id IS NOT NULL
  ),
  req_stats AS (
    SELECT 
      lc.requirement_type,
      lc.requirement_id,
      COUNT(DISTINCT lc.test_case_id) as total_cases,
      COUNT(DISTINCT lc.test_case_id) FILTER (WHERE lc.last_status = 'passed') as passed,
      COUNT(DISTINCT lc.test_case_id) FILTER (WHERE lc.last_status = 'failed') as failed,
      COUNT(DISTINCT lc.test_case_id) FILTER (WHERE lc.last_status = 'blocked') as blocked,
      COUNT(DISTINCT lc.test_case_id) FILTER (WHERE lc.last_status IS NULL OR lc.last_status = 'not_run') as not_run
    FROM linked_cases lc
    GROUP BY lc.requirement_type, lc.requirement_id
  )
  SELECT 
    rs.requirement_type,
    rs.requirement_id,
    CASE 
      WHEN rs.requirement_type = 'story' THEN s.title
      WHEN rs.requirement_type = 'epic' THEN e.name
      WHEN rs.requirement_type = 'feature' THEN f.name
      WHEN rs.requirement_type = 'business_request' THEN br.title
    END as requirement_title,
    CASE 
      WHEN rs.requirement_type = 'story' THEN s.status::TEXT
      WHEN rs.requirement_type = 'epic' THEN e.status::TEXT
      WHEN rs.requirement_type = 'feature' THEN f.status::TEXT
      WHEN rs.requirement_type = 'business_request' THEN br.process_step::TEXT
    END as requirement_status,
    rs.total_cases as total_test_cases,
    rs.passed as passed_count,
    rs.failed as failed_count,
    rs.blocked as blocked_count,
    rs.not_run as not_run_count,
    CASE WHEN rs.total_cases > 0 
      THEN ROUND((rs.passed::numeric / rs.total_cases) * 100, 1)
      ELSE 0 
    END as coverage_pct
  FROM req_stats rs
  LEFT JOIN stories s ON rs.requirement_type = 'story' AND rs.requirement_id = s.id
  LEFT JOIN epics e ON rs.requirement_type = 'epic' AND rs.requirement_id = e.id
  LEFT JOIN features f ON rs.requirement_type = 'feature' AND rs.requirement_id = f.id
  LEFT JOIN business_requests br ON rs.requirement_type = 'business_request' AND rs.requirement_id = br.id
  ORDER BY rs.requirement_type, requirement_title;
END;
$$;


--
-- Name: tm_get_version_history(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_get_version_history(p_case_id uuid) RETURNS TABLE(id uuid, version_number integer, change_summary text, changed_by uuid, changed_by_name text, created_at timestamp with time zone, snapshot jsonb)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    v.id,
    v.version_number,
    v.change_summary,
    v.changed_by,
    COALESCE(p.full_name, p.email, 'Unknown') as changed_by_name,
    v.created_at,
    v.snapshot
  FROM tm_test_case_versions v
  LEFT JOIN profiles p ON p.id = v.changed_by
  WHERE v.test_case_id = p_case_id
  ORDER BY v.version_number DESC;
END;
$$;


--
-- Name: tm_insert_step_at(uuid, integer, text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_insert_step_at(p_case_id uuid, p_position integer, p_step_type text DEFAULT 'action'::text, p_action text DEFAULT ''::text, p_expected_result text DEFAULT ''::text, p_test_data text DEFAULT NULL::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_new_step_id UUID;
BEGIN
  -- Shift subsequent steps
  UPDATE tm_test_steps 
  SET step_number = step_number + 1 
  WHERE case_id = p_case_id AND step_number >= p_position;
  
  -- Insert new step
  INSERT INTO tm_test_steps (
    case_id, step_number, step_type, action, expected_result, test_data
  ) VALUES (
    p_case_id, p_position, p_step_type, p_action, p_expected_result, p_test_data
  )
  RETURNING id INTO v_new_step_id;
  
  RETURN v_new_step_id;
END;
$$;


--
-- Name: tm_is_defect_open(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_is_defect_open(p_status text) RETURNS boolean
    LANGUAGE sql IMMUTABLE
    AS $$
  SELECT p_status IS NULL OR p_status NOT IN ('closed', 'resolved', 'rejected', 'duplicate', 'wont_fix');
$$;


--
-- Name: tm_link_requirement(uuid, text, uuid, text, text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_link_requirement(p_case_id uuid, p_requirement_type text, p_requirement_id uuid DEFAULT NULL::uuid, p_external_key text DEFAULT NULL::text, p_external_url text DEFAULT NULL::text, p_external_title text DEFAULT NULL::text, p_link_type text DEFAULT 'verifies'::text, p_notes text DEFAULT NULL::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_id UUID;
BEGIN
  INSERT INTO tm_requirement_links (
    test_case_id,
    requirement_type,
    requirement_id,
    external_key,
    external_url,
    external_title,
    link_type,
    notes,
    created_by
  ) VALUES (
    p_case_id,
    p_requirement_type,
    p_requirement_id,
    p_external_key,
    p_external_url,
    p_external_title,
    p_link_type,
    p_notes,
    auth.uid()
  )
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


--
-- Name: tm_log_cycle_assignment_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_log_cycle_assignment_change() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_tc_key   TEXT;
  v_tc_title TEXT;
BEGIN
  SELECT case_key, title
    INTO v_tc_key, v_tc_title
    FROM tm_test_cases
   WHERE id = NEW.test_case_id;

  INSERT INTO tm_cycle_execution_audit (
    cycle_id, test_case_id, action,
    assigned_to, performed_by, performed_at, notes
  ) VALUES (
    NEW.cycle_id, NEW.test_case_id, 'assigned',
    NEW.assigned_to, auth.uid(), NOW(),
    'Assigned — ' || COALESCE(v_tc_key, 'unknown')
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'assignment audit failed: %', SQLERRM;
  RETURN NEW;
END;
$$;


--
-- Name: tm_log_cycle_scope_status_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_log_cycle_scope_status_change() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_tc_key TEXT;
BEGIN
  IF OLD.current_status IS DISTINCT FROM NEW.current_status THEN
    SELECT case_key INTO v_tc_key
      FROM tm_test_cases WHERE id = NEW.test_case_id;

    INSERT INTO tm_cycle_execution_audit (
      cycle_id, test_case_id, action,
      performed_by, performed_at, notes
    ) VALUES (
      NEW.cycle_id, NEW.test_case_id, 'status_changed',
      auth.uid(), NOW(),
      COALESCE(v_tc_key,'unknown') || ': ' ||
      COALESCE(OLD.current_status,'none') || ' → ' || NEW.current_status
    );
  END IF;

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'status audit failed: %', SQLERRM;
  RETURN NEW;
END;
$$;


--
-- Name: tm_next_entity_key(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_next_entity_key(p_project_id uuid, p_prefix character varying) RETURNS character varying
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_next INTEGER;
BEGIN
  INSERT INTO tm_key_sequences (project_id, prefix, current_value)
  VALUES (p_project_id, p_prefix, 1)
  ON CONFLICT (project_id, prefix) 
  DO UPDATE SET current_value = tm_key_sequences.current_value + 1, updated_at = now()
  RETURNING current_value INTO v_next;
  
  RETURN p_prefix || '-' || LPAD(v_next::TEXT, 4, '0');
END;
$$;


--
-- Name: tm_recalculate_cycle_counters(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_recalculate_cycle_counters(p_cycle_id uuid DEFAULT NULL::uuid) RETURNS TABLE(cycle_id uuid, total_cases bigint, not_run_count bigint, in_progress_count bigint, passed_count bigint, failed_count bigint, blocked_count bigint, skipped_count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Update counters for specified cycle or all cycles
  UPDATE tm_test_cycles tc
  SET 
    total_cases = COALESCE(counts.total, 0)::integer,
    not_run_count = COALESCE(counts.not_run, 0)::integer,
    in_progress_count = COALESCE(counts.in_prog, 0)::integer,
    passed_count = COALESCE(counts.passed, 0)::integer,
    failed_count = COALESCE(counts.failed, 0)::integer,
    blocked_count = COALESCE(counts.blocked, 0)::integer,
    skipped_count = COALESCE(counts.skipped, 0)::integer,
    updated_at = now()
  FROM (
    SELECT 
      cs.cycle_id as cid,
      COUNT(*) as total,
      COUNT(*) FILTER (WHERE COALESCE(cs.current_status, 'not_run') = 'not_run') as not_run,
      COUNT(*) FILTER (WHERE cs.current_status = 'in_progress') as in_prog,
      COUNT(*) FILTER (WHERE cs.current_status = 'passed') as passed,
      COUNT(*) FILTER (WHERE cs.current_status = 'failed') as failed,
      COUNT(*) FILTER (WHERE cs.current_status = 'blocked') as blocked,
      COUNT(*) FILTER (WHERE cs.current_status = 'skipped') as skipped
    FROM tm_cycle_scope cs
    WHERE (p_cycle_id IS NULL OR cs.cycle_id = p_cycle_id)
    GROUP BY cs.cycle_id
  ) counts
  WHERE tc.id = counts.cid
    AND (p_cycle_id IS NULL OR tc.id = p_cycle_id);
  
  -- Reset counters for cycles with no scope entries
  UPDATE tm_test_cycles tc
  SET 
    total_cases = 0,
    not_run_count = 0,
    in_progress_count = 0,
    passed_count = 0,
    failed_count = 0,
    blocked_count = 0,
    skipped_count = 0,
    updated_at = now()
  WHERE (p_cycle_id IS NULL OR tc.id = p_cycle_id)
    AND NOT EXISTS (SELECT 1 FROM tm_cycle_scope cs WHERE cs.cycle_id = tc.id);
  
  -- Return updated values
  RETURN QUERY
  SELECT 
    tc.id,
    tc.total_cases::bigint,
    tc.not_run_count::bigint,
    COALESCE(tc.in_progress_count, 0)::bigint,
    tc.passed_count::bigint,
    tc.failed_count::bigint,
    tc.blocked_count::bigint,
    tc.skipped_count::bigint
  FROM tm_test_cycles tc
  WHERE (p_cycle_id IS NULL OR tc.id = p_cycle_id);
END;
$$;


--
-- Name: tm_recalculate_release_metrics(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_recalculate_release_metrics(p_release_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_test_cases_total INTEGER;
  v_test_cases_passed INTEGER;
  v_defects_open INTEGER;
  v_coverage_percent INTEGER;
  v_project_id UUID;
BEGIN
  SELECT project_id INTO v_project_id FROM releases WHERE id = p_release_id;

  SELECT COUNT(*) INTO v_test_cases_total FROM tm_test_cases WHERE release_id = p_release_id;

  SELECT COUNT(DISTINCT cs.test_case_id) INTO v_test_cases_passed
  FROM tm_test_runs tr
  JOIN tm_cycle_scope cs ON cs.id = tr.cycle_scope_id
  JOIN tm_test_cycles cyc ON cyc.id = cs.cycle_id
  WHERE cyc.release_id = p_release_id AND tr.status = 'passed';

  SELECT COUNT(*) INTO v_defects_open FROM tm_defects d
  WHERE d.project_id = v_project_id AND tm_is_defect_open(d.status::TEXT);

  v_coverage_percent := CASE WHEN v_test_cases_total > 0 
    THEN ROUND((v_test_cases_passed::NUMERIC / v_test_cases_total::NUMERIC) * 100)
    ELSE 0 END;

  UPDATE releases SET 
    test_cases_total = COALESCE(v_test_cases_total, 0),
    test_cases_passed = COALESCE(v_test_cases_passed, 0),
    defects_open = COALESCE(v_defects_open, 0),
    coverage_percent = COALESCE(v_coverage_percent, 0),
    updated_at = NOW()
  WHERE id = p_release_id;

  RETURN jsonb_build_object('release_id', p_release_id, 'test_cases_total', v_test_cases_total, 
    'test_cases_passed', v_test_cases_passed, 'defects_open', v_defects_open, 'coverage_percent', v_coverage_percent);
END;
$$;


--
-- Name: tm_remove_case_from_cycle(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_remove_case_from_cycle(p_cycle_id uuid, p_test_case_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  DELETE FROM tm_cycle_scope WHERE cycle_id = p_cycle_id AND test_case_id = p_test_case_id;
  
  -- Update cycle totals
  UPDATE tm_test_cycles 
  SET total_cases = (SELECT COUNT(*) FROM tm_cycle_scope WHERE cycle_id = p_cycle_id),
      not_run_count = (SELECT COUNT(*) FROM tm_cycle_scope WHERE cycle_id = p_cycle_id AND current_status = 'not_run'),
      passed_count = (SELECT COUNT(*) FROM tm_cycle_scope WHERE cycle_id = p_cycle_id AND current_status = 'passed'),
      failed_count = (SELECT COUNT(*) FROM tm_cycle_scope WHERE cycle_id = p_cycle_id AND current_status = 'failed'),
      blocked_count = (SELECT COUNT(*) FROM tm_cycle_scope WHERE cycle_id = p_cycle_id AND current_status = 'blocked'),
      skipped_count = (SELECT COUNT(*) FROM tm_cycle_scope WHERE cycle_id = p_cycle_id AND current_status = 'skipped'),
      updated_at = now()
  WHERE id = p_cycle_id;
  
  RETURN jsonb_build_object('success', true);
END;
$$;


--
-- Name: tm_remove_cases_from_run(uuid, uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_remove_cases_from_run(p_run_id uuid, p_case_ids uuid[]) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_removed_count INTEGER;
BEGIN
  DELETE FROM tm_run_case_assignments
  WHERE run_id = p_run_id
  AND test_case_id = ANY(p_case_ids)
  AND status = 'pending'; -- Only remove pending cases
  
  GET DIAGNOSTICS v_removed_count = ROW_COUNT;
  
  RETURN jsonb_build_object(
    'success', true,
    'removed_count', v_removed_count
  );
END;
$$;


--
-- Name: tm_remove_tester_from_cycle(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_remove_tester_from_cycle(p_cycle_id uuid, p_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  DELETE FROM tm_cycle_assignments WHERE cycle_id = p_cycle_id AND user_id = p_user_id;
  RETURN jsonb_build_object('success', true);
END;
$$;


--
-- Name: tm_reorder_steps(uuid, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_reorder_steps(p_case_id uuid, p_step_orders jsonb) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_step RECORD;
BEGIN
  FOR v_step IN SELECT * FROM jsonb_to_recordset(p_step_orders) AS x(step_id UUID, new_order INTEGER)
  LOOP
    UPDATE tm_test_steps 
    SET step_number = v_step.new_order
    WHERE id = v_step.step_id AND case_id = p_case_id;
  END LOOP;
  
  RETURN true;
END;
$$;


--
-- Name: tm_request_signoff(uuid, uuid, text, uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_request_signoff(p_release_id uuid, p_stakeholder_id uuid, p_stakeholder_role text, p_requested_by uuid DEFAULT NULL::uuid, p_is_required boolean DEFAULT true) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_signoff_id UUID;
  v_sort_order INTEGER;
BEGIN
  -- Get next sort order
  SELECT COALESCE(MAX(sort_order), 0) + 1
  INTO v_sort_order
  FROM tm_release_signoffs
  WHERE release_id = p_release_id;
  
  -- Insert or update signoff request
  INSERT INTO tm_release_signoffs (
    release_id, stakeholder_id, stakeholder_role, 
    requested_by, is_required, sort_order
  )
  VALUES (
    p_release_id, p_stakeholder_id, p_stakeholder_role,
    p_requested_by, p_is_required, v_sort_order
  )
  ON CONFLICT (release_id, stakeholder_id) DO UPDATE SET
    stakeholder_role = EXCLUDED.stakeholder_role,
    is_required = EXCLUDED.is_required,
    decision = 'pending',
    decided_at = NULL,
    comments = NULL
  RETURNING id INTO v_signoff_id;
  
  RETURN v_signoff_id;
END;
$$;


--
-- Name: tm_restore_version(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_restore_version(p_case_id uuid, p_version_number integer) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_snapshot JSONB;
  v_step JSONB;
  v_step_num INTEGER := 1;
BEGIN
  -- Get the snapshot
  SELECT snapshot INTO v_snapshot
  FROM tm_test_case_versions
  WHERE test_case_id = p_case_id AND version_number = p_version_number;

  IF v_snapshot IS NULL THEN
    RAISE EXCEPTION 'Version not found';
  END IF;

  -- Create a new version snapshot before restoring
  PERFORM tm_create_version_snapshot(p_case_id, 'Before restore to v' || p_version_number);

  -- Update test case
  UPDATE tm_test_cases SET
    title = v_snapshot->>'title',
    description = v_snapshot->>'description',
    description_html = v_snapshot->>'description_html',
    preconditions = v_snapshot->>'preconditions',
    preconditions_html = v_snapshot->>'preconditions_html',
    postconditions = v_snapshot->>'postconditions',
    postconditions_html = v_snapshot->>'postconditions_html',
    priority = v_snapshot->>'priority',
    type = v_snapshot->>'type',
    test_format = v_snapshot->>'test_format',
    gherkin_feature = v_snapshot->>'gherkin_feature',
    gherkin_scenario = v_snapshot->>'gherkin_scenario',
    updated_at = now()
  WHERE id = p_case_id;

  -- Delete existing steps
  DELETE FROM tm_test_steps WHERE test_case_id = p_case_id;

  -- Restore steps
  FOR v_step IN SELECT * FROM jsonb_array_elements(v_snapshot->'steps')
  LOOP
    INSERT INTO tm_test_steps (
      test_case_id,
      step_number,
      step_type,
      action,
      action_html,
      expected_result,
      expected_result_html,
      test_data,
      notes,
      is_optional,
      estimated_time_seconds
    ) VALUES (
      p_case_id,
      v_step_num,
      v_step->>'step_type',
      v_step->>'action',
      v_step->>'action_html',
      v_step->>'expected_result',
      v_step->>'expected_result_html',
      v_step->>'test_data',
      v_step->>'notes',
      COALESCE((v_step->>'is_optional')::boolean, false),
      (v_step->>'estimated_time_seconds')::integer
    );
    v_step_num := v_step_num + 1;
  END LOOP;

  -- Create new version for restore
  PERFORM tm_create_version_snapshot(p_case_id, 'Restored from v' || p_version_number);

  RETURN true;
END;
$$;


--
-- Name: tm_save_gherkin_scenario(uuid, text, text, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_save_gherkin_scenario(p_case_id uuid, p_feature text, p_scenario text, p_steps jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_step JSONB;
  v_step_num INTEGER := 1;
BEGIN
  -- Update test case with Gherkin content
  UPDATE tm_test_cases
  SET 
    gherkin_feature = p_feature,
    gherkin_scenario = p_scenario,
    test_format = 'bdd',
    updated_at = now()
  WHERE id = p_case_id;

  -- Delete existing gherkin steps
  DELETE FROM tm_gherkin_steps WHERE test_case_id = p_case_id;

  -- Insert new steps
  FOR v_step IN SELECT * FROM jsonb_array_elements(p_steps)
  LOOP
    INSERT INTO tm_gherkin_steps (
      test_case_id,
      step_number,
      keyword,
      step_text,
      data_table,
      doc_string
    ) VALUES (
      p_case_id,
      v_step_num,
      v_step->>'keyword',
      v_step->>'step_text',
      v_step->'data_table',
      v_step->>'doc_string'
    );
    v_step_num := v_step_num + 1;
  END LOOP;

  RETURN jsonb_build_object(
    'success', true,
    'steps_saved', v_step_num - 1
  );
END;
$$;


--
-- Name: tm_submit_signoff_decision(uuid, uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_submit_signoff_decision(p_signoff_id uuid, p_stakeholder_id uuid, p_decision text, p_comments text DEFAULT NULL::text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Verify stakeholder matches
  IF NOT EXISTS (
    SELECT 1 FROM tm_release_signoffs 
    WHERE id = p_signoff_id AND stakeholder_id = p_stakeholder_id
  ) THEN
    RAISE EXCEPTION 'Not authorized to submit this sign-off';
  END IF;
  
  -- Update decision
  UPDATE tm_release_signoffs SET
    decision = p_decision,
    comments = p_comments,
    decided_at = now()
  WHERE id = p_signoff_id;
  
  RETURN true;
END;
$$;


--
-- Name: tm_sync_release_defect_count(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_sync_release_defect_count() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_project_id UUID;
  v_was_open BOOLEAN;
  v_is_now_open BOOLEAN;
BEGIN
  v_project_id := COALESCE(NEW.project_id, OLD.project_id);
  v_was_open := CASE WHEN TG_OP != 'INSERT' THEN tm_is_defect_open(OLD.status::TEXT) ELSE FALSE END;
  v_is_now_open := CASE WHEN TG_OP != 'DELETE' THEN tm_is_defect_open(NEW.status::TEXT) ELSE FALSE END;
  
  IF v_project_id IS NOT NULL THEN
    IF v_is_now_open AND NOT v_was_open THEN
      UPDATE releases SET defects_open = defects_open + 1 WHERE project_id = v_project_id;
    ELSIF v_was_open AND NOT v_is_now_open THEN
      UPDATE releases SET defects_open = GREATEST(0, defects_open - 1) WHERE project_id = v_project_id;
    END IF;
  END IF;
  RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: tm_sync_release_test_case_count(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_sync_release_test_case_count() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'INSERT' AND NEW.release_id IS NOT NULL THEN
    UPDATE releases SET test_cases_total = test_cases_total + 1 WHERE id = NEW.release_id;
  ELSIF TG_OP = 'DELETE' AND OLD.release_id IS NOT NULL THEN
    UPDATE releases SET test_cases_total = GREATEST(0, test_cases_total - 1) WHERE id = OLD.release_id;
  ELSIF TG_OP = 'UPDATE' AND OLD.release_id IS DISTINCT FROM NEW.release_id THEN
    IF OLD.release_id IS NOT NULL THEN
      UPDATE releases SET test_cases_total = GREATEST(0, test_cases_total - 1) WHERE id = OLD.release_id;
    END IF;
    IF NEW.release_id IS NOT NULL THEN
      UPDATE releases SET test_cases_total = test_cases_total + 1 WHERE id = NEW.release_id;
    END IF;
  END IF;
  RETURN COALESCE(NEW, OLD);
END;
$$;


