--

CREATE FUNCTION public.tm_trigger_step_results_percolate() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_run_status tm_execution_status;
  v_scope_id UUID;
BEGIN
  v_run_status := tm_calculate_run_status(NEW.test_run_id);
  
  UPDATE tm_test_runs SET status = v_run_status, updated_at = now()
  WHERE id = NEW.test_run_id
  RETURNING cycle_scope_id INTO v_scope_id;
  
  UPDATE tm_cycle_scope SET current_status = v_run_status
  WHERE id = v_scope_id;
  
  RETURN NEW;
END;
$$;


--
-- Name: tm_trigger_update_folder_counts(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_trigger_update_folder_counts() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'DELETE' THEN
    PERFORM tm_update_folder_counts(OLD.folder_id);
    RETURN OLD;
  ELSIF TG_OP = 'INSERT' THEN
    PERFORM tm_update_folder_counts(NEW.folder_id);
    RETURN NEW;
  ELSE
    IF OLD.folder_id IS DISTINCT FROM NEW.folder_id THEN
      PERFORM tm_update_folder_counts(OLD.folder_id);
      PERFORM tm_update_folder_counts(NEW.folder_id);
    END IF;
    RETURN NEW;
  END IF;
END;
$$;


--
-- Name: tm_update_assignment_status(uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_update_assignment_status(p_assignment_id uuid, p_status text, p_notes text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_assignment RECORD;
BEGIN
  SELECT * INTO v_assignment
  FROM tm_run_case_assignments
  WHERE id = p_assignment_id;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Assignment not found');
  END IF;
  
  UPDATE tm_run_case_assignments
  SET 
    status = p_status,
    notes = COALESCE(p_notes, notes),
    started_at = CASE 
      WHEN p_status = 'in_progress' AND started_at IS NULL THEN now()
      ELSE started_at
    END,
    completed_at = CASE 
      WHEN p_status IN ('passed', 'failed', 'blocked', 'skipped') THEN now()
      ELSE completed_at
    END,
    duration_seconds = CASE 
      WHEN p_status IN ('passed', 'failed', 'blocked', 'skipped') AND started_at IS NOT NULL
      THEN EXTRACT(EPOCH FROM (now() - started_at))::INTEGER
      ELSE duration_seconds
    END,
    updated_at = now()
  WHERE id = p_assignment_id;
  
  RETURN jsonb_build_object(
    'success', true,
    'assignment_id', p_assignment_id,
    'new_status', p_status
  );
END;
$$;


