--
-- Name: tm_user_has_access(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_user_has_access(p_user_id uuid, p_project_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Check if user is authenticated
  IF p_user_id IS NULL THEN
    RETURN FALSE;
  END IF;
  
  -- Check tm_user_roles first
  IF EXISTS (
    SELECT 1 FROM tm_user_roles 
    WHERE user_id = p_user_id AND project_id = p_project_id
  ) THEN
    RETURN TRUE;
  END IF;
  
  -- Fallback: Allow authenticated users to access any project
  -- This is permissive for development but should be restricted in production
  IF p_project_id IS NOT NULL THEN
    RETURN TRUE;
  END IF;
  
  RETURN FALSE;
END;
$$;


--
-- Name: tm_waive_quality_gate(uuid, uuid, text, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tm_waive_quality_gate(p_gate_id uuid, p_user_id uuid, p_reason text, p_expires_at timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_gate RECORD;
BEGIN
  SELECT * INTO v_gate FROM tm_release_quality_gates WHERE id = p_gate_id;
  IF NOT FOUND THEN
    RETURN false;
  END IF;

  -- Record history
  INSERT INTO tm_gate_evaluation_history (
    gate_id, previous_status, new_status, metric_value, threshold_value, evaluation_type, evaluated_by, notes
  ) VALUES (
    p_gate_id, v_gate.status, 'waived', COALESCE(v_gate.current_value, 0), v_gate.threshold_value, 'waiver', p_user_id, p_reason
  );

  -- Update gate
  UPDATE tm_release_quality_gates SET
    status = 'waived',
    waived_at = NOW(),
    waived_by = p_user_id,
    waiver_reason = p_reason,
    waiver_expires_at = p_expires_at
  WHERE id = p_gate_id;

  RETURN true;
END;
$$;


--
-- Name: track_epic_process_step_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.track_epic_process_step_change() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF (TG_OP = 'UPDATE' AND OLD.process_step_id IS DISTINCT FROM NEW.process_step_id) THEN
    IF OLD.process_step_id IS NOT NULL THEN
      UPDATE epic_process_history
      SET exited_at = NOW()
      WHERE epic_id = NEW.id
        AND process_step_id = OLD.process_step_id
        AND exited_at IS NULL;
    END IF;
    
    IF NEW.process_step_id IS NOT NULL THEN
      INSERT INTO epic_process_history (epic_id, process_step_id, entered_at)
      VALUES (NEW.id, NEW.process_step_id, NOW());
      
      NEW.process_step_entered_at := NOW();
    END IF;
  END IF;
  
  IF (TG_OP = 'INSERT' OR (TG_OP = 'UPDATE' AND OLD.process_step_id IS NULL AND NEW.process_step_id IS NOT NULL)) THEN
    IF NEW.process_flow_entered_at IS NULL THEN
      NEW.process_flow_entered_at := NOW();
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$;


