--
-- Name: track_room_access(uuid, public.room_type, uuid, text, text, text, text, text, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.track_room_access(p_user_id uuid, p_room_type public.room_type, p_room_id uuid, p_room_name text, p_room_subtitle text, p_room_path text, p_pi_label text DEFAULT NULL::text, p_page_key text DEFAULT 'room'::text, p_timebox_type text DEFAULT NULL::text, p_timebox_id uuid DEFAULT NULL::uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_entry_count integer;
  v_oldest_id uuid;
BEGIN
  -- UPSERT at room level (one entry per room, not per page)
  INSERT INTO recent_activity (
    user_id, room_type, room_id, room_name, room_subtitle, room_path, 
    pi_label, page_key, timebox_type, timebox_id, last_accessed_at, access_count
  )
  VALUES (
    p_user_id, p_room_type, p_room_id, p_room_name, p_room_subtitle, p_room_path, 
    p_pi_label, p_page_key, p_timebox_type, p_timebox_id, NOW(), 1
  )
  ON CONFLICT (user_id, room_type, room_id)
  DO UPDATE SET
    last_accessed_at = NOW(),
    access_count = recent_activity.access_count + 1,
    room_name = EXCLUDED.room_name,
    room_subtitle = EXCLUDED.room_subtitle,  -- Update to show last visited page
    room_path = EXCLUDED.room_path,          -- Update to latest path
    page_key = EXCLUDED.page_key,            -- Update page key
    pi_label = EXCLUDED.pi_label,
    timebox_type = EXCLUDED.timebox_type,
    timebox_id = EXCLUDED.timebox_id;

  -- Prune to keep only 12 most recent entries per user
  SELECT COUNT(*) INTO v_entry_count
  FROM recent_activity
  WHERE user_id = p_user_id;

  IF v_entry_count > 12 THEN
    -- Delete oldest entries beyond 12
    DELETE FROM recent_activity
    WHERE id IN (
      SELECT id FROM recent_activity
      WHERE user_id = p_user_id
      ORDER BY last_accessed_at ASC
      LIMIT (v_entry_count - 12)
    );
  END IF;
END;
$$;


--
-- Name: track_work_item_activity(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.track_work_item_activity() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Only track if there's an authenticated user
  IF auth.uid() IS NULL THEN
    RETURN NEW;
  END IF;
  
  -- Determine activity type
  INSERT INTO work_item_activity (work_item_id, work_item_type, user_id, activity_type, metadata)
  VALUES (
    NEW.id,
    TG_ARGV[0],
    auth.uid(),
    CASE 
      WHEN TG_OP = 'INSERT' THEN 'updated'
      WHEN OLD.status IS DISTINCT FROM NEW.status THEN 'status_changed'
      ELSE 'updated'
    END,
    jsonb_build_object('operation', TG_OP)
  );
  
  RETURN NEW;
END;
$$;


--
-- Name: trg_sync_requirement_status(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_sync_requirement_status() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_req_id uuid;
  v_total int;
  v_passed int;
  v_failed_blocked int;
  v_new_req_status text;
BEGIN
  FOR v_req_id IN
    SELECT requirement_id
    FROM tm_requirement_tests
    WHERE test_case_id = NEW.test_case_id
  LOOP
    UPDATE tm_requirement_tests
    SET coverage_status = CASE NEW.result
      WHEN 'passed'  THEN 'Passed'
      WHEN 'failed'  THEN 'Failed'
      WHEN 'blocked' THEN 'Blocked'
      WHEN 'skipped' THEN 'Skipped'
      ELSE 'Not Run'
    END
    WHERE requirement_id = v_req_id
      AND test_case_id = NEW.test_case_id;

    SELECT
      COUNT(*),
      COUNT(*) FILTER (WHERE latest_result = 'passed'),
      COUNT(*) FILTER (WHERE latest_result IN ('failed','blocked'))
    INTO v_total, v_passed, v_failed_blocked
    FROM (
      SELECT DISTINCT ON (rt.test_case_id)
        rt.test_case_id,
        e.result AS latest_result
      FROM tm_requirement_tests rt
      LEFT JOIN th_test_executions e
        ON e.test_case_id = rt.test_case_id
      WHERE rt.requirement_id = v_req_id
      ORDER BY rt.test_case_id, e.executed_at DESC NULLS LAST
    ) sub;

    IF v_total = 0 THEN
      CONTINUE;
    ELSIF v_passed = v_total THEN
      v_new_req_status := 'verified';
    ELSIF v_failed_blocked > 0 THEN
      v_new_req_status := 'in_progress';
    ELSE
      v_new_req_status := 'in_progress';
    END IF;

    UPDATE tm_requirements
    SET status = v_new_req_status
    WHERE id = v_req_id
      AND status NOT IN ('deprecated', 'approved');
  END LOOP;

  RETURN NEW;
END;
$$;


