-- Name: unlink_defect_from_step_v2(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.unlink_defect_from_step_v2(p_defect_id uuid, p_step_result_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_link_id UUID;
BEGIN
  -- Find and delete link
  DELETE FROM tm_defect_links
  WHERE defect_id = p_defect_id AND step_result_id = p_step_result_id
  RETURNING id INTO v_link_id;

