  SET vote_count = (SELECT COUNT(*) FROM ph_idea_votes WHERE idea_id = target_idea_id),
      vote_score = (SELECT COALESCE(SUM(vote_value * weight), 0) FROM ph_idea_votes WHERE idea_id = target_idea_id)
