--
-- Name: update_recent_project(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_recent_project(p_project_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_recent UUID[];
BEGIN
  -- Get current recent projects
  SELECT recent_projects INTO v_recent
  FROM public.jira_user_preferences
  WHERE user_id = v_user_id;
  
  -- If no preferences exist, create them
  IF v_recent IS NULL THEN
    INSERT INTO public.jira_user_preferences (user_id, recent_projects)
    VALUES (v_user_id, ARRAY[p_project_id]);
    RETURN;
  END IF;
  
  -- Remove project if exists, add to front, limit to 10
  v_recent := array_remove(v_recent, p_project_id);
  v_recent := p_project_id || v_recent;
  v_recent := v_recent[1:10];
  
  -- Update preferences
  UPDATE public.jira_user_preferences
  SET recent_projects = v_recent, updated_at = NOW()
  WHERE user_id = v_user_id;
END;
$$;


--
-- Name: update_requirement_coverage(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_requirement_coverage(p_requirement_id uuid) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_total INTEGER;
  v_passed INTEGER;
  v_failed INTEGER;
  v_not_run INTEGER;
  v_coverage INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_total
  FROM th_requirement_tests WHERE requirement_id = p_requirement_id;

  SELECT 
    COUNT(*) FILTER (WHERE latest_status = 'passed'),
    COUNT(*) FILTER (WHERE latest_status = 'failed'),
    COUNT(*) FILTER (WHERE latest_status IS NULL OR latest_status = 'not_run')
  INTO v_passed, v_failed, v_not_run
  FROM (
    SELECT DISTINCT ON (rt.test_case_id) 
      rt.test_case_id,
      ctc.execution_status as latest_status
    FROM th_requirement_tests rt
    LEFT JOIN th_cycle_test_cases ctc ON ctc.test_case_id = rt.test_case_id
    WHERE rt.requirement_id = p_requirement_id
    ORDER BY rt.test_case_id, ctc.executed_at DESC NULLS LAST
  ) sub;

  IF v_total > 0 THEN
    v_coverage := ROUND(((v_passed + v_failed)::NUMERIC / v_total) * 100);
  ELSE
    v_coverage := 0;
  END IF;

  UPDATE th_requirements SET
    total_linked_tests = v_total,
    passed_tests = COALESCE(v_passed, 0),
    failed_tests = COALESCE(v_failed, 0),
    not_run_tests = COALESCE(v_not_run, 0),
    coverage_percent = v_coverage,
    updated_at = NOW()
  WHERE id = p_requirement_id;
END;
$$;


