--
-- Name: update_t10_week_counts(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_t10_week_counts() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE t10_weeks
  SET 
    total_count = (SELECT COUNT(*) FROM t10_items WHERE week_id = COALESCE(NEW.week_id, OLD.week_id) AND is_buffer = false),
    completed_count = (SELECT COUNT(*) FROM t10_items WHERE week_id = COALESCE(NEW.week_id, OLD.week_id) AND is_buffer = false AND status = 'done'),
    updated_at = now()
  WHERE id = COALESCE(NEW.week_id, OLD.week_id);
  
  RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: update_tag_usage_count(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_tag_usage_count() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_tag_id UUID;
BEGIN
  IF TG_OP = 'DELETE' THEN
    v_tag_id := OLD.tag_id;
  ELSE
    v_tag_id := NEW.tag_id;
  END IF;

  UPDATE th_tags SET usage_count = (
    SELECT COUNT(*) FROM th_test_case_tags WHERE tag_id = v_tag_id
  ) + (
    SELECT COUNT(*) FROM th_defect_tags WHERE tag_id = v_tag_id
  ) + (
    SELECT COUNT(*) FROM th_requirement_tags WHERE tag_id = v_tag_id
  )
  WHERE id = v_tag_id;

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;
  RETURN NEW;
END;
$$;


