--
-- Name: upload_evidence(uuid, text, text, text, text, integer, text, integer, integer, text, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.upload_evidence(p_step_result_id uuid, p_type text, p_filename text, p_original_filename text, p_storage_path text, p_file_size integer, p_mime_type text DEFAULT NULL::text, p_width integer DEFAULT NULL::integer, p_height integer DEFAULT NULL::integer, p_thumbnail_path text DEFAULT NULL::text, p_metadata jsonb DEFAULT '{}'::jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_evidence_id UUID;
  v_actor UUID := auth.uid();
  v_max_size INTEGER := 10485760;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM test_execution_step_results WHERE id = p_step_result_id) THEN
    RETURN jsonb_build_object('error', 'Step result not found');
  END IF;

  IF p_type NOT IN ('screenshot', 'video', 'file', 'log') THEN
    RETURN jsonb_build_object('error', 'Invalid evidence type');
  END IF;

  IF p_file_size > v_max_size THEN
    RETURN jsonb_build_object('error', 'File too large. Maximum size is 10MB');
  END IF;

  IF TRIM(COALESCE(p_filename, '')) = '' THEN
    RETURN jsonb_build_object('error', 'Filename is required');
  END IF;

  INSERT INTO test_step_evidence (
    step_result_id,
    type,
    filename,
    original_filename,
    storage_path,
    file_size,
    mime_type,
    width,
    height,
    thumbnail_path,
    metadata,
    uploaded_by
  ) VALUES (
    p_step_result_id,
    p_type,
    TRIM(p_filename),
    TRIM(p_original_filename),
    p_storage_path,
    p_file_size,
    p_mime_type,
    p_width,
    p_height,
    p_thumbnail_path,
    COALESCE(p_metadata, '{}'),
    v_actor
  )
  RETURNING id INTO v_evidence_id;

  RETURN jsonb_build_object(
    'success', true,
    'evidence_id', v_evidence_id,
    'filename', p_filename
  );
END;
$$;


--
-- Name: upsert_jira_board(text, text, text, uuid, jsonb, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.upsert_jira_board(p_jira_board_id text, p_jira_project_key text, p_name text, p_project_id uuid, p_columns jsonb, p_user_id uuid) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_board_id uuid;
BEGIN
  INSERT INTO boards (
    name, project_id, is_personal, visibility,
    jira_board_id, jira_project_key, last_jira_sync, jira_sync_enabled, created_by
  ) VALUES (
    p_name, p_project_id, false, 'project',
    p_jira_board_id, p_jira_project_key, now(), true, p_user_id
  )
  ON CONFLICT (jira_board_id) DO UPDATE SET
    name = EXCLUDED.name,
    last_jira_sync = now()
  RETURNING id INTO v_board_id;

  DELETE FROM board_columns WHERE board_id = v_board_id AND jira_mapped = true;
  INSERT INTO board_columns (board_id, name, position, jira_mapped)
  SELECT v_board_id, c->>'name', (c->>'order')::int, true
  FROM jsonb_array_elements(p_columns) c;

  RETURN v_board_id;
END;
$$;


--
-- Name: user_in_program(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.user_in_program(_user_id uuid, _program_id uuid) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT 
    has_role(_user_id, 'admin') OR
    EXISTS (
      SELECT 1 FROM public.program_members
      WHERE user_id = _user_id AND program_id = _program_id
    ) OR
    EXISTS (
      SELECT 1 FROM public.project_members pm
      JOIN public.projects p ON p.id = pm.project_id
      WHERE pm.user_id = _user_id AND p.program_id = _program_id
    ) OR
    EXISTS (
      SELECT 1 FROM public.team_members tm
      JOIN public.teams t ON t.id = tm.team_id
      JOIN public.projects p ON p.id = t.project_id
      WHERE tm.user_id = _user_id AND p.program_id = _program_id
    );
$$;


--
-- Name: user_in_project(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.user_in_project(_user_id uuid, _project_id uuid) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT 
    has_role(_user_id, 'admin') OR
    EXISTS (
      SELECT 1 FROM public.project_members
      WHERE user_id = _user_id AND project_id = _project_id
    ) OR
    EXISTS (
      SELECT 1 FROM public.team_members tm
      JOIN public.teams t ON t.id = tm.team_id
      WHERE tm.user_id = _user_id AND t.project_id = _project_id
    );
$$;


--
-- Name: user_in_team(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.user_in_team(_user_id uuid, _team_id uuid) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT 
    has_role(_user_id, 'admin') OR
    EXISTS (
      SELECT 1 FROM public.team_members
      WHERE user_id = _user_id AND team_id = _team_id
    );
$$;


--
-- Name: validate_ai_assist_document_stats(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_ai_assist_document_stats() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  -- pdf_page_count must be >= 1 if set
  IF NEW.pdf_page_count IS NOT NULL AND NEW.pdf_page_count < 1 THEN
    RAISE EXCEPTION 'pdf_page_count must be >= 1 when set, got %', NEW.pdf_page_count;
  END IF;
  
  -- ocr_images_processed must be >= 0 if set
  IF NEW.ocr_images_processed IS NOT NULL AND NEW.ocr_images_processed < 0 THEN
    RAISE EXCEPTION 'ocr_images_processed must be >= 0, got %', NEW.ocr_images_processed;
  END IF;
  
  -- sections_detected_count must be >= 0 if set
  IF NEW.sections_detected_count IS NOT NULL AND NEW.sections_detected_count < 0 THEN
    RAISE EXCEPTION 'sections_detected_count must be >= 0, got %', NEW.sections_detected_count;
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- Name: validate_batch_update(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_batch_update(p_job_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_job RECORD;
  v_tc RECORD;
  v_field TEXT;
  v_new_value TEXT;
  v_old_value TEXT;
  v_valid_count INTEGER := 0;
BEGIN
  -- Get job
  SELECT * INTO v_job
  FROM batch_update_jobs
  WHERE id = p_job_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Job not found');
  END IF;

  -- Update status
  UPDATE batch_update_jobs SET
    status = 'validating'
  WHERE id = p_job_id;

  -- Process each test case
  FOR v_tc IN 
    SELECT tc.*
    FROM test_cases tc
    WHERE tc.id IN (
      SELECT jsonb_array_elements_text(v_job.test_case_ids)::UUID
    )
    AND tc.deleted_at IS NULL
  LOOP
    -- Process each field update
    FOR v_field, v_new_value IN 
      SELECT key, value::TEXT
      FROM jsonb_each_text(v_job.field_updates)
    LOOP
      -- Get old value dynamically
      BEGIN
        EXECUTE format('SELECT (%L::jsonb->>%L)::TEXT', to_jsonb(v_tc), v_field)
        INTO v_old_value;
      EXCEPTION WHEN OTHERS THEN
        v_old_value := NULL;
      END;

      -- Create change record
      INSERT INTO batch_update_changes (
        job_id, test_case_id, field_name, old_value, new_value
      ) VALUES (
        p_job_id, v_tc.id, v_field, v_old_value, 
        CASE WHEN v_new_value = 'null' THEN NULL ELSE v_new_value END
      );
    END LOOP;

    v_valid_count := v_valid_count + 1;
  END LOOP;

  RETURN jsonb_build_object(
    'success', true,
    'valid_records', v_valid_count
  );
END;
$$;


--
-- Name: validate_committee_transition(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_committee_transition() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  member_count INTEGER;
BEGIN
  -- Only validate when status is being set to 'to_committee'
  IF NEW.status = 'to_committee' AND (OLD.status IS NULL OR OLD.status != 'to_committee') THEN
    -- Check if committee_id is set
    IF NEW.committee_id IS NULL THEN
      RAISE EXCEPTION 'Cannot move to Committee status without a committee configured';
    END IF;
    
    -- Check if committee has at least 1 approver
    SELECT COUNT(*) INTO member_count
    FROM public.committee_members
    WHERE committee_id = NEW.committee_id;
    
    IF member_count < 1 THEN
      RAISE EXCEPTION 'Add at least one approver to place in Committee';
    END IF;
    
    -- Set committee tracking fields
    NEW.committee_set_at := NOW();
    NEW.committee_set_by := auth.uid();
    NEW.requires_committee := TRUE;
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- Name: validate_cycle_status_transition(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_cycle_status_transition() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  allowed_transitions jsonb := '{
    "draft": ["active", "archived"],
    "active": ["paused", "completed", "archived"],
    "paused": ["active", "archived"],
    "completed": ["archived"]
  }'::jsonb;
  allowed_next_states jsonb;
BEGIN
  IF OLD.status = NEW.status THEN
    RETURN NEW;
  END IF;
  
  allowed_next_states := allowed_transitions->OLD.status::text;
  
  IF allowed_next_states IS NULL OR NOT (allowed_next_states ? NEW.status::text) THEN
    RAISE EXCEPTION 'Invalid status transition from % to %. Allowed transitions: %', 
      OLD.status, 
      NEW.status, 
      COALESCE(allowed_next_states::text, 'none');
  END IF;
  
  IF NEW.status = 'active' AND OLD.status IN ('draft', 'paused') AND NEW.actual_start IS NULL THEN
    NEW.actual_start := NOW();
  END IF;
  
  IF NEW.status = 'completed' AND NEW.actual_end IS NULL THEN
    NEW.actual_end := NOW();
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- Name: validate_dependency_commitment(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_dependency_commitment() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Validate committed_by_date is required when status is pending_commit or beyond
  IF NEW.status IN ('pending_commit', 'committed', 'in_progress', 'delivered', 'done') THEN
    IF NEW.committed_by_date IS NULL AND NEW.committed_by_sprint_id IS NULL THEN
      -- Allow for now but flag - can be made strict later
      NULL;
    END IF;
  END IF;

  -- If no_work_required is true, auto-set status
  IF NEW.no_work_required = TRUE THEN
    NEW.status := 'no_work_done';
  END IF;

  RETURN NEW;
END;
$$;


