--
-- Name: validate_ph_score_range(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_ph_score_range() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.strategic_alignment IS NOT NULL AND (NEW.strategic_alignment < 1.0 OR NEW.strategic_alignment > 5.0) THEN
    RAISE EXCEPTION 'strategic_alignment must be between 1.0 and 5.0';
  END IF;
  IF NEW.business_impact IS NOT NULL AND (NEW.business_impact < 1.0 OR NEW.business_impact > 5.0) THEN
    RAISE EXCEPTION 'business_impact must be between 1.0 and 5.0';
  END IF;
  IF NEW.time_urgency IS NOT NULL AND (NEW.time_urgency < 1.0 OR NEW.time_urgency > 5.0) THEN
    RAISE EXCEPTION 'time_urgency must be between 1.0 and 5.0';
  END IF;
  IF NEW.resource_feasibility IS NOT NULL AND (NEW.resource_feasibility < 1.0 OR NEW.resource_feasibility > 5.0) THEN
    RAISE EXCEPTION 'resource_feasibility must be between 1.0 and 5.0';
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: validate_ph_sdlc_issues(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_ph_sdlc_issues() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.type NOT IN ('epic','feature','story','task','bug','subtask') THEN
    RAISE EXCEPTION 'Invalid issue type: %', NEW.type;
  END IF;
  IF NEW.status NOT IN ('backlog','ready','in_dev','in_qa','in_uat','in_beta','prod_ready','production','on_hold') THEN
    RAISE EXCEPTION 'Invalid issue status: %', NEW.status;
  END IF;
  IF NEW.priority NOT IN ('urgent','high','medium','low') THEN
    RAISE EXCEPTION 'Invalid issue priority: %', NEW.priority;
  END IF;
  IF NEW.source NOT IN ('jira','catalyst') THEN
    RAISE EXCEPTION 'Invalid issue source: %', NEW.source;
  END IF;
  RETURN NEW;
END;
$$;


