-- Name: wiki_pages_fts_trigger(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.wiki_pages_fts_trigger() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  NEW.fts_vector :=
    setweight(to_tsvector('english', COALESCE(NEW.title, '')), 'A') ||
    setweight(to_tsvector('english', COALESCE(NEW.lead_content, '')), 'B') ||
    setweight(to_tsvector('english', COALESCE(NEW.tldr, '')), 'C') ||
    setweight(to_tsvector('english', COALESCE(array_to_string(NEW.tags, ' '), '')), 'C');
  RETURN NEW;
END;
$$;


--
-- Name: worker_heartbeat(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.worker_heartbeat(p_worker_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  UPDATE parallel_workers SET
    last_heartbeat = NOW()
  WHERE id = p_worker_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Worker not found');
  END IF;

  RETURN jsonb_build_object('success', true, 'heartbeat_at', NOW());
END;
$$;


