--
-- Name: committee_queue_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.committee_queue_view WITH (security_invoker='true') AS
 SELECT i.id AS incident_id,
    i.incident_key,
    i.title,
    i.severity,
    i.is_major_incident,
    ic.id AS committee_id,
    ic.status AS committee_status,
    ic.required_approvals,
    ic.due_date,
    ic.created_at AS committee_created_at,
    ( SELECT count(*) AS count
           FROM public.committee_votes cv
          WHERE ((cv.committee_id = ic.id) AND (cv.vote = 'approved'::public.vote_status))) AS approved_count,
    ( SELECT count(*) AS count
           FROM public.committee_votes cv
          WHERE ((cv.committee_id = ic.id) AND (cv.vote = ANY (ARRAY['rejected'::public.vote_status, 'vetoed'::public.vote_status])))) AS rejected_count,
    ( SELECT count(*) AS count
           FROM public.committee_members cm
          WHERE (cm.committee_id = ic.id)) AS total_members,
    (EXTRACT(epoch FROM (now() - ic.created_at)) / (3600)::numeric) AS age_hours
   FROM (public.incidents i
     JOIN public.incident_committees ic ON ((ic.id = i.committee_id)))
  WHERE ((i.deleted_at IS NULL) AND (ic.status = 'pending'::public.committee_status))
  ORDER BY i.severity, ic.created_at;


