--
-- Name: es_dashboard_execution_dials; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.es_dashboard_execution_dials WITH (security_invoker='true') AS
 SELECT ie.link_type,
    count(*) AS total_items,
    count(*) FILTER (WHERE (i.status = 'completed'::text)) AS completed_items,
    count(*) FILTER (WHERE (i.status = 'in_progress'::text)) AS in_progress_items,
    count(*) FILTER (WHERE (i.status = ANY (ARRAY['planned'::text, 'on_hold'::text]))) AS not_started_items,
    round((((count(*) FILTER (WHERE (i.status = 'completed'::text)))::numeric / (NULLIF(count(*), 0))::numeric) * (100)::numeric), 1) AS completion_pct
   FROM (public.es_initiative_epics ie
     JOIN public.es_initiatives i ON ((ie.initiative_id = i.id)))
  GROUP BY ie.link_type;


--
-- Name: es_health_scores; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.es_health_scores (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    organization_id uuid,
    composite_score numeric(5,2) NOT NULL,
    okr_velocity_score numeric(5,2) DEFAULT 0,
    execution_alignment_score numeric(5,2) DEFAULT 0,
    dependency_resolution_score numeric(5,2) DEFAULT 0,
    checkin_frequency_score numeric(5,2) DEFAULT 0,
    team_alignment_score numeric(5,2) DEFAULT 0,
    computed_at timestamp with time zone DEFAULT now() NOT NULL,
    computed_by text DEFAULT 'system'::text,
    period_start date,
    period_end date,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT es_health_scores_composite_score_check CHECK (((composite_score >= (0)::numeric) AND (composite_score <= (100)::numeric)))
);


--
-- Name: es_dashboard_health_composite; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.es_dashboard_health_composite WITH (security_invoker='true') AS
 SELECT id,
    composite_score,
    okr_velocity_score,
    execution_alignment_score,
    dependency_resolution_score,
    checkin_frequency_score,
    team_alignment_score,
    computed_at,
    period_start,
    period_end,
        CASE
            WHEN (composite_score >= (80)::numeric) THEN 'excellent'::text
            WHEN (composite_score >= (60)::numeric) THEN 'good'::text
            WHEN (composite_score >= (40)::numeric) THEN 'needs_attention'::text
            ELSE 'critical'::text
        END AS health_status,
    ( SELECT json_agg(json_build_object('id', r.id, 'title', r.title, 'description', r.description, 'priority', r.priority, 'category', r.category, 'status', r.status, 'linked_entity_type', r.linked_entity_type, 'linked_entity_id', r.linked_entity_id)) AS json_agg
           FROM public.es_ai_recommendations r
          WHERE ((r.health_score_id = hs.id) AND (r.status = 'pending'::text))) AS pending_recommendations
   FROM public.es_health_scores hs
  ORDER BY computed_at DESC
 LIMIT 1;


