    scope text DEFAULT 'team'::text,
    department_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by uuid,
    updated_by uuid,
    goal_key text,
    priority text DEFAULT 'medium'::text,
    weight numeric(5,2) DEFAULT 1.0,
    score_override numeric(3,2),
    fiscal_quarter text,
    bsc_perspective text,
    start_date date,
    sort_order integer DEFAULT 0,
    is_archived boolean DEFAULT false,
    tags text[] DEFAULT '{}'::text[],
    kr_count integer DEFAULT 0,
    check_in_count integer DEFAULT 0,
    last_check_in_at timestamp with time zone,
    ai_health_score integer,
    confidence_level numeric(3,2) DEFAULT 0.5,
    CONSTRAINT es_goals_progress_pct_check CHECK (((progress_pct >= (0)::numeric) AND (progress_pct <= (100)::numeric))),
    CONSTRAINT es_goals_quarter_check CHECK (((quarter >= 1) AND (quarter <= 4))),
    CONSTRAINT es_goals_scope_check CHECK ((scope = ANY (ARRAY['portfolio'::text, 'program'::text, 'team'::text]))),
    CONSTRAINT es_goals_status_check CHECK ((status = ANY (ARRAY['not_started'::text, 'in_progress'::text, 'draft'::text, 'active'::text, 'at_risk'::text, 'off_track'::text, 'on_track'::text, 'achieved'::text, 'completed'::text, 'cancelled'::text])))
);


