--
-- Name: es_dashboard_okr_heatmap; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.es_dashboard_okr_heatmap WITH (security_invoker='true') AS
 SELECT g.id AS goal_id,
    g.title AS goal_title,
    g.theme_id,
    t.title AS theme_title,
    t.color AS theme_color,
    kr.id AS kr_id,
    kr.title AS kr_title,
    kr.progress_pct,
    kr.status AS kr_status,
    kr.confidence_level,
    kr.due_date,
    kr.owner_id,
    g.quarter,
    g.year,
        CASE
            WHEN (kr.progress_pct >= (70)::numeric) THEN 'green'::text
            WHEN (kr.progress_pct >= (40)::numeric) THEN 'amber'::text
            ELSE 'red'::text
        END AS health_color
   FROM ((public.es_goals g
     JOIN public.es_strategic_themes t ON ((g.theme_id = t.id)))
     JOIN public.es_key_results kr ON ((kr.goal_id = g.id)))
  WHERE ((g.status <> 'cancelled'::text) AND (kr.status <> 'cancelled'::text))
  ORDER BY t.sort_order, g.title, kr.title;


--
-- Name: es_dashboard_okr_tree; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.es_dashboard_okr_tree WITH (security_invoker='true') AS
 SELECT t.id AS theme_id,
    t.title AS theme_title,
    t.color AS theme_color,
    t.sort_order,
    g.id AS goal_id,
    g.title AS goal_title,
    g.status AS goal_status,
    g.progress_pct AS goal_progress,
    g.owner_id AS goal_owner,
    kr.id AS kr_id,
    kr.title AS kr_title,
    kr.status AS kr_status,
    kr.progress_pct AS kr_progress,
    kr.confidence_level,
    kr.owner_id AS kr_owner,
    i.id AS initiative_id,
    i.title AS initiative_title,
    i.status AS initiative_status,
    i.progress_pct AS initiative_progress,
    ie.id AS link_id,
    ie.epic_id,
    ie.planner_task_id,
    ie.link_type
   FROM ((((public.es_strategic_themes t
     LEFT JOIN public.es_goals g ON (((g.theme_id = t.id) AND (g.status <> 'cancelled'::text))))
     LEFT JOIN public.es_key_results kr ON (((kr.goal_id = g.id) AND (kr.status <> 'cancelled'::text))))
     LEFT JOIN public.es_initiatives i ON (((i.key_result_id = kr.id) AND (i.status <> 'cancelled'::text))))
     LEFT JOIN public.es_initiative_epics ie ON ((ie.initiative_id = i.id)))
  WHERE (t.status = 'active'::text)
  ORDER BY t.sort_order, g.title, kr.title, i.title;


