--
-- Name: es_dashboard_pyramid_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.es_dashboard_pyramid_summary WITH (security_invoker='true') AS
 SELECT 'mission'::text AS layer,
    1 AS layer_order,
    count(*) AS item_count,
    NULL::numeric AS avg_progress
   FROM public.es_missions
  WHERE (es_missions.status = 'active'::text)
UNION ALL
 SELECT 'vision'::text AS layer,
    2 AS layer_order,
    count(*) AS item_count,
    NULL::numeric AS avg_progress
   FROM public.es_visions
  WHERE (es_visions.status = 'active'::text)
UNION ALL
 SELECT 'theme'::text AS layer,
    3 AS layer_order,
    count(*) AS item_count,
    NULL::numeric AS avg_progress
   FROM public.es_strategic_themes
  WHERE (es_strategic_themes.status = 'active'::text)
UNION ALL
 SELECT 'goal'::text AS layer,
    4 AS layer_order,
    count(*) AS item_count,
    round(avg(es_goals.progress_pct), 1) AS avg_progress
   FROM public.es_goals
  WHERE (es_goals.status <> 'cancelled'::text)
UNION ALL
 SELECT 'key_result'::text AS layer,
    5 AS layer_order,
    count(*) AS item_count,
    round(avg(es_key_results.progress_pct), 1) AS avg_progress
   FROM public.es_key_results
  WHERE (es_key_results.status <> 'cancelled'::text)
UNION ALL
 SELECT 'initiative'::text AS layer,
    6 AS layer_order,
    count(*) AS item_count,
    round(avg(es_initiatives.progress_pct), 1) AS avg_progress
   FROM public.es_initiatives
  WHERE (es_initiatives.status <> 'cancelled'::text)
UNION ALL
 SELECT 'execution_link'::text AS layer,
    7 AS layer_order,
    count(*) AS item_count,
    NULL::numeric AS avg_progress
   FROM public.es_initiative_epics
  ORDER BY 2;


