--
-- Name: es_dashboard_team_alignment; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.es_dashboard_team_alignment WITH (security_invoker='true') AS
 SELECT workstream,
    workstream_color,
    total_items,
    linked_items,
    orphaned_items,
    alignment_score,
        CASE
            WHEN (alignment_score >= (80)::numeric) THEN 'excellent'::text
            WHEN (alignment_score >= (60)::numeric) THEN 'good'::text
            WHEN (alignment_score >= (40)::numeric) THEN 'needs_attention'::text
            ELSE 'critical'::text
        END AS alignment_status,
    computed_at
   FROM public.es_team_alignment
  ORDER BY alignment_score DESC;


