--
-- Name: es_goals_tree_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.es_goals_tree_view WITH (security_invoker='true') AS
 SELECT g.id,
    g.goal_key,
    g.title,
    g.description,
    g.status,
    g.priority,
    g.progress_pct,
    g.confidence_level,
    g.weight,
    g.score_override,
    g.fiscal_quarter,
    g.bsc_perspective,
    g.start_date,
    g.target_date,
    g.sort_order,
    g.is_archived,
    g.tags,
    g.ai_health_score,
    g.created_at,
    g.updated_at,
    g.theme_id,
    t.title AS theme_title,
    t.color AS theme_color,
    t.status AS theme_status,
    g.owner_id,
    p.full_name AS owner_name,
    p.avatar_url AS owner_avatar,
    COALESCE(kr_agg.kr_count, (0)::bigint) AS kr_count,
    COALESCE(kr_agg.kr_completed, (0)::bigint) AS kr_completed,
    COALESCE(kr_agg.avg_kr_progress, (0)::numeric) AS avg_kr_progress,
    COALESCE(kr_agg.weighted_kr_progress, (0)::numeric) AS weighted_kr_progress,
    COALESCE(kr_agg.kr_on_track, (0)::bigint) AS kr_on_track,
    COALESCE(kr_agg.kr_at_risk, (0)::bigint) AS kr_at_risk,
    COALESCE(kr_agg.kr_off_track, (0)::bigint) AS kr_off_track,
    COALESCE(kr_agg.kr_overdue, (0)::bigint) AS kr_overdue,
    g.check_in_count,
    g.last_check_in_at,
    COALESCE(dep.dep_count, (0)::bigint) AS dependency_count
   FROM ((((public.es_goals g
     LEFT JOIN public.es_strategic_themes t ON ((g.theme_id = t.id)))
     LEFT JOIN public.profiles p ON ((g.owner_id = p.id)))
     LEFT JOIN LATERAL ( SELECT count(*) AS kr_count,
            count(*) FILTER (WHERE (kr.status = 'completed'::text)) AS kr_completed,
            round(avg(kr.progress_pct), 1) AS avg_kr_progress,
                CASE
                    WHEN (sum(COALESCE(kr.weight, (1)::numeric)) > (0)::numeric) THEN round((sum((COALESCE(kr.progress_pct, (0)::numeric) * COALESCE(kr.weight, (1)::numeric))) / sum(COALESCE(kr.weight, (1)::numeric))), 1)
                    ELSE (0)::numeric
                END AS weighted_kr_progress,
            count(*) FILTER (WHERE (kr.status = 'on_track'::text)) AS kr_on_track,
            count(*) FILTER (WHERE (kr.status = 'at_risk'::text)) AS kr_at_risk,
            count(*) FILTER (WHERE (kr.status = 'off_track'::text)) AS kr_off_track,
            count(*) FILTER (WHERE ((kr.due_date < CURRENT_DATE) AND (kr.status <> 'completed'::text))) AS kr_overdue
           FROM public.es_key_results kr
          WHERE (kr.goal_id = g.id)) kr_agg ON (true))
     LEFT JOIN LATERAL ( SELECT count(*) AS dep_count
           FROM public.es_goal_dependencies d
          WHERE ((d.source_goal_id = g.id) OR (d.target_goal_id = g.id))) dep ON (true))
  WHERE (g.is_archived = false);


