--
-- Name: es_themes_list_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.es_themes_list_view WITH (security_invoker='true') AS
 SELECT t.id,
    t.title,
    t.vision_statement,
    t.description,
    t.color,
    t.status,
    t.priority,
    t.bsc_perspective,
    t.fiscal_year,
    t.start_date,
    t.target_completion,
    t.planned_budget,
    t.sort_order,
    t.owner_id,
    t.theme_group_id,
    t.ai_health_score,
    t.success_metrics,
    t.process_step,
    t.is_major,
    t.created_at,
    t.updated_at,
    p.full_name AS owner_name,
    p.avatar_url AS owner_avatar,
    tg.name AS theme_group_name,
    COALESCE(g.goal_count, 0) AS goal_count,
    COALESCE(kr.kr_count, 0) AS kr_count,
    COALESCE(ini.initiative_count, 0) AS initiative_count,
    COALESCE(ms.milestone_count, 0) AS milestone_count,
        CASE
            WHEN (COALESCE(g.goal_count, 0) > 0) THEN (COALESCE(g.avg_progress, (0)::numeric))::integer
            ELSE COALESCE(t.progress_pct, 0)
        END AS progress_pct,
    COALESCE(ini.total_budget_allocated, (0)::numeric) AS budget_allocated,
    COALESCE(ini.total_budget_spent, (0)::numeric) AS budget_spent
   FROM ((((((public.es_strategic_themes t
     LEFT JOIN public.profiles p ON ((t.owner_id = p.id)))
     LEFT JOIN public.es_theme_groups tg ON ((t.theme_group_id = tg.id)))
     LEFT JOIN LATERAL ( SELECT (count(*))::integer AS goal_count,
            avg(es_goals.progress_pct) AS avg_progress
           FROM public.es_goals
          WHERE (es_goals.theme_id = t.id)) g ON (true))
     LEFT JOIN LATERAL ( SELECT (count(*))::integer AS kr_count
           FROM (public.es_key_results kr2
             JOIN public.es_goals g2 ON ((kr2.goal_id = g2.id)))
          WHERE (g2.theme_id = t.id)) kr ON (true))
     LEFT JOIN LATERAL ( SELECT (count(*))::integer AS initiative_count,
            sum(ini2.budget_allocated) AS total_budget_allocated,
            sum(ini2.budget_spent) AS total_budget_spent
           FROM ((public.es_initiatives ini2
             JOIN public.es_key_results kr3 ON ((ini2.key_result_id = kr3.id)))
             JOIN public.es_goals g3 ON ((kr3.goal_id = g3.id)))
          WHERE (g3.theme_id = t.id)) ini ON (true))
     LEFT JOIN LATERAL ( SELECT (count(*))::integer AS milestone_count
           FROM public.es_theme_milestones
          WHERE (es_theme_milestones.theme_id = t.id)) ms ON (true));


--
-- Name: es_themes_timeline_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.es_themes_timeline_view WITH (security_invoker='true') AS
 SELECT t.id,
    t.title,
    t.color,
    t.status,
    t.start_date,
    t.target_completion,
        CASE
            WHEN ((t.start_date IS NOT NULL) AND (t.target_completion IS NOT NULL)) THEN (t.target_completion - t.start_date)
            ELSE NULL::integer
        END AS duration_days,
        CASE
            WHEN ((t.start_date IS NOT NULL) AND (t.target_completion IS NOT NULL) AND (t.start_date <= CURRENT_DATE) AND (t.target_completion >= CURRENT_DATE)) THEN round(((((CURRENT_DATE - t.start_date))::numeric / (NULLIF((t.target_completion - t.start_date), 0))::numeric) * (100)::numeric))
            ELSE (0)::numeric
        END AS elapsed_pct,
    COALESCE(t.progress_pct, 0) AS progress_pct,
    p.full_name AS owner_name
   FROM (public.es_strategic_themes t
     LEFT JOIN public.profiles p ON ((t.owner_id = p.id)))
  WHERE (t.status <> 'archived'::text)
  ORDER BY t.start_date;


