--
-- Name: incident_list_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.incident_list_view WITH (security_invoker='true') AS
 SELECT i.id,
    i.incident_key,
    i.title,
    i.status,
    i.severity,
    i.priority,
    i.impact,
    i.urgency,
    i.is_major_incident,
    i.support_level,
    i.created_at,
    i.updated_at,
    i.resolved_at,
    i.closed_at,
    i.deleted_at,
    a.id AS assignee_id,
    a.full_name AS assignee_name,
    r.id AS reporter_id,
    r.full_name AS reporter_name,
    s.response_due_at,
    s.response_breached,
    s.resolution_due_at,
    s.resolution_breached,
    (EXTRACT(day FROM (now() - i.created_at)))::integer AS age_days,
    c.status AS committee_status,
    ( SELECT count(*) AS count
           FROM public.incident_watchers iw
          WHERE (iw.incident_id = i.id)) AS watcher_count,
    ( SELECT count(*) AS count
           FROM public.incident_comments ic
          WHERE ((ic.incident_id = i.id) AND (ic.deleted_at IS NULL))) AS comment_count
   FROM ((((public.incidents i
     LEFT JOIN public.incident_user_profiles a ON ((a.id = i.assignee_id)))
     LEFT JOIN public.incident_user_profiles r ON ((r.id = i.reporter_id)))
     LEFT JOIN public.sla_records s ON ((s.incident_id = i.id)))
     LEFT JOIN public.incident_committees c ON ((c.id = i.committee_id)))
  WHERE (i.deleted_at IS NULL);


