-- Name: license_allocation_totals; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.license_allocation_totals WITH (security_invoker='true') AS
 SELECT license_id,
    sum(allocation_percent) AS total_allocated,
        CASE
            WHEN (sum(allocation_percent) = (100)::numeric) THEN 'complete'::text
            WHEN (sum(allocation_percent) < (100)::numeric) THEN 'partial'::text
            ELSE 'over'::text
        END AS allocation_status
   FROM public.assignment_license_allocations
  GROUP BY license_id;


