--
-- Name: mv_dept_intelligence_stats; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.mv_dept_intelligence_stats AS
 SELECT ri.department_name,
    count(DISTINCT ri.id) AS resource_count,
    COALESCE(sum(rm.total_items), (0)::bigint) AS total_items,
    COALESCE(sum(rm.done_count), (0)::bigint) AS done_count,
    COALESCE(sum(rm.in_progress_count), (0)::bigint) AS in_progress_count,
    COALESCE(sum(rm.todo_count), (0)::bigint) AS todo_count,
        CASE
            WHEN (sum(rm.total_items) > 0) THEN round((((sum(rm.done_count))::numeric / (sum(rm.total_items))::numeric) * (100)::numeric), 1)
            ELSE (0)::numeric
        END AS closure_rate,
    array_agg(DISTINCT ri.id) AS resource_ids,
    array_agg(DISTINCT ri.jira_account_id) FILTER (WHERE (ri.jira_account_id IS NOT NULL)) AS jira_account_ids,
    now() AS refreshed_at
   FROM (public.resource_inventory ri
     LEFT JOIN public.r360_resource_metrics rm ON ((rm.resource_id = ri.id)))
  WHERE ((ri.is_active = true) AND (ri.department_name IS NOT NULL))
  GROUP BY ri.department_name
  WITH NO DATA;


