--
-- Name: notification_unread_counts; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.notification_unread_counts WITH (security_invoker='true') AS
 SELECT recipient_user_id,
    count(*) FILTER (WHERE (tab = 'direct'::text)) AS direct_unread,
    count(*) FILTER (WHERE (tab = 'watching'::text)) AS watching_unread,
    count(*) AS total_unread
   FROM public.notifications
  WHERE ((read_at IS NULL) AND ((snoozed_until IS NULL) OR (snoozed_until < now())) AND (entity_deleted = false))
  GROUP BY recipient_user_id;


