--
-- Name: pc_events_list_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.pc_events_list_view WITH (security_invoker='true') AS
 SELECT id,
    event_number,
    event_title,
    event_description,
    investor_impact,
    event_type,
    source_epic_key,
    source_epic_summary,
    linked_release_versions,
    linked_change_numbers,
    deployment_date,
    period_type,
    period_start,
    period_end,
    status,
    is_pinned,
    narrative_version,
    created_at,
    updated_at,
    deleted_at,
    COALESCE(( SELECT jsonb_agg(jsonb_build_object('ticketKey', t.ticket_key, 'summary', t.summary, 'type', t.type, 'fixVersion', t.fix_version, 'changeNumber', t.change_number) ORDER BY t.ticket_key) AS jsonb_agg
           FROM public.pc_event_tickets t
          WHERE (t.event_id = e.id)), '[]'::jsonb) AS ticket_details,
    (( SELECT count(*) AS count
           FROM public.pc_event_tickets t
          WHERE (t.event_id = e.id)))::integer AS linked_ticket_count
   FROM public.pc_events e;


