--
-- Name: ph_at_risk_items; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_at_risk_items WITH (security_invoker='true') AS
 SELECT issue_key,
    project_key,
    issue_type,
    summary,
    status,
    status_category,
    assignee_display_name,
    effective_due_date,
    effective_due_source,
    fix_versions,
    parent_key,
        CASE
            WHEN (status_category = 'Blocked'::text) THEN 'blocked'::text
            WHEN ((effective_due_date < CURRENT_DATE) AND (status_category <> 'Done'::text)) THEN 'overdue'::text
            WHEN ((jira_updated_at < (now() - '7 days'::interval)) AND (status_category <> 'Done'::text)) THEN 'stale'::text
            ELSE NULL::text
        END AS risk_tag
   FROM public.ph_issues
  WHERE ((status_category <> 'Done'::text) AND ((status_category = 'Blocked'::text) OR (effective_due_date < CURRENT_DATE) OR (jira_updated_at < (now() - '7 days'::interval))))
  ORDER BY
        CASE
            WHEN (status_category = 'Blocked'::text) THEN 1
            WHEN (effective_due_date < CURRENT_DATE) THEN 2
            ELSE 3
        END, effective_due_date
 LIMIT 20;


