--
-- Name: ph_backlog_initiatives_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_backlog_initiatives_view AS
 WITH linked_issues AS (
         SELECT i_1.id AS initiative_id,
            pi.issue_key,
            pi.status
           FROM (public.ph_initiatives i_1
             JOIN public.ph_issues pi ON ((pi.parent_key = (i_1.initiative_key)::text)))
          WHERE (i_1.is_deleted = false)
        UNION
         SELECT i_1.id AS initiative_id,
            pi.issue_key,
            pi.status
           FROM ((public.ph_initiatives i_1
             JOIN public.ph_issue_links pil ON (((pil.source_id = (i_1.initiative_key)::text) OR (pil.target_id = (i_1.initiative_key)::text))))
             JOIN public.ph_issues pi ON ((pi.issue_key =
                CASE
                    WHEN (pil.source_id = (i_1.initiative_key)::text) THEN pil.target_id
                    ELSE pil.source_id
                END)))
          WHERE (i_1.is_deleted = false)
        ), link_stats AS (
         SELECT linked_issues.initiative_id,
            count(*) AS total,
            count(*) FILTER (WHERE (linked_issues.status = ANY (ARRAY['Done'::text, 'Closed'::text, 'Resolved'::text]))) AS done
           FROM linked_issues
          GROUP BY linked_issues.initiative_id
        )
 SELECT i.id,
    i.initiative_key,
    i.title,
    i.description,
    i.status,
    i.assignee_id,
    i.business_owner_id,
    i.reporter_id,
    i.department_id,
    i.target_quarter,
    i.business_ask_date,
    i.kickoff_date,
    i.target_complete,
    i.progress,
    i.sort_order,
    i.risk_count,
    i.is_archived,
    i.is_deleted,
    i.created_at,
    i.updated_at,
    i.budget_allocated,
    i.on_roadmap,
    i.roadmap_added_at,
    i.roadmap_added_by,
    i.business_value,
    i.estimated_budget,
    i.roadmap_priority,
    i.health_status,
    i.tags,
    i.roadmap_start_date,
    i.roadmap_end_date,
    i.roadmap_sort_order,
    i.ea_review,
    i.priority,
    i.source,
    i.jira_issue_key,
    COALESCE(ls.total, (0)::bigint) AS linked_items_total,
    COALESCE(ls.done, (0)::bigint) AS linked_items_done,
    (COALESCE(round(((100.0 * (ls.done)::numeric) / (NULLIF(ls.total, 0))::numeric)), (0)::numeric))::integer AS linked_items_progress
   FROM (public.ph_initiatives i
     LEFT JOIN link_stats ls ON ((ls.initiative_id = i.id)))
  WHERE (i.is_deleted = false)
  ORDER BY i.created_at DESC;


