    sync_hash text,
    jira_key text,
    jira_sync_status text DEFAULT 'local_only'::text,
    jira_sync_error text,
    jira_pushed_at timestamp with time zone,
    CONSTRAINT ph_work_items_jira_sync_status_check CHECK ((jira_sync_status = ANY (ARRAY['local_only'::text, 'queued'::text, 'approval_pending'::text, 'pushed'::text, 'synced'::text, 'failed'::text, 'conflict'::text]))),
    CONSTRAINT ph_work_items_priority_check CHECK ((priority = ANY (ARRAY['critical'::text, 'high'::text, 'medium'::text, 'low'::text]))),
    CONSTRAINT ph_work_items_resolution_check CHECK (((resolution IS NULL) OR (resolution = ANY (ARRAY['done'::text, 'wont_do'::text, 'duplicate'::text, 'cannot_reproduce'::text])))),
    CONSTRAINT ph_work_items_security_level_check CHECK ((security_level = ANY (ARRAY['public'::text, 'standard'::text, 'confidential'::text, 'restricted'::text])))
);


--
-- Name: ph_board_column_counts_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_board_column_counts_view WITH (security_invoker='true') AS
 SELECT bc.project_id,
    bc.status_key,
    bc.column_label,
    bc.column_order,
    bc.wip_limit,
    bc.color_group,
    bc.is_visible,
    count(wi.id) AS item_count,
        CASE
            WHEN ((bc.wip_limit IS NOT NULL) AND (count(wi.id) > bc.wip_limit)) THEN 'exceeded'::text
            WHEN ((bc.wip_limit IS NOT NULL) AND (count(wi.id) = bc.wip_limit)) THEN 'at_limit'::text
            ELSE 'ok'::text
        END AS wip_status
   FROM (public.ph_board_config bc
     LEFT JOIN public.ph_work_items wi ON (((wi.status = bc.status_key) AND (wi.project_id = bc.project_id) AND (wi.deleted_at IS NULL))))
  WHERE (bc.is_visible = true)
  GROUP BY bc.id, bc.project_id, bc.status_key, bc.column_label, bc.column_order, bc.wip_limit, bc.color_group, bc.is_visible
  ORDER BY bc.column_order;


