--
-- Name: ph_exceptions; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_exceptions WITH (security_invoker='true') AS
 SELECT i.issue_key,
    i.project_key,
    i.issue_type,
    i.summary,
    i.status_category,
    i.effective_due_date,
    i.effective_due_source,
    i.parent_key,
        CASE
            WHEN ((i.effective_due_date IS NULL) AND (i.status_category <> 'Done'::text)) THEN 'unscheduled'::text
            WHEN ((i.effective_due_date IS NOT NULL) AND (p.effective_due_date IS NOT NULL) AND (i.effective_due_date > p.effective_due_date)) THEN 'conflicting'::text
            ELSE 'unmapped_type'::text
        END AS exception_type
   FROM (public.ph_issues i
     LEFT JOIN public.ph_issues p ON ((p.issue_key = i.parent_key)))
  WHERE ((i.status_category <> 'Done'::text) AND ((i.effective_due_date IS NULL) OR ((i.effective_due_date IS NOT NULL) AND (p.effective_due_date IS NOT NULL) AND (i.effective_due_date > p.effective_due_date))));


