--
-- Name: ph_ideas; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.ph_ideas (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    idea_key text NOT NULL,
    title text NOT NULL,
    description text,
    idea_type text DEFAULT 'Feature Request'::text NOT NULL,
    category text,
    source text DEFAULT 'Internal'::text NOT NULL,
    department text,
    tags text[] DEFAULT '{}'::text[],
    status text DEFAULT 'Draft'::text NOT NULL,
    priority text DEFAULT 'P3'::text,
    submitted_by uuid,
    assigned_to uuid,
    reach integer DEFAULT 0,
    impact integer DEFAULT 0,
    confidence numeric(3,2) DEFAULT 0.50,
    effort integer DEFAULT 1,
    rice_score numeric(10,2) GENERATED ALWAYS AS (
CASE
    WHEN (effort > 0) THEN ((((reach * impact))::numeric * confidence) / (effort)::numeric)
    ELSE (0)::numeric
END) STORED,
    business_value integer DEFAULT 0,
    time_criticality integer DEFAULT 0,
    risk_reduction integer DEFAULT 0,
    job_size integer DEFAULT 1,
    wsjf_score numeric(10,2) GENERATED ALWAYS AS (
CASE
    WHEN (job_size > 0) THEN ((((business_value + time_criticality) + risk_reduction))::numeric / (job_size)::numeric)
    ELSE (0)::numeric
END) STORED,
    custom_score numeric(10,2) DEFAULT 0,
    vote_count integer DEFAULT 0,
    vote_score numeric(10,2) DEFAULT 0,
    ai_summary text,
    ai_category text,
    ai_duplicate_ids uuid[] DEFAULT '{}'::uuid[],
    ai_enrichment_status text DEFAULT 'pending'::text,
    ai_tags text[] DEFAULT '{}'::text[],
    parent_idea_id uuid,
    linked_initiative_id uuid,
    converted_at timestamp with time zone,
    converted_by uuid,
    is_deleted boolean DEFAULT false,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    imperative numeric(2,1) DEFAULT 0,
    ministry_efficiency numeric(2,1) DEFAULT 0,
    pain_severity numeric(2,1) DEFAULT 0,
    alignment numeric(2,1) DEFAULT 0,
    complexity_score numeric(2,1) DEFAULT 0,
    timeframe_score numeric(2,1) DEFAULT 0,
    impact_total numeric(3,2) DEFAULT 0,
    innovation_drive_id uuid,
    theme text,
    assigned_team text,
    target_release_date date,
    is_committed boolean DEFAULT false NOT NULL,
    roadmap_quarter text,
    milestone_req date,
    milestone_des date,
    milestone_dev date,
    milestone_uat date,
    milestone_beta date,
    milestone_prod date,
    impact_investor_fit numeric(3,1) DEFAULT 0.0,
    impact_market_size numeric(3,1) DEFAULT 0.0,
    impact_problem_severity numeric(3,1) DEFAULT 0.0,
    impact_user_benefit numeric(3,1) DEFAULT 0.0,
    impact_complexity_inv numeric(3,1) DEFAULT 0.0,
    impact_time_to_value numeric(3,1) DEFAULT 0.0,
    converted_initiative_id uuid,
    CONSTRAINT ph_ideas_ai_enrichment_status_check CHECK ((ai_enrichment_status = ANY (ARRAY['pending'::text, 'processing'::text, 'complete'::text, 'failed'::text]))),
    CONSTRAINT ph_ideas_alignment_check CHECK (((alignment >= (0)::numeric) AND (alignment <= (5)::numeric))),
    CONSTRAINT ph_ideas_business_value_check CHECK (((business_value >= 0) AND (business_value <= 10))),
    CONSTRAINT ph_ideas_complexity_score_check CHECK (((complexity_score >= (0)::numeric) AND (complexity_score <= (5)::numeric))),
    CONSTRAINT ph_ideas_confidence_check CHECK (((confidence >= (0)::numeric) AND (confidence <= 1.00))),
    CONSTRAINT ph_ideas_effort_check CHECK (((effort >= 1) AND (effort <= 10))),
    CONSTRAINT ph_ideas_idea_type_check CHECK ((idea_type = ANY (ARRAY['Problem'::text, 'Opportunity'::text, 'Feature Request'::text, 'Solution'::text, 'Improvement'::text]))),
    CONSTRAINT ph_ideas_impact_check CHECK (((impact >= 0) AND (impact <= 10))),
    CONSTRAINT ph_ideas_imperative_check CHECK (((imperative >= (0)::numeric) AND (imperative <= (5)::numeric))),
    CONSTRAINT ph_ideas_job_size_check CHECK (((job_size >= 1) AND (job_size <= 10))),
    CONSTRAINT ph_ideas_ministry_efficiency_check CHECK (((ministry_efficiency >= (0)::numeric) AND (ministry_efficiency <= (5)::numeric))),
    CONSTRAINT ph_ideas_pain_severity_check CHECK (((pain_severity >= (0)::numeric) AND (pain_severity <= (5)::numeric))),
    CONSTRAINT ph_ideas_priority_check CHECK ((priority = ANY (ARRAY['P1'::text, 'P2'::text, 'P3'::text, 'P4'::text]))),
    CONSTRAINT ph_ideas_reach_check CHECK (((reach >= 0) AND (reach <= 10))),
    CONSTRAINT ph_ideas_risk_reduction_check CHECK (((risk_reduction >= 0) AND (risk_reduction <= 10))),
    CONSTRAINT ph_ideas_roadmap_quarter_check CHECK ((roadmap_quarter = ANY (ARRAY['Q1'::text, 'Q2'::text, 'Q3'::text, 'Q4'::text]))),
    CONSTRAINT ph_ideas_source_check CHECK ((source = ANY (ARRAY['Internal'::text, 'Stakeholder'::text, 'Customer Feedback'::text, 'Research'::text, 'Ministry Directive'::text]))),
    CONSTRAINT ph_ideas_status_check CHECK ((status = ANY (ARRAY['Draft'::text, 'Submitted'::text, 'Under Review'::text, 'Approved'::text, 'Rejected'::text, 'Converted'::text, 'Archived'::text]))),
    CONSTRAINT ph_ideas_time_criticality_check CHECK (((time_criticality >= 0) AND (time_criticality <= 10))),
    CONSTRAINT ph_ideas_timeframe_score_check CHECK (((timeframe_score >= (0)::numeric) AND (timeframe_score <= (5)::numeric)))
);


--
-- Name: ph_idea_list_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_idea_list_view WITH (security_invoker='true') AS
 SELECT i.id,
    i.idea_key,
    i.title,
    i.description,
    i.idea_type,
    i.category,
    i.source,
    i.department,
    i.tags,
    i.status,
    i.priority,
    i.submitted_by,
    i.assigned_to,
    i.reach,
    i.impact,
    i.confidence,
    i.effort,
    i.rice_score,
    i.business_value,
    i.time_criticality,
    i.risk_reduction,
    i.job_size,
    i.wsjf_score,
    i.custom_score,
    i.vote_count,
    i.vote_score,
    i.ai_summary,
    i.ai_category,
    i.ai_duplicate_ids,
    i.ai_enrichment_status,
    i.ai_tags,
    i.parent_idea_id,
    i.linked_initiative_id,
    i.converted_at,
    i.converted_by,
    i.is_deleted,
    i.created_at,
    i.updated_at,
    i.imperative,
    i.ministry_efficiency,
    i.pain_severity,
    i.alignment,
    i.complexity_score,
    i.timeframe_score,
    i.impact_total,
    i.innovation_drive_id,
    ap.full_name AS assignee_name,
    ap.avatar_url AS assignee_avatar,
    COALESCE((SUBSTRING(ap.full_name FROM 1 FOR 1) || SUBSTRING(ap.full_name FROM (POSITION((' '::text) IN (COALESCE(ap.full_name, ''::text))) + 1) FOR 1)), ''::text) AS assignee_initials,
    cp.full_name AS creator_name,
    init.initiative_key,
    (COALESCE(cc.cnt, (0)::bigint))::integer AS comment_count,
    (COALESCE(ec.cnt, (0)::bigint))::integer AS evidence_count,
    COALESCE(s.total_score, i.impact_total) AS computed_impact
   FROM ((((((public.ph_ideas i
     LEFT JOIN public.profiles ap ON ((i.assigned_to = ap.id)))
     LEFT JOIN public.profiles cp ON ((i.submitted_by = cp.id)))
     LEFT JOIN public.mim_initiatives init ON ((i.linked_initiative_id = init.id)))
     LEFT JOIN public.ph_idea_scores s ON ((s.idea_id = i.id)))
     LEFT JOIN ( SELECT ph_idea_comments.idea_id,
            count(*) AS cnt
           FROM public.ph_idea_comments
          GROUP BY ph_idea_comments.idea_id) cc ON ((cc.idea_id = i.id)))
     LEFT JOIN ( SELECT ph_idea_evidence.idea_id,
            count(*) AS cnt
           FROM public.ph_idea_evidence
          GROUP BY ph_idea_evidence.idea_id) ec ON ((ec.idea_id = i.id)));


