--
-- Name: ph_ideas_dept_counts; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_ideas_dept_counts WITH (security_invoker='true') AS
 SELECT COALESCE(department, 'Unassigned'::text) AS department,
    count(*) AS idea_count,
    round(avg(impact_total), 2) AS avg_impact,
    count(*) FILTER (WHERE ((status = 'Approved'::text) OR (status = 'Converted'::text))) AS approved_count
   FROM public.ph_ideas
  WHERE (is_deleted = false)
  GROUP BY department
  ORDER BY (count(*)) DESC;


--
-- Name: ph_ideas_impact_distribution; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_ideas_impact_distribution WITH (security_invoker='true') AS
 SELECT
        CASE
            WHEN (impact_total >= 4.0) THEN 'Excellent (4.0-5.0)'::text
            WHEN (impact_total >= 3.0) THEN 'Good (3.0-3.99)'::text
            WHEN (impact_total >= 2.0) THEN 'Fair (2.0-2.99)'::text
            WHEN (impact_total > (0)::numeric) THEN 'Low (0.01-1.99)'::text
            ELSE 'Unscored'::text
        END AS score_band,
    count(*) AS idea_count,
        CASE
            WHEN (impact_total >= 4.0) THEN 1
            WHEN (impact_total >= 3.0) THEN 2
            WHEN (impact_total >= 2.0) THEN 3
            WHEN (impact_total > (0)::numeric) THEN 4
            ELSE 5
        END AS sort_order
   FROM public.ph_ideas
  WHERE (is_deleted = false)
  GROUP BY
        CASE
            WHEN (impact_total >= 4.0) THEN 'Excellent (4.0-5.0)'::text
            WHEN (impact_total >= 3.0) THEN 'Good (3.0-3.99)'::text
            WHEN (impact_total >= 2.0) THEN 'Fair (2.0-2.99)'::text
            WHEN (impact_total > (0)::numeric) THEN 'Low (0.01-1.99)'::text
            ELSE 'Unscored'::text
        END,
        CASE
            WHEN (impact_total >= 4.0) THEN 1
            WHEN (impact_total >= 3.0) THEN 2
            WHEN (impact_total >= 2.0) THEN 3
            WHEN (impact_total > (0)::numeric) THEN 4
            ELSE 5
        END
  ORDER BY
        CASE
            WHEN (impact_total >= 4.0) THEN 1
            WHEN (impact_total >= 3.0) THEN 2
            WHEN (impact_total >= 2.0) THEN 3
            WHEN (impact_total > (0)::numeric) THEN 4
            ELSE 5
        END;


