    i.is_deleted,
    i.created_at,
    i.updated_at,
    i.imperative,
    i.ministry_efficiency,
    i.pain_severity,
    i.alignment,
    i.complexity_score,
    i.timeframe_score,
    i.impact_total,
    i.theme,
    i.assigned_team,
    i.target_release_date,
    i.roadmap_quarter,
    i.is_committed,
    ps.full_name AS submitted_by_name,
    pa.full_name AS assigned_to_name,
    ( SELECT count(*) AS count
           FROM public.ph_idea_comments c
          WHERE (c.idea_id = i.id)) AS comment_count,
    ( SELECT count(*) AS count
           FROM public.ph_idea_evidence e
          WHERE (e.idea_id = i.id)) AS evidence_count,
    ( SELECT count(*) AS count
           FROM public.ph_ideas child
          WHERE ((child.parent_idea_id = i.id) AND (child.is_deleted = false))) AS child_count,
    ( SELECT count(*) AS count
           FROM public.ph_idea_v2030_mappings v
          WHERE (v.idea_id = i.id)) AS v2030_pillar_count,
    ( SELECT count(*) AS count
           FROM public.ph_idea_compliance_tags ct
          WHERE (ct.idea_id = i.id)) AS compliance_tag_count,
    li.title AS linked_initiative_title,
    li.initiative_key AS linked_initiative_key
   FROM (((public.ph_ideas i
     LEFT JOIN public.profiles ps ON ((ps.id = i.submitted_by)))
     LEFT JOIN public.profiles pa ON ((pa.id = i.assigned_to)))
     LEFT JOIN public.ph_initiatives li ON ((li.id = i.linked_initiative_id)))
  WHERE (i.is_deleted = false);


--
-- Name: ph_ideas_matrix; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_ideas_matrix WITH (security_invoker='true') AS
 SELECT id,
    idea_key,
    title,
    idea_type,
    status,
    priority,
    category,
    department,
    imperative,
    ministry_efficiency,
    pain_severity,
    alignment,
    complexity_score,
    timeframe_score,
    impact_total,
    complexity_score AS matrix_x,
    round(((((imperative * 0.30) + (ministry_efficiency * 0.25)) + (pain_severity * 0.25)) + (alignment * 0.20)), 2) AS matrix_y,
    vote_count,
    vote_score
   FROM public.ph_ideas i
  WHERE ((is_deleted = false) AND (status <> ALL (ARRAY['Draft'::text, 'Archived'::text, 'Rejected'::text])) AND (impact_total > (0)::numeric));


--
-- Name: ph_ideas_monthly_trend; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_ideas_monthly_trend WITH (security_invoker='true') AS
 SELECT (date_trunc('month'::text, created_at))::date AS month,
    count(*) AS submitted,
    count(*) FILTER (WHERE ((status = 'Approved'::text) OR (status = 'Converted'::text))) AS approved,
    count(*) FILTER (WHERE (status = 'Rejected'::text)) AS rejected,
    round(avg(impact_total), 2) AS avg_impact
   FROM public.ph_ideas
  WHERE (is_deleted = false)
  GROUP BY (date_trunc('month'::text, created_at))
  ORDER BY ((date_trunc('month'::text, created_at))::date) DESC
 LIMIT 12;


--
-- Name: ph_ideas_status_counts; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_ideas_status_counts WITH (security_invoker='true') AS
 SELECT status,
    count(*) AS idea_count,
    round(avg(impact_total), 2) AS avg_impact,
    sum(vote_count) AS total_votes
   FROM public.ph_ideas
  WHERE (is_deleted = false)
  GROUP BY status;


--
-- Name: ph_ideas_top_contributors; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_ideas_top_contributors WITH (security_invoker='true') AS
 SELECT i.submitted_by,
    p.full_name AS contributor_name,
    count(*) AS ideas_submitted,
    count(*) FILTER (WHERE ((i.status = 'Approved'::text) OR (i.status = 'Converted'::text))) AS ideas_approved,
    round(avg(i.impact_total), 2) AS avg_impact
   FROM (public.ph_ideas i
     LEFT JOIN public.profiles p ON ((p.id = i.submitted_by)))
  WHERE ((i.is_deleted = false) AND (i.submitted_by IS NOT NULL))
  GROUP BY i.submitted_by, p.full_name
  ORDER BY (count(*)) DESC
 LIMIT 10;


--
-- Name: ph_ideas_triage; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_ideas_triage WITH (security_invoker='true') AS
 SELECT i.id,
    i.idea_key,
    i.title,
    i.idea_type,
    i.source,
    i.priority,
    i.department,
    i.impact_total,
    i.submitted_by,
    p.full_name AS submitted_by_name,
    i.ai_category,
    i.ai_duplicate_ids,
    i.ai_summary,
    i.ai_enrichment_status,
    i.created_at,
    ( SELECT count(*) AS count
           FROM public.ph_idea_evidence e
          WHERE (e.idea_id = i.id)) AS evidence_count
   FROM (public.ph_ideas i
     LEFT JOIN public.profiles p ON ((p.id = i.submitted_by)))
  WHERE ((i.status = 'Submitted'::text) AND (i.is_deleted = false))
  ORDER BY i.impact_total DESC NULLS LAST,
        CASE i.priority
            WHEN 'P1'::text THEN 1
            WHEN 'P2'::text THEN 2
            WHEN 'P3'::text THEN 3
            WHEN 'P4'::text THEN 4
            ELSE NULL::integer
        END, i.created_at;


