    CONSTRAINT ph_initiative_risks_category_check CHECK ((category = ANY (ARRAY['technical'::text, 'financial'::text, 'resource'::text, 'schedule'::text, 'scope'::text, 'external'::text, 'compliance'::text, 'organizational'::text]))),
    CONSTRAINT ph_initiative_risks_impact_check CHECK (((impact >= 1) AND (impact <= 5))),
    CONSTRAINT ph_initiative_risks_probability_check CHECK (((probability >= 1) AND (probability <= 5))),
    CONSTRAINT ph_initiative_risks_status_check CHECK ((status = ANY (ARRAY['open'::text, 'mitigating'::text, 'mitigated'::text, 'accepted'::text, 'closed'::text, 'occurred'::text])))
);


