    time_urgency numeric(2,1),
    resource_feasibility numeric(2,1),
    computed_score numeric(2,1) GENERATED ALWAYS AS (round(((((COALESCE(strategic_alignment, (0)::numeric) + COALESCE(business_impact, (0)::numeric)) + COALESCE(time_urgency, (0)::numeric)) + COALESCE(resource_feasibility, (0)::numeric)) / 4.0), 1)) STORED,
    scored_by uuid,
    scored_at timestamp with time zone DEFAULT now()
);


