--
-- Name: ph_lifecycle_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_lifecycle_view WITH (security_invoker='true') AS
 SELECT st.id,
    st.work_item_id,
    wi.item_key AS work_item_key,
    wi.item_type AS work_item_type,
    COALESCE(wi.title, wi.summary) AS work_item_title,
    wi.status AS current_status,
    r.name AS release_key,
    st.from_status,
    st.to_status,
    st.changed_at,
    p.full_name AS changed_by_name,
    (COALESCE((EXTRACT(epoch FROM (lead(st.changed_at) OVER (PARTITION BY st.work_item_id ORDER BY st.changed_at) - st.changed_at)) / (86400)::numeric), (EXTRACT(epoch FROM (now() - st.changed_at)) / (86400)::numeric)))::numeric(10,1) AS duration_days
   FROM (((public.ph_status_transitions st
     JOIN public.ph_work_items wi ON ((wi.id = st.work_item_id)))
     LEFT JOIN public.ph_releases r ON ((r.id = wi.release_id)))
     LEFT JOIN public.profiles p ON ((p.id = st.changed_by)))
  ORDER BY st.work_item_id, st.changed_at;


