    columns jsonb DEFAULT '["type", "key", "summary", "status", "assignee", "priority", "due_date"]'::jsonb NOT NULL,
    sort_by text DEFAULT 'created_at'::text,
    sort_dir text DEFAULT 'desc'::text,
    group_by text,
    filters jsonb DEFAULT '{}'::jsonb,
    is_default boolean DEFAULT false,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT ph_list_view_configs_sort_dir_check CHECK ((sort_dir = ANY (ARRAY['asc'::text, 'desc'::text])))
);


