--
-- Name: ph_overdue_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_overdue_view WITH (security_invoker='true') AS
 SELECT wi.id,
    wi.item_key,
    COALESCE(wi.title, wi.summary) AS title,
    wi.item_type,
    wi.status,
    wi.due_date,
    r.name AS release_key,
    p.full_name AS assignee_name,
    (CURRENT_DATE - wi.due_date) AS days_overdue
   FROM ((public.ph_work_items wi
     JOIN public.ph_releases r ON ((r.id = wi.release_id)))
     LEFT JOIN public.profiles p ON ((p.id = COALESCE(wi.assignee_id, wi.assignee_user_id))))
  WHERE ((wi.due_date < CURRENT_DATE) AND (wi.status <> ALL (ARRAY['Done'::text, 'in_production'::text, 'Cancelled'::text])))
  ORDER BY (CURRENT_DATE - wi.due_date) DESC;


--
-- Name: ph_overview_stats; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_overview_stats WITH (security_invoker='true') AS
 SELECT count(*) FILTER (WHERE (status_category <> 'Done'::text)) AS active_count,
    count(*) FILTER (WHERE ((status_category = 'Done'::text) AND (jira_updated_at >= (now() - '7 days'::interval)))) AS done_this_week,
    count(*) FILTER (WHERE ((effective_due_date < CURRENT_DATE) AND (status_category <> ALL (ARRAY['Done'::text, 'Blocked'::text])))) AS overdue_count,
    count(*) FILTER (WHERE ((jira_updated_at < (now() - '7 days'::interval)) AND (status_category <> 'Done'::text))) AS stale_count,
    count(*) FILTER (WHERE (status_category = 'Blocked'::text)) AS blocked_count
   FROM public.ph_issues;


--
-- Name: ph_person_workload; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_person_workload WITH (security_invoker='true') AS
 SELECT assignee_account_id,
    assignee_display_name,
    count(*) FILTER (WHERE (status_category <> 'Done'::text)) AS active_count,
    count(*) FILTER (WHERE (status_category = 'Done'::text)) AS done_count,
    count(*) FILTER (WHERE ((effective_due_date < CURRENT_DATE) AND (status_category <> ALL (ARRAY['Done'::text, 'Blocked'::text])))) AS overdue_count,
    count(*) FILTER (WHERE (status_category = 'Blocked'::text)) AS blocked_count,
    count(*) FILTER (WHERE ((status_category = 'Done'::text) AND (jira_updated_at >= (now() - '7 days'::interval)))) AS done_this_week
   FROM public.ph_issues
  WHERE (assignee_account_id IS NOT NULL)
  GROUP BY assignee_account_id, assignee_display_name;


