--
-- Name: ph_release_health; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_release_health WITH (security_invoker='true') AS
 SELECT v.jira_id,
    v.name AS version_name,
    v.project_key,
    COALESCE(v.release_date, v.parsed_date) AS effective_release_date,
    v.released,
    count(i.issue_key) AS total_issues,
    count(i.issue_key) FILTER (WHERE (i.status_category = 'Done'::text)) AS done_count,
    count(i.issue_key) FILTER (WHERE (i.status_category = 'In Progress'::text)) AS in_progress_count,
    count(i.issue_key) FILTER (WHERE (i.status_category = 'Blocked'::text)) AS blocked_count,
    count(i.issue_key) FILTER (WHERE (i.status_category = ANY (ARRAY['To Do'::text, 'In Review'::text]))) AS todo_count,
        CASE
            WHEN (count(i.issue_key) > 0) THEN round((((count(i.issue_key) FILTER (WHERE (i.status_category = 'Done'::text)))::numeric / (count(i.issue_key))::numeric) * (100)::numeric))
            ELSE (0)::numeric
        END AS completion_pct
   FROM (public.ph_versions v
     LEFT JOIN public.ph_issues i ON ((i.fix_versions @> jsonb_build_array(jsonb_build_object('id', v.jira_id)))))
  GROUP BY v.jira_id, v.name, v.project_key, v.release_date, v.parsed_date, v.released;


