-- Name: ph_roadmap_initiatives_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_roadmap_initiatives_view AS
 SELECT id,
    initiative_key,
    title,
    description,
    status,
    assignee_id,
    business_owner_id,
    reporter_id,
    department_id,
    target_quarter,
    business_ask_date,
    kickoff_date,
    target_complete,
    roadmap_start_date,
    roadmap_end_date,
    roadmap_sort_order,
    progress,
    sort_order,
    risk_count,
    is_archived,
    is_deleted,
    created_at,
    updated_at,
    budget_allocated,
    on_roadmap,
    roadmap_added_at,
    roadmap_added_by,
    business_value,
    estimated_budget,
    roadmap_priority,
    health_status,
    tags
   FROM public.ph_initiatives i
  WHERE ((on_roadmap = true) AND (is_deleted = false))
  ORDER BY roadmap_priority, roadmap_sort_order, created_at;


--
-- Name: ph_roadmap_summary_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_roadmap_summary_view AS
 SELECT count(*) FILTER (WHERE (on_roadmap = true)) AS total_on_roadmap,
    count(*) FILTER (WHERE (on_roadmap = false)) AS total_not_on_roadmap,
    count(*) AS total_initiatives,
    count(*) FILTER (WHERE ((on_roadmap = true) AND (status <> ALL (ARRAY['delivered'::public.initiative_status, 'closed'::public.initiative_status, 'cancelled'::public.initiative_status])))) AS active_count,
    count(*) FILTER (WHERE ((on_roadmap = true) AND (status = ANY (ARRAY['new_demand'::public.initiative_status, 'under_review'::public.initiative_status])))) AS validation_count,
    count(*) FILTER (WHERE ((on_roadmap = true) AND (health_status = 'on_track'::text))) AS roadmap_on_track,
    count(*) FILTER (WHERE ((on_roadmap = true) AND (health_status = 'at_risk'::text))) AS roadmap_at_risk,
    count(*) FILTER (WHERE ((on_roadmap = true) AND (health_status = 'off_track'::text))) AS roadmap_off_track
   FROM public.ph_initiatives i
  WHERE (is_deleted = false);


