--
-- Name: ph_team_workload_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_team_workload_view WITH (security_invoker='true') AS
 SELECT p.id AS user_id,
    p.full_name AS name,
    count(*) AS total_count,
    count(*) FILTER (WHERE (wi.item_type = ANY (ARRAY['Story'::text, 'story'::text]))) AS story_count,
    count(*) FILTER (WHERE (wi.item_type = ANY (ARRAY['Subtask'::text, 'subtask'::text]))) AS subtask_count,
    count(*) FILTER (WHERE (wi.item_type = ANY (ARRAY['Bug'::text, 'bug'::text]))) AS bug_count,
    count(*) FILTER (WHERE (wi.item_type = 'incident'::text)) AS incident_count,
    wi.project_id
   FROM (public.ph_work_items wi
     JOIN public.profiles p ON ((p.id = COALESCE(wi.assignee_id, wi.assignee_user_id))))
  WHERE (wi.status <> ALL (ARRAY['Done'::text, 'in_production'::text, 'Cancelled'::text]))
  GROUP BY p.id, p.full_name, wi.project_id;


