--
-- Name: ph_work_items_full_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ph_work_items_full_view WITH (security_invoker='true') AS
 SELECT wi.id,
    wi.item_key,
    wi.title,
    wi.item_type,
    wi.status,
    wi.priority,
    wi.sort_order,
    wi.due_date,
    wi.estimate,
    wi.labels,
    wi.description,
    wi.parent_id,
    wi.project_id,
    wi.release_id,
    wi.assignee_id,
    wi.reporter_id,
    wi.deleted_at,
    wi.created_at,
    wi.updated_at,
    wi.department,
    wi.team,
    wi.environment,
    wi.security_level,
    wi.is_flagged,
    wi.flag_reason,
    wi.cycle_time_days,
    wi.status_changed_at,
    wi.resolved_at,
    wi.on_hold_reason,
    wi.backlog_order,
    r.name AS release_name,
    r.status AS release_status,
    ap.full_name AS assignee_name,
    ap.avatar_url AS assignee_avatar,
    rp.full_name AS reporter_name,
    pw.item_key AS parent_key,
    pw.title AS parent_title,
    (COALESCE(EXTRACT(day FROM (now() - ( SELECT max(st.changed_at) AS max
           FROM public.ph_status_transitions st
          WHERE ((st.work_item_id = wi.id) AND (st.to_status = wi.status))))), EXTRACT(day FROM (now() - wi.created_at))))::integer AS days_in_status,
        CASE
            WHEN ((wi.due_date IS NOT NULL) AND (wi.due_date < CURRENT_DATE) AND (wi.status <> ALL (ARRAY['in_production'::text, 'production_ready'::text]))) THEN true
            ELSE false
        END AS is_overdue,
        CASE
            WHEN ((wi.due_date IS NOT NULL) AND (wi.due_date < CURRENT_DATE) AND (wi.status <> ALL (ARRAY['in_production'::text, 'production_ready'::text]))) THEN (CURRENT_DATE - wi.due_date)
            ELSE NULL::integer
        END AS days_overdue,
    ( SELECT count(*) AS count
           FROM public.ph_work_items sub
          WHERE ((sub.parent_id = wi.id) AND (sub.deleted_at IS NULL))) AS sub_issue_count
   FROM ((((public.ph_work_items wi
     LEFT JOIN public.ph_releases r ON ((r.id = wi.release_id)))
     LEFT JOIN public.profiles ap ON ((ap.id = wi.assignee_id)))
     LEFT JOIN public.profiles rp ON ((rp.id = wi.reporter_id)))
     LEFT JOIN public.ph_work_items pw ON ((pw.id = wi.parent_id)))
  WHERE (wi.deleted_at IS NULL);


