--

CREATE TABLE public.planhub_ai_config (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    api_key_encrypted text,
    model text DEFAULT 'gemini-1.5-flash'::text NOT NULL,
    temperature numeric(2,1) DEFAULT 0.7 NOT NULL,
