    time_estimate_minutes integer,
    time_logged_minutes integer DEFAULT 0,
    parent_task_id uuid,
    sort_order integer DEFAULT 0,
    is_archived boolean DEFAULT false,
    created_by uuid,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    completed_at timestamp with time zone,
    key character varying(20),
    "position" integer DEFAULT 0,
    deleted_at timestamp with time zone,
    is_starred boolean DEFAULT false,
    blocked boolean DEFAULT false,
    blocked_reason text,
    progress integer DEFAULT 0,
    cover_url text,
    reporter_id uuid,
    reviewer_id uuid,
    CONSTRAINT planner_tasks_priority_check CHECK (((priority)::text = ANY (ARRAY[('critical'::character varying)::text, ('high'::character varying)::text, ('medium'::character varying)::text, ('low'::character varying)::text])))
);


--
-- Name: planner_board_columns; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.planner_board_columns WITH (security_invoker='true') AS
 SELECT id,
    name,
    slug,
    color,
    sort_order,
    "position",
    is_default,
    is_done,
    is_completed_status,
    is_system,
    created_at,
    updated_at,
    ( SELECT (count(*))::integer AS count
           FROM public.planner_tasks pt
          WHERE ((pt.status_id = ps.id) AND (pt.deleted_at IS NULL))) AS task_count
   FROM public.planner_statuses ps
  ORDER BY "position";


--
-- Name: planner_board_tasks; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.planner_board_tasks WITH (security_invoker='true') AS
 SELECT t.id,
    COALESCE(t.key, t.task_key) AS key,
    t.task_key,
    t.title,
    t.description,
    t.priority,
    t.due_date,
    t.start_date,
    t."position",
    t.sort_order,
    t.is_starred,
    t.is_archived,
    t.deleted_at,
    t.created_at,
    t.updated_at,
    t.completed_at,
    t.assignee_id,
    t.created_by,
    t.status_id,
    t.workstream_id,
    t.parent_task_id,
    t.time_estimate_minutes,
    t.time_logged_minutes,
    t.blocked,
    t.blocked_reason,
    t.progress,
    t.cover_url,
    s.name AS status_name,
    s.slug AS status_slug,
    s.color AS status_color,
    s.is_done AS status_is_done,
    s."position" AS status_position,
    w.name AS workstream_name,
    w.slug AS workstream_slug,
    w.color AS workstream_color,
    p.full_name AS assignee_name,
    p.avatar_url AS assignee_avatar,
    p.email AS assignee_email,
    c.full_name AS creator_name
   FROM ((((public.planner_tasks t
     LEFT JOIN public.planner_statuses s ON ((t.status_id = s.id)))
     LEFT JOIN public.planner_workstreams w ON ((t.workstream_id = w.id)))
     LEFT JOIN public.profiles p ON ((t.assignee_id = p.id)))
     LEFT JOIN public.profiles c ON ((t.created_by = c.id)))
  WHERE (t.deleted_at IS NULL);


--
-- Name: planner_calendar_tasks; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.planner_calendar_tasks WITH (security_invoker='true') AS
 SELECT assignee_id,
    due_date,
    (count(*))::integer AS task_count,
    array_agg(priority) AS priorities
   FROM public.planner_tasks
  WHERE ((due_date IS NOT NULL) AND (is_archived = false) AND ((due_date >= (CURRENT_DATE - '7 days'::interval)) AND (due_date <= (CURRENT_DATE + '60 days'::interval))))
  GROUP BY assignee_id, due_date;


