--
-- Name: planner_dashboard_metrics; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.planner_dashboard_metrics WITH (security_invoker='true') AS
 SELECT (count(*))::integer AS total_tasks,
    (count(*) FILTER (WHERE (s.is_done = true)))::integer AS completed_tasks,
    (count(*) FILTER (WHERE ((t.due_date < CURRENT_DATE) AND (s.is_done = false))))::integer AS overdue_tasks,
    (count(*) FILTER (WHERE ((t.due_date < CURRENT_DATE) AND (s.is_done = false))))::integer AS overdue_count,
    (count(*) FILTER (WHERE (t.due_date = CURRENT_DATE)))::integer AS due_today,
    (count(*) FILTER (WHERE ((t.due_date >= CURRENT_DATE) AND (t.due_date <= (CURRENT_DATE + '7 days'::interval)))))::integer AS due_this_week,
    (count(*) FILTER (WHERE ((s.is_done = true) AND (t.completed_at >= (CURRENT_DATE - '7 days'::interval)))))::integer AS completed_this_week,
    (count(*) FILTER (WHERE (t.blocked = true)))::integer AS blocked_count,
    (count(*) FILTER (WHERE ((t.priority)::text = 'critical'::text)))::integer AS critical_count,
    (count(*) FILTER (WHERE ((t.priority)::text = 'high'::text)))::integer AS high_priority_count,
    (count(*) FILTER (WHERE (t.assignee_id IS NULL)))::integer AS unassigned_count,
    COALESCE(round((((count(*) FILTER (WHERE (s.is_done = true)))::numeric / NULLIF((count(*))::numeric, (0)::numeric)) * (100)::numeric), 1), (0)::numeric) AS completion_rate
   FROM (public.planner_tasks t
     LEFT JOIN public.planner_statuses s ON ((t.status_id = s.id)))
  WHERE (t.deleted_at IS NULL);


--
-- Name: planner_dashboard_status_distribution; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.planner_dashboard_status_distribution WITH (security_invoker='true') AS
 WITH totals AS (
         SELECT (count(*))::numeric AS total
           FROM public.planner_tasks
          WHERE (planner_tasks.deleted_at IS NULL)
        )
 SELECT s.id AS status_id,
    s.name AS status_name,
    s.slug AS status_slug,
    s.color AS status_color,
    s.sort_order,
    s."position",
    (count(t.id))::integer AS task_count,
    COALESCE(round((((count(t.id))::numeric / NULLIF(( SELECT totals.total
           FROM totals), (0)::numeric)) * (100)::numeric), 1), (0)::numeric) AS percentage
   FROM (public.planner_statuses s
     LEFT JOIN public.planner_tasks t ON (((t.status_id = s.id) AND (t.deleted_at IS NULL))))
  GROUP BY s.id, s.name, s.slug, s.color, s.sort_order, s."position"
  ORDER BY s.sort_order;


--
-- Name: planner_dashboard_team_workload; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.planner_dashboard_team_workload WITH (security_invoker='true') AS
 SELECT p.id AS profile_id,
    p.full_name,
    p.avatar_url,
    p.email,
    (count(t.id))::integer AS total_tasks,
    (count(t.id))::integer AS assigned_tasks,
    (count(t.id) FILTER (WHERE (s.is_done = false)))::integer AS active_tasks,
    (count(t.id) FILTER (WHERE ((s.slug)::text = 'progress'::text)))::integer AS in_progress_count,
    (count(t.id) FILTER (WHERE (s.is_done = true)))::integer AS completed_tasks,
    (count(t.id) FILTER (WHERE ((t.due_date < CURRENT_DATE) AND (s.is_done = false))))::integer AS overdue_tasks,
    (count(t.id) FILTER (WHERE ((t.due_date < CURRENT_DATE) AND (s.is_done = false))))::integer AS overdue_count,
        CASE
            WHEN (count(t.id) FILTER (WHERE (s.is_done = false)) > 10) THEN 'overloaded'::text
            WHEN (count(t.id) FILTER (WHERE (s.is_done = false)) > 5) THEN 'busy'::text
            ELSE 'available'::text
        END AS workload_status
   FROM ((public.profiles p
     LEFT JOIN public.planner_tasks t ON (((t.assignee_id = p.id) AND (t.deleted_at IS NULL))))
     LEFT JOIN public.planner_statuses s ON ((t.status_id = s.id)))
  WHERE (p.approval_status = 'APPROVED'::public.user_approval_status)
  GROUP BY p.id, p.full_name, p.avatar_url, p.email
  ORDER BY (count(t.id) FILTER (WHERE (s.is_done = false))) DESC, p.full_name;


--
-- Name: planner_dashboard_upcoming_deadlines; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.planner_dashboard_upcoming_deadlines WITH (security_invoker='true') AS
 SELECT t.id,
    COALESCE(t.key, t.task_key) AS key,
    t.title,
    t.priority,
    t.due_date,
    t.status_id,
    s.name AS status_name,
    s.slug AS status_slug,
    s.color AS status_color,
    t.assignee_id,
    p.full_name AS assignee_name,
    p.avatar_url AS assignee_avatar,
    w.name AS workstream_name,
    w.color AS workstream_color,
        CASE
            WHEN (t.due_date < CURRENT_DATE) THEN 'overdue'::text
            WHEN (t.due_date = CURRENT_DATE) THEN 'today'::text
            WHEN (t.due_date = (CURRENT_DATE + '1 day'::interval)) THEN 'tomorrow'::text
            ELSE 'upcoming'::text
        END AS urgency
   FROM (((public.planner_tasks t
     LEFT JOIN public.planner_statuses s ON ((t.status_id = s.id)))
     LEFT JOIN public.planner_workstreams w ON ((t.workstream_id = w.id)))
     LEFT JOIN public.profiles p ON ((t.assignee_id = p.id)))
  WHERE ((t.deleted_at IS NULL) AND (s.is_done = false) AND (t.due_date IS NOT NULL) AND (t.due_date <= (CURRENT_DATE + '14 days'::interval)))
  ORDER BY t.due_date, t.priority DESC
 LIMIT 20;


--
-- Name: planner_dashboard_workstream_health; Type: VIEW; Schema: public; Owner: -
