--
-- Name: planner_my_tasks; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.planner_my_tasks WITH (security_invoker='true') AS
 SELECT DISTINCT ON (t.id) t.id,
    t.task_key,
    t.title,
    t.description,
    t.status_id,
    t.priority,
    t.workstream_id,
    t.assignee_id,
    t.created_by,
    t.reporter_id,
    t.reviewer_id,
    t.due_date,
    t.start_date,
    t.time_estimate_minutes,
    t.time_logged_minutes,
    t.parent_task_id,
    t.sort_order,
    t.is_archived,
    t.created_at,
    t.updated_at,
    t.completed_at,
    t.key,
    t."position",
    t.deleted_at,
    t.is_starred,
    t.blocked,
    t.blocked_reason,
    t.progress,
    t.cover_url,
    s.name AS status_name,
    s.slug AS status_slug,
    s.color AS status_color,
    s.is_done AS status_is_done,
    w.name AS workstream_name,
    w.slug AS workstream_slug,
    w.color AS workstream_color,
    p_assignee.full_name AS assignee_name,
    p_assignee.avatar_url AS assignee_avatar,
    p_creator.full_name AS creator_name,
    p_reporter.full_name AS reporter_name,
    p_reviewer.full_name AS reviewer_name,
        CASE
            WHEN (t.assignee_id = auth.uid()) THEN 'assignee'::text
            WHEN (t.reviewer_id = auth.uid()) THEN 'reviewer'::text
            WHEN (t.created_by = auth.uid()) THEN 'creator'::text
            WHEN (t.reporter_id = auth.uid()) THEN 'reporter'::text
            WHEN (watcher.user_id IS NOT NULL) THEN 'watcher'::text
            WHEN (mention.user_id IS NOT NULL) THEN 'mentioned'::text
            ELSE 'assignee'::text
        END AS involvement_type,
        CASE
            WHEN (t.assignee_id = auth.uid()) THEN 1
            WHEN (t.reviewer_id = auth.uid()) THEN 2
            WHEN (t.created_by = auth.uid()) THEN 3
            WHEN (t.reporter_id = auth.uid()) THEN 4
            WHEN (watcher.user_id IS NOT NULL) THEN 5
            WHEN (mention.user_id IS NOT NULL) THEN 6
            ELSE 1
        END AS involvement_priority,
        CASE
            WHEN (t.completed_at IS NOT NULL) THEN 'completed'::text
            WHEN (t.due_date < CURRENT_DATE) THEN 'overdue'::text
            WHEN (t.due_date = CURRENT_DATE) THEN 'today'::text
            WHEN (t.due_date <= (CURRENT_DATE + 7)) THEN 'this_week'::text
            WHEN (t.due_date IS NOT NULL) THEN 'upcoming'::text
            ELSE 'someday'::text
        END AS time_section
   FROM ((((((((public.planner_tasks t
     LEFT JOIN public.planner_statuses s ON ((s.id = t.status_id)))
     LEFT JOIN public.planner_workstreams w ON ((w.id = t.workstream_id)))
     LEFT JOIN public.profiles p_assignee ON ((p_assignee.id = t.assignee_id)))
     LEFT JOIN public.profiles p_creator ON ((p_creator.id = t.created_by)))
     LEFT JOIN public.profiles p_reporter ON ((p_reporter.id = t.reporter_id)))
     LEFT JOIN public.profiles p_reviewer ON ((p_reviewer.id = t.reviewer_id)))
     LEFT JOIN public.planner_task_watchers watcher ON (((watcher.task_id = t.id) AND (watcher.user_id = auth.uid()))))
     LEFT JOIN public.planner_task_mentions mention ON (((mention.task_id = t.id) AND (mention.user_id = auth.uid()))))
  WHERE ((t.deleted_at IS NULL) AND (t.is_archived IS NOT TRUE) AND ((t.assignee_id = auth.uid()) OR (t.created_by = auth.uid()) OR (t.reporter_id = auth.uid()) OR (t.reviewer_id = auth.uid()) OR (watcher.user_id IS NOT NULL) OR (mention.user_id IS NOT NULL)))
  ORDER BY t.id,
        CASE
            WHEN (t.due_date < CURRENT_DATE) THEN 0
            WHEN (t.due_date = CURRENT_DATE) THEN 1
            WHEN (t.due_date <= (CURRENT_DATE + 7)) THEN 2
            ELSE 3
        END,
        CASE
            WHEN (t.assignee_id = auth.uid()) THEN 1
            WHEN (t.reviewer_id = auth.uid()) THEN 2
            WHEN (t.created_by = auth.uid()) THEN 3
            WHEN (t.reporter_id = auth.uid()) THEN 4
            ELSE 5
        END, t.due_date, t.sort_order;


--
-- Name: planner_my_tasks_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.planner_my_tasks_summary WITH (security_invoker='true') AS
 WITH user_tasks AS (
         SELECT t.id,
            t.assignee_id,
            t.created_by,
            t.reporter_id,
            t.reviewer_id,
            t.due_date,
            t.completed_at,
            (watcher.user_id IS NOT NULL) AS is_watcher,
            (mention.user_id IS NOT NULL) AS is_mentioned,
                CASE
                    WHEN (t.assignee_id = auth.uid()) THEN 'assignee'::text
                    WHEN (t.reviewer_id = auth.uid()) THEN 'reviewer'::text
                    WHEN (t.created_by = auth.uid()) THEN 'creator'::text
                    WHEN (t.reporter_id = auth.uid()) THEN 'reporter'::text
                    ELSE 'other'::text
                END AS direct_involvement
           FROM ((public.planner_tasks t
             LEFT JOIN public.planner_task_watchers watcher ON (((watcher.task_id = t.id) AND (watcher.user_id = auth.uid()))))
             LEFT JOIN public.planner_task_mentions mention ON (((mention.task_id = t.id) AND (mention.user_id = auth.uid()))))
          WHERE ((t.deleted_at IS NULL) AND (t.is_archived IS NOT TRUE) AND ((t.assignee_id = auth.uid()) OR (t.created_by = auth.uid()) OR (t.reporter_id = auth.uid()) OR (t.reviewer_id = auth.uid()) OR (watcher.user_id IS NOT NULL) OR (mention.user_id IS NOT NULL)))
        )
 SELECT auth.uid() AS user_id,
    count(*) FILTER (WHERE (completed_at IS NULL)) AS total_tasks,
    count(*) FILTER (WHERE ((completed_at IS NULL) AND (due_date < CURRENT_DATE))) AS overdue_count,
    count(*) FILTER (WHERE ((completed_at IS NULL) AND (due_date = CURRENT_DATE))) AS today_count,
    count(*) FILTER (WHERE ((completed_at IS NULL) AND (due_date > CURRENT_DATE) AND (due_date <= (CURRENT_DATE + 7)))) AS this_week_count,
    count(*) FILTER (WHERE ((completed_at IS NULL) AND (due_date > (CURRENT_DATE + 7)))) AS upcoming_count,
    count(*) FILTER (WHERE ((completed_at IS NULL) AND (due_date IS NULL))) AS someday_count,
    count(*) FILTER (WHERE ((completed_at IS NOT NULL) AND (date(completed_at) = CURRENT_DATE))) AS completed_today,
    count(*) FILTER (WHERE ((completed_at IS NULL) AND (direct_involvement = 'assignee'::text))) AS assigned_count,
    count(*) FILTER (WHERE ((completed_at IS NULL) AND (direct_involvement = 'creator'::text))) AS created_count,
    count(*) FILTER (WHERE ((completed_at IS NULL) AND (direct_involvement = 'reviewer'::text))) AS needs_review_count,
    count(*) FILTER (WHERE ((completed_at IS NULL) AND is_watcher)) AS watching_count
   FROM user_tasks;


