--
-- Name: planner_task_list; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.planner_task_list WITH (security_invoker='true') AS
 SELECT t.id,
    t.task_key,
    t.title,
    t.description,
    t.status_id,
    s.name AS status_name,
    s.slug AS status_slug,
    s.color AS status_color,
    COALESCE(s.is_done, false) AS status_is_done,
    t.priority,
    t.workstream_id,
    w.name AS workstream_name,
    w.slug AS workstream_slug,
    w.color AS workstream_color,
    t.assignee_id,
    p.full_name AS assignee_name,
    p.avatar_url AS assignee_avatar,
    t.due_date,
    t.start_date,
    t.progress,
    t.blocked,
    t.blocked_reason,
    t.time_estimate_minutes,
    t.time_logged_minutes,
    t.created_at,
    t.updated_at,
    t.created_by,
    creator.full_name AS creator_name,
    t.sort_order,
        CASE
            WHEN ((t.due_date < CURRENT_DATE) AND (COALESCE(s.is_done, false) = false)) THEN true
            ELSE false
        END AS is_overdue,
        CASE
            WHEN (t.due_date = CURRENT_DATE) THEN true
            ELSE false
        END AS is_due_today,
        CASE
            WHEN ((t.due_date IS NOT NULL) AND ((t.due_date >= CURRENT_DATE) AND (t.due_date <= (CURRENT_DATE + '2 days'::interval)))) THEN true
            ELSE false
        END AS is_due_soon
   FROM ((((public.planner_tasks t
     LEFT JOIN public.planner_statuses s ON ((t.status_id = s.id)))
     LEFT JOIN public.planner_workstreams w ON ((t.workstream_id = w.id)))
     LEFT JOIN public.profiles p ON ((t.assignee_id = p.id)))
     LEFT JOIN public.profiles creator ON ((t.created_by = creator.id)))
  WHERE (t.deleted_at IS NULL)
  ORDER BY
        CASE t.priority
            WHEN 'critical'::text THEN 0
            WHEN 'high'::text THEN 1
            WHEN 'medium'::text THEN 2
            WHEN 'low'::text THEN 3
            ELSE NULL::integer
        END, t.due_date, t.created_at DESC;


