--
-- Name: pri_items_full; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.pri_items_full WITH (security_invoker='true') AS
 SELECT i.id,
    i.list_id,
    i.week_id,
    i.title,
    i.description,
    i.status,
    i.rank,
    i.assignee_id,
    i.task_key,
    i.is_carryover,
    i.source_item_id,
    i.created_at,
    i.updated_at,
    p.full_name AS assignee_name,
    p.avatar_url AS assignee_avatar,
    COALESCE(( SELECT jsonb_agg(jsonb_build_object('id', l.id, 'name', l.name, 'color', l.color) ORDER BY l.name) AS jsonb_agg
           FROM (public.pri_item_labels il
             JOIN public.pri_labels l ON ((l.id = il.label_id)))
          WHERE (il.item_id = i.id)), '[]'::jsonb) AS labels,
    (( SELECT count(*) AS count
           FROM public.pri_item_notes n
          WHERE (n.item_id = i.id)))::integer AS note_count
   FROM (public.pri_items i
     LEFT JOIN public.profiles p ON ((p.id = i.assignee_id)));


