    CONSTRAINT pri_lists_workstream_check CHECK ((workstream = ANY (ARRAY['senaie'::text, 'catalyst'::text, 'tahommona'::text, 'delivery'::text, 'mim'::text, 'standalone'::text, 'dataai'::text])))
