    week_end date NOT NULL,
    status text DEFAULT 'active'::text NOT NULL,
    checked_out_at timestamp with time zone,
    checked_out_by uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT pri_weeks_status_check CHECK ((status = ANY (ARRAY['active'::text, 'checked_out'::text, 'archived'::text])))
);


--
-- Name: pri_lists_full; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.pri_lists_full WITH (security_invoker='true') AS
 SELECT l.id,
    l.title,
    l.description,
    l.owner_id,
    l.workstream,
    l.status,
    l.created_at,
    l.updated_at,
    p.full_name AS owner_name,
    p.avatar_url AS owner_avatar,
    ( SELECT w.id
           FROM public.pri_weeks w
          WHERE ((w.list_id = l.id) AND (w.status = 'active'::text))
          ORDER BY w.week_start DESC
         LIMIT 1) AS current_week_id,
    ( SELECT w.week_start
           FROM public.pri_weeks w
          WHERE ((w.list_id = l.id) AND (w.status = 'active'::text))
          ORDER BY w.week_start DESC
         LIMIT 1) AS current_week_start,
    ( SELECT w.week_end
           FROM public.pri_weeks w
          WHERE ((w.list_id = l.id) AND (w.status = 'active'::text))
          ORDER BY w.week_start DESC
         LIMIT 1) AS current_week_end,
    (( SELECT count(*) AS count
           FROM public.pri_weeks w
          WHERE (w.list_id = l.id)))::integer AS total_weeks,
    (( SELECT count(*) AS count
           FROM (public.pri_items i
             JOIN public.pri_weeks w ON ((w.id = i.week_id)))
          WHERE ((w.list_id = l.id) AND (w.status = 'active'::text))))::integer AS active_item_count,
    (( SELECT count(*) AS count
           FROM (public.pri_items i
             JOIN public.pri_weeks w ON ((w.id = i.week_id)))
          WHERE ((w.list_id = l.id) AND (w.status = 'active'::text) AND (i.status = 'completed'::text))))::integer AS completed_item_count
   FROM (public.pri_lists l
     LEFT JOIN public.profiles p ON ((p.id = l.owner_id)));


--
-- Name: pri_weeks_full; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.pri_weeks_full WITH (security_invoker='true') AS
 SELECT w.id,
    w.list_id,
    w.week_start,
    w.week_end,
    w.status,
    w.checked_out_at,
    w.checked_out_by,
    w.created_at,
    w.updated_at,
    p.full_name AS checked_out_by_name,
    (( SELECT count(*) AS count
           FROM public.pri_items i
          WHERE (i.week_id = w.id)))::integer AS total_items,
    (( SELECT count(*) AS count
           FROM public.pri_items i
          WHERE ((i.week_id = w.id) AND (i.status = 'todo'::text))))::integer AS todo_count,
    (( SELECT count(*) AS count
           FROM public.pri_items i
          WHERE ((i.week_id = w.id) AND (i.status = 'in_progress'::text))))::integer AS in_progress_count,
    (( SELECT count(*) AS count
           FROM public.pri_items i
          WHERE ((i.week_id = w.id) AND (i.status = 'completed'::text))))::integer AS completed_count,
    (( SELECT count(*) AS count
           FROM public.pri_items i
          WHERE ((i.week_id = w.id) AND (i.is_carryover = true))))::integer AS carryover_count,
    (( SELECT count(*) AS count
           FROM public.pri_items i
          WHERE ((i.week_id = w.id) AND (i.rank <= 10))))::integer AS top_count,
    (( SELECT count(*) AS count
           FROM public.pri_items i
          WHERE ((i.week_id = w.id) AND (i.rank > 10))))::integer AS overflow_count
   FROM (public.pri_weeks w
     LEFT JOIN public.profiles p ON ((p.id = w.checked_out_by)));


