--
-- Name: project_scores; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.project_scores (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    project_id uuid NOT NULL,
    strategic_alignment integer,
    business_impact integer,
    time_urgency integer,
    resource_feasibility integer,
    computed_score numeric(3,1) GENERATED ALWAYS AS (round((((((COALESCE(strategic_alignment, 0) + COALESCE(business_impact, 0)) + COALESCE(time_urgency, 0)) + COALESCE(resource_feasibility, 0)))::numeric / 4.0), 1)) STORED,
    scored_by uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT project_scores_business_impact_check CHECK (((business_impact >= 1) AND (business_impact <= 5))),
    CONSTRAINT project_scores_resource_feasibility_check CHECK (((resource_feasibility >= 1) AND (resource_feasibility <= 5))),
    CONSTRAINT project_scores_strategic_alignment_check CHECK (((strategic_alignment >= 1) AND (strategic_alignment <= 5))),
    CONSTRAINT project_scores_time_urgency_check CHECK (((time_urgency >= 1) AND (time_urgency <= 5)))
);


