--
-- Name: project_sync_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.project_sync_summary WITH (security_invoker='true') AS
 SELECT p.id AS project_id,
    p.key AS project_key,
    count(i.id) FILTER (WHERE ((i.source)::text = 'catalyst'::text)) AS catalyst_count,
    count(i.id) FILTER (WHERE ((i.source)::text = 'jira'::text)) AS jira_count,
    count(i.id) FILTER (WHERE ((i.sync_status)::text = 'conflict'::text)) AS conflict_count,
    count(i.id) FILTER (WHERE ((i.sync_status)::text = 'stale'::text)) AS stale_count,
    max(i.last_synced_at) AS last_synced_at
   FROM (public.ph_projects p
     LEFT JOIN public.ph_issues i ON ((i.project_key = (p.key)::text)))
  GROUP BY p.id, p.key;


