--
-- Name: r360_chronology_events_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.r360_chronology_events_view WITH (security_invoker='true') AS
 SELECT wi.resource_id,
    'assigned'::text AS event_type,
    (wi.assigned_date)::timestamp with time zone AS event_date,
    wi.id AS work_item_id,
    wi.item_key,
    wi.title,
    wi.work_item_type,
    wi.source_hub,
    wi.status_category,
    ab.full_name AS actor_name,
    rel.release_key
   FROM ((public.r360_work_items wi
     LEFT JOIN public.r360_resources ab ON ((ab.id = wi.assigned_by)))
     LEFT JOIN public.r360_releases rel ON ((rel.id = wi.release_id)))
  WHERE (wi.deleted_at IS NULL)
UNION ALL
 SELECT wi.resource_id,
    'status_change'::text AS event_type,
    st.transitioned_at AS event_date,
    wi.id AS work_item_id,
    wi.item_key,
    wi.title,
    wi.work_item_type,
    wi.source_hub,
    st.to_category AS status_category,
    NULL::character varying AS actor_name,
    rel.release_key
   FROM ((public.r360_status_transitions st
     JOIN public.r360_work_items wi ON (((wi.id = st.work_item_id) AND (wi.deleted_at IS NULL))))
     LEFT JOIN public.r360_releases rel ON ((rel.id = wi.release_id)))
UNION ALL
 SELECT wi.resource_id,
    'closed'::text AS event_type,
    (wi.resolved_date)::timestamp with time zone AS event_date,
    wi.id AS work_item_id,
    wi.item_key,
    wi.title,
    wi.work_item_type,
    wi.source_hub,
    'done'::public.r360_status_category AS status_category,
    NULL::character varying AS actor_name,
    rel.release_key
   FROM (public.r360_work_items wi
     LEFT JOIN public.r360_releases rel ON ((rel.id = wi.release_id)))
  WHERE ((wi.deleted_at IS NULL) AND (wi.resolved_date IS NOT NULL));


