--
-- Name: r360_constellation_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.r360_constellation_view WITH (security_invoker='true') AS
 SELECT r.id AS resource_id,
    r.full_name,
    r.initials,
    r.job_role,
    r.vendor_id,
    v.name AS vendor_name,
    count(wi.id) AS total_items,
    count(wi.id) FILTER (WHERE (wi.status_category = 'done'::public.r360_status_category)) AS done_items,
    count(DISTINCT wi.project_id) AS project_count
   FROM ((public.r360_resources r
     LEFT JOIN public.r360_work_items wi ON (((wi.resource_id = r.id) AND (wi.deleted_at IS NULL))))
     LEFT JOIN public.r360_vendors v ON ((v.id = r.vendor_id)))
  WHERE ((r.deleted_at IS NULL) AND (r.is_active = true))
  GROUP BY r.id, r.full_name, r.initials, r.job_role, r.vendor_id, v.name;


