--
-- Name: r360_gantt_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.r360_gantt_view WITH (security_invoker='true') AS
 SELECT wi.resource_id,
    wi.id AS work_item_id,
    wi.item_key,
    wi.title,
    wi.work_item_type,
    wi.status_category,
    wi.assigned_date AS bar_start,
    COALESCE(wi.resolved_date, CURRENT_DATE) AS bar_end,
    (COALESCE(wi.resolved_date, CURRENT_DATE) - wi.assigned_date) AS bar_days,
    rel.release_key,
    p.name AS project_name
   FROM ((public.r360_work_items wi
     LEFT JOIN public.r360_releases rel ON ((rel.id = wi.release_id)))
     LEFT JOIN public.r360_projects p ON ((p.id = wi.project_id)))
  WHERE (wi.deleted_at IS NULL)
  ORDER BY wi.assigned_date;


--
-- Name: r360_resource_hub_distribution_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.r360_resource_hub_distribution_view WITH (security_invoker='true') AS
 SELECT resource_id,
    source_hub,
    count(*) AS hub_item_count,
    round((((count(*))::numeric / NULLIF(sum(count(*)) OVER (PARTITION BY resource_id), (0)::numeric)) * (100)::numeric), 1) AS hub_pct,
    count(*) FILTER (WHERE (status_category = 'done'::public.r360_status_category)) AS hub_done_count,
    round((((count(*) FILTER (WHERE (status_category = 'done'::public.r360_status_category)))::numeric / (NULLIF(count(*), 0))::numeric) * (100)::numeric), 0) AS hub_closure_pct
   FROM public.r360_work_items wi
  WHERE (deleted_at IS NULL)
  GROUP BY resource_id, source_hub;


--
-- Name: r360_resource_summary_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.r360_resource_summary_view WITH (security_invoker='true') AS
 SELECT r.id AS resource_id,
    r.full_name,
    r.job_role,
    r.rid,
    count(wi.id) AS total_items,
    count(wi.id) FILTER (WHERE (wi.status_category = 'todo'::public.r360_status_category)) AS todo_count,
    count(wi.id) FILTER (WHERE (wi.status_category = 'progress'::public.r360_status_category)) AS progress_count,
    count(wi.id) FILTER (WHERE (wi.status_category = 'done'::public.r360_status_category)) AS done_count
   FROM (public.r360_resources r
     LEFT JOIN public.r360_work_items wi ON (((wi.resource_id = r.id) AND (wi.deleted_at IS NULL))))
  WHERE (r.deleted_at IS NULL)
  GROUP BY r.id, r.full_name, r.job_role, r.rid;


