--
-- Name: r360_unified_activity_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.r360_unified_activity_view WITH (security_invoker='true') AS
 SELECT ph.issue_key AS item_id,
    'jira'::text AS hub_source,
    ph.issue_type AS item_type,
    ph.summary AS title,
    ph.status,
        CASE
            WHEN (ph.status_category = 'Done'::text) THEN 'done'::text
            WHEN (ph.status_category = 'In Progress'::text) THEN 'in_progress'::text
            ELSE 'todo'::text
        END AS status_category,
    ph.priority,
    ph.assignee_account_id AS assignee_jira_id,
    NULL::uuid AS assignee_user_id,
    ph.project_name,
    ph.project_key,
    ph.fix_versions,
    ph.jira_created_at AS created_at,
    ph.jira_updated_at AS updated_at,
        CASE
            WHEN (ph.status_category = 'Done'::text) THEN ph.jira_updated_at
            ELSE NULL::timestamp with time zone
        END AS resolved_at,
    ph.due_date,
    ph.story_points,
    ph.parent_key,
    ph.parent_summary,
    ph.description_text
   FROM public.ph_issues ph
UNION ALL
 SELECT pw.item_key AS item_id,
    'producthub'::text AS hub_source,
    pw.item_type,
    COALESCE(pw.title, pw.summary) AS title,
    pw.status,
        CASE
            WHEN ((pw.resolved_at IS NOT NULL) OR (pw.completed_at IS NOT NULL)) THEN 'done'::text
            WHEN ((pw.status ~~* '%progress%'::text) OR (pw.status ~~* '%review%'::text)) THEN 'in_progress'::text
            ELSE 'todo'::text
        END AS status_category,
    pw.priority,
    NULL::text AS assignee_jira_id,
    pw.assignee_id AS assignee_user_id,
    NULL::text AS project_name,
    NULL::text AS project_key,
    NULL::jsonb AS fix_versions,
    pw.created_at,
    pw.updated_at,
    COALESCE(pw.resolved_at, pw.completed_at) AS resolved_at,
    pw.due_date,
    pw.story_points,
    NULL::text AS parent_key,
    NULL::text AS parent_summary,
    pw.description AS description_text
   FROM public.ph_work_items pw
UNION ALL
 SELECT td.defect_key AS item_id,
    'testhub'::text AS hub_source,
    'Defect'::text AS item_type,
    (td.title)::text AS title,
    (td.status)::text AS status,
        CASE
            WHEN (td.resolved_at IS NOT NULL) THEN 'done'::text
            WHEN ((td.status)::text ~~* '%progress%'::text) THEN 'in_progress'::text
            ELSE 'todo'::text
        END AS status_category,
    (td.priority)::text AS priority,
    NULL::text AS assignee_jira_id,
    td.assigned_to AS assignee_user_id,
    NULL::text AS project_name,
    NULL::text AS project_key,
    NULL::jsonb AS fix_versions,
    td.created_at,
    td.updated_at,
    td.resolved_at,
    td.due_date,
    NULL::numeric AS story_points,
    NULL::text AS parent_key,
    NULL::text AS parent_summary,
    td.description AS description_text
   FROM public.th_defects td
UNION ALL
 SELECT (tmd.defect_key)::text AS item_id,
    'testhub'::text AS hub_source,
    'Defect'::text AS item_type,
    (tmd.title)::text AS title,
    (tmd.status)::text AS status,
        CASE
            WHEN (tmd.resolved_at IS NOT NULL) THEN 'done'::text
            WHEN ((tmd.status)::text ~~* '%progress%'::text) THEN 'in_progress'::text
            ELSE 'todo'::text
        END AS status_category,
    (tmd.priority)::text AS priority,
    NULL::text AS assignee_jira_id,
    tmd.assignee_id AS assignee_user_id,
    NULL::text AS project_name,
    NULL::text AS project_key,
    NULL::jsonb AS fix_versions,
    tmd.created_at,
    tmd.updated_at,
    tmd.resolved_at,
    tmd.due_date,
    NULL::numeric AS story_points,
    NULL::text AS parent_key,
    NULL::text AS parent_summary,
    tmd.description AS description_text
   FROM public.tm_defects tmd
UNION ALL
 SELECT inc.incident_key AS item_id,
    'incidents'::text AS hub_source,
    COALESCE(inc.incident_type, 'Incident'::text) AS item_type,
    inc.title,
    (inc.status)::text AS status,
        CASE
            WHEN ((inc.resolved_at IS NOT NULL) OR (inc.closed_at IS NOT NULL)) THEN 'done'::text
            WHEN ((inc.status)::text ~~* '%progress%'::text) THEN 'in_progress'::text
            ELSE 'todo'::text
        END AS status_category,
    (inc.priority)::text AS priority,
    NULL::text AS assignee_jira_id,
    inc.assignee_id AS assignee_user_id,
    NULL::text AS project_name,
    NULL::text AS project_key,
    NULL::jsonb AS fix_versions,
    inc.created_at,
    inc.updated_at,
    COALESCE(inc.resolved_at, inc.closed_at) AS resolved_at,
    inc.target_date AS due_date,
    NULL::numeric AS story_points,
    NULL::text AS parent_key,
    NULL::text AS parent_summary,
    inc.description AS description_text
   FROM public.incidents inc
  WHERE (inc.deleted_at IS NULL)
UNION ALL
 SELECT (pt.id)::text AS item_id,
    'planner'::text AS hub_source,
    'Task'::text AS item_type,
    (pt.title)::text AS title,
    ps.name AS status,
        CASE
            WHEN ((ps.name)::text = 'Done'::text) THEN 'done'::text
            WHEN ((ps.name)::text = ANY (ARRAY[('In Progress'::character varying)::text, ('Review'::character varying)::text, ('Testing'::character varying)::text])) THEN 'in_progress'::text
            ELSE 'todo'::text
        END AS status_category,
    (pt.priority)::text AS priority,
    NULL::text AS assignee_jira_id,
    pt.assignee_id AS assignee_user_id,
    ws.name AS project_name,
    NULL::text AS project_key,
    NULL::jsonb AS fix_versions,
    pt.created_at,
    pt.updated_at,
    pt.completed_at AS resolved_at,
    pt.due_date,
    NULL::numeric AS story_points,
    NULL::text AS parent_key,
    NULL::text AS parent_summary,
    NULL::text AS description_text
   FROM ((public.planner_tasks pt
     LEFT JOIN public.planner_statuses ps ON ((ps.id = pt.status_id)))
     LEFT JOIN public.planner_workstreams ws ON ((ws.id = pt.workstream_id)))
UNION ALL
 SELECT (pht.id)::text AS item_id,
    'planhub'::text AS hub_source,
    (pht.type)::text AS item_type,
    pht.name AS title,
        CASE
            WHEN (pht.progress >= 100) THEN 'Done'::text
            WHEN (pht.progress > 0) THEN 'In Progress'::text
            ELSE 'Not Started'::text
        END AS status,
        CASE
            WHEN (pht.progress >= 100) THEN 'done'::text
            WHEN (pht.progress > 0) THEN 'in_progress'::text
            ELSE 'todo'::text
        END AS status_category,
    NULL::text AS priority,
    NULL::text AS assignee_jira_id,
    pht.assignee_id AS assignee_user_id,
    NULL::text AS project_name,
    NULL::text AS project_key,
    NULL::jsonb AS fix_versions,
    pht.created_at,
    pht.updated_at,
        CASE
            WHEN (pht.progress >= 100) THEN pht.updated_at
            ELSE NULL::timestamp with time zone
        END AS resolved_at,
    pht.end_date AS due_date,
    NULL::numeric AS story_points,
    NULL::text AS parent_key,
    NULL::text AS parent_summary,
    NULL::text AS description_text
   FROM public.planhub_tasks pht;


