--
-- Name: r360_work_items_enriched_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.r360_work_items_enriched_view WITH (security_invoker='true') AS
 SELECT wi.id,
    wi.item_key,
    wi.title,
    wi.description,
    wi.work_item_type,
    wi.source_hub,
    wi.status,
    wi.status_category,
    wi.priority,
    wi.project_id,
    wi.release_id,
    wi.parent_item_id,
    wi.resource_id,
    wi.resource_role,
    wi.assigned_by,
    wi.assigned_date,
    wi.due_date,
    wi.resolved_date,
    wi.source_table,
    wi.source_id,
    wi.created_at,
    wi.updated_at,
    wi.created_by,
    wi.updated_by,
    wi.deleted_at,
    (COALESCE(wi.resolved_date, CURRENT_DATE) - wi.assigned_date) AS age_days,
    r.full_name AS resource_name,
    r.initials AS resource_initials,
    r.job_role AS resource_job_role,
    ab.full_name AS assigned_by_name,
    p.name AS project_name,
    p.project_key,
    rel.release_key,
    rel.end_date AS release_end_date,
    parent.item_key AS parent_item_key,
    COALESCE(wi.due_date, rel.end_date) AS effective_due_date,
    (COALESCE(wi.due_date, rel.end_date) - CURRENT_DATE) AS days_until_due
   FROM (((((public.r360_work_items wi
     JOIN public.r360_resources r ON ((r.id = wi.resource_id)))
     LEFT JOIN public.r360_resources ab ON ((ab.id = wi.assigned_by)))
     LEFT JOIN public.r360_projects p ON ((p.id = wi.project_id)))
     LEFT JOIN public.r360_releases rel ON ((rel.id = wi.release_id)))
     LEFT JOIN public.r360_work_items parent ON ((parent.id = wi.parent_item_id)))
  WHERE (wi.deleted_at IS NULL);


