);


--
-- Name: r360md_chronology_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.r360md_chronology_view WITH (security_invoker='true') AS
 SELECT wi.id,
    wi.item_key,
    wi.title,
    wi.item_type,
    wi.priority,
    sc.name AS status_name,
    sc.category AS status_category,
    sc.color AS status_color,
    sc.bg_color AS status_bg_color,
    sc.dot_color AS status_dot_color,
    p.key_prefix AS project_key,
    p.name AS project_name,
    p.color AS project_color,
    m.full_name AS assignee_name,
    m.avatar_url AS assignee_avatar,
    m.id AS assignee_id,
    assigner.full_name AS assigner_name,
    assigner.avatar_url AS assigner_avatar,
    parent.item_key AS parent_key,
    parent.title AS parent_title,
    ((wi.updated_at AT TIME ZONE 'Asia/Riyadh'::text))::date AS group_date,
        CASE
            WHEN (((wi.updated_at AT TIME ZONE 'Asia/Riyadh'::text))::date = ((now() AT TIME ZONE 'Asia/Riyadh'::text))::date) THEN ('Today, '::text || to_char((wi.updated_at AT TIME ZONE 'Asia/Riyadh'::text), 'Mon DD'::text))
            WHEN (((wi.updated_at AT TIME ZONE 'Asia/Riyadh'::text))::date = (((now() AT TIME ZONE 'Asia/Riyadh'::text) - '1 day'::interval))::date) THEN ('Yesterday, '::text || to_char((wi.updated_at AT TIME ZONE 'Asia/Riyadh'::text), 'Mon DD'::text))
            ELSE to_char((wi.updated_at AT TIME ZONE 'Asia/Riyadh'::text), 'Dy, Mon DD'::text)
        END AS date_label,
    (EXTRACT(day FROM (now() - wi.created_at)))::integer AS age_days,
        CASE
            WHEN ((EXTRACT(day FROM (now() - wi.created_at)))::integer <= 7) THEN 'green'::text
            WHEN ((EXTRACT(day FROM (now() - wi.created_at)))::integer <= 14) THEN 'amber'::text
            ELSE 'red'::text
        END AS age_class,
    wi.release_name AS release,
    wi.due_date,
    wi.updated_at
   FROM (((((public.r360md_work_items wi
     JOIN public.r360md_status_config sc ON ((wi.status_id = sc.id)))
     JOIN public.r360md_projects p ON ((wi.project_id = p.id)))
     JOIN public.r360md_members m ON ((wi.assigned_to = m.id)))
     LEFT JOIN public.r360md_members assigner ON ((wi.assigner_id = assigner.id)))
     LEFT JOIN public.r360md_work_items parent ON ((wi.parent_item_id = parent.id)))
  ORDER BY wi.updated_at DESC;


--
-- Name: r360md_date_group_stats_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.r360md_date_group_stats_view WITH (security_invoker='true') AS
 SELECT ((wi.updated_at AT TIME ZONE 'Asia/Riyadh'::text))::date AS group_date,
    count(*) AS total_count,
    count(*) FILTER (WHERE (sc.category = 'completed'::text)) AS done_count,
    count(*) FILTER (WHERE (sc.category = 'started'::text)) AS in_progress_count,
    count(*) FILTER (WHERE (sc.category = 'unstarted'::text)) AS todo_count,
    count(*) FILTER (WHERE (sc.category = 'blocked'::text)) AS blocked_count,
    round((((count(*) FILTER (WHERE (sc.category = 'completed'::text)))::numeric / (NULLIF(count(*), 0))::numeric) * (100)::numeric), 0) AS progress_pct
   FROM (public.r360md_work_items wi
     JOIN public.r360md_status_config sc ON ((wi.status_id = sc.id)))
  GROUP BY (((wi.updated_at AT TIME ZONE 'Asia/Riyadh'::text))::date)
  ORDER BY (((wi.updated_at AT TIME ZONE 'Asia/Riyadh'::text))::date) DESC;


--
-- Name: r360md_member_kpis_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.r360md_member_kpis_view WITH (security_invoker='true') AS
 SELECT m.id AS member_id,
    count(wi.id) AS total_items,
    count(wi.id) FILTER (WHERE (sc.category <> 'completed'::text)) AS open_items,
    count(wi.id) FILTER (WHERE ((sc.category <> 'completed'::text) AND (EXTRACT(day FROM (now() - wi.created_at)) > (14)::numeric))) AS stale_items,
    round((((count(wi.id) FILTER (WHERE (sc.category = 'completed'::text)))::numeric / (NULLIF(count(wi.id), 0))::numeric) * (100)::numeric), 1) AS closure_pct,
    round(avg(EXTRACT(day FROM (now() - wi.created_at))), 1) AS avg_age_days
   FROM ((public.r360md_members m
     LEFT JOIN public.r360md_work_items wi ON ((wi.assigned_to = m.id)))
     LEFT JOIN public.r360md_status_config sc ON ((wi.status_id = sc.id)))
  GROUP BY m.id;


