--
-- Name: resource_current_cost; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.resource_current_cost WITH (security_invoker='true') AS
 SELECT DISTINCT ON (resource_id) id,
    resource_id,
    resource_type,
    monthly_cost,
    (monthly_cost * (12)::numeric) AS annual_cost,
    effective_from,
    effective_to,
    created_at,
    created_by
   FROM public.resource_cost_history
  WHERE ((effective_from <= CURRENT_DATE) AND ((effective_to IS NULL) OR (effective_to >= CURRENT_DATE)))
  ORDER BY resource_id, effective_from DESC;


