--
-- Name: rh_command_center_kpis; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.rh_command_center_kpis AS
 SELECT ( SELECT count(*) AS count
           FROM public.rh_releases
          WHERE (rh_releases.status = ANY (ARRAY['planning'::text, 'in_progress'::text]))) AS active_releases,
    ( SELECT count(*) AS count
           FROM public.rh_changes
          WHERE (rh_changes.status <> 'in_production'::text)) AS changes_in_flight,
    ( SELECT count(*) AS count
           FROM public.rh_change_signoffs
          WHERE (rh_change_signoffs.status = ANY (ARRAY['pending'::text, 'waiting'::text]))) AS signoffs_pending,
    ( SELECT count(*) AS count
           FROM public.rh_change_test_cycles
          WHERE (rh_change_test_cycles.result = 'IN_PROGRESS'::text)) AS test_cycles_running,
    ( SELECT count(*) AS count
           FROM public.rh_changes
          WHERE (rh_changes.release_id IS NULL)) AS triage_count;


