    NULL::text AS jira_key,
    NULL::date AS target_date,
    NULL::uuid AS owner_id,
    NULL::uuid AS project_id,
    NULL::integer AS chg_count,
    NULL::timestamp with time zone AS created_at,
    NULL::timestamp with time zone AS updated_at,
    NULL::bigint AS change_count,
    NULL::bigint AS completed_change_count,
    NULL::bigint AS test_cycle_count,
    NULL::integer AS days_remaining,
    NULL::boolean AS is_overdue;


