--
-- Name: sla_dashboard_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.sla_dashboard_view WITH (security_invoker='true') AS
 SELECT count(*) AS total_incidents,
    count(*) FILTER (WHERE (s.resolution_breached = true)) AS breached_count,
    count(*) FILTER (WHERE ((s.resolution_breached = false) AND (s.resolution_due_at < (now() + '02:00:00'::interval)) AND (i.status <> ALL (ARRAY['resolved'::public.incident_status, 'closed'::public.incident_status, 'converted'::public.incident_status])))) AS at_risk_count,
    count(*) FILTER (WHERE (i.severity = 'SEV1'::public.severity_level)) AS sev1_count,
    count(*) FILTER (WHERE (i.severity = 'SEV2'::public.severity_level)) AS sev2_count,
    avg(EXTRACT(day FROM (COALESCE(i.resolved_at, now()) - i.created_at))) AS avg_resolution_days
   FROM (public.incidents i
     LEFT JOIN public.sla_records s ON ((s.incident_id = i.id)))
  WHERE (i.deleted_at IS NULL);


