--
-- Name: slack_connected_users; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.slack_connected_users WITH (security_invoker='true') AS
 SELECT ui.id,
    ui.user_id,
    p.full_name,
    p.email,
    p.avatar_url,
    ui.slack_user_id,
    ui.slack_team_id,
    ui.slack_team_name,
    ui.is_active,
    ui.connected_at,
    ui.disconnected_at,
    ( SELECT count(*) AS count
           FROM (public.notification_delivery_log ndl
             JOIN public.user_notifications un ON ((un.id = ndl.notification_id)))
          WHERE ((un.user_id = ui.user_id) AND ((ndl.channel)::text = 'slack'::text) AND ((ndl.status)::text = 'delivered'::text))) AS notifications_sent,
    ( SELECT max(ndl.delivered_at) AS max
           FROM (public.notification_delivery_log ndl
             JOIN public.user_notifications un ON ((un.id = ndl.notification_id)))
          WHERE ((un.user_id = ui.user_id) AND ((ndl.channel)::text = 'slack'::text))) AS last_notification_at
   FROM (public.user_integrations ui
     JOIN public.profiles p ON ((p.id = ui.user_id)))
  WHERE ((ui.integration_type)::text = 'slack'::text);


