);


--
-- Name: t10_completed_items_detail; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.t10_completed_items_detail WITH (security_invoker='true') AS
 SELECT i.id AS item_id,
    i.week_id,
    i.rank,
    i.title,
    i.description,
    i.taskhub_key,
    i.due_date,
    i.status AS item_status,
    i.completed_at,
    i.carryover_count,
    i.is_buffer,
    i.carried_from_week_id,
    i.created_at AS item_created_at,
    i.assignee_id,
    ap.full_name AS assignee_name,
    ap.avatar_url AS assignee_avatar,
    w.week_start,
    w.week_end,
    w.list_id,
    l.key AS list_key,
    l.name AS list_name,
    COALESCE(( SELECT json_agg(json_build_object('id', lb.id, 'name', lb.name, 'color', lb.color) ORDER BY lb.name) AS json_agg
           FROM (public.t10_item_labels il
             JOIN public.t10_labels lb ON ((il.label_id = lb.id)))
          WHERE (il.item_id = i.id)), '[]'::json) AS labels
   FROM (((public.t10_items i
     JOIN public.t10_weeks w ON ((w.id = i.week_id)))
     JOIN public.t10_lists l ON ((l.id = w.list_id)))
     LEFT JOIN public.profiles ap ON ((i.assignee_id = ap.id)))
  WHERE ((w.status)::text = 'completed'::text)
  ORDER BY i.rank;


--
-- Name: t10_completed_weeks_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.t10_completed_weeks_summary WITH (security_invoker='true') AS
 SELECT w.id AS week_id,
    w.list_id,
    w.week_start,
    w.week_end,
    w.status AS week_status,
    w.checkout_at,
    w.checkout_by,
    l.key AS list_key,
    l.name AS list_name,
    cp.full_name AS checkout_by_name,
    cp.avatar_url AS checkout_by_avatar,
    COALESCE((w.total_count)::bigint, ( SELECT count(*) AS count
           FROM public.t10_items
          WHERE (t10_items.week_id = w.id))) AS total_count,
    COALESCE((w.completed_count)::bigint, ( SELECT count(*) AS count
           FROM public.t10_items
          WHERE ((t10_items.week_id = w.id) AND ((t10_items.status)::text = ANY (ARRAY['done'::text, 'completed'::text]))))) AS completed_count,
    COALESCE((w.carried_forward_count)::bigint, ( SELECT count(*) AS count
           FROM public.t10_items
          WHERE ((t10_items.week_id = w.id) AND ((t10_items.status)::text = 'carried_forward'::text)))) AS carried_forward_count,
    COALESCE((w.dropped_count)::bigint, ( SELECT count(*) AS count
           FROM public.t10_items
          WHERE ((t10_items.week_id = w.id) AND ((t10_items.status)::text = 'dropped'::text)))) AS dropped_count,
        CASE
            WHEN (COALESCE(w.total_count, 0) = 0) THEN (0)::numeric
            ELSE round((((COALESCE(w.completed_count, 0))::numeric / (COALESCE(w.total_count, 1))::numeric) * (100)::numeric), 1)
        END AS completion_rate,
    row_number() OVER (PARTITION BY w.list_id ORDER BY w.week_start) AS week_number,
    count(*) OVER (PARTITION BY w.list_id) AS total_weeks_in_list
   FROM ((public.t10_weeks w
     JOIN public.t10_lists l ON ((l.id = w.list_id)))
     LEFT JOIN public.profiles cp ON ((w.checkout_by = cp.id)))
  WHERE ((w.status)::text = 'completed'::text)
  ORDER BY w.checkout_at DESC NULLS LAST, w.week_end DESC;


--
-- Name: t10_completed_summary_stats; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.t10_completed_summary_stats WITH (security_invoker='true') AS
 SELECT (COALESCE(count(DISTINCT list_id), (0)::bigint))::integer AS total_lists_completed,
    (COALESCE(count(*), (0)::bigint))::integer AS total_weeks_completed,
    COALESCE(round(avg(
        CASE
            WHEN (total_count = 0) THEN (0)::numeric
            ELSE (((completed_count)::numeric / (total_count)::numeric) * (100)::numeric)
        END), 1), (0)::numeric) AS avg_completion_rate,
    (COALESCE(sum(completed_count), (0)::numeric))::integer AS total_items_completed,
    (COALESCE(sum(carried_forward_count), (0)::numeric))::integer AS total_carried_forward,
    (COALESCE(sum(dropped_count), (0)::numeric))::integer AS total_dropped
   FROM public.t10_completed_weeks_summary;


--
-- Name: t10_completed_weeks; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.t10_completed_weeks WITH (security_invoker='true') AS
 SELECT w.id AS week_id,
    w.list_id,
    l.key AS list_key,
    l.name AS list_name,
    w.week_start,
    w.week_end,
    w.total_count,
    w.completed_count,
    w.carried_forward_count,
    w.dropped_count,
    w.checkout_at,
    w.checkout_by,
    p.full_name AS checkout_by_name,
        CASE
            WHEN (w.total_count > 0) THEN round((((w.completed_count)::numeric / (w.total_count)::numeric) * (100)::numeric))
            ELSE (0)::numeric
        END AS completion_rate,
        CASE
            WHEN (w.completed_count = w.total_count) THEN 'full'::text
            WHEN ((w.completed_count)::numeric >= ((w.total_count)::numeric * 0.7)) THEN 'partial'::text
            ELSE 'low'::text
        END AS status_badge
   FROM ((public.t10_weeks w
     JOIN public.t10_lists l ON ((l.id = w.list_id)))
     LEFT JOIN public.profiles p ON ((w.checkout_by = p.id)))
  WHERE ((w.status)::text = 'completed'::text)
  ORDER BY w.checkout_at DESC NULLS LAST;


--
-- Name: t10_items_full; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.t10_items_full WITH (security_invoker='true') AS
 SELECT i.id,
    i.week_id,
    i.rank,
    i.title,
    i.description,
    i.taskhub_key,
    i.assignee_id,
    i.due_date,
    i.status,
    i.carryover_count,
    i.is_buffer,
    i.created_by,
    i.created_at,
    i.updated_at,
    p.full_name AS assignee_name,
    p.avatar_url AS assignee_avatar,
    COALESCE(( SELECT json_agg(json_build_object('id', lb.id, 'name', lb.name, 'color', lb.color) ORDER BY lb.name) AS json_agg
           FROM (public.t10_item_labels il
             JOIN public.t10_labels lb ON ((il.label_id = lb.id)))
          WHERE (il.item_id = i.id)), '[]'::json) AS labels
   FROM (public.t10_items i
     LEFT JOIN public.profiles p ON ((i.assignee_id = p.id)));


--
-- Name: t10_list_cards; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.t10_list_cards WITH (security_invoker='true') AS
 SELECT l.id,
    l.key,
    l.name,
    l.description,
    l.status,
    l.created_at,
    l.updated_at,
    l.created_by,
    l.archived_at,
    l.archived_by,
    p.full_name AS creator_name,
    p.avatar_url AS creator_avatar,
    cw.id AS current_week_id,
    cw.week_start,
    cw.week_end,
    COALESCE(cw.total_count, 0) AS total_count,
    COALESCE(cw.completed_count, 0) AS completed_count,
    GREATEST(0, (10 - COALESCE(cw.total_count, 0))) AS slots_available,
        CASE
            WHEN (COALESCE(cw.total_count, 0) > 0) THEN round((((cw.completed_count)::numeric / (cw.total_count)::numeric) * (100)::numeric))
            ELSE (0)::numeric
        END AS completion_percent,
    ( SELECT count(*) AS count
           FROM public.t10_weeks
          WHERE ((t10_weeks.list_id = l.id) AND (t10_weeks.is_current = false))) AS past_weeks_count,
    COALESCE(( SELECT json_agg(json_build_object('id', pw.id, 'week_start', pw.week_start, 'week_end', pw.week_end, 'completed_count', pw.completed_count, 'total_count', pw.total_count, 'is_complete', ((pw.completed_count = pw.total_count) AND (pw.total_count > 0)), 'status', pw.status) ORDER BY pw.week_start DESC) AS json_agg
           FROM ( SELECT t10_weeks.id,
                    t10_weeks.week_start,
                    t10_weeks.week_end,
                    t10_weeks.completed_count,
                    t10_weeks.total_count,
                    t10_weeks.status
                   FROM public.t10_weeks
                  WHERE ((t10_weeks.list_id = l.id) AND (t10_weeks.is_current = false))
                  ORDER BY t10_weeks.week_start DESC
                 LIMIT 10) pw), '[]'::json) AS past_weeks
   FROM ((public.t10_lists l
     LEFT JOIN public.profiles p ON ((l.created_by = p.id)))
     LEFT JOIN public.t10_weeks cw ON (((cw.list_id = l.id) AND (cw.is_current = true))))
  ORDER BY
        CASE
            WHEN ((l.status)::text = 'archived'::text) THEN 1
            ELSE 0
        END, l.updated_at DESC;


--
-- Name: t10_list_key_seq; Type: SEQUENCE; Schema: public; Owner: -
--

CREATE SEQUENCE public.t10_list_key_seq
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1;


--
-- Name: t10_list_performance; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.t10_list_performance AS
SELECT
    NULL::uuid AS list_id,
    NULL::character varying(10) AS list_key,
    NULL::character varying(100) AS list_name,
    NULL::bigint AS total_weeks,
    NULL::numeric AS avg_completion_rate,
    NULL::bigint AS total_completed,
    NULL::bigint AS total_carried_forward,
    NULL::json AS weeks_breakdown,
    NULL::json AS recurring_carryovers;


--
-- Name: t10_list_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.t10_list_summary WITH (security_invoker='true') AS
 SELECT l.id,
    l.key,
    l.name,
    l.description,
    l.status,
    l.created_by,
    l.created_at,
    l.updated_at,
    p.full_name AS creator_name,
    p.avatar_url AS creator_avatar,
    cw.id AS current_week_id,
    cw.week_start,
    cw.week_end,
    cw.status AS week_status,
    COALESCE(cw.completed_count, 0) AS completed_count,
    COALESCE(cw.total_count, 0) AS total_count,
    ( SELECT count(*) AS count
           FROM public.t10_weeks
          WHERE (t10_weeks.list_id = l.id)) AS total_weeks
   FROM ((public.t10_lists l
     LEFT JOIN public.profiles p ON ((l.created_by = p.id)))
     LEFT JOIN public.t10_weeks cw ON (((cw.list_id = l.id) AND (cw.is_current = true))));


--
-- Name: t10_week_items; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.t10_week_items WITH (security_invoker='true') AS
 SELECT i.id,
    i.week_id,
    i.rank,
    i.title,
    i.description,
    i.status,
    i.taskhub_key,
    i.due_date,
    i.completed_at,
    i.carryover_count,
    i.is_buffer,
    i.assignee_id,
    p.full_name AS assignee_name,
    p.avatar_url AS assignee_avatar,
    w.week_start,
    w.week_end,
    l.id AS list_id,
    l.key AS list_key,
    l.name AS list_name,
    COALESCE(( SELECT json_agg(json_build_object('id', lb.id, 'name', lb.name, 'color', lb.color)) AS json_agg
           FROM (public.t10_item_labels il
             JOIN public.t10_labels lb ON ((il.label_id = lb.id)))
          WHERE (il.item_id = i.id)), '[]'::json) AS labels
   FROM (((public.t10_items i
     JOIN public.t10_weeks w ON ((w.id = i.week_id)))
     JOIN public.t10_lists l ON ((l.id = w.list_id)))
     LEFT JOIN public.profiles p ON ((i.assignee_id = p.id)))
  ORDER BY i.rank;


