--
-- Name: tm_folders_with_counts; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.tm_folders_with_counts WITH (security_invoker='true') AS
 SELECT f.id,
    f.project_id,
    f.name,
    f.parent_id,
    f.path,
    f.depth,
    f.case_count,
    f.sort_order,
    f.created_by,
    f.created_at,
    f.updated_at,
    f.icon,
    f.color,
    f.description,
    COALESCE(tc.test_case_count, (0)::bigint) AS test_case_count,
    COALESCE(sf.subfolder_count, (0)::bigint) AS subfolder_count
   FROM ((public.tm_folders f
     LEFT JOIN ( SELECT tm_test_cases.folder_id,
            count(*) AS test_case_count
           FROM public.tm_test_cases
          GROUP BY tm_test_cases.folder_id) tc ON ((f.id = tc.folder_id)))
     LEFT JOIN ( SELECT tm_folders.parent_id,
            count(*) AS subfolder_count
           FROM public.tm_folders
          GROUP BY tm_folders.parent_id) sf ON ((f.id = sf.parent_id)));


