--
-- Name: v_project_list; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_project_list AS
 SELECT p.id,
    p.key AS project_key,
    p.name,
    p.department,
    p.description,
    COALESCE(p.display_status, (p.status)::text) AS status,
    p.health_status,
    p.status_category,
    COALESCE(pic.epic_count, p.total_epics) AS total_epics,
    COALESCE(pic.feature_count, 0) AS total_features,
    COALESCE(pic.story_count, p.total_stories) AS total_stories,
    COALESCE(pic.task_count, p.total_tasks) AS total_tasks,
    COALESCE(pic.todo_count, p.work_items_todo) AS work_items_todo,
    COALESCE(pic.in_progress_count, p.work_items_in_progress) AS work_items_in_progress,
    COALESCE(pic.done_count, p.work_items_done) AS work_items_done,
        CASE
            WHEN (COALESCE(pic.total_count, 0) > 0) THEN ((COALESCE(pic.done_count, 0) * 100) / pic.total_count)
            ELSE p.completion_percentage
        END AS completion_percentage,
    COALESCE(pic.total_count, ((p.total_epics + p.total_stories) + p.total_tasks)) AS total_issues,
    p.updated_at,
    p.created_at,
    p.owner_id,
    p.priority,
    p.tags,
    COALESCE(mc.member_count, 0) AS member_count,
    mc.member_ids,
    php.updated_at AS last_synced_at,
    p.lead_id,
    lp.full_name AS lead_name,
    lp.avatar_url AS lead_avatar_url
   FROM ((((public.projects p
     LEFT JOIN LATERAL ( SELECT (count(*))::integer AS member_count,
            array_agg(pm.user_id) AS member_ids
           FROM public.project_members pm
          WHERE (pm.project_id = p.id)) mc ON (true))
     LEFT JOIN public.ph_projects php ON ((((php.key)::text = p.key) AND (php.is_archived = false))))
     LEFT JOIN LATERAL ( SELECT (count(*))::integer AS total_count,
            (count(*) FILTER (WHERE (i.issue_type = 'Epic'::text)))::integer AS epic_count,
            (count(*) FILTER (WHERE (i.issue_type = 'Feature'::text)))::integer AS feature_count,
            (count(*) FILTER (WHERE (i.issue_type = 'Story'::text)))::integer AS story_count,
            (count(*) FILTER (WHERE (i.issue_type = ANY (ARRAY['Task'::text, 'Sub-task'::text, 'Bug'::text]))))::integer AS task_count,
            (count(*) FILTER (WHERE (i.status = ANY (ARRAY['to_do'::text, 'To Do'::text, 'backlog'::text, 'Backlog'::text, 'open'::text, 'Open'::text]))))::integer AS todo_count,
            (count(*) FILTER (WHERE (i.status = ANY (ARRAY['in_progress'::text, 'In Progress'::text, 'in_review'::text, 'In Review'::text]))))::integer AS in_progress_count,
            (count(*) FILTER (WHERE (i.status = ANY (ARRAY['done'::text, 'Done'::text, 'closed'::text, 'Closed'::text, 'resolved'::text, 'Resolved'::text]))))::integer AS done_count
           FROM public.ph_issues i
          WHERE (i.project_key = p.key)) pic ON (true))
     LEFT JOIN public.profiles lp ON ((lp.id = p.lead_id)))
  WHERE (p.status = 'active'::public.program_status)
UNION ALL
 SELECT ph.id,
    ph.key AS project_key,
    ph.name,
    ph.department,
    ph.description,
    COALESCE(ph.status, 'active'::character varying) AS status,
    ph.health AS health_status,
    NULL::text AS status_category,
    COALESCE(pic2.epic_count, 0) AS total_epics,
    COALESCE(pic2.feature_count, 0) AS total_features,
    COALESCE(pic2.story_count, 0) AS total_stories,
    COALESCE(pic2.task_count, 0) AS total_tasks,
    COALESCE(pic2.todo_count, 0) AS work_items_todo,
    COALESCE(pic2.in_progress_count, 0) AS work_items_in_progress,
    COALESCE(pic2.done_count, 0) AS work_items_done,
        CASE
            WHEN (COALESCE(pic2.total_count, 0) > 0) THEN ((COALESCE(pic2.done_count, 0) * 100) / pic2.total_count)
            ELSE 0
        END AS completion_percentage,
    COALESCE(pic2.total_count, 0) AS total_issues,
    ph.updated_at,
    ph.created_at,
    ph.created_by AS owner_id,
    ph.priority,
    NULL::text[] AS tags,
    COALESCE(phmc.member_count, 0) AS member_count,
    phmc.member_ids,
    ph.updated_at AS last_synced_at,
    NULL::uuid AS lead_id,
    NULL::text AS lead_name,
    NULL::text AS lead_avatar_url
   FROM ((public.ph_projects ph
     LEFT JOIN LATERAL ( SELECT (count(*))::integer AS member_count,
            array_agg(pm.user_id) AS member_ids
           FROM public.ph_project_members pm
          WHERE (pm.project_id = ph.id)) phmc ON (true))
     LEFT JOIN LATERAL ( SELECT (count(*))::integer AS total_count,
            (count(*) FILTER (WHERE (i.issue_type = 'Epic'::text)))::integer AS epic_count,
            (count(*) FILTER (WHERE (i.issue_type = 'Feature'::text)))::integer AS feature_count,
            (count(*) FILTER (WHERE (i.issue_type = 'Story'::text)))::integer AS story_count,
            (count(*) FILTER (WHERE (i.issue_type = ANY (ARRAY['Task'::text, 'Sub-task'::text, 'Bug'::text]))))::integer AS task_count,
            (count(*) FILTER (WHERE (i.status = ANY (ARRAY['to_do'::text, 'To Do'::text, 'backlog'::text, 'Backlog'::text, 'open'::text, 'Open'::text]))))::integer AS todo_count,
            (count(*) FILTER (WHERE (i.status = ANY (ARRAY['in_progress'::text, 'In Progress'::text, 'in_review'::text, 'In Review'::text]))))::integer AS in_progress_count,
            (count(*) FILTER (WHERE (i.status = ANY (ARRAY['done'::text, 'Done'::text, 'closed'::text, 'Closed'::text, 'resolved'::text, 'Resolved'::text]))))::integer AS done_count
           FROM public.ph_issues i
          WHERE (i.project_key = (ph.key)::text)) pic2 ON (true))
  WHERE ((ph.is_archived = false) AND (NOT (EXISTS ( SELECT 1
           FROM public.projects p2
          WHERE ((p2.key = (ph.key)::text) AND (p2.status = 'active'::public.program_status))))));


--
-- Name: v_tm_cycle_progress; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tm_cycle_progress WITH (security_invoker='true') AS
 SELECT c.id,
    c.project_id,
    c.cycle_key,
    c.name,
    c.description,
    c.status,
    c.environment_id,
    c.planned_start,
    c.planned_end,
    c.actual_start,
    c.actual_end,
    c.total_cases,
    c.passed_count,
    c.failed_count,
    c.blocked_count,
    c.skipped_count,
    c.not_run_count,
    c.created_by,
    c.created_at,
    c.updated_at,
    p.name AS project_name,
    p.key AS project_key,
    e.name AS environment_name,
    creator.full_name AS created_by_name,
        CASE
            WHEN (c.total_cases = 0) THEN (0)::numeric
            ELSE round(((((c.passed_count + c.skipped_count))::numeric / (c.total_cases)::numeric) * (100)::numeric), 2)
        END AS progress_percent,
        CASE
            WHEN (c.status = 'completed'::public.tm_cycle_status) THEN 'completed'::text
            WHEN ((c.planned_end < now()) AND (c.status <> 'completed'::public.tm_cycle_status)) THEN 'overdue'::text
            WHEN (c.planned_start > now()) THEN 'upcoming'::text
            ELSE 'on_track'::text
        END AS schedule_status
   FROM (((public.tm_test_cycles c
     LEFT JOIN public.tm_projects p ON ((c.project_id = p.id)))
     LEFT JOIN public.tm_environments e ON ((c.environment_id = e.id)))
     LEFT JOIN public.profiles creator ON ((c.created_by = creator.id)));


--
-- Name: v_tm_execution_by_assignee; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tm_execution_by_assignee WITH (security_invoker='true') AS
 SELECT cs.assigned_to AS user_id,
    u.full_name AS assignee_name,
    c.id AS cycle_id,
    c.name AS cycle_name,
    c.project_id,
    count(*) AS total_assigned,
    count(*) FILTER (WHERE (cs.current_status = 'passed'::public.tm_execution_status)) AS passed,
    count(*) FILTER (WHERE (cs.current_status = 'failed'::public.tm_execution_status)) AS failed,
    count(*) FILTER (WHERE (cs.current_status = 'blocked'::public.tm_execution_status)) AS blocked,
    count(*) FILTER (WHERE (cs.current_status = 'not_run'::public.tm_execution_status)) AS not_run,
        CASE
            WHEN (count(*) = 0) THEN (0)::numeric
            ELSE round((((count(*) FILTER (WHERE (cs.current_status <> ALL (ARRAY['not_run'::public.tm_execution_status, 'in_progress'::public.tm_execution_status]))))::numeric / (count(*))::numeric) * (100)::numeric), 2)
        END AS completion_percent
   FROM ((public.tm_cycle_scope cs
     JOIN public.tm_test_cycles c ON ((cs.cycle_id = c.id)))
     LEFT JOIN public.profiles u ON ((cs.assigned_to = u.id)))
  WHERE (cs.assigned_to IS NOT NULL)
  GROUP BY cs.assigned_to, u.full_name, c.id, c.name, c.project_id;


--
-- Name: v_tm_my_work; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tm_my_work WITH (security_invoker='true') AS
 SELECT cs.assigned_to AS user_id,
    'cycle_scope'::text AS work_type,
    cs.id AS item_id,
    tc.case_key AS item_key,
    tc.title AS item_title,
    cs.current_status AS status,
    c.name AS context_name,
    c.id AS context_id,
    c.planned_end AS due_date,
        CASE
            WHEN (c.planned_end < now()) THEN 'overdue'::text
            WHEN (c.planned_end < (now() + '2 days'::interval)) THEN 'due_soon'::text
            ELSE 'normal'::text
        END AS urgency,
    cs.added_at AS assigned_at
   FROM ((public.tm_cycle_scope cs
     JOIN public.tm_test_cycles c ON ((cs.cycle_id = c.id)))
     JOIN public.tm_test_cases tc ON ((cs.test_case_id = tc.id)))
  WHERE ((cs.current_status = ANY (ARRAY['not_run'::public.tm_execution_status, 'in_progress'::public.tm_execution_status, 'blocked'::public.tm_execution_status])) AND (c.status = ANY (ARRAY['planned'::public.tm_cycle_status, 'in_progress'::public.tm_cycle_status])));


--
-- Name: v_tm_test_cases_full; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tm_test_cases_full WITH (security_invoker='true') AS
 SELECT tc.id,
    tc.project_id,
    tc.folder_id,
    tc.case_key,
    tc.title,
    tc.description,
    tc.preconditions,
    tc.expected_result,
    tc.status,
    tc.priority_id,
    tc.case_type_id,
    tc.estimated_time,
    tc.automation_status,
    tc.automation_id,
    tc.version,
    tc.is_template,
    tc.custom_fields,
    tc.created_by,
    tc.created_at,
    tc.updated_at,
    p.name AS project_name,
    p.key AS project_key,
    f.name AS folder_name,
    f.path AS folder_path,
    cp.name AS priority_name,
    cp.color AS priority_color,
    ct.name AS type_name,
    ct.color AS type_color,
    creator.full_name AS created_by_name,
    COALESCE(( SELECT json_agg(json_build_object('id', l.id, 'name', l.name, 'color', l.color)) AS json_agg
           FROM (public.tm_case_labels cl
             JOIN public.tm_labels l ON ((cl.label_id = l.id)))
          WHERE (cl.test_case_id = tc.id)), '[]'::json) AS labels,
    ( SELECT count(*) AS count
           FROM public.tm_test_steps
          WHERE (tm_test_steps.test_case_id = tc.id)) AS step_count
   FROM (((((public.tm_test_cases tc
     LEFT JOIN public.tm_projects p ON ((tc.project_id = p.id)))
     LEFT JOIN public.tm_folders f ON ((tc.folder_id = f.id)))
     LEFT JOIN public.tm_case_priorities cp ON ((tc.priority_id = cp.id)))
     LEFT JOIN public.tm_case_types ct ON ((tc.case_type_id = ct.id)))
     LEFT JOIN public.profiles creator ON ((tc.created_by = creator.id)));


--
-- Name: v_tm_test_cycle_list_metrics; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tm_test_cycle_list_metrics WITH (security_invoker='true') AS
 SELECT c.id,
    c.project_id,
    c.cycle_key,
    c.name,
    c.description,
    c.status,
    c.environment,
    c.release_id,
    c.assigned_to,
    c.planned_start,
    c.planned_end,
    c.actual_start,
    c.actual_end,
    c.created_at,
    c.updated_at,
    c.created_by,
    COALESCE(scope_metrics.tests_count, 0) AS tests_count,
    COALESCE(run_metrics.runs_total, 0) AS runs_total,
    COALESCE(run_metrics.runs_passed, 0) AS runs_passed,
    COALESCE(run_metrics.runs_failed, 0) AS runs_failed,
    COALESCE(run_metrics.runs_blocked, 0) AS runs_blocked,
    COALESCE(run_metrics.runs_skipped, 0) AS runs_skipped,
        CASE
            WHEN (COALESCE(scope_metrics.tests_count, 0) = 0) THEN 0
            ELSE (round((((COALESCE(run_metrics.unique_cases_executed, 0))::numeric / (scope_metrics.tests_count)::numeric) * (100)::numeric)))::integer
        END AS progress_pct,
        CASE
            WHEN ((COALESCE(run_metrics.runs_passed, 0) + COALESCE(run_metrics.runs_failed, 0)) = 0) THEN NULL::integer
            ELSE (round((((COALESCE(run_metrics.runs_passed, 0))::numeric / ((COALESCE(run_metrics.runs_passed, 0) + COALESCE(run_metrics.runs_failed, 0)))::numeric) * (100)::numeric)))::integer
        END AS pass_rate_pct,
    GREATEST(c.updated_at, COALESCE(scope_metrics.latest_scope_update, c.updated_at), COALESCE(run_metrics.latest_run_time, c.updated_at)) AS updated_at_effective,
    run_metrics.avg_duration_seconds
   FROM ((public.tm_test_cycles c
     LEFT JOIN LATERAL ( SELECT s.cycle_id,
            (count(*))::integer AS tests_count,
            max(s.added_at) AS latest_scope_update
           FROM public.tm_cycle_scope s
          WHERE (s.cycle_id = c.id)
          GROUP BY s.cycle_id) scope_metrics ON (true))
     LEFT JOIN LATERAL ( SELECT (count(r.id))::integer AS runs_total,
            (count(
                CASE
                    WHEN (r.status = 'passed'::public.tm_execution_status) THEN 1
                    ELSE NULL::integer
                END))::integer AS runs_passed,
            (count(
                CASE
                    WHEN (r.status = 'failed'::public.tm_execution_status) THEN 1
                    ELSE NULL::integer
                END))::integer AS runs_failed,
            (count(
                CASE
                    WHEN (r.status = 'blocked'::public.tm_execution_status) THEN 1
                    ELSE NULL::integer
                END))::integer AS runs_blocked,
            (count(
                CASE
                    WHEN (r.status = 'skipped'::public.tm_execution_status) THEN 1
                    ELSE NULL::integer
                END))::integer AS runs_skipped,
            (count(DISTINCT
                CASE
                    WHEN (r.status = ANY (ARRAY['passed'::public.tm_execution_status, 'failed'::public.tm_execution_status, 'blocked'::public.tm_execution_status, 'skipped'::public.tm_execution_status])) THEN s.test_case_id
                    ELSE NULL::uuid
                END))::integer AS unique_cases_executed,
            max(COALESCE(r.completed_at, r.created_at)) AS latest_run_time,
            (avg(r.duration_seconds) FILTER (WHERE (r.duration_seconds IS NOT NULL)))::integer AS avg_duration_seconds
           FROM (public.tm_cycle_scope s
             LEFT JOIN public.tm_test_runs r ON ((r.cycle_scope_id = s.id)))
          WHERE (s.cycle_id = c.id)) run_metrics ON (true));


--
-- Name: v_tm_traceability_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tm_traceability_summary WITH (security_invoker='true') AS
 SELECT id AS project_id,
    name AS project_name,
    key AS project_key,
    ( SELECT count(*) AS count
           FROM public.tm_test_cases
          WHERE (tm_test_cases.project_id = p.id)) AS total_cases,
    ( SELECT count(*) AS count
           FROM public.tm_test_cases
          WHERE ((tm_test_cases.project_id = p.id) AND (tm_test_cases.status = 'approved'::public.tm_case_status))) AS approved_cases,
    ( SELECT count(*) AS count
           FROM public.tm_test_cycles
          WHERE (tm_test_cycles.project_id = p.id)) AS total_cycles,
    ( SELECT count(*) AS count
           FROM public.tm_test_cycles
          WHERE ((tm_test_cycles.project_id = p.id) AND (tm_test_cycles.status = 'completed'::public.tm_cycle_status))) AS completed_cycles,
    ( SELECT count(*) AS count
           FROM public.tm_defects
          WHERE ((tm_defects.project_id = p.id) AND (tm_defects.status = 'open'::public.tm_defect_status))) AS open_defects
   FROM public.tm_projects p
  WHERE (is_active = true);


--
-- Name: v_user_roles; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_user_roles WITH (security_invoker='true') AS
 SELECT upr.user_id,
