--
-- Name: vw_alignment_map; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_alignment_map WITH (security_invoker='true') AS
 SELECT t.id AS theme_id,
    ('ST-'::text || lpad((t.sort_order)::text, 3, '0'::text)) AS theme_key,
    t.title AS theme_name,
    t.color AS theme_color,
    t.status AS theme_status,
    (t.progress_pct)::numeric AS theme_progress,
    g.id AS goal_id,
    g.goal_key,
    g.title AS goal_title,
    g.status AS goal_status,
    (g.progress_pct)::numeric AS goal_progress,
    g.ai_health_score AS goal_health,
    kr.id AS kr_id,
    kr.kr_key,
    kr.title AS kr_title,
    kr.status AS kr_status,
    (kr.progress_pct)::numeric AS kr_progress,
    esi.id AS initiative_id,
    esi.title AS initiative_key,
    esi.title AS initiative_title,
    esi.status AS initiative_status,
    (esi.progress_pct)::numeric AS initiative_progress,
    ep.id AS epic_id,
    ep.epic_key,
    ep.name AS epic_title,
    ep.status AS epic_status
   FROM (((((public.es_strategic_themes t
     LEFT JOIN public.es_goals g ON ((g.theme_id = t.id)))
     LEFT JOIN public.es_key_results kr ON ((kr.goal_id = g.id)))
     LEFT JOIN public.es_initiatives esi ON ((esi.key_result_id = kr.id)))
     LEFT JOIN public.es_initiative_epics eie ON ((eie.initiative_id = esi.id)))
     LEFT JOIN public.epics ep ON ((ep.id = eie.epic_id)))
  ORDER BY t.sort_order, g.goal_key, kr.kr_key;


--
-- Name: vw_chain_intelligence; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_chain_intelligence WITH (security_invoker='true') AS
 WITH theme_keys AS (
         SELECT es_strategic_themes.id,
            ('ST-'::text || lpad((row_number() OVER (ORDER BY es_strategic_themes.created_at))::text, 3, '0'::text)) AS theme_key
           FROM public.es_strategic_themes
        )
 SELECT t.id AS theme_id,
    tk.theme_key,
    t.title AS theme_name,
    t.status AS theme_status,
    t.progress_pct AS theme_progress,
    t.created_at AS theme_created_at,
    t.start_date AS theme_start,
    t.target_completion AS theme_end,
    t_own.id AS theme_owner_id,
    t_own.full_name AS theme_owner_name,
    t_own.role AS theme_owner_role,
    g.id AS goal_id,
    g.goal_key,
    g.title AS goal_title,
    g.status AS goal_status,
    g.progress_pct AS goal_progress,
    g.ai_health_score AS goal_health,
    g.created_at AS goal_created_at,
    g.start_date AS goal_start,
    g.target_date AS goal_target,
    g_own.id AS goal_owner_id,
    g_own.full_name AS goal_owner_name,
    g_own.role AS goal_owner_role,
    kr.id AS kr_id,
    kr.kr_key,
    kr.title AS kr_title,
    kr.status AS kr_status,
    kr.progress_pct AS kr_progress,
    kr.target_value AS kr_target,
    kr.current_value AS kr_current,
    kr.unit AS kr_unit,
    kr.created_at AS kr_created_at,
    kr.due_date AS kr_target_date,
    kr_own.id AS kr_owner_id,
    kr_own.full_name AS kr_owner_name,
    kr_own.role AS kr_owner_role,
    ini.id AS initiative_id,
    ini.initiative_key,
    ini.title AS initiative_title,
    ini.status AS initiative_status,
    ini.progress AS initiative_progress,
    ini.created_at AS initiative_created_at,
    ini.target_complete AS initiative_target,
    ini_own.id AS initiative_owner_id,
    ini_own.full_name AS initiative_owner_name,
    wi.id AS epic_id,
    wi.item_key AS epic_key,
    wi.summary AS epic_title,
    wi.status AS epic_status,
    wi.created_at AS epic_created_at,
    wi.due_date AS epic_due,
    wi.updated_at AS epic_updated_at,
    ep_own.id AS epic_owner_id,
    ep_own.full_name AS epic_owner_name,
    ekri.linked_at AS kr_initiative_linked_at,
    eie.created_at AS initiative_epic_linked_at
   FROM ((((((((((((public.es_strategic_themes t
     JOIN theme_keys tk ON ((tk.id = t.id)))
     LEFT JOIN public.profiles t_own ON ((t_own.id = t.owner_id)))
     LEFT JOIN public.es_goals g ON ((g.theme_id = t.id)))
     LEFT JOIN public.profiles g_own ON ((g_own.id = g.owner_id)))
     LEFT JOIN public.es_key_results kr ON ((kr.goal_id = g.id)))
     LEFT JOIN public.profiles kr_own ON ((kr_own.id = kr.owner_id)))
     LEFT JOIN public.es_kr_initiatives ekri ON ((ekri.key_result_id = kr.id)))
     LEFT JOIN public.ph_initiatives ini ON ((ini.id = ekri.initiative_id)))
     LEFT JOIN public.profiles ini_own ON ((ini_own.id = ini.assignee_id)))
     LEFT JOIN public.es_initiative_epics eie ON ((eie.initiative_id = ini.id)))
     LEFT JOIN public.ph_work_items wi ON ((((wi.id)::text = (eie.epic_id)::text) AND (wi.item_type = 'Epic'::text))))
     LEFT JOIN public.profiles ep_own ON ((ep_own.id = wi.assignee_id)))
  ORDER BY t.title, g.goal_key, kr.kr_key;


--
-- Name: vw_epic_stories; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_epic_stories WITH (security_invoker='true') AS
 SELECT wi.parent_id AS epic_id,
    wi.id AS story_id,
    wi.item_key AS story_key,
    wi.summary AS story_title,
    wi.status AS story_status,
    wi.priority AS story_priority,
    wi.created_at AS story_created_at,
    wi.updated_at AS story_updated_at,
    wi.due_date AS story_due,
    wi.assignee_id,
    p.full_name AS assignee_name,
    COALESCE((wi.cycle_time_days)::numeric, (EXTRACT(epoch FROM (wi.updated_at - wi.created_at)) / (86400)::numeric)) AS cycle_days,
    r.id AS release_id,
    r.name AS release_name,
    r.status AS release_status
   FROM ((public.ph_work_items wi
     LEFT JOIN public.profiles p ON ((p.id = wi.assignee_id)))
     LEFT JOIN public.releases r ON ((r.id = wi.release_id)))
  WHERE (wi.item_type = ANY (ARRAY['Story'::text, 'Bug'::text, 'Task'::text, 'Subtask'::text]))
  ORDER BY wi.created_at;


--
-- Name: vw_ph_calendar_events; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_ph_calendar_events WITH (security_invoker='true') AS
 SELECT r.id AS entity_id,
    'release'::text AS event_type,
    ((r.name || ' — '::text) || r.title) AS event_title,
    r.target_date AS event_date,
    r.start_date AS event_start,
    r.target_date AS event_end,
    r.status AS event_status,
    NULL::uuid AS assignee_user_id,
    NULL::text AS assignee_name,
    r.color AS event_color
   FROM public.ph_releases r
  WHERE (r.target_date IS NOT NULL)
UNION ALL
 SELECT t.id AS entity_id,
    'theme'::text AS event_type,
    t.name AS event_title,
    t.start_date AS event_date,
    t.start_date AS event_start,
    t.end_date AS event_end,
    t.status AS event_status,
    NULL::uuid AS assignee_user_id,
    NULL::text AS assignee_name,
    t.color AS event_color
   FROM public.ph_themes t
  WHERE (t.start_date IS NOT NULL)
UNION ALL
 SELECT wi.id AS entity_id,
    'workitem'::text AS event_type,
    ((wi.item_key || ' — '::text) || wi.summary) AS event_title,
    wi.due_date AS event_date,
    wi.start_date AS event_start,
    wi.due_date AS event_end,
    wi.status AS event_status,
    wi.assignee_user_id,
    res.name AS assignee_name,
        CASE wi.item_type
            WHEN 'Epic'::text THEN '#1e40af'::text
            WHEN 'Story'::text THEN '#065f46'::text
            WHEN 'Bug'::text THEN '#dc2626'::text
            ELSE '#475569'::text
        END AS event_color
   FROM (public.ph_work_items wi
     LEFT JOIN public.ph_resources res ON ((wi.assignee_user_id = res.user_id)))
  WHERE (wi.due_date IS NOT NULL);


--
-- Name: vw_ph_dashboard_kpis; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_ph_dashboard_kpis WITH (security_invoker='true') AS
 SELECT ( SELECT count(*) AS count
           FROM public.ph_releases
          WHERE (ph_releases.status = 'Active'::text)) AS active_releases,
    ( SELECT count(*) AS count
           FROM public.ph_releases
          WHERE (ph_releases.status = 'At Risk'::text)) AS at_risk_releases,
    ( SELECT count(*) AS count
           FROM public.ph_themes
          WHERE (ph_themes.status = 'Active'::text)) AS active_themes,
    ( SELECT count(*) AS count
           FROM public.ph_resources
          WHERE (ph_resources.is_active = true)) AS total_resources,
    ( SELECT count(*) AS count
           FROM public.ph_work_items
          WHERE (ph_work_items.status = 'Blocked'::text)) AS blocked_items,
    ( SELECT count(*) AS count
           FROM public.ph_work_items) AS total_work_items,
    ( SELECT count(*) AS count
           FROM public.ph_work_items
          WHERE (ph_work_items.status = 'Done'::text)) AS done_work_items,
    ( SELECT round(
                CASE
                    WHEN (count(*) = 0) THEN (0)::numeric
                    ELSE (((count(*) FILTER (WHERE (ph_work_items.status = 'Done'::text)))::numeric / (count(*))::numeric) * (100)::numeric)
                END, 1) AS round
           FROM public.ph_work_items) AS overall_completion_percent,
    ( SELECT count(*) AS count
           FROM public.ph_work_items
          WHERE ((ph_work_items.due_date < CURRENT_DATE) AND (ph_work_items.status <> ALL (ARRAY['Done'::text, 'Cancelled'::text])))) AS overdue_items,
    ( SELECT count(*) AS count
           FROM public.ph_work_items
          WHERE ((ph_work_items.due_date >= CURRENT_DATE) AND (ph_work_items.due_date <= (CURRENT_DATE + '7 days'::interval)) AND (ph_work_items.status <> ALL (ARRAY['Done'::text, 'Cancelled'::text])))) AS due_this_week;


--
-- Name: vw_ph_release_progress; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_ph_release_progress WITH (security_invoker='true') AS
 SELECT r.id,
    r.name,
    r.title,
    r.description,
    r.status,
    r.color,
    r.start_date,
    r.target_date,
    r.actual_date,
    r.owner_user_id,
    count(wi.id) AS total_items,
    count(wi.id) FILTER (WHERE (wi.status = 'Done'::text)) AS done_items,
    count(wi.id) FILTER (WHERE (wi.status = 'In Progress'::text)) AS in_progress_items,
    count(wi.id) FILTER (WHERE (wi.status = 'In Review'::text)) AS in_review_items,
    count(wi.id) FILTER (WHERE (wi.status = 'Blocked'::text)) AS blocked_items,
    count(wi.id) FILTER (WHERE (wi.status = 'To Do'::text)) AS todo_items,
        CASE
            WHEN (count(wi.id) = 0) THEN (0)::numeric
            ELSE round((((count(wi.id) FILTER (WHERE (wi.status = 'Done'::text)))::numeric / (count(wi.id))::numeric) * (100)::numeric), 1)
        END AS completion_percent,
    count(DISTINCT wi.assignee_user_id) AS unique_assignees,
    count(DISTINCT wi.jira_project_id) AS project_count,
    min(wi.due_date) AS earliest_due,
    max(wi.due_date) AS latest_due
   FROM (public.ph_releases r
     LEFT JOIN public.ph_work_items wi ON ((wi.release_id = r.id)))
  GROUP BY r.id, r.name, r.title, r.description, r.status, r.color, r.start_date, r.target_date, r.actual_date, r.owner_user_id;


--
-- Name: vw_ph_resource_utilization; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_ph_resource_utilization WITH (security_invoker='true') AS
 WITH assignee_stats AS (
         SELECT i.assignee_account_id,
            i.assignee_display_name,
            count(*) AS total_items,
            count(*) FILTER (WHERE ((i.status_category <> 'Done'::text) AND (i.status <> 'Cancelled'::text))) AS active_items,
            count(*) FILTER (WHERE (i.status_category = 'Done'::text)) AS completed_items,
            count(*) FILTER (WHERE (i.status_category = 'In Progress'::text)) AS in_progress_items,
            count(*) FILTER (WHERE (i.status = 'Blocked'::text)) AS blocked_items,
            COALESCE(sum(i.story_points) FILTER (WHERE ((i.status_category <> 'Done'::text) AND (i.status <> 'Cancelled'::text))), (0)::numeric) AS total_estimated_hours,
            COALESCE(sum(i.story_points) FILTER (WHERE (i.status_category = 'Done'::text)), (0)::numeric) AS total_actual_hours,
            count(DISTINCT i.fix_versions) FILTER (WHERE ((i.fix_versions IS NOT NULL) AND (i.fix_versions <> '[]'::jsonb))) AS release_count,
            count(DISTINCT i.theme_id) FILTER (WHERE (i.theme_id IS NOT NULL)) AS theme_count,
            min(i.due_date) FILTER (WHERE ((i.status_category <> 'Done'::text) AND (i.status <> 'Cancelled'::text) AND (i.due_date >= CURRENT_DATE))) AS next_due_date
           FROM public.ph_issues i
          WHERE (i.assignee_account_id IS NOT NULL)
          GROUP BY i.assignee_account_id, i.assignee_display_name
        )
 SELECT COALESCE(m.catalyst_profile_id, extensions.uuid_generate_v5(extensions.uuid_ns_url(), s.assignee_account_id)) AS id,
    m.catalyst_profile_id AS user_id,
    s.assignee_account_id AS jira_account_id,
    COALESCE(p.full_name, m.jira_display_name, s.assignee_display_name) AS name,
    COALESCE(p.email, m.jira_email) AS email,
    COALESCE(ri.role_name, 'Team Member'::text) AS role,
    COALESCE(ri.department_name, 'Unassigned'::text) AS department,
    COALESCE(p.avatar_url, m.jira_avatar_url) AS avatar_url,
        CASE (abs(hashtext(COALESCE(p.full_name, s.assignee_display_name, ''::text))) % 8)
            WHEN 0 THEN '#2563eb'::text
            WHEN 1 THEN '#0d9488'::text
            WHEN 2 THEN '#7c3aed'::text
            WHEN 3 THEN '#d97706'::text
            WHEN 4 THEN '#ef4444'::text
            WHEN 5 THEN '#16a34a'::text
            WHEN 6 THEN '#be185d'::text
            WHEN 7 THEN '#92400e'::text
            ELSE '#2563eb'::text
        END AS color,
    NULL::text[] AS skills,
    40.0 AS capacity_hours_per_week,
    true AS is_active,
    s.total_items,
    s.active_items,
    s.completed_items,
    s.in_progress_items,
    s.blocked_items,
    s.total_estimated_hours,
    s.total_actual_hours,
        CASE
            WHEN (s.total_items > 0) THEN round((((s.completed_items)::numeric / (s.total_items)::numeric) * (100)::numeric), 1)
            ELSE (0)::numeric
        END AS utilization_percent,
    s.release_count,
    s.theme_count,
    s.next_due_date
   FROM (((assignee_stats s
     LEFT JOIN public.ph_user_mapping m ON (((m.jira_account_id = s.assignee_account_id) AND (m.is_mapped = true))))
     LEFT JOIN public.profiles p ON ((p.id = m.catalyst_profile_id)))
     LEFT JOIN public.resource_inventory ri ON (((ri.profile_id = m.catalyst_profile_id) AND (ri.is_active = true))))
  ORDER BY s.total_items DESC;


--
-- Name: vw_ph_theme_progress; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_ph_theme_progress WITH (security_invoker='true') AS
 SELECT t.id,
    t.name,
    t.description,
    t.color,
    t.owner_user_id,
    t.start_date,
    t.end_date,
    t.status,
    t.progress,
    count(wi.id) AS total_items,
    count(wi.id) FILTER (WHERE (wi.status = 'Done'::text)) AS done_items,
    count(wi.id) FILTER (WHERE (wi.item_type = 'Epic'::text)) AS epic_count,
    count(wi.id) FILTER (WHERE (wi.item_type = 'Story'::text)) AS story_count,
    count(wi.id) FILTER (WHERE (wi.item_type = 'Subtask'::text)) AS subtask_count,
        CASE
            WHEN (count(wi.id) = 0) THEN (0)::numeric
            ELSE round((((count(wi.id) FILTER (WHERE (wi.status = 'Done'::text)))::numeric / (count(wi.id))::numeric) * (100)::numeric), 1)
        END AS completion_percent
   FROM (public.ph_themes t
     LEFT JOIN public.ph_work_items wi ON ((wi.theme_id = t.id)))
  GROUP BY t.id, t.name, t.description, t.color, t.owner_user_id, t.start_date, t.end_date, t.status, t.progress;


--
-- Name: vw_ph_work_items_full; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_ph_work_items_full WITH (security_invoker='true') AS
 SELECT wi.id,
    wi.jira_issue_id,
    wi.item_key,
    wi.item_type,
    wi.summary,
    wi.description,
    wi.status,
    wi.priority,
    wi.parent_id,
    wi.hierarchy_path,
    wi.depth,
    wi.jira_project_id,
    wi.jira_status,
    wi.jira_priority,
    wi.jira_labels,
    wi.jira_sprint,
    wi.jira_story_points,
    wi.jira_url,
    wi.release_id,
    wi.theme_id,
    wi.assignee_user_id,
    wi.team_id,
    wi.due_date,
    wi.start_date,
    wi.completed_at,
    wi.last_synced_at,
    wi.sync_source,
    wi.is_jira_locked,
    wi.story_points,
    wi.estimated_hours,
    wi.actual_hours,
    wi.created_at,
    wi.updated_at,
    jp.project_key,
    jp.name AS project_name,
    jp.color AS project_color,
    r.name AS release_name,
    r.title AS release_title,
    r.status AS release_status,
    r.color AS release_color,
    t.name AS theme_name,
    t.color AS theme_color,
    res.name AS assignee_name,
    res.role AS assignee_role,
    res.department AS assignee_department,
    res.color AS assignee_color,
    parent_wi.item_key AS parent_key,
    parent_wi.summary AS parent_summary,
    ( SELECT count(*) AS count
           FROM public.ph_work_items c
          WHERE (c.parent_id = wi.id)) AS children_count,
    ( SELECT count(*) AS count
           FROM public.ph_comments cm
          WHERE (cm.work_item_id = wi.id)) AS comment_count
   FROM (((((public.ph_work_items wi
     LEFT JOIN public.ph_jira_projects jp ON ((wi.jira_project_id = jp.id)))
     LEFT JOIN public.ph_releases r ON ((wi.release_id = r.id)))
     LEFT JOIN public.ph_themes t ON ((wi.theme_id = t.id)))
     LEFT JOIN public.ph_resources res ON ((wi.assignee_user_id = res.user_id)))
     LEFT JOIN public.ph_work_items parent_wi ON ((wi.parent_id = parent_wi.id)));


--
-- Name: vw_wh_calendar_events; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_wh_calendar_events WITH (security_invoker='true') AS
 SELECT (r.id)::text AS entity_id,
    'release'::text AS event_type,
    COALESCE(((r.name || ' — '::text) || r.title), r.name) AS event_title,
    (r.target_date)::text AS event_date,
    (r.start_date)::text AS event_start,
    (r.target_date)::text AS event_end,
    r.status AS event_status,
    NULL::uuid AS assignee_user_id,
    NULL::text AS assignee_name,
    COALESCE(r.color, '#2563eb'::text) AS event_color
   FROM public.ph_releases r
  WHERE (r.target_date IS NOT NULL)
UNION ALL
 SELECT (t.id)::text AS entity_id,
    'theme'::text AS event_type,
    t.name AS event_title,
    (t.target_date)::text AS event_date,
    (t.start_date)::text AS event_start,
    (t.end_date)::text AS event_end,
    t.status AS event_status,
    NULL::uuid AS assignee_user_id,
    NULL::text AS assignee_name,
    COALESCE(t.color, '#7c3aed'::text) AS event_color
   FROM public.ph_themes t
  WHERE ((t.start_date IS NOT NULL) OR (t.end_date IS NOT NULL))
UNION ALL
 SELECT (w.id)::text AS entity_id,
    'workitem'::text AS event_type,
    COALESCE(((w.item_key || ' — '::text) || w.summary), w.summary) AS event_title,
    (w.due_date)::text AS event_date,
    (w.start_date)::text AS event_start,
    (w.due_date)::text AS event_end,
    w.status AS event_status,
    w.assignee_user_id,
    p.full_name AS assignee_name,
        CASE w.item_type
            WHEN 'Epic'::text THEN '#1e40af'::text
            WHEN 'Story'::text THEN '#065f46'::text
            WHEN 'Bug'::text THEN '#991b1b'::text
            WHEN 'Task'::text THEN '#475569'::text
            WHEN 'Subtask'::text THEN '#3730a3'::text
            ELSE '#2563eb'::text
        END AS event_color
   FROM (public.ph_work_items w
     LEFT JOIN public.profiles p ON ((p.id = w.assignee_user_id)))
  WHERE (w.due_date IS NOT NULL);


--
-- Name: vw_wh_resource_360; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_wh_resource_360 WITH (security_invoker='true') AS
 SELECT ri.rid AS resource_id,
    ri.name AS resource_name,
    COALESCE(p.email, ''::text) AS resource_email,
    ri.role_name AS job_role,
    ri.department_name AS department,
    p.avatar_url,
    phi.issue_key AS work_item_id,
    phi.issue_key AS item_key,
    phi.summary AS title,
    phi.issue_type AS item_type,
    phi.status,
    COALESCE(phi.status_category, 'To Do'::text) AS status_category,
    phi.priority,
    'ProjectHub'::text AS hub,
    phi.jira_created_at AS item_created_at,
    phi.jira_created_at AS assigned_at,
    'Assignee'::text AS role_on_item,
    100 AS allocation_percent,
    GREATEST(0, (EXTRACT(day FROM (now() - phi.jira_created_at)))::integer) AS age_days,
    phi.project_name,
    phi.project_key,
    COALESCE(((phi.fix_versions -> 0) ->> 'name'::text), phi.sprint_name) AS release_name,
    phi.effective_due_date AS release_end_date,
    NULL::text AS release_status,
    phi.parent_key AS parent_id,
    phi.parent_key,
    phi.parent_summary AS parent_title,
    NULL::text AS parent_type,
    NULL::text AS parent_status,
    NULL::text AS parent_hub,
    phi.reporter_display_name AS assigner_name,
    '[]'::jsonb AS status_transitions,
    GREATEST(0, (EXTRACT(day FROM (now() - phi.jira_created_at)))::integer) AS total_cycle_days
   FROM ((public.resource_inventory ri
     JOIN public.profiles p ON ((p.id = ri.profile_id)))
     JOIN public.ph_issues phi ON ((phi.assignee_account_id = ri.jira_account_id)))
  WHERE ((ri.is_active = true) AND (ri.jira_account_id IS NOT NULL))
UNION ALL
 SELECT ri.rid AS resource_id,
    ri.name AS resource_name,
    COALESCE(p.email, ''::text) AS resource_email,
    ri.role_name AS job_role,
    ri.department_name AS department,
    p.avatar_url,
    phi.issue_key AS work_item_id,
    phi.issue_key AS item_key,
    phi.summary AS title,
    phi.issue_type AS item_type,
    phi.status,
    COALESCE(phi.status_category, 'To Do'::text) AS status_category,
    phi.priority,
    'ProjectHub'::text AS hub,
    phi.jira_created_at AS item_created_at,
    phi.jira_created_at AS assigned_at,
    'Contributor'::text AS role_on_item,
    0 AS allocation_percent,
    GREATEST(0, (EXTRACT(day FROM (now() - phi.jira_created_at)))::integer) AS age_days,
    phi.project_name,
    phi.project_key,
    COALESCE(((phi.fix_versions -> 0) ->> 'name'::text), phi.sprint_name) AS release_name,
    phi.effective_due_date AS release_end_date,
    NULL::text AS release_status,
    phi.parent_key AS parent_id,
    phi.parent_key,
    phi.parent_summary AS parent_title,
    NULL::text AS parent_type,
    NULL::text AS parent_status,
    NULL::text AS parent_hub,
    phi.assignee_display_name AS assigner_name,
    '[]'::jsonb AS status_transitions,
    GREATEST(0, (EXTRACT(day FROM (now() - phi.jira_created_at)))::integer) AS total_cycle_days
   FROM ((public.resource_inventory ri
     JOIN public.profiles p ON ((p.id = ri.profile_id)))
     JOIN public.ph_issues phi ON ((phi.reporter_account_id = ri.jira_account_id)))
  WHERE ((ri.is_active = true) AND (ri.jira_account_id IS NOT NULL) AND (lower(ri.role_name) <> ALL (ARRAY['.net developer'::text, '.net lead'::text, 'backend architect'::text, 'backend developer'::text, 'data engineer'::text, 'database engineer'::text, 'devops'::text, 'infrastructure engineer'::text, 'mobile developer'::text, 'n&s engineer'::text, 'react developer'::text, 'react lead'::text, 'service engineer'::text, 'support engineer'::text])) AND (phi.assignee_account_id IS DISTINCT FROM ri.jira_account_id));


--
-- Name: vw_wh_resource_360_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_wh_resource_360_summary WITH (security_invoker='true') AS
 SELECT ri.rid AS resource_id,
    ri.name,
    COALESCE(p.email, ''::text) AS email,
    ri.role_name AS role,
    ri.department_name AS department,
    p.avatar_url,
    (count(*))::integer AS total_items,
    (count(*) FILTER (WHERE (phi.status_category = 'To Do'::text)))::integer AS todo_count,
    (count(*) FILTER (WHERE (phi.status_category = 'In Progress'::text)))::integer AS progress_count,
    (count(*) FILTER (WHERE (phi.status_category = 'Done'::text)))::integer AS done_count,
    (count(DISTINCT phi.project_key))::integer AS hub_count,
    (count(DISTINCT phi.project_key))::integer AS project_count
   FROM ((public.resource_inventory ri
     JOIN public.profiles p ON ((p.id = ri.profile_id)))
     JOIN public.ph_issues phi ON ((phi.assignee_account_id = ri.jira_account_id)))
  WHERE ((ri.is_active = true) AND (ri.jira_account_id IS NOT NULL))
  GROUP BY ri.rid, ri.name, p.email, ri.role_name, ri.department_name, p.avatar_url;


