--
-- Name: wh_all_work_list; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.wh_all_work_list WITH (security_invoker='true') AS
 SELECT wi.id,
    wi.project_id,
    wi.item_key,
    wi.key_sequence,
    wi.summary,
    wi.description,
    wi.priority,
    wi.severity,
    wi.rank,
    wi.created_at,
    wi.updated_at,
    wt.id AS work_type_id,
    wt.name AS work_type_name,
    wt.icon_glyph,
    wt.icon_color,
    wt.is_subtask,
    ws.id AS status_id,
    ws.name AS status_name,
    ws.category AS status_category,
    ws.color_key AS status_color,
    wi.parent_id,
    pw.item_key AS parent_key,
    pw.summary AS parent_summary,
    fv.id AS fix_version_id,
    fv.name AS fix_version_name,
    wi.assignee_id,
    ap.full_name AS assignee_name,
    ap.avatar_url AS assignee_avatar,
    wi.reporter_id,
    rp.full_name AS reporter_name,
    COALESCE(cc.comment_count, 0) AS comment_count,
    COALESCE(ac.attachment_count, 0) AS attachment_count,
    COALESCE(ch.child_count, 0) AS child_count,
    COALESCE(ll.label_list, '[]'::jsonb) AS labels
   FROM ((((((((((public.wh_work_items wi
     JOIN public.wh_work_types wt ON ((wt.id = wi.work_type_id)))
     JOIN public.wh_statuses ws ON ((ws.id = wi.status_id)))
     LEFT JOIN public.wh_work_items pw ON ((pw.id = wi.parent_id)))
     LEFT JOIN public.wh_fix_versions fv ON ((fv.id = wi.fix_version_id)))
     LEFT JOIN public.profiles ap ON ((ap.id = wi.assignee_id)))
     LEFT JOIN public.profiles rp ON ((rp.id = wi.reporter_id)))
     LEFT JOIN LATERAL ( SELECT (count(*))::integer AS comment_count
           FROM public.wh_comments c
          WHERE ((c.work_item_id = wi.id) AND (c.deleted_at IS NULL))) cc ON (true))
     LEFT JOIN LATERAL ( SELECT (count(*))::integer AS attachment_count
           FROM public.wh_attachments a
          WHERE ((a.work_item_id = wi.id) AND (a.deleted_at IS NULL))) ac ON (true))
     LEFT JOIN LATERAL ( SELECT (count(*))::integer AS child_count
           FROM public.wh_work_items ch_1
          WHERE ((ch_1.parent_id = wi.id) AND (ch_1.deleted_at IS NULL))) ch ON (true))
     LEFT JOIN LATERAL ( SELECT COALESCE(jsonb_agg(jsonb_build_object('id', l.id, 'name', l.name, 'color', l.color)), '[]'::jsonb) AS label_list
           FROM (public.wh_work_item_labels wil
             JOIN public.wh_labels l ON ((l.id = wil.label_id)))
          WHERE ((wil.work_item_id = wi.id) AND (l.deleted_at IS NULL))) ll ON (true))
  WHERE (wi.deleted_at IS NULL);


