--
-- Name: wh_dashboard_stats; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.wh_dashboard_stats WITH (security_invoker='true') AS
 SELECT wi.project_id,
    count(*) FILTER (WHERE (wi.deleted_at IS NULL)) AS total_items,
    count(*) FILTER (WHERE ((ws.category = 'todo'::text) AND (wi.deleted_at IS NULL))) AS todo_count,
    count(*) FILTER (WHERE ((ws.category = 'in_progress'::text) AND (wi.deleted_at IS NULL))) AS in_progress_count,
    count(*) FILTER (WHERE ((ws.category = 'done'::text) AND (wi.deleted_at IS NULL))) AS done_count,
    count(*) FILTER (WHERE ((wi.priority = 'highest'::public.wh_priority) AND (ws.category <> 'done'::text) AND (wi.deleted_at IS NULL))) AS critical_open,
    count(*) FILTER (WHERE ((wi.created_at > (now() - '7 days'::interval)) AND (wi.deleted_at IS NULL))) AS created_this_week,
    count(*) FILTER (WHERE ((wi.updated_at > (now() - '24:00:00'::interval)) AND (wi.deleted_at IS NULL))) AS updated_today
   FROM (public.wh_work_items wi
     JOIN public.wh_statuses ws ON ((ws.id = wi.status_id)))
  GROUP BY wi.project_id;


