CREATE VIEW public.wh_sidebar_projects WITH (security_invoker='true') AS
 SELECT p.id,
    p.name,
    p.key,
    p.color,
        CASE
            WHEN (s.user_id IS NOT NULL) THEN true
            ELSE false
        END AS is_starred,
    r.last_visited
   FROM ((public.projects p
     LEFT JOIN public.wh_project_stars s ON ((s.project_id = p.id)))
     LEFT JOIN public.wh_project_recents r ON ((r.project_id = p.id)))
  WHERE (p.is_archived = false);


