CREATE VIEW public.wh_valid_transitions WITH (security_invoker='true') AS
 SELECT t.project_id,
    t.from_status_id,
    fs.name AS from_status_name,
    t.to_status_id,
    ts.name AS to_status_name,
    ts.color_key AS to_status_color,
    ts.category AS to_status_category
   FROM ((public.wh_workflow_transitions t
     JOIN public.wh_statuses fs ON ((fs.id = t.from_status_id)))
     JOIN public.wh_statuses ts ON ((ts.id = t.to_status_id)))
  WHERE (t.is_active = true);


--
-- Name: wh_work_item_detail; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.wh_work_item_detail WITH (security_invoker='true') AS
 SELECT wi.id,
    wi.project_id,
    wi.work_type_id,
    wi.status_id,
    wi.parent_id,
    wi.fix_version_id,
    wi.item_key,
    wi.key_sequence,
    wi.summary,
    wi.description,
    wi.assignee_id,
    wi.reporter_id,
    wi.priority,
    wi.severity,
    wi.rank,
    wi.original_estimate_minutes,
    wi.remaining_estimate_minutes,
    wi.time_spent_minutes,
    wi.environment,
    wi.resolution,
    wi.created_at,
    wi.updated_at,
    wi.created_by,
    wi.updated_by,
    wi.deleted_at,
    wt.name AS work_type_name,
    wt.icon_glyph,
    wt.icon_color,
    wt.is_subtask,
    ws.name AS status_name,
    ws.category AS status_category,
    ws.color_key AS status_color,
    fv.name AS fix_version_name,
    pw.item_key AS parent_key,
    pw.summary AS parent_summary,
    ap.full_name AS assignee_name,
    ap.avatar_url AS assignee_avatar,
    rp.full_name AS reporter_name,
    rp.avatar_url AS reporter_avatar
   FROM ((((((public.wh_work_items wi
     JOIN public.wh_work_types wt ON ((wt.id = wi.work_type_id)))
     JOIN public.wh_statuses ws ON ((ws.id = wi.status_id)))
     LEFT JOIN public.wh_fix_versions fv ON ((fv.id = wi.fix_version_id)))
     LEFT JOIN public.wh_work_items pw ON ((pw.id = wi.parent_id)))
     LEFT JOIN public.profiles ap ON ((ap.id = wi.assignee_id)))
     LEFT JOIN public.profiles rp ON ((rp.id = wi.reporter_id)))
  WHERE (wi.deleted_at IS NULL);


