--
-- Name: wiki_admin_stats; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.wiki_admin_stats WITH (security_invoker='true') AS
 SELECT ( SELECT count(*) AS count
           FROM public.wiki_pages
          WHERE (wiki_pages.status = 'published'::text)) AS total_pages,
    ( SELECT count(*) AS count
           FROM public.wiki_pages
          WHERE (wiki_pages.status = 'draft'::text)) AS draft_pages,
    ( SELECT count(*) AS count
           FROM public.wiki_pages
          WHERE (wiki_pages.status = 'review'::text)) AS review_pages,
    ( SELECT count(*) AS count
           FROM public.kb_embeddings) AS total_chunks,
    ( SELECT count(*) AS count
           FROM public.wiki_documents
          WHERE (wiki_documents.status = 'complete'::text)) AS total_documents,
    ( SELECT count(*) AS count
           FROM public.wiki_documents
          WHERE (wiki_documents.status = 'failed'::text)) AS failed_documents,
    ( SELECT avg(wiki_pages.ai_confidence) AS avg
           FROM public.wiki_pages
          WHERE (wiki_pages.status = 'published'::text)) AS avg_confidence,
    ( SELECT count(*) AS count
           FROM public.kb_query_log
          WHERE (kb_query_log.created_at > (now() - '24:00:00'::interval))) AS queries_today,
    ( SELECT count(*) AS count
           FROM public.kb_cache) AS cache_entries,
    ( SELECT max(wiki_sync_runs.started_at) AS max
           FROM public.wiki_sync_runs
          WHERE (wiki_sync_runs.status = 'complete'::text)) AS last_sync;


