--
-- Name: wiki_domain_stats; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.wiki_domain_stats WITH (security_invoker='true') AS
 SELECT d.id,
    d.domain_code,
    d.name,
    d.name_ar,
    d.icon,
    d.description,
    d.description_ar,
    d.sort_order,
    count(DISTINCT p.id) FILTER (WHERE (p.status = 'published'::text)) AS article_count,
    count(DISTINCT doc.id) FILTER (WHERE (doc.status = 'complete'::text)) AS document_count,
    max(p.updated_at) AS last_updated
   FROM ((public.wiki_domains d
     LEFT JOIN public.wiki_pages p ON ((p.domain_code = d.domain_code)))
     LEFT JOIN public.wiki_documents doc ON ((doc.domain_code = d.domain_code)))
  GROUP BY d.id, d.domain_code, d.name, d.name_ar, d.icon, d.description, d.description_ar, d.sort_order
  ORDER BY d.sort_order;


