--
-- Name: work_item_cycle_time_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.work_item_cycle_time_view WITH (security_invoker='true') AS
 WITH transitions_ordered AS (
         SELECT work_item_transitions.work_item_id,
            work_item_transitions.to_status,
            work_item_transitions.to_status_category,
            work_item_transitions.transitioned_at,
            work_item_transitions.transitioned_by,
            lead(work_item_transitions.transitioned_at) OVER (PARTITION BY work_item_transitions.work_item_id ORDER BY work_item_transitions.transitioned_at) AS next_transition_at,
            row_number() OVER (PARTITION BY work_item_transitions.work_item_id ORDER BY work_item_transitions.transitioned_at) AS seq
           FROM public.work_item_transitions
        ), time_in_status AS (
         SELECT transitions_ordered.work_item_id,
            transitions_ordered.to_status AS status,
            transitions_ordered.to_status_category AS status_category,
            transitions_ordered.transitioned_at AS entered_at,
            COALESCE(transitions_ordered.next_transition_at, now()) AS exited_at,
            EXTRACT(epoch FROM (COALESCE(transitions_ordered.next_transition_at, now()) - transitions_ordered.transitioned_at)) AS seconds_in_status
           FROM transitions_ordered
        )
 SELECT work_item_id,
    status,
    status_category,
    entered_at,
    exited_at,
    seconds_in_status,
        CASE
            WHEN (seconds_in_status < (3600)::numeric) THEN (round((seconds_in_status / (60)::numeric)) || 'm'::text)
            WHEN (seconds_in_status < (86400)::numeric) THEN (round((seconds_in_status / (3600)::numeric), 1) || 'h'::text)
            ELSE (round((seconds_in_status / (86400)::numeric), 1) || 'd'::text)
        END AS duration_formatted,
    (seconds_in_status / 86400.0) AS days_in_status
   FROM time_in_status
  ORDER BY work_item_id, entered_at;


--
-- Name: work_item_cycle_summary_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.work_item_cycle_summary_view WITH (security_invoker='true') AS
 SELECT work_item_id,
    status_category,
    sum(seconds_in_status) AS total_seconds,
    count(*) AS times_entered,
    min(entered_at) AS first_entered,
    max(exited_at) AS last_exited,
    round((sum(seconds_in_status) / 86400.0), 1) AS total_days
   FROM public.work_item_cycle_time_view
  GROUP BY work_item_id, status_category;


