    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    deleted_at timestamp with time zone,
    CONSTRAINT workgroups_support_level_default_check CHECK ((support_level_default = ANY (ARRAY['L1'::text, 'L2'::text, 'L3'::text])))
);


--
-- Name: workhub_activity; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.workhub_activity (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    issue_key text NOT NULL,
    actor_id uuid,
    actor_name text DEFAULT 'System'::text NOT NULL,
    action text NOT NULL,
    field_changed text,
    old_value text,
    new_value text,
    comment_text text,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: workhub_items_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.workhub_items_view WITH (security_invoker='true') AS
 SELECT wi.id,
    wi.issue_key,
    wi.project_key,
    wi.project_name,
    wi.issue_type,
    wi.summary,
    wi.description_text,
    wi.status,
    wi.status_category,
    wi.priority,
    wi.assignee_account_id,
    wi.assignee_display_name,
    wi.reporter_account_id,
    wi.reporter_display_name,
    wi.parent_key,
    wi.parent_summary,
    wi.story_points,
    wi.due_date,
    wi.labels,
    wi.components,
    wi.sprint_name,
    wi.fix_versions,
    wi.resolution,
    wi.source,
    wi.sort_order,
    wi.deleted_at,
    wi.jira_created_at,
    wi.jira_updated_at,
    wi.synced_at,
    wi.theme_id,
    wi.type_icon_url,
    COALESCE(cc.child_count, 0) AS child_count,
    COALESCE(cc.completed_child_count, 0) AS completed_child_count
   FROM (public.ph_issues wi
     LEFT JOIN LATERAL ( SELECT (count(*))::integer AS child_count,
            (count(*) FILTER (WHERE (c.status_category = ANY (ARRAY['Done'::text, 'Complete'::text]))))::integer AS completed_child_count
           FROM public.ph_issues c
          WHERE ((c.parent_key = wi.issue_key) AND (c.deleted_at IS NULL))) cc ON (true))
  WHERE (wi.deleted_at IS NULL);


--
-- Name: workhub_saved_views; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.workhub_saved_views (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    project_key text NOT NULL,
    name text NOT NULL,
    filter_config jsonb DEFAULT '{}'::jsonb NOT NULL,
    sort_config jsonb DEFAULT '{}'::jsonb NOT NULL,
    group_by text DEFAULT 'status_category'::text,
    column_config jsonb DEFAULT '[]'::jsonb NOT NULL,
    created_by uuid,
    is_default boolean DEFAULT false,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


