--
-- Name: planner_dashboard_workstream_health _RETURN; Type: RULE; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.planner_dashboard_workstream_health WITH (security_invoker='true') AS
 SELECT w.id AS workstream_id,
    w.name AS workstream_name,
    w.slug AS workstream_slug,
    w.color AS workstream_color,
    (count(t.id))::integer AS total_tasks,
    (count(t.id) FILTER (WHERE (s.is_done = true)))::integer AS completed_tasks,
    (count(t.id) FILTER (WHERE ((t.due_date < CURRENT_DATE) AND (s.is_done = false))))::integer AS overdue_tasks,
    (count(t.id) FILTER (WHERE (t.blocked = true)))::integer AS blocked_tasks,
    COALESCE(round((((count(t.id) FILTER (WHERE (s.is_done = true)))::numeric / NULLIF((count(t.id))::numeric, (0)::numeric)) * (100)::numeric), 1), (0)::numeric) AS completion_rate,
        CASE
            WHEN (count(t.id) FILTER (WHERE ((t.due_date < CURRENT_DATE) AND (s.is_done = false))) > 2) THEN 'critical'::text
            WHEN (count(t.id) FILTER (WHERE (t.blocked = true)) > 0) THEN 'warning'::text
            WHEN (COALESCE(((count(t.id) FILTER (WHERE (s.is_done = true)))::numeric / NULLIF((count(t.id))::numeric, (0)::numeric)), (0)::numeric) > 0.8) THEN 'healthy'::text
            ELSE 'normal'::text
        END AS health_status
   FROM ((public.planner_workstreams w
     LEFT JOIN public.planner_tasks t ON (((t.workstream_id = w.id) AND (t.deleted_at IS NULL))))
     LEFT JOIN public.planner_statuses s ON ((t.status_id = s.id)))
  GROUP BY w.id, w.name, w.slug, w.color
  ORDER BY w.sort_order;


--
-- Name: planner_dashboard_workstream_progress _RETURN; Type: RULE; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.planner_dashboard_workstream_progress WITH (security_invoker='true') AS
 SELECT w.id AS workstream_id,
    w.name AS workstream_name,
    w.slug AS workstream_slug,
    w.color AS workstream_color,
    (count(t.id))::integer AS total_tasks,
    (count(t.id) FILTER (WHERE (s.is_done = true)))::integer AS completed_tasks,
    COALESCE(round((((count(t.id) FILTER (WHERE (s.is_done = true)))::numeric / NULLIF((count(t.id))::numeric, (0)::numeric)) * (100)::numeric), 1), (0)::numeric) AS completion_rate
   FROM ((public.planner_workstreams w
     LEFT JOIN public.planner_tasks t ON (((t.workstream_id = w.id) AND (t.deleted_at IS NULL))))
     LEFT JOIN public.planner_statuses s ON ((t.status_id = s.id)))
  GROUP BY w.id, w.name, w.slug, w.color
  ORDER BY w.sort_order;


--
-- Name: rh_change_summary _RETURN; Type: RULE; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.rh_change_summary WITH (security_invoker='true') AS
 SELECT c.id,
    c.chg_number,
    c.title,
    c.status,
    c.risk_level,
    c.risk_score,
    c.source,
    c.release_id,
    c.category,
    c.deployment_date,
    c.frontend_required,
    c.frontend_commit,
    c.backend_required,
    c.backend_commit,
    c.dependency,
    c.deployment_process,
    c.additional_commands,
    c.additional_comments,
    c.sn_imported,
    c.created_by,
    c.project_id,
    c.created_at,
    c.updated_at,
    r.name AS release_name,
    r.version AS release_version,
    r.status AS release_status,
    count(wi.id) AS work_item_count,
    count(s.id) FILTER (WHERE (s.status = 'pending'::text)) AS pending_signoffs,
    min(s.wait_started_at) FILTER (WHERE (s.status = 'pending'::text)) AS oldest_pending_signoff_at
   FROM (((public.rh_changes c
     LEFT JOIN public.rh_releases r ON ((c.release_id = r.id)))
     LEFT JOIN public.rh_change_work_items wi ON ((c.id = wi.change_id)))
     LEFT JOIN public.rh_change_signoffs s ON ((c.id = s.change_id)))
  GROUP BY c.id, r.name, r.version, r.status;


--
-- Name: rh_release_summary _RETURN; Type: RULE; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.rh_release_summary AS
 SELECT r.id,
    r.name,
    r.version,
    r.status,
    r.source,
    r.jira_key,
    r.target_date,
    r.owner_id,
    r.project_id,
    r.chg_count,
    r.created_at,
    r.updated_at,
    count(DISTINCT c.id) AS change_count,
    ( SELECT count(*) AS count
           FROM public.rh_changes c2
          WHERE ((c2.release_id = r.id) AND (c2.status = 'IN_PRODUCTION'::text))) AS completed_change_count,
    count(DISTINCT rtcl.test_cycle_id) AS test_cycle_count,
    GREATEST(0, (r.target_date - CURRENT_DATE)) AS days_remaining,
    ((r.target_date < CURRENT_DATE) AND (r.status <> ALL (ARRAY['done'::text, 'archived'::text]))) AS is_overdue
   FROM ((public.rh_releases r
     LEFT JOIN public.rh_changes c ON ((c.release_id = r.id)))
     LEFT JOIN public.rh_release_test_cycle_links rtcl ON ((rtcl.release_id = r.id)))
  GROUP BY r.id;


--
-- Name: t10_list_performance _RETURN; Type: RULE; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.t10_list_performance WITH (security_invoker='true') AS
 SELECT l.id AS list_id,
    l.key AS list_key,
    l.name AS list_name,
    count(w.id) AS total_weeks,
    round(avg(
        CASE
            WHEN (w.total_count = 0) THEN (0)::numeric
            ELSE (((w.completed_count)::numeric / (w.total_count)::numeric) * (100)::numeric)
        END), 1) AS avg_completion_rate,
    sum(w.completed_count) AS total_completed,
    sum(w.carried_forward_count) AS total_carried_forward,
    ( SELECT json_agg(sub.week_data ORDER BY (sub.week_data ->> 'week_start'::text) DESC) AS json_agg
           FROM ( SELECT json_build_object('week_id', cw.id, 'week_start', cw.week_start, 'week_end', cw.week_end, 'total', cw.total_count, 'completed', cw.completed_count, 'carried_forward', cw.carried_forward_count, 'rate',
                        CASE
                            WHEN (cw.total_count = 0) THEN (0)::numeric
                            ELSE round((((cw.completed_count)::numeric / (cw.total_count)::numeric) * (100)::numeric), 1)
                        END) AS week_data
                   FROM public.t10_weeks cw
                  WHERE ((cw.list_id = l.id) AND ((cw.status)::text = 'completed'::text))) sub) AS weeks_breakdown,
    ( SELECT json_agg(json_build_object('title', sub.title, 'carry_count', sub.carry_count)) AS json_agg
           FROM ( SELECT i.title,
                    count(*) AS carry_count
                   FROM (public.t10_items i
                     JOIN public.t10_weeks iw ON ((iw.id = i.week_id)))
                  WHERE ((iw.list_id = l.id) AND ((i.status)::text = 'carried_forward'::text))
                  GROUP BY i.title
                 HAVING (count(*) > 1)
                  ORDER BY (count(*)) DESC
                 LIMIT 5) sub) AS recurring_carryovers
   FROM (public.t10_lists l
     JOIN public.t10_weeks w ON (((w.list_id = l.id) AND ((w.status)::text = 'completed'::text))))
  GROUP BY l.id
  ORDER BY (count(w.id)) DESC;


--
-- Name: v_project_epics _RETURN; Type: RULE; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.v_project_epics AS
 SELECT wi.id,
    wi.project_id,
    wi.parent_id,
    wi.parent_key,
    wi.jira_key,
    wi.type,
    wi.summary,
    wi.status,
    wi.priority,
    wi.assignee_id,
    wi.reporter_id,
    wi.fix_version,
    wi.comments_count,
    wi.description,
    wi.jira_sync_at,
    wi.created_at,
    wi.updated_at,
    wi.created_by,
    wi.updated_by,
    count(children.id) AS total_children,
    count(children.id) FILTER (WHERE (children.status = 'done'::text)) AS done_children,
    count(children.id) FILTER (WHERE (children.status = ANY (ARRAY['in_progress'::text, 'in_dev'::text, 'in_qa'::text, 'in_uat'::text, 'in_production'::text, 'ready_for_qa'::text]))) AS inprog_children,
        CASE
            WHEN (count(children.id) = 0) THEN (0)::numeric
            ELSE round((((count(children.id) FILTER (WHERE (children.status = 'done'::text)))::numeric / (count(children.id))::numeric) * (100)::numeric))
        END AS pct_done
   FROM (public.ph_list_items wi
     LEFT JOIN public.ph_list_items children ON ((children.parent_id = wi.id)))
  WHERE (wi.type = 'epic'::text)
  GROUP BY wi.id;


--
-- Name: wiki_page_admin_list _RETURN; Type: RULE; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.wiki_page_admin_list WITH (security_invoker='true') AS
 SELECT p.id,
    p.slug,
    p.title,
    p.domain_code,
    p.status,
    p.ai_confidence,
    p.source_coverage,
    p.version,
    p.last_generated,
    p.updated_at,
    (EXTRACT(day FROM (now() - p.updated_at)))::integer AS days_since_update,
    count(DISTINCT r.id) AS reference_count,
    count(DISTINCT rl.id) AS read_count
   FROM ((public.wiki_pages p
     LEFT JOIN public.wiki_references r ON ((r.page_id = p.id)))
     LEFT JOIN public.wiki_read_log rl ON ((rl.page_id = p.id)))
  GROUP BY p.id;


