   FROM (public.user_product_roles upr
     JOIN public.product_roles pr ON ((pr.id = upr.role_id)))
  WHERE ((upr.user_id = auth.uid()) AND (pr.code = 'program_manager'::text)))) OR (EXISTS ( SELECT 1
   FROM public.workstream_members wm
  WHERE ((wm.workstream_id = workstream_members.workstream_id) AND (wm.user_id = auth.uid()) AND (wm.role = 'lead'::text)))))) WITH CHECK ((public.can_access_all_workstreams(auth.uid()) OR (EXISTS ( SELECT 1
   FROM (public.user_product_roles upr
     JOIN public.product_roles pr ON ((pr.id = upr.role_id)))
  WHERE ((upr.user_id = auth.uid()) AND (pr.code = 'program_manager'::text)))) OR (EXISTS ( SELECT 1
