--
-- Name: board_issue_rank issue_rank_delete; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY issue_rank_delete ON public.board_issue_rank FOR DELETE TO authenticated USING ((EXISTS ( SELECT 1
   FROM public.boards b
  WHERE ((b.id = board_issue_rank.board_id) AND ((b.created_by = auth.uid()) OR (EXISTS ( SELECT 1
           FROM public.board_members bm
          WHERE ((bm.board_id = b.id) AND (bm.user_id = auth.uid())))))))));


--
-- Name: board_issue_rank issue_rank_insert; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY issue_rank_insert ON public.board_issue_rank FOR INSERT TO authenticated WITH CHECK ((EXISTS ( SELECT 1
   FROM public.boards b
  WHERE ((b.id = board_issue_rank.board_id) AND ((b.created_by = auth.uid()) OR (EXISTS ( SELECT 1
           FROM public.board_members bm
          WHERE ((bm.board_id = b.id) AND (bm.user_id = auth.uid())))))))));


--
-- Name: board_issue_rank issue_rank_select; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY issue_rank_select ON public.board_issue_rank FOR SELECT TO authenticated USING (public.board_not_deleted(board_id));


--
-- Name: board_issue_rank issue_rank_update; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY issue_rank_update ON public.board_issue_rank FOR UPDATE TO authenticated USING ((EXISTS ( SELECT 1
   FROM public.boards b
  WHERE ((b.id = board_issue_rank.board_id) AND ((b.created_by = auth.uid()) OR (EXISTS ( SELECT 1
           FROM public.board_members bm
          WHERE ((bm.board_id = b.id) AND (bm.user_id = auth.uid())))))))));


