--
-- Name: ph_attachments ph_attachments_delete_uploader_or_admin; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY ph_attachments_delete_uploader_or_admin ON public.ph_attachments FOR DELETE TO authenticated USING (((uploaded_by = auth.uid()) OR (EXISTS ( SELECT 1
   FROM ((public.ph_issues i
     JOIN public.ph_projects p ON (((p.key)::text = i.project_key)))
     JOIN public.ph_project_members m ON ((m.project_id = p.id)))
  WHERE ((i.id = ph_attachments.work_item_id) AND (m.user_id = auth.uid()) AND ((m.role)::text = ANY ((ARRAY['admin'::character varying, 'owner'::character varying])::text[])))))));


--
-- Name: ph_attachments ph_attachments_insert_project_members; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY ph_attachments_insert_project_members ON public.ph_attachments FOR INSERT TO authenticated WITH CHECK (((uploaded_by = auth.uid()) AND (EXISTS ( SELECT 1
   FROM ((public.ph_issues i
     JOIN public.ph_projects p ON (((p.key)::text = i.project_key)))
     JOIN public.ph_project_members m ON ((m.project_id = p.id)))
  WHERE ((i.id = ph_attachments.work_item_id) AND (m.user_id = auth.uid()))))));


--
-- Name: ph_attachments ph_attachments_select_project_members; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY ph_attachments_select_project_members ON public.ph_attachments FOR SELECT TO authenticated USING ((EXISTS ( SELECT 1
   FROM ((public.ph_issues i
     JOIN public.ph_projects p ON (((p.key)::text = i.project_key)))
     JOIN public.ph_project_members m ON ((m.project_id = p.id)))
  WHERE ((i.id = ph_attachments.work_item_id) AND (m.user_id = auth.uid())))));


