-- Name: ph_issue_remote_links remote_links_delete_members; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY remote_links_delete_members ON public.ph_issue_remote_links FOR DELETE TO authenticated USING ((EXISTS ( SELECT 1
   FROM ((public.ph_issues i
     JOIN public.ph_projects p ON (((p.key)::text = i.project_key)))
     JOIN public.ph_project_members pm ON ((pm.project_id = p.id)))
  WHERE ((i.id = ph_issue_remote_links.issue_id) AND (pm.user_id = auth.uid())))));


--
-- Name: ph_issue_remote_links remote_links_insert_members; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY remote_links_insert_members ON public.ph_issue_remote_links FOR INSERT TO authenticated WITH CHECK (((EXISTS ( SELECT 1
   FROM ((public.ph_issues i
     JOIN public.ph_projects p ON (((p.key)::text = i.project_key)))
     JOIN public.ph_project_members pm ON ((pm.project_id = p.id)))
  WHERE ((i.id = ph_issue_remote_links.issue_id) AND (pm.user_id = auth.uid())))) AND (created_by = auth.uid())));


--
-- Name: ph_issue_remote_links remote_links_select_members; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY remote_links_select_members ON public.ph_issue_remote_links FOR SELECT TO authenticated USING ((EXISTS ( SELECT 1
   FROM ((public.ph_issues i
     JOIN public.ph_projects p ON (((p.key)::text = i.project_key)))
     JOIN public.ph_project_members pm ON ((pm.project_id = p.id)))
  WHERE ((i.id = ph_issue_remote_links.issue_id) AND (pm.user_id = auth.uid())))));


