   FROM ((public.tm_test_runs tr
     JOIN public.tm_cycle_scope cs ON ((tr.cycle_scope_id = cs.id)))
     JOIN public.tm_test_cycles c ON ((cs.cycle_id = c.id)))
  WHERE ((tr.id = tm_step_results.test_run_id) AND public.tm_user_has_access(auth.uid(), c.project_id)))));


